-- Scenario 7001: 隣街への封書配達 (qst_gen_deliver)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7001,
    'qst_gen_deliver',
    '隣街への封書配達',
    '[配達] 隣街の旅籠へ封書を届けて戻る。道中の追い剥ぎに注意。',
    '配達組合',
    2,
    2,
    8,
    '{"gold":250,"items":[],"reputation":2}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['all']::text[],
    '{"location_tags":["all"]}'::jsonb,
    '{"nodes":{"start_prep":{"text":"今日も重い足取りでギルドの依頼板を眺める。まともな日銭になりそうなのは、やはり配達の依頼くらいのものだ。","type":"text","bg_key":"bg_guild","next":"start_street","choices":[{"label":"続ける","next":"start_street"}]},"start_street":{"text":"木賃宿から大通りへ出ると、朝の冷気と土埃の匂いが混じった風が、容赦なく頬を叩いて通り過ぎていく。","type":"text","bg_key":"bg_guild","next":"start","choices":[{"label":"続ける","next":"start"}]},"start":{"text":"配達組合の窓口に足を運ぶと、小太りの受付がうんざりした顔でこちらを睨み、帳面から目を離して話し出した。","type":"text","bg_key":"bg_guild","next":"text_01","choices":[{"label":"続ける","next":"text_01"}]},"text_01":{"text":"「ああ、またお前か。ちょうどいい、この封書を一通、隣街の旅籠の主人へ届けてきてくれ」","type":"text","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","next":"text_01_warn","choices":[{"label":"続ける","next":"text_01_warn"}]},"text_01_warn":{"text":"「絶対に濡らすんじゃないぞ！ 中身のインクが滲んだら、あそこの主人は受け取ってくれないからな」","type":"text","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","next":"text_02","choices":[{"label":"続ける","next":"text_02"}]},"text_02":{"text":"「内容が何かは俺も知らんし、詮索するなよ。組合は中身に関知しない決まりになっている...わかるな？」","type":"text","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","next":"text_02_look","choices":[{"label":"続ける","next":"text_02_look"}]},"text_02_look":{"text":"（知らぬ方が身のため、ということか……。不穏な気配が漂っている）","type":"text","bg_key":"bg_guild","next":"text_03","choices":[{"label":"続ける","next":"text_03"}]},"text_03":{"text":"受け取りの署名を帳面に走らせると、受付は引き出しの奥から厳重に蝋封された一通の手紙を取り出した。","type":"text","bg_key":"bg_guild","next":"text_03_weight","choices":[{"label":"続ける","next":"text_03_weight"}]},"text_03_weight":{"text":"手にした手紙はずしりと重い。まるで誰かの重苦しい人生が封印されているかのようだった。","type":"text","bg_key":"bg_guild","next":"text_04","choices":[{"label":"続ける","next":"text_04"}]},"text_04":{"text":"「往復で八日は見ておけよ。最近は街道の治安が悪く、物騒な追い剥ぎがうろついているらしい」","type":"text","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","next":"text_05","choices":[{"label":"続ける","next":"text_05"}]},"text_05":{"text":"「まあ、そのぶん報酬は多めに上乗せしてある。途中で野垂れ死んでくれるなよ」","type":"text","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","next":"receive","choices":[{"label":"続ける","next":"receive"}]},"receive":{"text":"二重に封印された手紙を背負い袋の奥へ慎重に収め、見覚えのない不気味な紋章の封蝋をそっとなぞった。","type":"text","bg_key":"bg_guild","next":"depart","choices":[{"label":"続ける","next":"depart"}]},"depart":{"text":"重い門をくぐり、隣街へ続く荒涼とした街道へと歩み出す。乾いた熱風が激しく吹き荒れ、砂礫を巻き上げていく。","type":"text","bg_key":"bg_road_day","next":"depart_scenery","choices":[{"label":"続ける","next":"depart_scenery"}]},"depart_scenery":{"text":"周囲を見渡すと、街道の脇には枯れ草に覆われた古い名も無き旅人たちの墓標が、静かに佇んでいた。","type":"text","bg_key":"bg_road_day","next":"road_01","choices":[{"label":"続ける","next":"road_01"}]},"road_01":{"text":"さらに進むと、深く刻まれた馬車の轍の跡が、何故か途中で不自然に引き返した形で途切れている。","type":"text","bg_key":"bg_road_day","next":"road_scenery","choices":[{"label":"続ける","next":"road_scenery"}]},"road_scenery":{"text":"背負い袋の紐が徐々に肩へ食い込み、歩くたびに靴底が砂利と擦れて鈍い音を立てた。","type":"text","bg_key":"bg_road_day","next":"road_scenery_2","choices":[{"label":"続ける","next":"road_scenery_2"}]},"road_scenery_2":{"text":"照りつける太陽が容赦なく体力を奪い、喉の渇きを潤す水筒の水も、すでに底をつきかけている。","type":"text","bg_key":"bg_road_day","next":"road_scenery_3","choices":[{"label":"続ける","next":"road_scenery_3"}]},"road_scenery_3":{"text":"ふと視線を感じて顔を上げると、遠くの岩陰で不気味な人影のようなものが蠢いた気がする。","type":"text","bg_key":"bg_road_day","next":"encounter_alert","choices":[{"label":"続ける","next":"encounter_alert"}]},"encounter_alert":{"text":"その直後、にわかに風が止み、周囲の藪から鳥たちが一斉に羽ばたいて逃げていく。嫌な予感が胸を刺した。","type":"text","bg_key":"bg_road_day","next":"encounter_01","choices":[{"label":"続ける","next":"encounter_01"}]},"encounter_01":{"text":"街道の曲がり角を抜けた瞬間、抜刀した大柄な男が、威嚇するように道を塞いで立ち塞がった！","type":"text","bg_key":"bg_road_day","next":"encounter_02","choices":[{"label":"続ける","next":"encounter_02"}]},"encounter_02":{"text":"さらに背後の藪からもう二人、痩せこけた男たちが音もなく現れ、こちらの退路を完全に遮断した。","type":"text","bg_key":"bg_road_day","next":"encounter_look","choices":[{"label":"続ける","next":"encounter_look"}]},"encounter_look":{"text":"男たちの衣服はボロボロに擦り切れ、その目の奥には飢えた肉食獣のようなぎらついた光が宿っている。","type":"text","bg_key":"bg_road_day","next":"encounter_03","choices":[{"label":"続ける","next":"encounter_03"}]},"encounter_03":{"text":"「おいおい、そこの配達屋。その背負い袋の中身、かなり金目のものが入ってそうだな？」","type":"text","bg_key":"bg_road_day","speaker_name":"追い剥ぎの頭","speaker":"追い剥ぎの頭","next":"encounter_04","choices":[{"label":"続ける","next":"encounter_04"}]},"encounter_04":{"text":"「大人しく荷物を全部置いていきな。そうすれば、お前の命までは取らないでおいてやるよ」","type":"text","bg_key":"bg_road_day","speaker_name":"追い剥ぎの頭","speaker":"追い剥ぎの頭","next":"encounter_prep","choices":[{"label":"続ける","next":"encounter_prep"}]},"encounter_prep":{"text":"（話が通じる相手ではないな……。観念して剣を抜き、身構える）","type":"text","bg_key":"bg_road_day","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","enemy_group_id":"400","enemy_name":"追い剥ぎ一味","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"after_01"},"after_01":{"text":"激しい剣戟の末、ついに追い剥ぎどもを退けた。倒れた頭目の懐からは、安っぽい銅貨数枚がこぼれ落ちて転がっている。","type":"text","bg_key":"bg_road_day","next":"after_01_scenery","choices":[{"label":"続ける","next":"after_01_scenery"}]},"after_01_scenery":{"text":"男たちの苦悶の呻き声を聞き流しながら、自分の服にこびりついた血と土埃を静かに払い落とす。","type":"text","bg_key":"bg_road_day","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"背嚢から封書を取り出して確認する。傷一つなく、蝋封も完璧なままだ。よし、先を急ぐとしよう。","type":"text","bg_key":"bg_road_day","next":"after_02_check","choices":[{"label":"続ける","next":"after_02_check"}]},"after_02_check":{"text":"（何とか生き延びたか……。それだけが、この荒野における唯一の揺るぎない真実だ）","type":"text","bg_key":"bg_road_day","next":"arrive_01","choices":[{"label":"続ける","next":"arrive_01"}]},"arrive_01":{"text":"それから数日、警戒を怠らずに進み、ようやく目的地の寂れた旅籠「黄昏亭」に到着した。","type":"text","bg_key":"bg_tavern_day","next":"arrive_inn_scenery","choices":[{"label":"続ける","next":"arrive_inn_scenery"}]},"arrive_inn_scenery":{"text":"木製の重い扉を開けると、安酒のツンとした臭いと、酸っぱいシチューの匂いが鼻をつく。","type":"text","bg_key":"bg_tavern_day","next":"arrive_inn_look","choices":[{"label":"続ける","next":"arrive_inn_look"}]},"arrive_inn_look":{"text":"（およそ治安が良いとは言えない宿だな。だが、手紙を無事に渡せれば私にはどうでもいい）","type":"text","bg_key":"bg_tavern_day","next":"arrive_02","choices":[{"label":"続ける","next":"arrive_02"}]},"arrive_02":{"text":"「……配達か。組合から？」","type":"text","bg_key":"bg_tavern_day","speaker_name":"黄昏亭の主人","speaker":"黄昏亭の主人","next":"arrive_02_look","choices":[{"label":"続ける","next":"arrive_02_look"}]},"arrive_02_look":{"text":"男の濁った目が、こちらの差し出した封書の蝋に刻まれた紋章に、一瞬だけ鋭く留まる。","type":"text","bg_key":"bg_tavern_day","next":"deliver","choices":[{"label":"続ける","next":"deliver"}]},"deliver":{"type":"choice","bg_key":"bg_tavern_day","choices":[{"label":"封書を渡す","next":"delivery_01"}]},"delivery_01":{"text":"封書を手渡すと、主人はゆっくりと蝋封の凹凸を指でなぞり、そっと懐の奥へと収めた。","type":"text","bg_key":"bg_tavern_day","next":"delivery_01_look","choices":[{"label":"続ける","next":"delivery_01_look"}]},"delivery_01_look":{"text":"主人は満足げに頷くと、周囲を気にしながら、手紙を引き出しの二重底の奥へと隠した。","type":"text","bg_key":"bg_tavern_day","next":"delivery_02","choices":[{"label":"続ける","next":"delivery_02"}]},"delivery_02":{"text":"「ご苦労だった。帰りも気をつけろ。物騒だからな」","type":"text","bg_key":"bg_tavern_day","speaker_name":"黄昏亭の主人","speaker":"黄昏亭の主人","next":"delivery_03","choices":[{"label":"続ける","next":"delivery_03"}]},"delivery_03":{"text":"（この手紙が何をもたらすのか……。いや、詮索は無用。私の仕事はこれで終わりだ）","type":"text","bg_key":"bg_tavern_day","next":"return_road","choices":[{"label":"続ける","next":"return_road"}]},"return_road":{"text":"復路の足取りは往路に比べてはるかに軽い。だが、背後の林から執拗な視線を感じる気がした。","type":"text","bg_key":"bg_road_day","next":"return_look","choices":[{"label":"続ける","next":"return_look"}]},"return_look":{"text":"（ただの気のせいか？ いや、この荒野ではわずかな油断をした者から例外なく死んでいく）","type":"text","bg_key":"bg_road_day","next":"return_near","choices":[{"label":"続ける","next":"return_near"}]},"return_near":{"text":"ひたすら走り続け、遠くに我が街の頑強な石壁が見えてきた。ようやくまともに息がつける。","type":"text","bg_key":"bg_road_day","next":"return_near_02","choices":[{"label":"続ける","next":"return_near_02"}]},"return_near_02":{"text":"ギルドの温かな明かりが見えてくると、無事に旅を終えられた安堵感が全身に込み上げてきた。","type":"text","bg_key":"bg_road_day","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"組合の窓口に報告書を提出すると、受付は無愛想に報酬の入った革袋を机に放り投げた。","type":"text","bg_key":"bg_guild","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「戻ったか。……ふん、生きて帰れただけマシだな。ほら、次の仕事もすぐに回してやる」","type":"end","result":"success","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","params":{"rewards":{"gold":250,"reputation":2}},"choices":[]},"end_failure_01":{"text":"追い剥ぎどもに無残に叩き伏せられ、気がついた時には……手紙も金も、すべて奪い去られていた。","type":"text","bg_key":"bg_guild","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"「手紙を奪われただと！？ 馬鹿野郎、お前の失態に組合からの補償は一銭も出せんぞ！」","type":"end","result":"failure","bg_key":"bg_guild","speaker_name":"配達組合の受付","speaker":"配達組合の受付","choices":[]}},"short_description":"[配達] 隣街の旅籠へ封書を届けて戻る。道中の追い剥ぎに注意。"}'::jsonb,
    8,
    8
) ON CONFLICT (id) DO UPDATE SET
