-- Scenario 7002: 放浪商人の護衛 (qst_gen_escort)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7002,
    'qst_gen_escort',
    '放浪商人の護衛',
    '[護衛] 旅の商人を隣街まで護衛する。商人が倒れれば失敗。',
    '旅商人組合',
    2,
    2,
    8,
    '{"gold":350,"items":[],"reputation":3}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['all']::text[],
    '{"location_tags":["all"]}'::jsonb,
    '{"nodes":{"start_prep":{"text":"旅商人組合の窓口。香辛料と生革の匂いが狭い部屋に満ちている。","type":"text","bg_key":"bg_guild","next":"start","choices":[{"label":"続ける","next":"start"}]},"start":{"text":"埃っぽい木製のカウンター越しに、羊皮紙の依頼書を受け取った。","type":"text","bg_key":"bg_guild","next":"text_01","choices":[{"label":"続ける","next":"text_01"}]},"text_01":{"text":"「護衛対象は行商人のマルコ。隣街まで往復八日の旅だ」","type":"text","bg_key":"bg_guild","speaker_name":"旅商人組合の受付","speaker":"旅商人組合の受付","next":"text_02","choices":[{"label":"続ける","next":"text_02"}]},"text_02":{"text":"「積み荷は雑貨と薬品。狙われやすい品ばかりだな」","type":"text","bg_key":"bg_guild","speaker_name":"旅商人組合の受付","speaker":"旅商人組合の受付","next":"text_03","choices":[{"label":"続ける","next":"text_03"}]},"text_03":{"text":"「先月、同じ路線で護衛二名が殺された。気を抜くなよ」","type":"text","bg_key":"bg_guild","speaker_name":"旅商人組合の受付","speaker":"旅商人組合の受付","next":"text_03_warning","choices":[{"label":"続ける","next":"text_03_warning"}]},"text_03_warning":{"text":"「依頼料が他より跳ね上がっているのはそういうわけだ。せいぜい生きて戻ることだけを考えろよ」","type":"text","bg_key":"bg_guild","speaker_name":"旅商人組合の受付","speaker":"旅商人組合の受付","next":"meet_01","choices":[{"label":"続ける","next":"meet_01"}]},"meet_01":{"text":"酒場の片隅。山積みの麻袋と木箱の影に、小柄な中年男がいた。","type":"text","bg_key":"bg_tavern_day","next":"meet_look","choices":[{"label":"続ける","next":"meet_look"}]},"meet_look":{"text":"男は擦り切れた外套を羽織り、絶えず周囲を気にしている。","type":"text","bg_key":"bg_tavern_day","next":"meet_02","choices":[{"label":"続ける","next":"meet_02"}]},"meet_02":{"text":"「あんたが今回の護衛かい？ ありがてえ、よろしく頼むよ……マルコだ」","type":"text","bg_key":"bg_tavern_day","speaker_name":"マルコ","speaker":"マルコ","next":"meet_03","choices":[{"label":"続ける","next":"meet_03"}]},"meet_03":{"text":"握った手は冷たく汗ばんでいた。どこか落ち着きがない。","type":"text","bg_key":"bg_tavern_day","next":"meet_chk","choices":[{"label":"続ける","next":"meet_chk"}]},"meet_chk":{"text":"挨拶もそこそこに、荷車の車輪を点検する。油は差されているが、軋む重い音が響いた。","type":"text","bg_key":"bg_tavern_day","next":"join","choices":[{"label":"続ける","next":"join"}]},"join":{"text":"マルコがパーティに加わった。","type":"guest_join","bg_key":"bg_tavern_day","params":{"guest_id":"npc_gen_merchant","is_escort_target":true},"next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"重い石門をくぐり、荒涼とした街道へ足を踏み入れる。だが、マルコの足取りは酷く遅い。","type":"text","bg_key":"bg_road_day","next":"travel_01_road","choices":[{"label":"続ける","next":"travel_01_road"}]},"travel_01_road":{"text":"周囲を見渡すと遮るもののない平原が広がり、乾燥した風が錆びた車輪を鳴らしていた。","type":"text","bg_key":"bg_road_day","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"やがて陽が傾き、空が鈍い血の色に染まる頃、彼が囁いた。","type":"text","bg_key":"bg_road_day","next":"travel_03","choices":[{"label":"続ける","next":"travel_03"}]},"travel_03":{"text":"「実はな……荷の中に、少しだけ\"特別な品\"が混ざっているんだ」","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"travel_04","choices":[{"label":"続ける","next":"travel_04"}]},"travel_04":{"text":"「もし追い剥ぎに目をつけられたら、面倒なことになるかもしれねえ」","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"travel_05","choices":[{"label":"続ける","next":"travel_05"}]},"travel_05":{"text":"男の怯えた目が、固く縛られた木箱の隙間に向けられている。","type":"text","bg_key":"bg_road_day","next":"travel_05_think","choices":[{"label":"続ける","next":"travel_05_think"}]},"travel_05_think":{"text":"中身は詮索しない。それが冒険者としての護身の知恵だ。","type":"text","bg_key":"bg_road_day","next":"midway","choices":[{"label":"続ける","next":"midway"}]},"midway":{"text":"街道が崖の影に折れ曲がる場所で、林の向こうから黒い煙が立ち上るのが見えた。","type":"text","bg_key":"bg_road_day","next":"encounter_alert","choices":[{"label":"続ける","next":"encounter_alert"}]},"encounter_alert":{"text":"鳥の羽ばたきが唐突に途絶える。マルコは短く息を呑み、荷車の影へと身を隠した。","type":"text","bg_key":"bg_road_day","next":"encounter_01","choices":[{"label":"続ける","next":"encounter_01"}]},"encounter_01":{"text":"『動くな！ 荷を置いていけ！』茂みの奥から、ギラついた目の男たちが立ち塞がる！","type":"text","bg_key":"bg_road_day","next":"encounter_02","choices":[{"label":"続ける","next":"encounter_02"}]},"encounter_02":{"text":"「ひっ、旦那ッ！ 荷物だけは、荷物だけは何としても守ってくれ！」","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"夜盗が襲いかかってきた！","type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","enemy_group_id":"400","enemy_name":"追い剥ぎ一味","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"激しい剣戟の末、夜盗どもを蹴散らした。地面には赤黒い血だまりが広がっていく。","type":"text","bg_key":"bg_road_day","next":"after_01_look","choices":[{"label":"続ける","next":"after_01_look"}]},"after_01_look":{"text":"マルコは荷車の陰から怯えながら這い出し、荷を結ぶロープの無事を確認した。","type":"text","bg_key":"bg_road_day","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"「……全部無事だ。あんた、本当に腕の立つ冒険者なんだな…」","type":"text","bg_key":"bg_road_day","speaker_name":"マルコ","speaker":"マルコ","next":"after_02_rest","choices":[{"label":"続ける","next":"after_02_rest"}]},"after_02_rest":{"text":"息を整える。血の匂いに誘われて魔物が来る前に、先を急ごう。","type":"text","bg_key":"bg_road_day","next":"arrive_01","choices":[{"label":"続ける","next":"arrive_01"}]},"arrive_01":{"text":"隣街の煤けた酒場に到着。マルコは手早く荷物を降ろし始めた。","type":"text","bg_key":"bg_tavern_day","next":"arrive_inn_look","choices":[{"label":"続ける","next":"arrive_inn_look"}]},"arrive_inn_look":{"text":"奥の部屋から現れたガタイのいい男たちに、木箱が手渡される。","type":"text","bg_key":"bg_tavern_day","next":"arrive_02","choices":[{"label":"続ける","next":"arrive_02"}]},"arrive_02":{"text":"引き渡しを終えたマルコが、安堵の表情で銀貨の袋を差し出す。","type":"text","bg_key":"bg_tavern_day","next":"arrive_03","choices":[{"label":"続ける","next":"arrive_03"}]},"arrive_03":{"text":"「約束通り、あの\"特別な品\"については他所で口外しないでくれよ？」","type":"text","bg_key":"bg_tavern_day","speaker_name":"マルコ","speaker":"マルコ","next":"leave","choices":[{"label":"続ける","next":"leave"}]},"leave":{"text":"マルコがパーティから離れた。","type":"leave","bg_key":"bg_tavern_day","next":"return_scenery","choices":[{"label":"続ける","next":"return_scenery"}]},"return_scenery":{"text":"帰路は一人。重荷を降ろした街道は、往路より広く感じられた。","type":"text","bg_key":"bg_road_day","next":"return_scenery_2","choices":[{"label":"続ける","next":"return_scenery_2"}]},"return_scenery_2":{"text":"夕闇が荒野を飲み込んでいく。急ぎ足で自分の街へと向かった。","type":"text","bg_key":"bg_road_day","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"護衛任務完了。\"特別な品\"とマルコの安堵の表情を思い出したが、詳しく考えないようにした。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":350,"reputation":3}},"choices":[]},"end_failure":{"text":"マルコが倒れた。荷物は夜盗に奪われ、全てを失った。","type":"end","result":"failure","bg_key":"bg_guild","params":{"guest_id":"npc_gen_merchant"},"choices":[]}},"short_description":"[護衛] 旅の商人を隣街まで護衛する。商人が倒れれば失敗。"}'::jsonb,
    8,
    8
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7003: 廃墟の金庫回収 (qst_gen_scavenge)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7003,
    'qst_gen_scavenge',
    '廃墟の金庫回収',
    '[探索] 廃墟の金庫から物資を回収する。届けるか売りさばくか。',
    '冒険者ギルド',
    2,
    2,
    3,
    '{"gold":250,"items":[],"reputation":2}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['all']::text[],
    '{"location_tags":["all"]}'::jsonb,
    '{"nodes":{"start_prep":{"text":"朝のギルドは騒がしい。押し寄せる冒険者たちを押しのけ、依頼板を見る。","type":"text","bg_key":"bg_guild","next":"start","choices":[{"label":"続ける","next":"start"}]},"start":{"text":"冒険者ギルドの掲示板に、急ぎの依頼が貼られていた。","type":"text","bg_key":"bg_guild","next":"text_01","choices":[{"label":"続ける","next":"text_01"}]},"text_01":{"text":"「崩壊街区の廃墟金庫から物資を回収。中身は開封不可」","type":"text","bg_key":"bg_guild","next":"text_02","choices":[{"label":"続ける","next":"text_02"}]},"text_02":{"text":"「場所は崩壊街区の北だ。先週の地震で通路の一部が崩れているから注意しろ」","type":"text","bg_key":"bg_guild","speaker_name":"ギルド担当","speaker":"ギルド担当","next":"text_03","choices":[{"label":"続ける","next":"text_03"}]},"text_03":{"text":"「最近はあの辺りをゴブリンどもがねぐらにしているという報告もある」","type":"text","bg_key":"bg_guild","speaker_name":"ギルド担当","speaker":"ギルド担当","next":"text_04","choices":[{"label":"続ける","next":"text_04"}]},"text_04":{"text":"依頼書にサインを入れ、廃墟の地図を受け取った。","type":"text","bg_key":"bg_guild","next":"enter_01","choices":[{"label":"続ける","next":"enter_01"}]},"enter_01":{"text":"廃墟の入り口に足を踏み入れる。天井の半ばが崩れ落ち、瓦礫が散乱していた。","type":"text","bg_key":"bg_ruins_field","next":"enter_scenery","choices":[{"label":"続ける","next":"enter_scenery"}]},"enter_scenery":{"text":"周囲を見渡すと、湿った土と腐った木材の臭いが漂い、かつての繁栄の面影など微塵もなかった。","type":"text","bg_key":"bg_ruins_field","next":"enter_02","choices":[{"label":"続ける","next":"enter_02"}]},"enter_02":{"text":"壁にはかすれた古い紋章。かつて商家の倉庫だったようだ。","type":"text","bg_key":"bg_ruins_field","next":"enter_03","choices":[{"label":"続ける","next":"enter_03"}]},"enter_03":{"text":"奥に進むと薄暗い通路の先に、頑強だが錆びた鉄扉が見えた。","type":"text","bg_key":"bg_ruins_field","next":"enter_darkness","choices":[{"label":"続ける","next":"enter_darkness"}]},"enter_darkness":{"text":"足元に転がる小石を慎重に避けながら、呼吸を整える。","type":"text","bg_key":"bg_ruins_field","next":"goblin_01","choices":[{"label":"続ける","next":"goblin_01"}]},"goblin_01":{"text":"鉄扉の前にゴブリンが二匹。木箱を漁っている。","type":"text","bg_key":"bg_ruins_field","next":"goblin_02","choices":[{"label":"続ける","next":"goblin_02"}]},"goblin_02":{"text":"こちらに気づくと、黄色い目をギラつかせ、耳障りな金切声を上げて威嚇してきた！","type":"text","bg_key":"bg_ruins_field","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"ゴブリンが襲いかかってきた！","type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle","enemy_group_id":"402","enemy_name":"ゴブリンたち","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"ゴブリンを倒した。緑の血を吸った土を踏みしめ前へ進む。","type":"text","bg_key":"bg_ruins_field","next":"after_lock","choices":[{"label":"続ける","next":"after_lock"}]},"after_lock":{"text":"鉄扉の前に立ち、錆びついた錠前へナイフの刃先を突き立てた。","type":"text","bg_key":"bg_ruins_field","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"中には重厚な鉄の金庫が一つ。ギルドの封印が施されている。","type":"text","bg_key":"bg_ruins_field","next":"hob_01","choices":[{"label":"続ける","next":"hob_01"}]},"hob_01":{"text":"金庫の横にもう一つの通路。奥から重く湿った足音。","type":"text","bg_key":"bg_ruins_field","next":"hob_02","choices":[{"label":"続ける","next":"hob_02"}]},"hob_02":{"text":"暗闇から、倍以上の体躯を持つホブゴブリンが、取り巻きを引き連れて姿を現した！","type":"text","bg_key":"bg_ruins_field","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"ホブゴブリンの群れが襲いかかってきた！","type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle","enemy_group_id":"403","enemy_name":"ホブゴブリン一味","choices":[{"label":"win","next":"recover"},{"label":"lose","next":"end_failure"}],"battle_success_next":"recover"},"recover":{"text":"なんとか敵を退けた。呼吸は荒く、全身が泥と血に汚れている。","type":"text","bg_key":"bg_ruins_field","next":"recover_weight","choices":[{"label":"続ける","next":"recover_weight"}]},"recover_weight":{"text":"重い金庫を担ぎ上げる。中身がかすかに揺れる音がした。","type":"text","bg_key":"bg_ruins_field","next":"moral_01","choices":[{"label":"続ける","next":"moral_01"}]},"moral_01":{"text":"重い金庫を背負って外へと出た。だが、これを闇市へ持っていけば、ギルドを介すより倍で売れるだろう。","type":"text","bg_key":"bg_road_day","next":"moral_02","choices":[{"label":"続ける","next":"moral_02"}]},"moral_02":{"type":"choice","bg_key":"bg_road_day","choices":[{"label":"ギルドに届ける","next":"guild_01"},{"label":"闇市に売る","next":"dark_01"}]},"guild_01":{"text":"金庫をギルドに持ち帰った。担当が封印の無事を確認する。","type":"text","bg_key":"bg_guild","next":"guild_02","choices":[{"label":"続ける","next":"guild_02"}]},"guild_02":{"text":"「封印は無事だな。よし、よくやった。これが約束の報酬だ」","type":"text","bg_key":"bg_guild","speaker_name":"ギルド担当","speaker":"ギルド担当","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"物資回収完了。正当な報酬を受け取った。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":250,"exp":35,"reputation":2}},"choices":[]},"dark_01":{"text":"スラムの裏路地、薄暗い倉庫に金庫を持ち込んだ。","type":"text","bg_key":"bg_slum","next":"dark_02","choices":[{"label":"続ける","next":"dark_02"}]},"dark_02":{"text":"「フッ……いい品じゃないか。ギルドの倍額で買い取ろう。もちろん、お互いのために秘密裏にな」","type":"text","bg_key":"bg_slum","speaker_name":"闇商人","speaker":"闇商人","next":"dark_think","choices":[{"label":"続ける","next":"dark_think"}]},"dark_think":{"text":"中身は誰に渡ったのか。考えるのはよそう。金がすべてだ。","type":"text","bg_key":"bg_slum","next":"end_dark","choices":[{"label":"続ける","next":"end_dark"}]},"end_dark":{"text":"闇市で売りさばいた。懐は潤ったが、良心が痛む。","type":"end","result":"success","bg_key":"bg_slum","params":{"rewards":{"gold":500,"exp":35,"reputation":-5,"alignment_shift":{"chaos":10}}},"choices":[]},"end_failure":{"text":"力尽き、廃墟の床に倒れ伏す。金庫は泥の中に残された。","type":"end","result":"failure","bg_key":"bg_ruins_field","choices":[]}},"short_description":"[探索] 廃墟の金庫から物資を回収する。届けるか売りさばくか。"}'::jsonb,
    3,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7004: 食料暴動の事前鎮圧 (qst_gen_riot)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7004,
    'qst_gen_riot',
    '食料暴動の事前鎮圧',
    '[鎮圧] 暴動を企てる飢えた市民を力でねじ伏せる。',
    '自治会',
    2,
    2,
    1,
    '{"gold":200,"items":[],"reputation":5,"alignment_shift":{"order":5,"justice":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['all']::text[],
    '{"location_tags":["all"]}'::jsonb,
    '{"nodes":{"start_prep":{"text":"石造りの重苦しい自治会事務所。暖炉の煤が天井を黒く汚している。","type":"text","bg_key":"bg_office","next":"start","choices":[{"label":"続ける","next":"start"}]},"start":{"text":"自治会の事務所に呼ばれた。閉め切った窓の外から怒声が響く。","type":"text","bg_key":"bg_office","next":"text_01","choices":[{"label":"続ける","next":"text_01"}]},"text_01":{"text":"「東区画の広場に、腹を空かせた市民どもが集結し始めている」","type":"text","bg_key":"bg_office","speaker_name":"自治会事務官","speaker":"自治会事務官","next":"text_02","choices":[{"label":"続ける","next":"text_02"}]},"text_02":{"text":"「放っておけば確実に大規模な暴動へと発展する。ただちに鎮圧してもらいたい」","type":"text","bg_key":"bg_office","speaker_name":"自治会事務官","speaker":"自治会事務官","next":"text_03","choices":[{"label":"続ける","next":"text_03"}]},"text_03":{"text":"「首謀者は先月の凶作で食い詰めた農民どもだ。備蓄倉庫を襲撃する計画を立てているらしい」","type":"text","bg_key":"bg_office","speaker_name":"自治会事務官","speaker":"自治会事務官","next":"text_04","choices":[{"label":"続ける","next":"text_04"}]},"text_04":{"text":"「暴動を許せば街の秩序が崩壊する。ただし、余計な反発を避けるためにも、なるべく殺さずにね」","type":"text","bg_key":"bg_office","speaker_name":"自治会事務官","speaker":"自治会事務官","next":"text_04_think","choices":[{"label":"続ける","next":"text_04_think"}]},"text_04_think":{"text":"「なるべく殺さずに」。冷たい官僚の言い回しに胸が痛む。","type":"text","bg_key":"bg_office","next":"square_road","choices":[{"label":"続ける","next":"square_road"}]},"square_road":{"text":"裏通りをすり抜けて進む。物乞いさえ消えたスラムは、不気味なほどに静まり返っていた。","type":"text","bg_key":"bg_slum","next":"square_01","choices":[{"label":"続ける","next":"square_01"}]},"square_01":{"text":"だが、角を曲がって東区画の広場に入った途端、ぼろ切れを纏った市民たちの怒号が耳を刺す。","type":"text","bg_key":"bg_slum","next":"square_scenery","choices":[{"label":"続ける","next":"square_scenery"}]},"square_scenery":{"text":"空気は澱み、熱気の中に酸っぱいゴミの臭いが混じっていた。","type":"text","bg_key":"bg_slum","next":"square_02","choices":[{"label":"続ける","next":"square_02"}]},"square_02":{"text":"子供を抱えた女、杖にすがる老人。錆びた鎌を握る若い男。","type":"text","bg_key":"bg_slum","next":"square_03","choices":[{"label":"続ける","next":"square_03"}]},"square_03":{"text":"「俺たちは飢えてるんだ！ 倉庫を開けろ！」","type":"text","bg_key":"bg_slum","speaker_name":"暴徒のリーダー","speaker":"暴徒のリーダー","next":"square_mood","choices":[{"label":"続ける","next":"square_mood"}]},"square_mood":{"text":"男の叫びに応え、人々が手に持った棒切れを突き上げる。","type":"text","bg_key":"bg_slum","next":"square_04_think","choices":[{"label":"続ける","next":"square_04_think"}]},"square_04_think":{"text":"彼らを力で抑えることが、本当にこの街の「秩序」なのか。","type":"text","bg_key":"bg_slum","next":"confront_01","choices":[{"label":"続ける","next":"confront_01"}]},"confront_01":{"text":"群衆の前にゆっくりと立ちはだかった。一瞬、静寂が訪れる。","type":"text","bg_key":"bg_slum","next":"confront_look","choices":[{"label":"続ける","next":"confront_look"}]},"confront_look":{"text":"武器を抜く私を睨みつけ、人々の目に恐怖と剥き出しの憎悪が浮かんだ。","type":"text","bg_key":"bg_slum","next":"confront_02","choices":[{"label":"続ける","next":"confront_02"}]},"confront_02":{"text":"「自治会の犬か……飢えた子供を守ってるだけだ」","type":"text","bg_key":"bg_slum","speaker_name":"暴徒のリーダー","speaker":"暴徒のリーダー","next":"confront_03","choices":[{"label":"続ける","next":"confront_03"}]},"confront_03":{"text":"群衆が殺気立つ。錆びた農具を握る手が小刻みに震えていた。","type":"text","bg_key":"bg_slum","next":"confront_shout","choices":[{"label":"続ける","next":"confront_shout"}]},"confront_shout":{"text":"「邪魔するなら容赦はしねえ！ 叩き出せ！」","type":"text","bg_key":"bg_slum","speaker_name":"暴徒のリーダー","speaker":"暴徒のリーダー","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"暴動が始まった！","type":"battle","bg_key":"bg_slum","bgm":"bgm_battle","enemy_group_id":"404","enemy_name":"飢えた市民たち","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"暴徒を鎮圧した。地面に倒れ、うずくまる市民たちの呻き声。","type":"text","bg_key":"bg_slum","next":"after_bloodshed","choices":[{"label":"続ける","next":"after_bloodshed"}]},"after_bloodshed":{"text":"折れた木棒と農具が散らばる。流れた血は赤黒く土に染みる。","type":"text","bg_key":"bg_slum","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"リーダーの男が額から血を流しながら、こちらを見上げた。","type":"text","bg_key":"bg_slum","next":"after_03","choices":[{"label":"続ける","next":"after_03"}]},"after_03":{"text":"「…俺たちが悪いんじゃねえ…飢えさせた奴らが悪いんだっ！」","type":"text","bg_key":"bg_slum","speaker_name":"暴徒のリーダー","speaker":"暴徒のリーダー","next":"after_04","choices":[{"label":"続ける","next":"after_04"}]},"after_04":{"text":"重装備の衛兵たちが到着し、泣き叫ぶ群衆を強引に解散させた。","type":"text","bg_key":"bg_slum","next":"after_silent","choices":[{"label":"続ける","next":"after_silent"}]},"after_silent":{"text":"誰もいなくなった広場に、千切れた子供の靴だけが残る。","type":"text","bg_key":"bg_slum","next":"return_office","choices":[{"label":"続ける","next":"return_office"}]},"return_office":{"text":"冷たい静寂が降り積もる東区画を後にし、私たちは自治会事務所へと足を向けた。","type":"text","bg_key":"bg_office","next":"return_scenery","choices":[{"label":"続ける","next":"return_scenery"}]},"return_scenery":{"text":"見上げる空は灰色に曇り、乾いた風が吹き抜けては路地の土埃を激しく巻き上げる。","type":"text","bg_key":"bg_office","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"任務完了。血の付いた報酬の金貨は、ひどく冷たかった。","type":"end","result":"success","bg_key":"bg_office","params":{"rewards":{"gold":200,"reputation":5,"alignment_shift":{"order":5,"justice":5}}},"choices":[]},"end_failure":{"text":"暴徒の熱量に押し返された。地面に這いつくばり敗北を知る。","type":"end","result":"failure","bg_key":"bg_slum","choices":[]}},"short_description":"[鎮圧] 暴動を企てる飢えた市民を力でねじ伏せる。"}'::jsonb,
    1,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7005: 凶熊狩り (qst_gen_bear)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7005,
    'qst_gen_bear',
    '凶熊狩り',
    '[討伐] 開拓村を襲う凶暴な大熊を狩る。前任の猟師は行方不明。',
    '開拓村の長',
    2,
    2,
    4,
    '{"gold":200,"items":["item_bear_pelt"],"reputation":5}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['all']::text[],
    '{"location_tags":["all"]}'::jsonb,
    '{"nodes":{"start_prep":{"text":"暖炉に薪が爆ぜる音が響く、開拓村の荒れ果てた集会所。","type":"text","bg_key":"bg_guild","next":"start","choices":[{"label":"続ける","next":"start"}]},"start":{"text":"暖かなスープをすすりながら、長の話に耳を傾ける。","type":"text","bg_key":"bg_guild","next":"text_01","choices":[{"label":"続ける","next":"text_01"}]},"text_01":{"text":"「村の東の森に、恐ろしく凶暴な大熊が棲みついてしまってな…」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"text_02","choices":[{"label":"続ける","next":"text_02"}]},"text_02":{"text":"「畑を荒らすだけならまだしも、調査に向かった猟師のヨルンが行方不明になっておる」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"text_03","choices":[{"label":"続ける","next":"text_03"}]},"text_03":{"text":"「もう三日も戻らん。加えて、森の入り口には、奴の血痕が点々と残されていたというわけだ」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"text_04","choices":[{"label":"続ける","next":"text_04"}]},"text_04":{"text":"「あの獣は体中に傷があり、片目が潰れている。わしの経験上、手負いの獣ほど厄介なものはない」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"text_04_think","choices":[{"label":"続ける","next":"text_04_think"}]},"text_04_think":{"text":"「片目が潰れた熊」。かつて手負いにされ、凶暴化した獣か。","type":"text","bg_key":"bg_guild","next":"forest_01","choices":[{"label":"続ける","next":"forest_01"}]},"forest_01":{"text":"鬱蒼と生い茂る森へ足を踏み入れる。密な枝葉が日光を遮り、冷たい湿気が立ち込めていた。","type":"text","bg_key":"bg_forest_day","next":"forest_scenery","choices":[{"label":"続ける","next":"forest_scenery"}]},"forest_scenery":{"text":"足元の枯れたシダを踏みしめるたび、乾いた音が周囲へやけに大きく響いた。","type":"text","bg_key":"bg_forest_day","next":"forest_02","choices":[{"label":"続ける","next":"forest_02"}]},"forest_02":{"text":"地面に巨大な足跡。五本の爪跡が泥の中に深く刻まれていた。","type":"text","bg_key":"bg_forest_day","next":"forest_deep","choices":[{"label":"続ける","next":"forest_deep"}]},"forest_deep":{"text":"森の奥へ進むほど、空気から生命の気配が薄れていく。","type":"text","bg_key":"bg_forest_day","next":"trail_01","choices":[{"label":"続ける","next":"trail_01"}]},"trail_01":{"text":"足跡の先に引き裂かれた鉄製の罠。猟師ヨルンの物だろう。","type":"text","bg_key":"bg_forest_day","next":"trail_01_body","choices":[{"label":"続ける","next":"trail_01_body"}]},"trail_01_body":{"text":"罠の周りに飛び散った血痕は、すでに黒く変色している。","type":"text","bg_key":"bg_forest_day","next":"trail_02","choices":[{"label":"続ける","next":"trail_02"}]},"trail_02":{"text":"巨木の幹に荒々しい爪痕。皮が剥がれ、獣の強烈な臭いが漂う。","type":"text","bg_key":"bg_forest_day","next":"trail_02_scenery","choices":[{"label":"続ける","next":"trail_02_scenery"}]},"trail_02_scenery":{"text":"静寂が森を支配している。微かな風の音さえも消えた。","type":"text","bg_key":"bg_forest_day","next":"trail_03","choices":[{"label":"続ける","next":"trail_03"}]},"trail_03":{"text":"突如、目前の藪の奥から、低く地鳴りのような唸り声が響き渡る。","type":"text","bg_key":"bg_forest_day","next":"encounter_01","choices":[{"label":"続ける","next":"encounter_01"}]},"encounter_01":{"text":"茂みを掻き分けると、見上げるほどの巨躯が立ち上がった。","type":"text","bg_key":"bg_forest_day","next":"encounter_look","choices":[{"label":"続ける","next":"encounter_look"}]},"encounter_look":{"text":"岩のような筋肉に覆われた体躯。剥き出しの牙が光る。","type":"text","bg_key":"bg_forest_day","next":"encounter_02","choices":[{"label":"続ける","next":"encounter_02"}]},"encounter_02":{"text":"全身は無数の古傷に覆われ、白く濁った片目の奥には底知れぬ狂気が宿っていた。","type":"text","bg_key":"bg_forest_day","next":"encounter_03","choices":[{"label":"続ける","next":"encounter_03"}]},"encounter_03":{"text":"こちらを睨みつけると、森全体を激しく震わせる咆哮を上げた！","type":"text","bg_key":"bg_forest_day","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"大熊が襲いかかってきた！","type":"battle","bg_key":"bg_forest_day","bgm":"bgm_battle","enemy_group_id":"405","enemy_name":"ジャイアントベア","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"大熊が崩れ落ちた。濁った片目の奥には、深い疲労があった。","type":"text","bg_key":"bg_forest_day","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"無残に引き裂かれた猟師の外套の切れ端を見つけ、懐に収める。","type":"text","bg_key":"bg_forest_day","next":"after_02_silent","choices":[{"label":"続ける","next":"after_02_silent"}]},"after_02_silent":{"text":"静まり返った森で、大熊の骸から流れる血の匂いが漂う。","type":"text","bg_key":"bg_forest_day","next":"return_01","choices":[{"label":"続ける","next":"return_01"}]},"return_01":{"text":"剥ぎ取った大熊の毛皮を担いで村へと戻る。それを示すと、長は深く安堵の息を吐き出した。","type":"text","bg_key":"bg_guild","next":"return_02","choices":[{"label":"続ける","next":"return_02"}]},"return_02":{"text":"「……ヨルンはどうなった？ 遺品だけでも、何か見つからなかったか？」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"return_03","choices":[{"label":"続ける","next":"return_03"}]},"return_03":{"text":"「あいつの外套か……。ありがとう。これで村の連中も安心できる」","type":"text","bg_key":"bg_guild","speaker_name":"開拓村の長","speaker":"開拓村の長","next":"return_03_rest","choices":[{"label":"続ける","next":"return_03_rest"}]},"return_03_rest":{"text":"長はヨルンの外套を抱きしめ、静かに目を閉じた。","type":"text","bg_key":"bg_guild","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"凶熊狩り完了。手にした報酬の重みと、残された哀愁を感じる。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":200,"reputation":5}},"choices":[]},"end_failure":{"text":"大熊の爪が胸を裂く。冷たい落ち葉の上で意識が消え去った。","type":"end","result":"failure","bg_key":"bg_forest_day","choices":[]}},"short_description":"[討伐] 開拓村を襲う凶暴な大熊を狩る。前任の猟師は行方不明。"}'::jsonb,
    4,
    4
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7006: 禁制品の闇ルート輸送 (qst_gen_smuggle)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7006,
    'qst_gen_smuggle',
    '禁制品の闇ルート輸送',
    '[密輸] 中身不明の禁制品を隣街まで運ぶ。追手に注意。',
    '闇商人',
    2,
    2,
    8,
    '{"gold":800,"items":[],"reputation":-5,"alignment_shift":{"evil":5,"chaos":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['all']::text[],
    '{"location_tags":["all"],"max_reputation":-50}'::jsonb,
    '{"nodes":{"start_prep":{"text":"スラムの腐ったゴミとドブの臭いが漂う、暗い路地裏。","type":"text","bg_key":"bg_slum","next":"start","choices":[{"label":"続ける","next":"start"}]},"start":{"text":"黒い外套をまとった闇商人が立っていた。鋭い目が光る。","type":"text","bg_key":"bg_slum","next":"text_01","choices":[{"label":"続ける","next":"text_01"}]},"text_01":{"text":"「中身を詮索するなよ。この箱を無事に隣街の赤猫亭まで届けてもらいたい」","type":"text","bg_key":"bg_slum","speaker_name":"闇商人","speaker":"闇商人","next":"text_02","choices":[{"label":"続ける","next":"text_02"}]},"text_02":{"text":"「衛兵の検問を避けるため、街道ではなく旧道の山道を通るんだ」","type":"text","bg_key":"bg_slum","speaker_name":"闇商人","speaker":"闇商人","next":"text_03","choices":[{"label":"続ける","next":"text_03"}]},"text_03":{"text":"「厄介な追手がつくかもしれないが、そこはあんたの腕で片付けろ」","type":"text","bg_key":"bg_slum","speaker_name":"闇商人","speaker":"闇商人","next":"text_03_warning","choices":[{"label":"続ける","next":"text_03_warning"}]},"text_03_warning":{"text":"「言っておくが、へまをすればお前も私も消される。……わかるな？」","type":"text","bg_key":"bg_slum","speaker_name":"闇商人","speaker":"闇商人","next":"text_04","choices":[{"label":"続ける","next":"text_04"}]},"text_04":{"text":"商人は黒い木箱を押しつけ、影のように闇へ消え去った。","type":"text","bg_key":"bg_slum","next":"text_04_think","choices":[{"label":"続ける","next":"text_04_think"}]},"text_04_think":{"text":"ずっしりと重い。隙間から、何かの薬品の臭いが漂う。","type":"text","bg_key":"bg_slum","next":"depart","choices":[{"label":"続ける","next":"depart"}]},"depart":{"text":"人目を避けるように街の裏門を抜け、荒れた旧道へと入る。舗装などされていない獣道を静かに歩んだ。","type":"text","bg_key":"bg_road_night","next":"depart_scenery","choices":[{"label":"続ける","next":"depart_scenery"}]},"depart_scenery":{"text":"月明かりだけが頼りだ。夜の静寂が五感を研ぎ澄ます。","type":"text","bg_key":"bg_road_night","next":"night_01","choices":[{"label":"続ける","next":"night_01"}]},"night_01":{"text":"箱を背負い、足音を殺して進む。草むらの虫の声だけ。","type":"text","bg_key":"bg_road_night","next":"night_01_sound","choices":[{"label":"続ける","next":"night_01_sound"}]},"night_01_sound":{"text":"風が木々を揺らし、木化けのような影が道を覆う。","type":"text","bg_key":"bg_road_night","next":"night_02","choices":[{"label":"続ける","next":"night_02"}]},"night_02":{"text":"道の途中で背後に気配を感じた。闇の中に二つの人影。","type":"text","bg_key":"bg_road_night","next":"night_03","choices":[{"label":"続ける","next":"night_03"}]},"night_03":{"text":"こちらの速度に合わせて追ってくる。手慣れた追跡者だ。","type":"text","bg_key":"bg_road_night","next":"night_03_rush","choices":[{"label":"続ける","next":"night_03_rush"}]},"night_03_rush":{"text":"走って逃げ切ることは難しい。敵を迎撃する覚悟を決める。","type":"text","bg_key":"bg_road_night","next":"encounter_01","choices":[{"label":"続ける","next":"encounter_01"}]},"encounter_01":{"text":"「止まれ！ その大事そうに抱えている荷物を置いていけ！」","type":"text","bg_key":"bg_road_night","speaker_name":"追手","speaker":"追手","next":"encounter_02","choices":[{"label":"続ける","next":"encounter_02"}]},"encounter_02":{"text":"闇の中から、抜き放たれた刃を構えた追手たちが静かに進み出る。もはや逃げ場はない！","type":"text","bg_key":"bg_road_night","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"text":"追手が襲いかかってきた！","type":"battle","bg_key":"bg_road_night","bgm":"bgm_battle","enemy_group_id":"406","enemy_name":"追手部隊","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"追手を退けた。倒れた敵の息の根を止め、息を整える。","type":"text","bg_key":"bg_road_night","next":"after_bloodshed","choices":[{"label":"続ける","next":"after_bloodshed"}]},"after_bloodshed":{"text":"荷を確認する。封印は無事だ。中身は漏れ出していない。","type":"text","bg_key":"bg_road_night","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"これ以上、この場に留まるのは自殺行為だ。先へ進もう。","type":"text","bg_key":"bg_road_night","next":"after_02_rush","choices":[{"label":"続ける","next":"after_02_rush"}]},"after_02_rush":{"text":"夜霧が立ち込める中、残りの夜道を急ぎ足で駆け抜けた。","type":"text","bg_key":"bg_road_night","next":"arrive","choices":[{"label":"続ける","next":"arrive"}]},"arrive":{"text":"夜明け前の冷気が包む頃、ようやく目的の隣街に到着した。裏路地へ回り、赤猫亭の戸を固く叩く。","type":"text","bg_key":"bg_tavern_night","next":"arrive_inn_scenery","choices":[{"label":"続ける","next":"arrive_inn_scenery"}]},"arrive_inn_scenery":{"text":"きしむ扉の隙間から、鋭い目つきの男が顔を覗かせた。","type":"text","bg_key":"bg_tavern_night","next":"arrive_02","choices":[{"label":"続ける","next":"arrive_02"}]},"arrive_02":{"text":"無言の男が木箱を受け取り、代わりに重い革袋を渡す。","type":"text","bg_key":"bg_tavern_night","next":"arrive_02_accept","choices":[{"label":"続ける","next":"arrive_02_accept"}]},"arrive_02_accept":{"text":"袋の中で、ぎっしりと詰まった金貨が鈍い音を立てた。","type":"text","bg_key":"bg_tavern_night","next":"return_road","choices":[{"label":"続ける","next":"return_road"}]},"return_road":{"text":"街の朝靄の中、引き返す。背負い袋の軽さがひどく虚しい。","type":"text","bg_key":"bg_road_night","next":"return_scenery","choices":[{"label":"続ける","next":"return_scenery"}]},"return_scenery":{"text":"汚れた手を見て、自分がまた一歩踏み外したことを知る。","type":"text","bg_key":"bg_road_night","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"密輸完了。報酬は多いが、良心の痛みは消えそうにない。","type":"end","result":"success","bg_key":"bg_tavern_night","params":{"rewards":{"gold":800,"reputation":-5,"alignment_shift":{"evil":5,"chaos":5}}},"choices":[]},"end_failure":{"text":"追手に捕まり、荷物を没収された。このまま生きて帰れるかは自分の運次第だと腹をくくった。","type":"end","result":"failure","bg_key":"bg_road_night","choices":[]}},"short_description":"[密輸] 中身不明の禁制品を隣街まで運ぶ。追手に注意。"}'::jsonb,
    8,
    8
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7007: 地下水路の害獣駆除 (qst_gen_rat)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7007,
    'qst_gen_rat',
    '地下水路の害獣駆除',
    '[駆除] 地下水路の巨大ネズミの群れを2連戦で殲滅せよ。',
    '自治会',
    2,
    2,
    2,
    '{"gold":400,"items":[],"reputation":2}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['all']::text[],
    '{"location_tags":["all"]}'::jsonb,
    '{"nodes":{"start_prep":{"text":"自治会事務所の扉を開ける。中に漂うカビとインクの臭いが、私たちの鼻腔を強く刺激した。","type":"text","bg_key":"bg_office","next":"start","choices":[{"label":"続ける","next":"start"}]},"start":{"text":"奥の机では、衛生担当の役人が顔を青くしながら、薬草を浸した布で必死に鼻を覆っている。","type":"text","bg_key":"bg_office","next":"text_01","choices":[{"label":"続ける","next":"text_01"}]},"text_01":{"text":"「うう……よく来てくれた。実は地下水路で巨大な害獣が大量発生して、本当に困り果てているのだ」","type":"text","bg_key":"bg_office","speaker_name":"衛生担当の役人","speaker":"衛生担当の役人","next":"text_02","choices":[{"label":"続ける","next":"text_02"}]},"text_02":{"text":"「修繕に向かった作業員が噛まれて高熱で倒れた。奴らは恐ろしく凶暴で、犬ほどの大きさもあるという」","type":"text","bg_key":"bg_office","speaker_name":"衛生担当の役人","speaker":"衛生担当の役人","next":"text_03","choices":[{"label":"続ける","next":"text_03"}]},"text_03":{"text":"「さらに水路の奥からは、普通のネズミとは思えない不気味な鳴き声が聞こえるとのことだ」","type":"text","bg_key":"bg_office","speaker_name":"衛生担当の役人","speaker":"衛生担当の役人","next":"text_04","choices":[{"label":"続ける","next":"text_04"}]},"text_04":{"text":"「これが水路の地図だ。なんとか発生源である『巣』を探し出し、奴らを根絶してほしい」","type":"text","bg_key":"bg_office","speaker_name":"衛生担当の役人","speaker":"衛生担当の役人","next":"text_accept","choices":[{"label":"続ける","next":"text_accept"}]},"text_accept":{"text":"地図を受け取り、懐にしまう。暗く湿った地下での戦いに備え、装備を点検した。","type":"text","bg_key":"bg_office","next":"depart","choices":[{"label":"続ける","next":"depart"}]},"depart":{"text":"街の片隅にある錆びついた鉄格子を開け、冷気が這い出る暗闇の奥へと足を踏み入れる。","type":"text","bg_key":"bg_catacombs","next":"sewer_01","choices":[{"label":"続ける","next":"sewer_01"}]},"sewer_01":{"text":"錆びた梯子を慎重に降りると、そこは下水路だった。足元を濁った汚水がゴーゴーと音を立てて流れていく。","type":"text","bg_key":"bg_catacombs","next":"sewer_scenery","choices":[{"label":"続ける","next":"sewer_scenery"}]},"sewer_scenery":{"text":"壁は黒く濡れ、天井からは絶え間なく冷たい水滴が落ちてきて首筋を濡らした。","type":"text","bg_key":"bg_catacombs","next":"sewer_02","choices":[{"label":"続ける","next":"sewer_02"}]},"sewer_02":{"text":"壁の苔が怪しく光る中、松明の灯りをかざすと、暗がりの奥で無数の赤い目が爛々と明滅する。","type":"text","bg_key":"bg_catacombs","next":"sewer_03","choices":[{"label":"続ける","next":"sewer_03"}]},"sewer_03":{"text":"気配はすぐに消えた。だが、排水管の奥から爪で壁を引っかく音が不気味に響く。","type":"text","bg_key":"bg_catacombs","next":"rat_01","choices":[{"label":"続ける","next":"rat_01"}]},"rat_01":{"text":"曲がり角を抜けると、汚水の泥だまりで巨大ネズミが３匹、何かの骨を貪っていた。","type":"text","bg_key":"bg_catacombs","next":"rat_01_warn","choices":[{"label":"続ける","next":"rat_01_warn"}]},"rat_01_warn":{"text":"ネズミは骨を引きちぎり、ぬらぬらと濡れた毛皮を揺らしながら、こちらの出方をじっと窺っていた。","type":"text","bg_key":"bg_catacombs","next":"rat_02","choices":[{"label":"続ける","next":"rat_02"}]},"rat_02":{"text":"こちらの存在を完全に捉えたそいつらは、黄色く濁った鋭い牙を剥き出しにして牙を鳴らす！","type":"text","bg_key":"bg_catacombs","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"巨大ネズミの群れが、汚水を跳ね上げながら一斉に襲いかかってきた！","type":"battle","bg_key":"bg_catacombs","bgm":"bgm_battle","enemy_group_id":"407","enemy_name":"巨大ネズミ","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"手応えはあったが、泥とネズミの返り血で体が汚れる。息を整え、さらに奥を目指す。","type":"text","bg_key":"bg_catacombs","next":"after_scenery","choices":[{"label":"続ける","next":"after_scenery"}]},"after_scenery":{"text":"進むにつれ、悪臭が鼻を刺すほど強くなる。水路の壁には粘液のようなものが付着していた。","type":"text","bg_key":"bg_catacombs","next":"nest_01","choices":[{"label":"続ける","next":"nest_01"}]},"nest_01":{"text":"最深部の空間に辿り着いた。そこには骨やゴミ、ぼろ布で築かれた巨大な巣があった。","type":"text","bg_key":"bg_catacombs","next":"nest_scenery","choices":[{"label":"続ける","next":"nest_scenery"}]},"nest_scenery":{"text":"巣の周囲には、無数の小さな骨が散乱している。ここが害獣どもの繁殖地なのだろう。","type":"text","bg_key":"bg_catacombs","next":"nest_02","choices":[{"label":"続ける","next":"nest_02"}]},"nest_02":{"text":"巣の中央から、一際巨大な影が這い出てきた。その頭部には骨のような突起がある。","type":"text","bg_key":"bg_catacombs","next":"nest_03","choices":[{"label":"続ける","next":"nest_03"}]},"nest_03":{"text":"暗闇で禍々しい紫色の瞳が爛々と輝く。知性すら感じさせる、この巣の女王が立ち塞がる！","type":"text","bg_key":"bg_catacombs","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"ネズミの女王と、周囲を守る群れが牙を剥いて襲いかかってきた！","type":"battle","bg_key":"bg_catacombs","bgm":"bgm_battle","enemy_group_id":"408","enemy_name":"ネズミの女王と取り巻き","choices":[{"label":"win","next":"after_queen_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_queen_01"},"after_queen_01":{"text":"激闘の末、女王は泥の中に沈んだ。主を失った小さな子ネズミたちが四散していく。","type":"text","bg_key":"bg_catacombs","next":"after_queen_02","choices":[{"label":"続ける","next":"after_queen_02"}]},"after_queen_02":{"text":"周囲を見渡すと、水路を満たしていた禍々しい気配は綺麗に消え去り、泥の滴る音だけが響く静寂が戻っていた。","type":"text","bg_key":"bg_catacombs","next":"sewer_exit","choices":[{"label":"続ける","next":"sewer_exit"}]},"sewer_exit":{"text":"松明の火も残り僅かだ。私たちは悪臭と疲労に耐えながら、水路の出口へと引き返した。","type":"text","bg_key":"bg_catacombs","next":"arrive_office","choices":[{"label":"続ける","next":"arrive_office"}]},"arrive_office":{"text":"自治会事務所に戻り、役人に任務完了を報告した。泥まみれの私たちに、彼は目を丸くする。","type":"text","bg_key":"bg_office","next":"office_01","choices":[{"label":"続ける","next":"office_01"}]},"office_01":{"text":"「おお……！ 見事に女王を仕留めてくれたか！ これでようやく、安心して水路の修繕を進められるよ」","type":"text","bg_key":"bg_office","speaker_name":"衛生担当の役人","speaker":"衛生担当の役人","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"害獣駆除完了。しばらくはネズミの夢を見そうだが、懐の報酬がその労を労ってくれた。","type":"end","result":"success","bg_key":"bg_office","params":{"rewards":{"gold":400,"reputation":2}},"choices":[]},"end_failure":{"text":"ネズミの猛攻に圧倒され、命からがら退却した。地下にはまだ、無数の牙が潜んでいる。","type":"end","result":"failure","bg_key":"bg_catacombs","choices":[]}},"short_description":"[駆除] 地下水路の巨大ネズミの群れを2連戦で殲滅せよ。"}'::jsonb,
    2,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7008: 難民野営地への薬草救援 (qst_gen_mercy)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7008,
    'qst_gen_mercy',
    '難民野営地への薬草救援',
    '[救援] 癒やし草を採取して傷ついた難民の野営地へ届ける。',
    '救護団',
    2,
    2,
    4,
    '{"gold":10,"items":[],"reputation":10,"alignment_shift":{"justice":10,"order":10}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['all']::text[],
    '{"location_tags":["all"]}'::jsonb,
    '{"nodes":{"start_prep":{"text":"冒険者ギルドは喧騒に満ちていた。高額な討伐任務の張り紙の陰で、一枚の薄汚れた紙を見つける。","type":"text","bg_key":"bg_guild","next":"start","choices":[{"label":"続ける","next":"start"}]},"start":{"text":"それは難民野営地からの救援依頼だった。震える手で書かれたような文字が、薬草の調達を必死に懇願していた。","type":"text","bg_key":"bg_guild","next":"text_01","choices":[{"label":"続ける","next":"text_01"}]},"text_01":{"text":"「癒やし草を五束、どうか届けてください」——そう綴られた依頼は、誰にも見向きもされていなかった。","type":"text","bg_key":"bg_guild","next":"text_02","choices":[{"label":"続ける","next":"text_02"}]},"text_02":{"text":"金にならない慈善事業だが、このまま見捨てるのも寝覚めが悪い。依頼書を乱暴に剥ぎ取り、懐へと押し込んだ。","type":"text","bg_key":"bg_guild","next":"meet_01","choices":[{"label":"続ける","next":"meet_01"}]},"meet_01":{"text":"指定された酒場へ向かう。昼間の店内は荒れており、隅の席で若い修道女が小さく身を縮めていた。","type":"text","bg_key":"bg_tavern_day","next":"meet_02","choices":[{"label":"続ける","next":"meet_02"}]},"meet_02":{"text":"彼女の白い法衣は泥に汚れ、目の下には濃い隈が刻まれている。限界はもう目前に違いない。","type":"text","bg_key":"bg_tavern_day","next":"meet_03","choices":[{"label":"続ける","next":"meet_03"}]},"meet_03":{"text":"「引き受けてくださり感謝します。私はシスター・エレナ。難民の治療を行っています」","type":"text","bg_key":"bg_tavern_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"meet_04","choices":[{"label":"続ける","next":"meet_04"}]},"meet_04":{"text":"「怪我人が増え、手持ちの薬草が尽きてしまいました。どうか力を貸してください」","type":"text","bg_key":"bg_tavern_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"camp_01","choices":[{"label":"続ける","next":"camp_01"}]},"camp_01":{"text":"彼女に同行し、街外れの難民野営地を訪れた。粗末な布テントが泥濘にいくつも並んでいる。","type":"text","bg_key":"bg_road_day","next":"camp_scenery","choices":[{"label":"続ける","next":"camp_scenery"}]},"camp_scenery":{"text":"そこら中から咳き込む声や呻き声が聞こえる。衛生的とは言えない過酷な環境だった。","type":"text","bg_key":"bg_road_day","next":"camp_02","choices":[{"label":"続ける","next":"camp_02"}]},"camp_02":{"text":"テントの奥では老人が熱にうなされ、化膿した傷口からは酷い悪臭が立ち上る。","type":"text","bg_key":"bg_road_day","next":"camp_03","choices":[{"label":"続ける","next":"camp_03"}]},"camp_03":{"text":"「皆、矢傷や病で苦しんでいます。傷を癒やすための薬草が、どうしても必要なのです」","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"info_01","choices":[{"label":"続ける","next":"info_01"}]},"info_01":{"text":"「森の奥、沢沿いの苔むした岩場に白い花を咲かせる薬草です。どうか探してください」","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"info_02","choices":[{"label":"続ける","next":"info_02"}]},"info_02":{"text":"「怪我人たちの命を救うため、最低でも五束は持ち帰っていただく必要があります」","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"forest_enter","choices":[{"label":"続ける","next":"forest_enter"}]},"forest_enter":{"text":"日暮れまでに戻らねば、野営地の者たちは手遅れになる。私たちは急ぎ、薄暗い森へ足を踏み入れた。","type":"text","bg_key":"bg_forest_day","next":"gather_01","choices":[{"label":"続ける","next":"gather_01"}]},"gather_01":{"text":"木々の隙間を抜け、冷たい水の音が響く沢に辿り着いた。苔むした岩肌に咲く白い花を見つける。","type":"text","bg_key":"bg_forest_day","next":"gather_02","choices":[{"label":"続ける","next":"gather_02"}]},"gather_02":{"text":"茎を傷つけないよう慎重にナイフで刈り取る。まずは一束目だ。だが、これだけでは足りない。","type":"text","bg_key":"bg_forest_day","next":"gather_03","choices":[{"label":"続ける","next":"gather_03"}]},"gather_03":{"text":"湿った腐葉土を踏みしめ、周囲を探す。倒木の陰に小さな群生を見つけ、さらに二束を確保することに成功した。","type":"text","bg_key":"bg_forest_day","next":"gather_04","choices":[{"label":"続ける","next":"gather_04"}]},"gather_04":{"text":"すでに陽が傾き始めている。森の影が徐々に伸びる中、私たちは沢の上流へと捜索範囲を広げていく。","type":"text","bg_key":"bg_forest_day","next":"branch","choices":[{"label":"続ける","next":"branch"}]},"branch":{"type":"random_branch","bg_key":"bg_forest_day","prob":70,"choices":[{"label":"success","next":"gather_ok"},{"label":"failure","next":"gather_fail_01"}]},"gather_ok":{"text":"運良く上流の岩陰に群生が残っていた。四束目、五束目を刈り取り、用意した布で丁寧に包む。","type":"text","bg_key":"bg_forest_day","next":"deliver","choices":[{"label":"続ける","next":"deliver"}]},"gather_fail_01":{"text":"だが、沢の上流は日照りで乾ききっており、白い花はすべて枯れ果てていた。三束しかない。","type":"text","bg_key":"bg_forest_day","next":"gather_fail_02","choices":[{"label":"続ける","next":"gather_fail_02"}]},"gather_fail_02":{"text":"手持ちの荷物の中に、以前採取した『癒やし草』が残っていれば補填できるかもしれないが……","type":"text","bg_key":"bg_forest_day","next":"check","choices":[{"label":"続ける","next":"check"}]},"check":{"type":"check_delivery","bg_key":"bg_forest_day","params":{"item_id":"702","quantity":5},"choices":[{"label":"success","next":"gather_backup"},{"label":"failure","next":"not_enough"}]},"gather_backup":{"text":"荷袋から古い薬草を取り出し、合わせる。これでなんとか五束分だ。急いで野営地へ戻ろう。","type":"text","bg_key":"bg_forest_day","next":"deliver","choices":[{"label":"続ける","next":"deliver"}]},"not_enough":{"text":"持ってきた三束だけでは、全員を救う薬としては少なすぎる。だが、持ち帰るしかない。","type":"text","bg_key":"bg_forest_day","next":"not_enough_02","choices":[{"label":"続ける","next":"not_enough_02"}]},"not_enough_02":{"text":"野営地に戻り、薬草を差し出す。エレナは受け取ったが、その表情は陰っていた。","type":"text","bg_key":"bg_road_day","next":"not_enough_03","choices":[{"label":"続ける","next":"not_enough_03"}]},"not_enough_03":{"text":"「ありがとうございます。ですが……これだけでは、救えない命が出てしまいます」","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"薬草が足りず、手当ては不完全に終わった。自分の力不足を呪いながら、野営地を去った。","type":"end","result":"failure","bg_key":"bg_road_day","choices":[]},"deliver":{"text":"夕闇が野営地を包む頃、私たちは戻った。入り口でシスター・エレナが焦燥した顔で待っていた。","type":"text","bg_key":"bg_road_day","next":"deliver_02","choices":[{"label":"続ける","next":"deliver_02"}]},"deliver_02":{"text":"五束の薬草を手渡すと、彼女はそれを愛おしそうに胸に抱きしめ、張り詰めていた糸が切れたように息を吐く。","type":"text","bg_key":"bg_road_day","next":"deliver_03","choices":[{"label":"続ける","next":"deliver_03"}]},"deliver_03":{"text":"「よかった……これで薬を作れます。本当に、本当にありがとうございました」","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"deliver_04","choices":[{"label":"続ける","next":"deliver_04"}]},"deliver_04":{"text":"「これしかお渡しできませんが、どうかお受け取りください」","type":"text","bg_key":"bg_road_day","speaker_name":"シスター・エレナ","speaker":"シスター・エレナ","next":"deliver_pay","choices":[{"label":"続ける","next":"deliver_pay"}]},"deliver_pay":{"text":"彼女の細い手から、数枚の汚れた銅貨を受け取った。これが彼らの全財産なのだろう。","type":"text","bg_key":"bg_road_day","next":"deliver_apply","choices":[{"label":"続ける","next":"deliver_apply"}]},"deliver_apply":{"text":"彼女は休む間もなく、すり鉢で薬草の調合を始めた。手際よく怪我人の手当てに当たっていく。","type":"text","bg_key":"bg_road_day","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"報酬は銅貨10枚。だが、野営地の呻き声は小さくなった。少しは救いがあったのだろう。","type":"end","result":"success","bg_key":"bg_road_day","params":{"rewards":{"gold":10,"reputation":10,"alignment_shift":{"justice":10,"order":10}}},"choices":[]}},"short_description":"[救援] 癒やし草を採取して傷ついた難民の野営地へ届ける。"}'::jsonb,
    4,
    4
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7010: 異端者の粛清 (qst_rol_heretic)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7010,
    'qst_rol_heretic',
    '異端者の粛清',
    '[討伐] 教会に背く異端の信徒たちを、騎士団に代わって旧市街の廃教会で処理する。',
    '聖騎士団',
    3,
    4,
    2,
    '{"gold":600,"items":[],"alignment_shift":{"order":20},"exp":100,"reputation":5}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_holy_empire']::text[],
    '{"location_tags":["loc_holy_empire"],"min_reputation":80}'::jsonb,
    '{"nodes":{"start":{"text":"聖騎士団の詰め所に呼び出された。冷たい石造りの部屋に、重苦しい空気が漂っている。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"薄暗い執務室の奥。副隊長が、羊皮紙の依頼書を無造作に机の上に放り投げた。","type":"text","bg_key":"bg_guild","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「旧市街の廃教会で、聖堂の秩序を乱す異端者どもが夜な夜な怪しげな集会を開いているそうだ」","type":"text","bg_key":"bg_guild","speaker_name":"副隊長","speaker":"副隊長","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「『偽りの神を捨て、真の星の導きに従え』などと妄言を吐く連中だ」","type":"text","bg_key":"bg_guild","speaker_name":"副隊長","speaker":"副隊長","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「表沙汰になれば余計な騒ぎになる。そこで、お前に奴らの『排除』を委ねたい」","type":"text","bg_key":"bg_guild","speaker_name":"副隊長","speaker":"副隊長","next":"intro_2_warn","choices":[{"label":"続ける","next":"intro_2_warn"}]},"intro_2_warn":{"text":"「教会の名誉を守るためだ。多少の手荒な真似は黙認する。奴らを生かして帰すなよ」","type":"text","bg_key":"bg_guild","speaker_name":"副隊長","speaker":"副隊長","next":"accept_think","choices":[{"label":"続ける","next":"accept_think"}]},"accept_think":{"text":"暗黙の了解。血生臭い汚れ仕事だ。だが、断れば次の仕事はない。依頼書を懐に収めた。","type":"text","bg_key":"bg_guild","next":"arrive_slum","choices":[{"label":"続ける","next":"arrive_slum"}]},"arrive_slum":{"text":"それから間もなく、私たちは王都のきらびやかな大通りを離れ、影に覆われた旧市街の路地裏へと足を踏み入れた。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_tense","next":"slums_desc","choices":[{"label":"続ける","next":"slums_desc"}]},"slums_desc":{"text":"じめじめとした悪臭が漂う。やせ細った野良犬が、こちらを警戒するように通り過ぎた。","type":"text","bg_key":"bg_slums","next":"slums_think","choices":[{"label":"続ける","next":"slums_think"}]},"slums_think":{"text":"こんな日陰の街だからこそ、人々はすがるように異端の救いを求めるのだろうか。","type":"text","bg_key":"bg_slums","next":"church_out","choices":[{"label":"続ける","next":"church_out"}]},"church_out":{"text":"目的の廃教会に辿り着いた。ステンドグラスは砕け散り、不気味な静寂を湛えている。","type":"text","bg_key":"bg_ruined_church","next":"church_outside","choices":[{"label":"続ける","next":"church_outside"}]},"church_outside":{"text":"教会の入り口に立つ女神の石像は、何者かの手によって顔が削り取られていた。","type":"text","bg_key":"bg_ruined_church","next":"church_in","choices":[{"label":"続ける","next":"church_in"}]},"church_in":{"text":"歪んだ木扉を押し開け、地下へと続く階段を降りる。埃の臭いの中に、香の甘い香りが混じる。","type":"text","bg_key":"bg_ruined_church","next":"church_deep","choices":[{"label":"続ける","next":"church_deep"}]},"church_deep":{"text":"壁を伝う湿気と、わずかに聞こえる祈りの唱句。私たちは足音を殺し、さらに奥の礼拝堂へと歩みを進めた。","type":"text","bg_key":"bg_ruined_church","next":"ritual_scene","choices":[{"label":"続ける","next":"ritual_scene"}]},"ritual_scene":{"text":"そこに広がっていたのは、広い地下礼拝堂。黒いローブの集団が、怪しげな文様を描いた祭壇を取り囲んでいた。","type":"text","bg_key":"bg_ruined_church","next":"ritual_priest","choices":[{"label":"続ける","next":"ritual_priest"}]},"ritual_priest":{"text":"「光は我らを救わない！ 真の救済は、深き星の海から訪れるのだ！」","type":"text","bg_key":"bg_ruined_church","speaker_name":"異端の司祭","speaker":"異端の司祭","next":"ritual_priest_02","choices":[{"label":"続ける","next":"ritual_priest_02"}]},"ritual_priest_02":{"text":"「今こそ聖王国の偽りの偶像を打ち砕き、我らが祈りを星へ……」","type":"text","bg_key":"bg_ruined_church","speaker_name":"異端の司祭","speaker":"異端の司祭","next":"confront","choices":[{"label":"続ける","next":"confront"}]},"confront":{"text":"足元の瓦礫を踏みしめ、姿を現す。松明の赤暗い光が、侵入者である私たちを照らし出す。","type":"text","bg_key":"bg_ruined_church","next":"confront_cultists","choices":[{"label":"続ける","next":"confront_cultists"}]},"confront_cultists":{"text":"祈りが突如として止まった。十数人の信徒たちが一斉にこちらを振り返る。その目の奥には、狂信の光が爛々と宿っていた！","type":"text","bg_key":"bg_ruined_church","next":"cultist_shout","choices":[{"label":"続ける","next":"cultist_shout"}]},"cultist_shout":{"text":"「騎士団の飼い犬め！ 聖なる星の儀式を邪魔する者は、ここで生贄とする！」","type":"text","bg_key":"bg_ruined_church","speaker_name":"異端の司祭","speaker":"異端の司祭","next":"battle_cultists","choices":[{"label":"続ける","next":"battle_cultists"}]},"battle_cultists":{"text":"狂信者たちが隠し持っていた短剣を抜き、狂気に満ちた叫び声を上げて襲いかかってきた！","type":"battle","bg_key":"bg_ruined_church","bgm":"bgm_battle","enemy_group_id":"410","enemy_name":"異端の信徒たち","choices":[{"label":"win","next":"after_battle_1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_battle_1"},"after_battle_1":{"text":"狂信者たちは床に伏し、動かなくなった。祭壇の火が消え、地下室は再び闇に包まれる。","type":"text","bg_key":"bg_ruined_church","bgm":"bgm_quest_calm","next":"after_battle_desc","choices":[{"label":"続ける","next":"after_battle_desc"}]},"after_battle_desc":{"text":"辺りには鉄の匂いと、倒れた者たちの最期の吐息だけが残されていた。","type":"text","bg_key":"bg_ruined_church","next":"after_battle_2","choices":[{"label":"続ける","next":"after_battle_2"}]},"after_battle_2":{"text":"彼らが本当に邪悪だったのかは分からない。だが、これが依頼だ。異端の教典を回収する。","type":"text","bg_key":"bg_ruined_church","next":"church_exit","choices":[{"label":"続ける","next":"church_exit"}]},"church_exit":{"text":"本をしっかりと抱えて冷たい地下室を後にし、夜風が吹き抜ける地上へと戻る。見上げる街の灯りは、妙に遠く見えた。","type":"text","bg_key":"bg_ruined_church","next":"report_knights","choices":[{"label":"続ける","next":"report_knights"}]},"report_knights":{"text":"騎士団の詰め所に戻り、証拠となる黒い装丁の教典を副隊長の机の上に置いた。","type":"text","bg_key":"bg_guild","next":"knight_reply","choices":[{"label":"続ける","next":"knight_reply"}]},"knight_reply":{"text":"「見事な仕事だ。これでこの街の秩序は、一時的にせよ守られたというわけだな」","type":"text","bg_key":"bg_guild","speaker_name":"副隊長","speaker":"副隊長","next":"knight_reply_02","choices":[{"label":"続ける","next":"knight_reply_02"}]},"knight_reply_02":{"text":"「お前の腕と、何より口の堅さは高く評価しよう。また裏の仕事があれば声をかける」","type":"text","bg_key":"bg_guild","speaker_name":"副隊長","speaker":"副隊長","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"冷淡な笑みと共に報酬を受け取る。金貨の重みだけが、この手の汚れを忘れさせてくれた。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":600,"alignment_shift":{"order":20},"exp":100,"reputation":5}},"choices":[]},"end_failure":{"text":"狂信者たちの圧倒的な数の前に、力尽き倒れ伏す。冷たい石の床で、意識は闇に消えた。","type":"end","result":"failure","bg_key":"bg_ruined_church","choices":[]}},"short_description":"[討伐] 教会に背く異端の信徒たちを、騎士団に代わって旧市街の廃教会で処理する。"}'::jsonb,
    2,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7011: 最前線への聖水輸送 (qst_rol_holywater)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7011,
    'qst_rol_holywater',
    '最前線への聖水輸送',
    '[輸送] アンデッド対策として、前線の砦に祝福された聖水を運ぶ。',
    '教会',
    2,
    4,
    4,
    '{"gold":400,"items":[],"alignment_shift":{"order":10},"exp":120,"reputation":5}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_holy_empire']::text[],
    '{"location_tags":["loc_holy_empire"]}'::jsonb,
    '{"nodes":{"start":{"text":"大聖堂の地下礼拝堂。冷たい空気の中で、大司祭から頑丈な木箱を引き渡された。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"中には祝福された銀の小瓶が、緩衝材の乾草と共にぎっしりと詰められている。","type":"text","bg_key":"bg_church","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「最前線の砦において、戦死した兵士たちが歩き出しているという不吉な報告がありました」","type":"text","bg_key":"bg_church","speaker_name":"大司祭","speaker":"大司祭","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「この聖水は、失われた彼らの魂に安らかな眠りを与えるためのものです」","type":"text","bg_key":"bg_church","speaker_name":"大司祭","speaker":"大司祭","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「道中は魔物が彷徨い非常に危険ですが、砦の守備隊の命が、ひいては王国の防衛がかかっています」","type":"text","bg_key":"bg_church","speaker_name":"大司祭","speaker":"大司祭","next":"intro_2_wish","choices":[{"label":"続ける","next":"intro_2_wish"}]},"intro_2_wish":{"text":"「どうか、神の祝福が宿るこの聖水を、一本も欠かすことなく無事に前線まで届けてください」","type":"text","bg_key":"bg_church","speaker_name":"大司祭","speaker":"大司祭","next":"travel_start","choices":[{"label":"続ける","next":"travel_start"}]},"travel_start":{"text":"木箱を頑丈な荷車に載せ、門兵の厳しい視線を浴びながら王都を出発した。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_start_think","choices":[{"label":"続ける","next":"travel_start_think"}]},"travel_start_think":{"text":"目的地までは片道二日の過酷な旅路。重い荷車を引く手に、自然と力がこもる。","type":"text","bg_key":"bg_road_day","next":"travel_mid","choices":[{"label":"続ける","next":"travel_mid"}]},"travel_mid":{"text":"街道は荒れ果て、すれ違う者もいない。時折、風が嫌な臭いを運んできた。","type":"text","bg_key":"bg_road_day","next":"travel_scenery","choices":[{"label":"続ける","next":"travel_scenery"}]},"travel_scenery":{"text":"立ち枯れた木々が並ぶ光景は、ここが戦場に近いことを無言で物語っている。","type":"text","bg_key":"bg_road_day","next":"camp","choices":[{"label":"続ける","next":"camp"}]},"camp":{"text":"夜が訪れ、街道沿いの崩れた廃墟で野営をする。小さな焚き火が周囲の闇を静かに睨みつけていた。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_calm","next":"night_watch","choices":[{"label":"続ける","next":"night_watch"}]},"night_watch":{"text":"不気味な静寂の中、ひとり見張りに立つ。闇の奥からカタカタと、骨が擦れ合うような不快な音が響く。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_tense","next":"encounter_wave1","choices":[{"label":"続ける","next":"encounter_wave1"}]},"encounter_wave1":{"text":"松明の火の中に、錆びた甲冑を纏った骸骨たちの白い姿が浮かび上がった！","type":"text","bg_key":"bg_camp","next":"battle_wave1","choices":[{"label":"続ける","next":"battle_wave1"}]},"battle_wave1":{"text":"荷車に群がろうとする骸骨の群れを迎え撃つ！ 聖水を死守せよ！","type":"battle","bg_key":"bg_camp","bgm":"bgm_battle","enemy_group_id":"411","enemy_name":"骸骨の群れ","choices":[{"label":"win","next":"after_wave1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave1"},"after_wave1":{"text":"骸骨を打ち砕き、骨の破片が泥に散らばる。木箱の封印は無事のようだ。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_calm","next":"deeper_night","choices":[{"label":"続ける","next":"deeper_night"}]},"deeper_night":{"text":"だが一息つく間もなく、足元の湿った土が盛り上がり、何かが這い出るような音が周囲に響き渡る。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_tense","next":"encounter_wave2","choices":[{"label":"続ける","next":"encounter_wave2"}]},"encounter_wave2":{"text":"腐りかけた肉体を引きずりながら、ゾンビの群れがこちらへ手を伸ばしてくるっ…！","type":"text","bg_key":"bg_camp","next":"battle_wave2","choices":[{"label":"続ける","next":"battle_wave2"}]},"battle_wave2":{"text":"悪臭を放つ死体どもが、獲物を求めて一斉に襲いかかってきた！","type":"battle","bg_key":"bg_camp","bgm":"bgm_battle","enemy_group_id":"412","enemy_name":"ゾンビの群れ","choices":[{"label":"win","next":"after_wave2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave2"},"after_wave2":{"text":"激しい死闘の末、二度目の襲撃も退けた。息が荒れ、疲労が全身を蝕む。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_calm","next":"after_wave2_think","choices":[{"label":"続ける","next":"after_wave2_think"}]},"after_wave2_think":{"text":"しかし、聖水の瓶はすべて無事だ。夜明けまであとわずか、気を抜けない。","type":"text","bg_key":"bg_camp","next":"dawn_road","choices":[{"label":"続ける","next":"dawn_road"}]},"dawn_road":{"text":"ようやく夜が明け、朝靄が立ち込める街道を急ぐ。その前方に、冷たい霧の壁が立ち塞がった。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"encounter_wave3","choices":[{"label":"続ける","next":"encounter_wave3"}]},"encounter_wave3":{"text":"霧の奥から不気味な怨嗟の声が響く。骸骨とゾンビ、そして幽鬼が立ち塞がった！","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"battle_wave3","choices":[{"label":"続ける","next":"battle_wave3"}]},"battle_wave3":{"text":"前線の瘴気が生み出した、強力な混成亡者どもとの最後の戦いだ！","type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","enemy_group_id":"413","enemy_name":"混成亡者","choices":[{"label":"win","next":"arrive_fort"},{"label":"lose","next":"end_failure"}],"battle_success_next":"arrive_fort"},"arrive_fort":{"text":"満身創痍で前線の砦に辿り着いた。周囲には重苦しい血の臭いが充満している。","type":"text","bg_key":"bg_fort","bgm":"bgm_quest_calm","next":"arrive_fort_desc","choices":[{"label":"続ける","next":"arrive_fort_desc"}]},"arrive_fort_desc":{"text":"木柵の奥では、多くの負傷兵が力なく地面に横たわり、うめいていた。","type":"text","bg_key":"bg_fort","next":"meet_commander","choices":[{"label":"続ける","next":"meet_commander"}]},"meet_commander":{"text":"「おお、待ち望んでいた教会の支援物資か！ よくぞこの危険な道を届けてくれた、感謝する！」","type":"text","bg_key":"bg_fort","speaker_name":"砦の守備隊長","speaker":"砦の守備隊長","next":"meet_commander_02","choices":[{"label":"続ける","next":"meet_commander_02"}]},"meet_commander_02":{"text":"「これだけの聖水があれば、戦死した仲間を敵に回さずに埋葬できる」","type":"text","bg_key":"bg_fort","speaker_name":"砦の守備隊長","speaker":"砦の守備隊長","next":"deliver","choices":[{"label":"続ける","next":"deliver"}]},"deliver":{"text":"守備隊長に木箱を引き渡す。彼の強張っていた顔が、安堵に和らいだ。","type":"text","bg_key":"bg_fort","next":"deliver_think","choices":[{"label":"続ける","next":"deliver_think"}]},"deliver_think":{"text":"兵士たちが早速聖水を受け取り、砦の守りを固めるために慌ただしく動き始める。","type":"text","bg_key":"bg_fort","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"任務完了。王都に戻り、受け取った報酬は前線で見た安堵の顔より重かった。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":400,"alignment_shift":{"order":10},"exp":120,"reputation":5}},"choices":[]},"end_failure":{"text":"亡者の群れに圧倒され、荷車を失った。聖水が土に吸い込まれていく……","type":"end","result":"failure","bg_key":"bg_camp","choices":[]}},"short_description":"[輸送] アンデッド対策として、前線の砦に祝福された聖水を運ぶ。"}'::jsonb,
    3,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7012: 聖地巡礼者の護衛 (qst_rol_pilgrim)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7012,
    'qst_rol_pilgrim',
    '聖地巡礼者の護衛',
    '[護衛] 狂信的な巡礼者を護送する。彼が死ねば報酬はない。',
    '教会',
    3,
    4,
    10,
    '{"gold":700,"items":[],"alignment_shift":{"chaos":10},"exp":150,"reputation":-10}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_holy_empire']::text[],
    '{"location_tags":["loc_holy_empire"]}'::jsonb,
    '{"nodes":{"start":{"text":"大聖堂の門前。粗末な法衣を纏い、首から巨大な木製十字架を下げた男が立っていた。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"彼の目は不自然にギラつき、行き交う人々は彼を狂人を見るかのように避けていく。","type":"text","bg_key":"bg_church","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「あなたが今回の護衛ですか。主神の啓示がありました。西の危険な谷の祠へ行かねばならんのです」","type":"text","bg_key":"bg_church","speaker_name":"巡礼者アルバート","speaker":"巡礼者アルバート","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「あなたが私の肉の盾となるのも、すべては神の尊き御意志。さあ、直ちに出発しましょう」","type":"text","bg_key":"bg_church","speaker_name":"巡礼者アルバート","speaker":"巡礼者アルバート","next":"join_albert","choices":[{"label":"続ける","next":"join_albert"}]},"join_albert":{"text":"こちらの返事も待たず、彼は歩き出す。彼が死ねば報酬はゼロ。厄介な旅の始まりだ。","type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_pilgrim_albert","is_escort_target":true},"next":"travel_scenery","choices":[{"label":"続ける","next":"travel_scenery"}]},"travel_scenery":{"text":"それから数日間の道中、彼は食事や休息の勧めに一切耳を貸そうとせず、ただ前だけを見つめて歩き続けた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_think","choices":[{"label":"続ける","next":"travel_think"}]},"travel_think":{"text":"ただでさえ危険な旅路だ。護衛というより、嵐の跡を追いかけているような気分になる。","type":"text","bg_key":"bg_road_day","next":"mountain_road","choices":[{"label":"続ける","next":"mountain_road"}]},"mountain_road":{"text":"やがて、切り立った崖が続く峻険な山道に入った。道幅は人一人が通れる程度に狭い。","type":"text","bg_key":"bg_mountain","next":"albert_walk","choices":[{"label":"続ける","next":"albert_walk"}]},"albert_walk":{"text":"「おお……これぞ主が与えし苦難の道。私の足の痛みが、深き信仰の証となるのです」","type":"text","bg_key":"bg_mountain","speaker_name":"巡礼者アルバート","speaker":"巡礼者アルバート","next":"warning","choices":[{"label":"続ける","next":"warning"}]},"warning":{"text":"彼は足元の千尋の谷も見ず、祈りを口ずさみ進む。だが、頭上の岩陰に人影が見えた。","type":"text","bg_key":"bg_mountain","next":"ambush","choices":[{"label":"続ける","next":"ambush"}]},"ambush":{"text":"「そこまでだ、巡礼者さんよ」","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"ambush_desc","choices":[{"label":"続ける","next":"ambush_desc"}]},"ambush_desc":{"text":"頭上の岩場から、弓を構えた汚い身なりの男たちが顔を出した。退路は塞がれている。","type":"text","bg_key":"bg_mountain","next":"bandit_threat","choices":[{"label":"続ける","next":"bandit_threat"}]},"bandit_threat":{"text":"「命が惜しければ、教会から支給された旅費をすべて置いていってもらおうか」","type":"text","bg_key":"bg_mountain","speaker_name":"山賊の頭","speaker":"山賊の頭","next":"albert_ignore","choices":[{"label":"続ける","next":"albert_ignore"}]},"albert_ignore":{"text":"「……（虚ろな目で宙を見つめ、ひたすらぶつぶつと祈りの言葉を唱えている）」","type":"text","bg_key":"bg_mountain","speaker_name":"巡礼者アルバート","speaker":"巡礼者アルバート","next":"albert_ignore_2","choices":[{"label":"続ける","next":"albert_ignore_2"}]},"albert_ignore_2":{"text":"アルバートは足を止めることなく、山賊の警告を完全に無視して歩みを進める。その態度に、山賊たちは激昂し、殺気立つ！","type":"text","bg_key":"bg_mountain","next":"battle_wave1","choices":[{"label":"続ける","next":"battle_wave1"}]},"battle_wave1":{"text":"激怒した山賊の先遣隊が襲いかかってきた！ 頑固な巡礼者を死守しなければならない！","type":"battle","bg_key":"bg_mountain","bgm":"bgm_battle","enemy_group_id":"414","enemy_name":"山賊の先遣隊","choices":[{"label":"win","next":"after_battle_1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_battle_1"},"after_battle_1":{"text":"先遣隊を片付けた。しかし、谷の奥から更なる野盗の怒号と靴音が近づいてくる。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"deeper_mountain","choices":[{"label":"続ける","next":"deeper_mountain"}]},"deeper_mountain":{"text":"アルバートは戦闘など最初から眼中にないかのように、無傷のままで山奥へとどんどん進んでいく。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"deeper_mountain_think","choices":[{"label":"続ける","next":"deeper_mountain_think"}]},"deeper_mountain_think":{"text":"慌てて彼を追いかけたが、行く手の峠道に、重武装の用心棒たちが立ち塞がった。","type":"text","bg_key":"bg_mountain","next":"encounter_wave2","choices":[{"label":"続ける","next":"encounter_wave2"}]},"encounter_wave2":{"text":"「先ほどの連中をやったな……！ ここを通る奴は、一人残らず命を置いていけ！」","type":"text","bg_key":"bg_mountain","speaker_name":"山賊の用心棒","speaker":"山賊の用心棒","next":"battle_wave2","choices":[{"label":"続ける","next":"battle_wave2"}]},"battle_wave2":{"text":"山賊の精鋭が襲いかかる！ 頑固な巡礼者が牙にかかる前に、敵を殲滅せよ！","type":"battle","bg_key":"bg_mountain","bgm":"bgm_battle","enemy_group_id":"415","enemy_name":"山賊の精鋭","choices":[{"label":"win","next":"after_battle_2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_battle_2"},"after_battle_2":{"text":"残党を倒した。アルバートを確認する。彼は煤にまみれつつも、やはり無傷だった。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"albert_praise","choices":[{"label":"続ける","next":"albert_praise"}]},"albert_praise":{"text":"「神の御加護が、またしても悪しき者を滅ぼした。主よ、感謝いたします」","type":"text","bg_key":"bg_mountain","speaker_name":"巡礼者アルバート","speaker":"巡礼者アルバート","next":"sigh","choices":[{"label":"続ける","next":"sigh"}]},"sigh":{"text":"戦いたのはこちらだが、狂人に理屈は通じない。深いため息をつき、彼の背を追った。","type":"text","bg_key":"bg_mountain","next":"arrive_shrine","choices":[{"label":"続ける","next":"arrive_shrine"}]},"arrive_shrine":{"text":"険しい山道を乗り越え、ついに目的の祠へと辿り着いた。風雨に晒され苔むした、小さな古い石造りの祠だ。","type":"text","bg_key":"bg_shrine","next":"albert_pray","choices":[{"label":"続ける","next":"albert_pray"}]},"albert_pray":{"text":"アルバートは祠の前に跪き、額を土につけて長い祈りを始めた。夜が近づいていく。","type":"text","bg_key":"bg_shrine","next":"albert_thanks","choices":[{"label":"続ける","next":"albert_thanks"}]},"albert_thanks":{"text":"「よくぞ私をここまで運んだ。神の意思を実現する手足として、見事な働きです」","type":"text","bg_key":"bg_shrine","speaker_name":"巡礼者アルバート","speaker":"巡礼者アルバート","next":"leave_albert","choices":[{"label":"続ける","next":"leave_albert"}]},"leave_albert":{"text":"少しは感謝されたのだろうか。祈り続ける彼を祠に残し、私は帰路に就いた。","type":"leave","bg_key":"bg_shrine","params":{"guest_id":"npc_pilgrim_albert"},"next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"教会に戻り、報酬を受け取った。あの哀れな男は、今も山奥で祈り続けているのだろうか。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":700,"alignment_shift":{"chaos":10},"exp":150,"reputation":-10}},"choices":[]},"end_failure":{"text":"守りきれず、山賊の刃がアルバートを貫いた。神の加護は、彼に届かなかったのだ。","type":"end","result":"failure","bg_key":"bg_mountain","choices":[]}},"short_description":"[護衛] 狂信的な巡礼者を護送する。彼が死ねば報酬はない。"}'::jsonb,
    10,
    5
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7013: 遺体安置所の亡者討伐 (qst_rol_undead)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7013,
    'qst_rol_undead',
    '遺体安置所の亡者討伐',
    '[討伐] 瘴気によって動き出した腐乱死体たちを土へと還す。',
    '聖騎士団',
    3,
    4,
    2,
    '{"gold":450,"items":[],"alignment_shift":{"order":10},"exp":100,"reputation":15}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_holy_empire']::text[],
    '{"location_tags":["loc_holy_empire"]}'::jsonb,
    '{"nodes":{"start":{"text":"聖騎士団の詰め所に呼ばれた。室内には戦況報告の羊皮紙が乱雑に散らばっている。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"担当の騎士が、血の跡が残る古い教区墓地の地図を机の上に広げた。","type":"text","bg_key":"bg_guild","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「教区の共同墓地で異常事態だ。死体が突如として動き出し、警備の衛兵たちを襲った」","type":"text","bg_key":"bg_guild","speaker_name":"担当の騎士","speaker":"担当の騎士","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「直ちに内部へ突入し、奴らを物理的に破壊して土へ還してくれ。発生源の瘴気を絶つんだ」","type":"text","bg_key":"bg_guild","speaker_name":"担当の騎士","speaker":"担当の騎士","next":"enter_crypt","choices":[{"label":"続ける","next":"enter_crypt"}]},"enter_crypt":{"text":"閉鎖された遺体安置所の重い鉄扉を開ける。錆びた蝶番が悲鳴を上げた。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"enter_crypt_desc","choices":[{"label":"続ける","next":"enter_crypt_desc"}]},"enter_crypt_desc":{"text":"地下へ続く石段を一歩降りるたび、這い上がるような冷気と腐敗臭が強くなる。","type":"text","bg_key":"bg_crypt","next":"crypt_desc","choices":[{"label":"続ける","next":"crypt_desc"}]},"crypt_desc":{"text":"壁の棺はことごとく破壊され、中身はもぬけの殻。暗闇の奥からは、濡れた足音が近づいてきた。","type":"text","bg_key":"bg_crypt","next":"encounter_wave1","choices":[{"label":"続ける","next":"encounter_wave1"}]},"encounter_wave1":{"text":"松明を掲げると、通路を塞ぐ骸骨やゾンビ、幽鬼の姿が赤く浮かび上がった。","type":"text","bg_key":"bg_crypt","next":"battle_wave1","choices":[{"label":"続ける","next":"battle_wave1"}]},"battle_wave1":{"text":"生者の熱を感知した亡者の群れが一斉に襲いかかってきた！ 武器を構えろ！","type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle","enemy_group_id":"413","enemy_name":"混成亡者","choices":[{"label":"win","next":"after_wave1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave1"},"after_wave1":{"text":"最初の群れを切り伏せた。床には骸骨の破片と、焦げた腐肉が散乱している。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"after_wave1_think","choices":[{"label":"続ける","next":"after_wave1_think"}]},"after_wave1_think":{"text":"だが、まだ戦いは終わりではない。さらに濃い瘴気が、地下の暗闇の奥から絶え間なく流れ出ていた。","type":"text","bg_key":"bg_crypt","next":"deeper","choices":[{"label":"続ける","next":"deeper"}]},"deeper":{"text":"私たちは武器の血糊を拭い、さらに深部へと歩みを進める。床は黒く濡れ、壁には不気味な菌糸が這っていた。","type":"text","bg_key":"bg_crypt","next":"deeper_scenery","choices":[{"label":"続ける","next":"deeper_scenery"}]},"deeper_scenery":{"text":"まるで巨大な獣の胎内に入り込んでしまったかのような、異様な圧迫感だ。","type":"text","bg_key":"bg_crypt","next":"encounter_wave2","choices":[{"label":"続ける","next":"encounter_wave2"}]},"encounter_wave2":{"text":"通路の角から青白い光が漏れる。次の瞬間、半透明のレイスが壁を抜けて突如として現れた！","type":"text","bg_key":"bg_crypt","next":"battle_wave2","choices":[{"label":"続ける","next":"battle_wave2"}]},"battle_wave2":{"text":"氷のような冷気を纏うレイスの群れが、私たちの魂を刈り取りに迫る！","type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle","enemy_group_id":"416","enemy_name":"レイスの群れ","choices":[{"label":"win","next":"after_wave2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave2"},"after_wave2":{"text":"レイスを消滅させたが、凍えるような寒気が体に残り、呼吸が白く染まる。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"after_wave2_think","choices":[{"label":"続ける","next":"after_wave2_think"}]},"after_wave2_think":{"text":"体の芯から体力を激しく削られていく。それでも、瘴気の源はすでに目と鼻の先だった。","type":"text","bg_key":"bg_crypt","next":"find_altar","choices":[{"label":"続ける","next":"find_altar"}]},"find_altar":{"text":"冷たい手触りの霧を掻き分け、ついに最奥の礼拝堂に辿り着いた。そこには黒く拍動する異様な石が、朽ち果てた祭壇の上に置かれていた。","type":"text","bg_key":"bg_crypt","next":"boss_desc","choices":[{"label":"続ける","next":"boss_desc"}]},"boss_desc":{"text":"石が放つ瘴気のせいで、空間全体が歪んでいる。石の周囲には光が渦巻く。","type":"text","bg_key":"bg_crypt","next":"encounter_wave3","choices":[{"label":"続ける","next":"encounter_wave3"}]},"encounter_wave3":{"text":"守護者たるレイスの大群が、私たちの存在を排除すべく一斉に牙を剥いた。","type":"text","bg_key":"bg_crypt","next":"battle_wave3","choices":[{"label":"続ける","next":"battle_wave3"}]},"battle_wave3":{"text":"瘴気の中心地での戦い。 渦巻く霊体たちをすべて切り払え！","type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle_boss","enemy_group_id":"417","enemy_name":"大量のレイス","choices":[{"label":"win","next":"after_wave3"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave3"},"after_wave3":{"text":"最後のレイスが叫びと共に霧散し、静寂が戻る。残るは祭壇の黒い石のみ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"destroy_stone","choices":[{"label":"続ける","next":"destroy_stone"}]},"destroy_stone":{"text":"全身の力を込めて武器を振り下ろし、拍動する黒い石を真っ二つに叩き割る。","type":"text","bg_key":"bg_crypt","next":"destroy_stone_desc","choices":[{"label":"続ける","next":"destroy_stone_desc"}]},"destroy_stone_desc":{"text":"甲高い破砕音と共に、部屋を満たしていた紫の瘴気が一気に薄れて消えた。","type":"text","bg_key":"bg_crypt","next":"purge_done","choices":[{"label":"続ける","next":"purge_done"}]},"purge_done":{"text":"空気が清浄に戻っていく。これで新たなアンデッドが生まれることはない。","type":"text","bg_key":"bg_crypt","next":"purge_think","choices":[{"label":"続ける","next":"purge_think"}]},"purge_think":{"text":"だが、なぜ共同墓地にこのような呪具が？ 人為的な陰謀の影を感じる。","type":"text","bg_key":"bg_crypt","next":"report","choices":[{"label":"続ける","next":"report"}]},"report":{"text":"重苦しい泥と血の臭いを身に纏い、騎士団の詰め所へ帰還を報告した。","type":"text","bg_key":"bg_guild","next":"knight_thanks","choices":[{"label":"続ける","next":"knight_thanks"}]},"knight_thanks":{"text":"「実に見事な仕事だ。この禍々しい石は、秩序を揺るがす異端の呪具に違いない」","type":"text","bg_key":"bg_guild","speaker_name":"担当の騎士","speaker":"担当の騎士","next":"knight_thanks_02","choices":[{"label":"続ける","next":"knight_thanks_02"}]},"knight_thanks_02":{"text":"「背後関係は我らが調査しよう。約束の報酬だ。受け取ってくれ」","type":"text","bg_key":"bg_guild","speaker_name":"担当の騎士","speaker":"担当の騎士","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"報酬の金貨を掴む。地下の嫌な冷気は、まだ指先に残ったままだった。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":450,"alignment_shift":{"order":10},"exp":100,"reputation":15}},"choices":[]},"end_failure":{"text":"無数の亡者に引きずり下ろされ、意識が薄れる。私もこの闇の一部となる。","type":"end","result":"failure","bg_key":"bg_crypt","choices":[]}},"short_description":"[討伐] 瘴気によって動き出した腐乱死体たちを土へと還す。"}'::jsonb,
    4,
    2
