-- Scenario 7014: 貧民窟からの税徴収 (qst_rol_tithe)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7014,
    'qst_rol_tithe',
    '貧民窟からの税徴収',
    '[徴収] 貧民窟の住民たちから十分の一税を取り立てる。見逃すか取り立てるかはあなた次第。',
    '教会',
    2,
    4,
    1,
    '{"gold":200,"items":[],"alignment_shift":{"evil":10}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_holy_empire']::text[],
    '{"location_tags":["loc_holy_empire"],"max_reputation":-50}'::jsonb,
    '{"nodes":{"start":{"text":"酒場の裏口。教会の使いと名乗る男から、旧市街の住民リストが入った小袋を渡された。","type":"text","bg_key":"bg_tavern_night","bgm":"bgm_quest_calm","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"小袋の中には、教区の印章が押された古い羊皮紙が入っていた。そこには４つの名前が記されている。","type":"text","bg_key":"bg_tavern_night","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「神聖なる税を払わぬゴミどもなど、聖王国の恩恵を受ける資格などありません」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「リストにある４軒の家から、十分の一税を回収してください」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「払えぬのなら家財を売り払わせ、抵抗する愚か者からは力ずくで奪えばいいのです」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"intro_2_detail","choices":[{"label":"続ける","next":"intro_2_detail"}]},"intro_2_detail":{"text":"「温情で見逃すのも自由ですが、その場合、あなたの報酬は減るだけですからね」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"arrive_slum","choices":[{"label":"続ける","next":"arrive_slum"}]},"arrive_slum":{"text":"リストを手に貧民窟へ足を踏み入れる。すれ違う人々の目が警戒と敵意に満ちていた。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_tense","next":"house_1","choices":[{"label":"続ける","next":"house_1"}]},"house_1":{"text":"まず向かったのは、リストの最初にある家。半壊した長屋の木扉を叩くと、中から怯えた老夫婦が出てきた。","type":"text","bg_key":"bg_slums","next":"plea_1","choices":[{"label":"続ける","next":"plea_1"}]},"plea_1":{"text":"「税の徴収……？ 昨日のパンを買う金すら、もう残っていないのです」","type":"text","bg_key":"bg_slums","speaker_name":"貧民窟の老人","speaker":"貧民窟の老人","next":"choice_1","choices":[{"label":"続ける","next":"choice_1"}]},"choice_1":{"text":"老人の服は継ぎ接ぎだらけ。部屋には売れるような物は何もない。どうする？","type":"choice","bg_key":"bg_slums","choices":[{"label":"見逃す","next":"mercy_1"},{"label":"強制的に取り立てる","next":"battle_1"}]},"mercy_1":{"text":"老夫婦の家を後にした。背中から、小さな感謝の囁きが聞こえた気がした。","type":"text","bg_key":"bg_slums","next":"extort_1","choices":[{"label":"続ける","next":"extort_1"}]},"battle_1":{"text":"老人を脅すと、周囲の住民たちが農具を手にして一斉に集まってきた！","type":"battle","bg_key":"bg_slums","bgm":"bgm_battle","enemy_group_id":"404","enemy_name":"怒れる住民","choices":[{"label":"win","next":"add_1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"add_1"},"add_1":{"type":"modify_flag","bg_key":"bg_slums","next":"extort_1","choices":[{"label":"続ける","next":"extort_1"}]},"extort_1":{"text":"抵抗を力でねじ伏せ、銅貨を搾り取った。老人のすすり泣きが耳に残る。","type":"text","bg_key":"bg_slums","next":"house_2_intro","choices":[{"label":"続ける","next":"house_2_intro"}]},"house_2_intro":{"text":"二軒目の家へ向かう。路地の住民たちが、こちらを遠巻きに睨みつけている。","type":"text","bg_key":"bg_slums","next":"house_2","choices":[{"label":"続ける","next":"house_2"}]},"house_2":{"text":"次の対象は、幼い子供を抱えた若い母親。痩せ細った顔に深い隈が刻まれていた。","type":"text","bg_key":"bg_slums","next":"plea_2","choices":[{"label":"続ける","next":"plea_2"}]},"plea_2":{"text":"「お願いです、子供たちだけは……。もう奪うものは何もないのです」","type":"text","bg_key":"bg_slums","speaker_name":"若い母親","speaker":"若い母親","next":"choice_2","choices":[{"label":"続ける","next":"choice_2"}]},"choice_2":{"text":"子供たちが怯えた目でこちらを見上げている。どうする？","type":"choice","bg_key":"bg_slums","choices":[{"label":"見逃す","next":"mercy_2"},{"label":"強制的に取り立てる","next":"battle_2"}]},"mercy_2":{"text":"母親の家を後にした。子供の一人が、小さな手を振っているのが見えた。","type":"text","bg_key":"bg_slums","next":"extort_2","choices":[{"label":"続ける","next":"extort_2"}]},"battle_2":{"text":"母親を庇おうと、隣人たちが武器を手に怒りの叫びを上げて立ちはだかった！","type":"battle","bg_key":"bg_slums","bgm":"bgm_battle","enemy_group_id":"404","enemy_name":"怒れる住民","choices":[{"label":"win","next":"add_2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"add_2"},"add_2":{"type":"modify_flag","bg_key":"bg_slums","next":"extort_2","choices":[{"label":"続ける","next":"extort_2"}]},"extort_2":{"text":"泣き叫ぶ子供たちの前で、母親が隠していた最後の家財を力ずくで奪い取った。","type":"text","bg_key":"bg_slums","next":"house_3_intro","choices":[{"label":"続ける","next":"house_3_intro"}]},"house_3_intro":{"text":"三軒目の家へ。住民たちの視線は明確な敵意へと変わり、足元に小石が投げつけられる。","type":"text","bg_key":"bg_slums","next":"house_3","choices":[{"label":"続ける","next":"house_3"}]},"house_3":{"text":"対象は片足の老兵士。壁の松葉杖の横に、錆びついた古い剣が置かれていた。","type":"text","bg_key":"bg_slums","next":"plea_3","choices":[{"label":"続ける","next":"plea_3"}]},"plea_3":{"text":"「国のために片足を失ったのに、まだ奪うか。好きにするがいい」","type":"text","bg_key":"bg_slums","speaker_name":"片足の老兵士","speaker":"片足の老兵士","next":"choice_3","choices":[{"label":"続ける","next":"choice_3"}]},"choice_3":{"text":"老兵士は諦めたような暗い瞳で、こちらの出方を静かに待っている。どうする？","type":"choice","bg_key":"bg_slums","choices":[{"label":"見逃す","next":"mercy_3"},{"label":"強制的に取り立てる","next":"battle_3"}]},"mercy_3":{"text":"老兵士の家を後にした。彼は何も言わず、ただ虚空を見つめ続けていた。","type":"text","bg_key":"bg_slums","next":"extort_3","choices":[{"label":"続ける","next":"extort_3"}]},"battle_3":{"text":"老兵士を脅そうとした瞬間、彼の元戦友たちが武器を手に駆けつけてきた！","type":"battle","bg_key":"bg_slums","bgm":"bgm_battle","enemy_group_id":"404","enemy_name":"怒れる住民","choices":[{"label":"win","next":"add_3"},{"label":"lose","next":"end_failure"}],"battle_success_next":"add_3"},"add_3":{"type":"modify_flag","bg_key":"bg_slums","next":"extort_3","choices":[{"label":"続ける","next":"extort_3"}]},"extort_3":{"text":"かつて国のために戦った男の誇りを踏みにじり、なけなしの金を奪い取った。","type":"text","bg_key":"bg_slums","next":"house_4_intro","choices":[{"label":"続ける","next":"house_4_intro"}]},"house_4_intro":{"text":"最後の一軒。もう誰もこちらを見ようとせず、貧民窟は冷たい沈黙に包まれる。","type":"text","bg_key":"bg_slums","next":"house_4","choices":[{"label":"続ける","next":"house_4"}]},"house_4":{"text":"最後の対象は、病床の少女を看病する老婆。室内には不快な薬草の臭いが漂う。","type":"text","bg_key":"bg_slums","next":"plea_4","choices":[{"label":"続ける","next":"plea_4"}]},"plea_4":{"text":"「この子の薬代すら足りないのです。税を払えば、この子は死にます」","type":"text","bg_key":"bg_slums","speaker_name":"看病する老婆","speaker":"看病する老婆","next":"choice_4","choices":[{"label":"続ける","next":"choice_4"}]},"choice_4":{"text":"少女は荒い呼吸で苦しそうに眠っている。どうする？","type":"choice","bg_key":"bg_slums","choices":[{"label":"見逃す","next":"mercy_4"},{"label":"強制的に取り立てる","next":"battle_4"}]},"mercy_4":{"text":"老婆の家を後にした。老婆は両手を合わせ、深々とこちらに頭を下げていた。","type":"text","bg_key":"bg_slums","next":"extort_4","choices":[{"label":"続ける","next":"extort_4"}]},"battle_4":{"text":"絶望した住民たちが、最後の怒りを爆発させて一斉に襲いかかってきた！","type":"battle","bg_key":"bg_slums","bgm":"bgm_battle","enemy_group_id":"404","enemy_name":"怒れる住民","choices":[{"label":"win","next":"add_4"},{"label":"lose","next":"end_failure"}],"battle_success_next":"add_4"},"add_4":{"type":"modify_flag","bg_key":"bg_slums","next":"extort_4","choices":[{"label":"続ける","next":"extort_4"}]},"extort_4":{"text":"少女の薬代すらも無慈悲に奪い取った。背後で激しい咳き込みが響く。","type":"text","bg_key":"bg_slums","next":"report_check","choices":[{"label":"続ける","next":"report_check"}]},"report_check":{"type":"check_flags","bg_key":"bg_slums","choices":[{"label":"success","next":"report_0"},{"label":"failure","next":"report_check_4"}]},"report_check_4":{"type":"check_flags","bg_key":"bg_slums","choices":[{"label":"success","next":"report_4"},{"label":"failure","next":"report_mid_check"}]},"report_mid_check":{"type":"check_flags","bg_key":"bg_slums","choices":[{"label":"success","next":"report_mid_1"},{"label":"failure","next":"report_mid_check_2"}]},"report_mid_check_2":{"type":"check_flags","bg_key":"bg_slums","choices":[{"label":"success","next":"report_mid_2"},{"label":"failure","next":"report_mid_3"}]},"report_0":{"text":"「回収できた金は一枚もないと？ フン、お優しい冒険者様だ。それでは分け前もありません、当然です。」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"end_success_0","choices":[{"label":"続ける","next":"end_success_0"}]},"end_success_0":{"text":"金は手に入らなかったが、貧民窟の人々は守られた。これが私の選んだ道だ。","type":"end","result":"success","bg_key":"bg_tavern_night","params":{"rewards":{"gold":0,"reputation":30}},"choices":[]},"report_mid_1":{"text":"「ふむ、回収できたのは一軒だけですか。温情ですか？ まあ、最低限の脅しにはなったでしょう」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"end_success_1","choices":[{"label":"続ける","next":"end_success_1"}]},"end_success_1":{"text":"受け取ったわずかな分け前を懐に仕舞う。心には、言い知れぬ暗い澱みが残っていた。","type":"end","result":"success","bg_key":"bg_tavern_night","params":{"rewards":{"gold":50,"reputation":10,"alignment_shift":{"order":5,"evil":3}}},"choices":[]},"report_mid_2":{"text":"「回収できたのは二軒ですか。ふむ、悪くはありませんが……次はもっと冷徹に仕事をしていただきたい」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"end_success_2","choices":[{"label":"続ける","next":"end_success_2"}]},"end_success_2":{"text":"金袋の半分は軽いままだ。貧民窟の親子の泣き顔と、握りしめた硬貨の冷たさが脳裏をよぎる。","type":"end","result":"success","bg_key":"bg_tavern_night","params":{"rewards":{"gold":100,"reputation":-5,"alignment_shift":{"order":10,"evil":5}}},"choices":[]},"report_mid_3":{"text":"「三軒から回収ですか。上出来です。これでゴミどもも、教会の権威を思い知ったことでしょう」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"end_success_3","choices":[{"label":"続ける","next":"end_success_3"}]},"end_success_3":{"text":"ほぼ満額の分け前。だが手にした金貨には、老兵士や看病する老婆の血と汗が染み付いている。","type":"end","result":"success","bg_key":"bg_tavern_night","params":{"rewards":{"gold":150,"reputation":-10,"alignment_shift":{"order":15,"evil":8}}},"choices":[]},"report_4":{"text":"「素晴らしい！ 四軒すべてから回収するとは。これこそ法と秩序の勝利、見事な働きです！」","type":"text","bg_key":"bg_tavern_night","speaker_name":"教会の使い","speaker":"教会の使い","next":"end_success_4","choices":[{"label":"続ける","next":"end_success_4"}]},"end_success_4":{"text":"満額の金貨を受け取った。貧民窟の絶望の叫びなど、重い金袋の響きの前には無意味だった。","type":"end","result":"success","bg_key":"bg_tavern_night","params":{"rewards":{"gold":200,"reputation":-10,"alignment_shift":{"order":20,"evil":10}}},"choices":[]},"end_failure":{"text":"絶望した暴徒たちの暴力の前に倒れ伏す。泥水の中で意識は闇に消えた。","type":"end","result":"failure","bg_key":"bg_slums","choices":[]}},"short_description":"[徴収] 貧民窟の住民たちから十分の一税を取り立てる。見逃すか取り立てるかはあなた次第。"}'::jsonb,
    1,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7015: 盗まれた聖遺物の奪還 (qst_rol_relic)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7015,
    'qst_rol_relic',
    '盗まれた聖遺物の奪還',
    '[奪還] 盗賊団のアジトを襲撃し、教会から盗まれた聖杯を奪い返す。',
    '教会',
    4,
    4,
    3,
    '{"gold":500,"items":[],"alignment_shift":{"order":10},"exp":200,"reputation":10}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_holy_empire']::text[],
    '{"location_tags":["loc_holy_empire"]}'::jsonb,
    '{"nodes":{"start":{"text":"大聖堂の宝物庫。重々しい扉がこじ開けられ、司教たちが怒りと困惑に顔を歪めていた。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"台座の上に安置されていたはずの最古の聖杯は消え去り、塵だけが残されている。","type":"text","bg_key":"bg_church","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「身の程知らずの盗賊どもが、教会宝物庫より主の尊き聖遺物を盗み出しました」","type":"text","bg_key":"bg_church","speaker_name":"司教","speaker":"司教","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「奴らのアジトは、東の森の奥にある廃城跡だと突き止めています」","type":"text","bg_key":"bg_church","speaker_name":"司教","speaker":"司教","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「闇市へと売却される前に取り戻すのです。悪党どもは全員、ただちに『浄化』しなさい」","type":"text","bg_key":"bg_church","speaker_name":"司教","speaker":"司教","next":"intro_2_detail","choices":[{"label":"続ける","next":"intro_2_detail"}]},"intro_2_detail":{"text":"「聖なる品のためです、血が流れることを恐れてはなりません。神の正義を示しなさい」","type":"text","bg_key":"bg_church","speaker_name":"司教","speaker":"司教","next":"forest_approach","choices":[{"label":"続ける","next":"forest_approach"}]},"forest_approach":{"text":"手がかりを頼りに東の森へ進む。木々の隙間から、廃城の荒れた石壁が見えた。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_field","next":"forest_scenery","choices":[{"label":"続ける","next":"forest_scenery"}]},"forest_scenery":{"text":"城壁の崩れた隙間では、数人の野盗たちが武器を手に周囲を警戒していた。","type":"text","bg_key":"bg_forest_day","next":"stealth_or_assault","choices":[{"label":"続ける","next":"stealth_or_assault"}]},"stealth_or_assault":{"text":"だが、身を隠して進むには地形が開けすぎている。不意打ちは諦め、正面から力ずくで突破を図る。","type":"text","bg_key":"bg_forest_day","next":"spotted","choices":[{"label":"続ける","next":"spotted"}]},"spotted":{"text":"「曲者だ！ 騎士団の回し者か！」","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"spotted_desc","choices":[{"label":"続ける","next":"spotted_desc"}]},"spotted_desc":{"text":"見張りが声を上げ、即座に矢を放ってきた。私はそれを剣で弾き落とす。","type":"text","bg_key":"bg_forest_day","next":"assault","choices":[{"label":"続ける","next":"assault"}]},"assault":{"text":"アジトの奥から、騒ぎを聞きつけた盗賊たちが怒号と共に一斉に押し寄せてきた！","type":"text","bg_key":"bg_forest_day","next":"battle_wave1","choices":[{"label":"続ける","next":"battle_wave1"}]},"battle_wave1":{"text":"包囲される前に敵の前衛を叩き潰す！ 容赦なく武器を振るえ！","type":"battle","bg_key":"bg_forest_day","bgm":"bgm_battle","enemy_group_id":"418","enemy_name":"盗賊団の構成員","choices":[{"label":"win","next":"after_wave1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave1"},"after_wave1":{"text":"前衛を斬り伏せ、廃城の内庭に侵入する。奥からずっしりとした足音が響く。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"boss_appear","choices":[{"label":"続ける","next":"boss_appear"}]},"boss_appear":{"text":"「てめえ、たった一人で乗り込んできやがったか。いい度胸だな」","type":"text","bg_key":"bg_forest_day","speaker_name":"盗賊団の頭目","speaker":"盗賊団の頭目","next":"boss_talk","choices":[{"label":"続ける","next":"boss_talk"}]},"boss_talk":{"text":"「あの聖杯は俺たちのものだ。売れば一生遊んで暮らせるんだよ！」","type":"text","bg_key":"bg_forest_day","speaker_name":"盗賊団の頭目","speaker":"盗賊団の頭目","next":"battle_wave2","choices":[{"label":"続ける","next":"battle_wave2"}]},"battle_wave2":{"text":"聖杯に目が眩んだ強欲な頭目を討ち倒し、主の器を奪還せよ！","type":"battle","bg_key":"bg_forest_day","bgm":"bgm_battle_boss","enemy_group_id":"419","enemy_name":"盗賊団の頭領","choices":[{"label":"win","next":"after_wave2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave2"},"after_wave2":{"text":"激闘の末、頭目は血の海に沈んだ。残された手下たちは我先にと逃げ出す。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_calm","next":"find_relic","choices":[{"label":"続ける","next":"find_relic"}]},"find_relic":{"text":"奥のテントの木箱から、見事な細工が施された金の聖杯を見つけ出した。","type":"text","bg_key":"bg_forest_day","next":"check_relic","choices":[{"label":"続ける","next":"check_relic"}]},"check_relic":{"text":"美しい。だが、この聖杯を闇市に持ち込めば、莫大な金になるだろう。","type":"text","bg_key":"bg_forest_day","next":"choice_relic","choices":[{"label":"続ける","next":"choice_relic"}]},"choice_relic":{"text":"目の前の聖杯をどうする？ 信仰か、あるいは目の前の富か。","type":"choice","bg_key":"bg_road_day","choices":[{"label":"教会に届ける","next":"report"},{"label":"闇市で売却する","next":"sell_market"}]},"report":{"text":"聖杯を慎重に包んで王都へと戻り、大聖堂の司教へ献上した。彼は一瞬で歓喜の声を上げる。","type":"text","bg_key":"bg_guild","next":"bishop_thanks","choices":[{"label":"続ける","next":"bishop_thanks"}]},"bishop_thanks":{"text":"「おお、主の器が戻った！ 感謝します。これは約束の報酬です」","type":"text","bg_key":"bg_guild","speaker_name":"司教","speaker":"司教","next":"bishop_thanks_02","choices":[{"label":"続ける","next":"bishop_thanks_02"}]},"bishop_thanks_02":{"text":"「あなたのような頼もしい冒険者には、また主の導きがあることでしょう」","type":"text","bg_key":"bg_guild","speaker_name":"司教","speaker":"司教","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"報酬の金貨を手にする。教会の信力を高める手伝いをした満足感を得た。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":500,"alignment_shift":{"order":10},"exp":200,"reputation":10}},"choices":[]},"sell_market":{"text":"聖杯を布に包み、王都の裏路地に潜む闇市へと足を運んだ。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_tense","next":"sell_market_desc","choices":[{"label":"続ける","next":"sell_market_desc"}]},"sell_market_desc":{"text":"怪しげな骨董屋の主人が聖杯の刻印を眺め、いやらしい笑みを浮かべる。","type":"text","bg_key":"bg_slums","next":"sell_deal","choices":[{"label":"続ける","next":"sell_deal"}]},"sell_deal":{"text":"「これは教会の逸品だな。出所は問わん、倍の額で買い取ろう」","type":"text","bg_key":"bg_slums","speaker_name":"闇商人","speaker":"闇商人","next":"end_dark","choices":[{"label":"続ける","next":"end_dark"}]},"end_dark":{"text":"重い金袋を懐に収める。司教には『聖杯は既に売却されていた』と報告した。","type":"end","result":"success","bg_key":"bg_slums","params":{"rewards":{"gold":1000,"alignment_shift":{"evil":20},"reputation":-30}},"choices":[]},"end_failure":{"text":"盗賊たちの数の前に力尽き、倒れ伏す。聖杯は彼らの手の内に残された。","type":"end","result":"failure","bg_key":"bg_forest_day","choices":[]}},"short_description":"[奪還] 盗賊団のアジトを襲撃し、教会から盗まれた聖杯を奪い返す。"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7020: 大砂漠の長距離交易護衛 (qst_mar_caravan)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7020,
    'qst_mar_caravan',
    '大砂漠の長距離交易護衛',
    '[護衛] 広大な砂漠を越える商隊の用心棒。盗賊と魔獣の連戦を耐え抜け。',
    '交易商会',
    3,
    5,
    8,
    '{"gold":500,"items":[],"alignment_shift":{"chaos":10},"exp":150,"reputation":5}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_marcund']::text[],
    '{"location_tags":["loc_marcund"]}'::jsonb,
    '{"nodes":{"start":{"text":"交易商会の詰め所。照りつける太陽から逃れた室内も、息苦しい熱気に満ちていた。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"壁には砂丘の連なりを示す古びた地図。机の上では、隊長が金貨を数えている。","type":"text","bg_key":"bg_guild","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「今回の荷は香辛料と絹だ。ラクダ２０頭分。片道８日の旅になる」","type":"text","bg_key":"bg_guild","speaker_name":"交易商会の隊長","speaker":"交易商会の隊長","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「万一、途中で荷を一つでも失えば、お前の報酬から差し引くからな」","type":"text","bg_key":"bg_guild","speaker_name":"交易商会の隊長","speaker":"交易商会の隊長","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「砂漠の野盗どもに加え、最近は砂の下の化け物も狂暴化している」","type":"text","bg_key":"bg_guild","speaker_name":"交易商会の隊長","speaker":"交易商会の隊長","next":"intro_2_warn","choices":[{"label":"続ける","next":"intro_2_warn"}]},"intro_2_warn":{"text":"「死にたくなければ、片時も気を抜くんじゃないぞ」","type":"text","bg_key":"bg_guild","speaker_name":"交易商会の隊長","speaker":"交易商会の隊長","next":"depart","choices":[{"label":"続ける","next":"depart"}]},"depart":{"text":"王都の頑丈な門を出て、果てなき熱砂の海へと足を踏み出す。長い旅の始まりだ。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"depart_scenery","choices":[{"label":"続ける","next":"depart_scenery"}]},"depart_scenery":{"text":"ラクダの長い列が、黄金色の砂丘の彼方までゆっくりと連なっていく。","type":"text","bg_key":"bg_desert","next":"desert_day1","choices":[{"label":"続ける","next":"desert_day1"}]},"desert_day1":{"text":"出発から二日目。見渡す限りの砂海と青空。前後左右、すべての景色が同じだった。","type":"text","bg_key":"bg_desert","next":"desert_heat","choices":[{"label":"続ける","next":"desert_heat"}]},"desert_heat":{"text":"陽炎が揺れる。革の水筒は早くも空に近い。乾いた風が容赦なく喉を焼いた。","type":"text","bg_key":"bg_desert","next":"desert_night","choices":[{"label":"続ける","next":"desert_night"}]},"desert_night":{"text":"夜は極寒。気温が急降下する中、私たちはラクダで壁を作り野営の準備を整える。","type":"text","bg_key":"bg_desert_night","bgm":"bgm_quest_calm","next":"campfire","choices":[{"label":"続ける","next":"campfire"}]},"campfire":{"text":"小さく爆ぜる焚き火。男たちは声を潜め、砂漠に住まう死霊の怪談を囁き合う。","type":"text","bg_key":"bg_camp","next":"ambush_alert","choices":[{"label":"続ける","next":"ambush_alert"}]},"ambush_alert":{"text":"深夜、見張りが私の肩を揺さぶる。砂丘の影に、不気味な火が揺れていた。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_tense","next":"ambush_desc","choices":[{"label":"続ける","next":"ambush_desc"}]},"ambush_desc":{"text":"ターバンを巻いた無数の人影が、音もなく近づく。商隊を狙う砂漠の野盗団だ。","type":"text","bg_key":"bg_desert_night","next":"battle_wave1","choices":[{"label":"続ける","next":"battle_wave1"}]},"battle_wave1":{"text":"闇に紛れて奇襲を仕掛けてきた野盗どもを迎え撃て！ 交易品を守るのだ！","type":"battle","bg_key":"bg_desert_night","bgm":"bgm_battle","enemy_group_id":"420","enemy_name":"砂漠の盗賊団","choices":[{"label":"win","next":"after_wave1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave1"},"after_wave1":{"text":"野盗を撃退した。逃げていく影の足跡は、風が運ぶ砂によってすぐに消え去る。","type":"text","bg_key":"bg_desert_night","bgm":"bgm_quest_calm","next":"after_wave1_check","choices":[{"label":"続ける","next":"after_wave1_check"}]},"after_wave1_check":{"text":"荷を確認する。絹の包みは無事だ。ラクダも欠けることなく息を整えている。","type":"text","bg_key":"bg_desert_night","next":"travel_resume","choices":[{"label":"続ける","next":"travel_resume"}]},"travel_resume":{"text":"明朝、旅を再開する。体は重いが、立ち止まれば更なる追撃を招くだけだ。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"sandstorm","choices":[{"label":"続ける","next":"sandstorm"}]},"sandstorm":{"text":"五日目の昼。突如、空が赤褐色に染まり、猛烈な砂嵐が全てを覆い尽くした。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"sandstorm_pass","choices":[{"label":"続ける","next":"sandstorm_pass"}]},"sandstorm_pass":{"text":"ラクダにしがみつき、嵐が去るのを耐える。周囲の砂が不自然に脈動し始めた。","type":"text","bg_key":"bg_desert","next":"beast_alert","choices":[{"label":"続ける","next":"beast_alert"}]},"beast_alert":{"text":"地響きと共に地表面が揺れる。獣の危険を察知し、ラクダたちが狂乱する。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"beast_desc","choices":[{"label":"続ける","next":"beast_desc"}]},"beast_desc":{"text":"砂が爆発的に噴き上がり、巨大な口が姿を現した。砂漠の魔獣サンドワームだ。","type":"text","bg_key":"bg_desert","next":"battle_wave2","choices":[{"label":"続ける","next":"battle_wave2"}]},"battle_wave2":{"text":"砂の下から襲いかかる巨大な大虫と、毒針を構える大サソリを撃破せよ！","type":"battle","bg_key":"bg_desert","bgm":"bgm_battle_boss","enemy_group_id":"421","enemy_name":"砂漠の魔獣","choices":[{"label":"win","next":"after_wave2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave2"},"after_wave2":{"text":"魔獣は血を吹き出しながら砂の中へ沈んでいった。危険な戦闘を生き延びた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"after_wave2_think","choices":[{"label":"続ける","next":"after_wave2_think"}]},"after_wave2_think":{"text":"装備に入り込んだ砂を払い落とす。目的地である交易都市は、もう間近のはずだ。","type":"text","bg_key":"bg_desert","next":"arrive","choices":[{"label":"続ける","next":"arrive"}]},"arrive":{"text":"八日目の夕暮れ。沈む夕陽に照らされた、美しい交易都市の白い城壁が見えた。","type":"text","bg_key":"bg_desert","next":"arrive_guild","choices":[{"label":"続ける","next":"arrive_guild"}]},"arrive_guild":{"text":"門をくぐり、商会の倉庫に到着した。泥や砂に汚れた私たちを代理人が迎える。","type":"text","bg_key":"bg_guild","next":"reward_scene","choices":[{"label":"続ける","next":"reward_scene"}]},"reward_scene":{"text":"「全頭無事での帰還とは恐れ入った！ 約束の報酬だ、受け取ってくれ」","type":"text","bg_key":"bg_guild","speaker_name":"交易商会の代理人","speaker":"交易商会の代理人","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"ずっしりと重い金袋を受け取る。この砂と汗まみれの旅も、無駄ではなかった。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":500,"alignment_shift":{"chaos":10},"exp":150,"reputation":5}},"choices":[]},"end_failure":{"text":"過酷な熱砂と魔獣の前に力尽きる。商隊は散り散りになり、砂の海へ消えた。","type":"end","result":"failure","bg_key":"bg_desert","choices":[]}},"short_description":"[護衛] 広大な砂漠を越える商隊の用心棒。盗賊と魔獣の連戦を耐え抜け。"}'::jsonb,
    8,
    4
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7021: 幻覚サソリの毒針調達 (qst_mar_scorpion)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7021,
    'qst_mar_scorpion',
    '幻覚サソリの毒針調達',
    '[納品] 砂漠の奥地に棲む幻覚サソリを狩り、闇商人に毒針を納品する。',
    '闇商人',
    2,
    5,
    2,
    '{"gold":300,"items":[],"alignment_shift":{"evil":5,"chaos":5},"exp":100}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_marcund']::text[],
    '{"location_tags":["loc_marcund"]}'::jsonb,
    '{"nodes":{"start":{"text":"マルカンドの裏路地。強い香辛料と不衛生なドブの臭いが混じり合う、狭い闇市の一角。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_tense","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"フードを目深に被った男が、外套の下から細く汚れた指を伸ばして手招きする。","type":"text","bg_key":"bg_slums","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「幻覚サソリの毒針が欲しい。鮮度の良いものを３本だ」","type":"text","bg_key":"bg_slums","speaker_name":"闇商人","speaker":"闇商人","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「何に使うかは詮索するな。それがここのルールだ」","type":"text","bg_key":"bg_slums","speaker_name":"闇商人","speaker":"闇商人","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「巣は砂漠の東にある岩場だ。尾の先が紫色に光っている」","type":"text","bg_key":"bg_slums","speaker_name":"闇商人","speaker":"闇商人","next":"intro_2_warn","choices":[{"label":"続ける","next":"intro_2_warn"}]},"intro_2_warn":{"text":"「ほんの掠り傷でも、脳が狂って死ぬことになるぞ」","type":"text","bg_key":"bg_slums","speaker_name":"闇商人","speaker":"闇商人","next":"travel_desert","choices":[{"label":"続ける","next":"travel_desert"}]},"travel_desert":{"text":"東の熱砂へ向かう。巻き上がる砂塵が視界を遮り、喉を執拗に痛めつける。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"travel_scenery","choices":[{"label":"続ける","next":"travel_scenery"}]},"travel_scenery":{"text":"乾いた風が吹き抜け、不気味な白骨化した獣の死骸があちこちに転がっていた。","type":"text","bg_key":"bg_desert","next":"reach_rocks","choices":[{"label":"続ける","next":"reach_rocks"}]},"reach_rocks":{"text":"半日歩き、赤茶けた岩場に到着した。岩壁の隙間から、紫色の怪しい光が漏れる。","type":"text","bg_key":"bg_desert","next":"reach_rocks_desc","choices":[{"label":"続ける","next":"reach_rocks_desc"}]},"reach_rocks_desc":{"text":"岩場の周囲の草木は毒気で枯れ果て、触れるだけで崩れ去るほど脆くなっていた。","type":"text","bg_key":"bg_desert","next":"search_1","choices":[{"label":"続ける","next":"search_1"}]},"search_1":{"text":"岩の奥へ石を投げ込む。暗闇からカサカサと、硬い殻が擦れ合う音が響いた。","type":"text","bg_key":"bg_desert","next":"search_wait","choices":[{"label":"続ける","next":"search_wait"}]},"search_wait":{"text":"様子を見る。しかし、用心深い魔獣はなかなか暗い裂け目から姿を現そうとしない。","type":"text","bg_key":"bg_desert","next":"find_nest","choices":[{"label":"続ける","next":"find_nest"}]},"find_nest":{"text":"岩の裏には無数の巣穴。周囲の砂が紫色に染まっているのは、蓄積した毒のせいか。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"nest_desc","choices":[{"label":"続ける","next":"nest_desc"}]},"nest_desc":{"text":"穴から巨大なサソリが現れた。大人の腕ほどもあり、鋭い鋏を威嚇するように鳴らす。","type":"text","bg_key":"bg_desert","next":"nest_rush","choices":[{"label":"続ける","next":"nest_rush"}]},"nest_rush":{"text":"一匹だけではない。地中から次々と、紫色の毒針を掲げた影が這い回り始める。","type":"text","bg_key":"bg_desert","next":"battle_scorpion","choices":[{"label":"続ける","next":"battle_scorpion"}]},"battle_scorpion":{"text":"尾の毒針を妖しく光らせた幻覚サソリの群れが、一斉に襲いかかってきた！","type":"battle","bg_key":"bg_desert","bgm":"bgm_battle","enemy_group_id":"422","enemy_name":"幻覚サソリの群れ","choices":[{"label":"win","next":"harvest_result"},{"label":"lose","next":"end_failure"}],"battle_success_next":"harvest_result"},"harvest_result":{"type":"random_branch","bg_key":"bg_desert","prob":50,"choices":[{"label":"success","next":"harvest_success"},{"label":"failure","next":"harvest_fail"}]},"harvest_success":{"text":"慎重に切り離した。紫色の鮮やかな針を、丁寧にガラス瓶の中へ封印する。","type":"reward","bg_key":"bg_desert","params":{"item_id":"item_scorpion_needle"},"next":"check_needles","choices":[{"label":"続ける","next":"check_needles"}]},"harvest_fail":{"text":"切り離す際に力が入り、針が砕けてしまった。有毒な紫の霧が微かに舞い散る。","type":"text","bg_key":"bg_desert","next":"harvest_fail_avoid","choices":[{"label":"続ける","next":"harvest_fail_avoid"}]},"harvest_fail_avoid":{"text":"慌てて息を止めて飛び退く。砕けた針は、もはや何の価値もなくなってしまった。","type":"text","bg_key":"bg_desert","next":"check_needles","choices":[{"label":"続ける","next":"check_needles"}]},"check_needles":{"type":"check_delivery","bg_key":"bg_desert","params":{"item_id":"item_scorpion_needle","quantity":3},"choices":[{"label":"success","next":"travel_back"},{"label":"failure","next":"hunt_continue"}]},"hunt_continue":{"text":"まだ３本に達していない。巣穴を刺激し、次の獲物を地表へと引きずり出す。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"travel_back","choices":[{"label":"続ける","next":"travel_back"}]},"travel_back":{"text":"毒針が３本揃った。砂漠の熱で変質する前に、急いでマルカンドへ戻らねば。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"travel_back_scenery","choices":[{"label":"続ける","next":"travel_back_scenery"}]},"travel_back_scenery":{"text":"夕陽が砂漠を血のように赤く染めていく。背中の猛毒の危険を感じつつ歩みを急ぐ。","type":"text","bg_key":"bg_desert","next":"back_alley","choices":[{"label":"続ける","next":"back_alley"}]},"back_alley":{"text":"日没後、異様な香とドブの臭いが満ちる裏路地へ戻る。闇商人は同じ場所にいた。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_tense","next":"back_alley_desc","choices":[{"label":"続ける","next":"back_alley_desc"}]},"back_alley_desc":{"text":"怪しげな薬売りや密売人たちの視線を避けながら、待ち合わせの路地裏の奥へと進む。","type":"text","bg_key":"bg_slums","next":"deliver_1","choices":[{"label":"続ける","next":"deliver_1"}]},"deliver_1":{"text":"毒針の入った瓶を手渡す。男は小窓のランプの光に透かし、一本ずつ吟味した。","type":"text","bg_key":"bg_slums","next":"dealer_reply","choices":[{"label":"続ける","next":"dealer_reply"}]},"dealer_reply":{"text":"「どれも極上だ。これだけ新鮮なら、最高の幻覚剤が作れる」","type":"text","bg_key":"bg_slums","speaker_name":"闇商人","speaker":"闇商人","next":"dealer_reply_02","choices":[{"label":"続ける","next":"dealer_reply_02"}]},"dealer_reply_02":{"text":"「これは報酬だ。また汚い仕事が欲しくなったらここへ来い」","type":"text","bg_key":"bg_slums","speaker_name":"闇商人","speaker":"闇商人","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"金貨を受け取る。この毒が誰かを狂わせるのだろうが、私には関係のないことだ。","type":"end","result":"success","bg_key":"bg_slums","params":{"rewards":{"gold":300,"alignment_shift":{"evil":5,"chaos":5},"exp":100}},"choices":[]},"end_failure":{"text":"防ぎきれず、毒針が肉を引き裂いた。紫色の幻想の中、意識は永遠に失われた。","type":"end","result":"failure","bg_key":"bg_desert","choices":[]}},"short_description":"[納品] 砂漠の奥地に棲む幻覚サソリを狩り、闇商人に毒針を納品する。"}'::jsonb,
    2,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7022: 逃亡奴隷の連れ戻し (qst_mar_debt)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7022,
    'qst_mar_debt',
    '逃亡奴隷の連れ戻し',
    '[捕縛] 借金を踏み倒して逃げた元奴隷を、生死問わず連れ戻す。',
    '奴隷商',
    3,
    5,
    3,
    '{"gold":450,"items":[],"alignment_shift":{"evil":10,"chaos":5},"exp":100,"reputation":-5}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_marcund']::text[],
    '{"location_tags":["loc_marcund"],"max_reputation":-50}'::jsonb,
    '{"nodes":{"start":{"text":"奴隷商の邸宅。香油の甘い香りの陰で、微かに錆びた鉄鎖の擦れ合う音が響いていた。","type":"text","bg_key":"bg_mar_mansion","bgm":"bgm_quest_tense","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"肥え太った男が金歯を剥き出しにして下卑た笑みを浮かべ、一枚の羊皮紙を差し出す。","type":"text","bg_key":"bg_mar_mansion","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「あいつは私の財産だ。大金を踏み倒して逃げやがった」","type":"text","bg_key":"bg_slums","speaker_name":"奴隷商","speaker":"奴隷商","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「足の二三本へし折っても構わん。私の元へ連れ戻せ」","type":"text","bg_key":"bg_slums","speaker_name":"奴隷商","speaker":"奴隷商","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「居場所は砂漠の端の無法者集落だ。用心棒どもがいる」","type":"text","bg_key":"bg_slums","speaker_name":"奴隷商","speaker":"奴隷商","next":"intro_2_warn","choices":[{"label":"続ける","next":"intro_2_warn"}]},"intro_2_warn":{"text":"「抵抗するなら容赦は要らん。お前なら楽な仕事だろう」","type":"text","bg_key":"bg_slums","speaker_name":"奴隷商","speaker":"奴隷商","next":"travel_desert","choices":[{"label":"続ける","next":"travel_desert"}]},"travel_desert":{"text":"砂漠の東端へと向かう。半日歩くと、崩れかけた岩山の影に錆びた集落が見えた。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"reach_colony","choices":[{"label":"続ける","next":"reach_colony"}]},"reach_colony":{"text":"無法者集落。犯罪者や逃亡者が寄り添って暮らす、砂漠の最果ての吹き溜まりだ。","type":"text","bg_key":"bg_mar_outlaw","next":"colony_desc","choices":[{"label":"続ける","next":"colony_desc"}]},"colony_desc":{"text":"薄汚れたバラック小屋の陰から、住人たちの殺気立った視線がこちらを突き刺す。","type":"text","bg_key":"bg_mar_outlaw","next":"watchman","choices":[{"label":"続ける","next":"watchman"}]},"watchman":{"text":"集落の入り口。黒いターバンを巻いた大柄な男が、槍を構えて行く手を阻んだ。","type":"text","bg_key":"bg_mar_outlaw","bgm":"bgm_quest_tense","next":"watchman_threat","choices":[{"label":"続ける","next":"watchman_threat"}]},"watchman_threat":{"text":"「奴隷商の飼い犬め。ここへは何の用だ。引き返せ」","type":"text","bg_key":"bg_slums","speaker_name":"集落の見張り","speaker":"集落の見張り","next":"sneak_in","choices":[{"label":"続ける","next":"sneak_in"}]},"sneak_in":{"text":"隙を見て路地へ忍び込む。住民の喧騒を避け、目的の男が潜む小屋を探した。","type":"text","bg_key":"bg_slums","next":"find_fugitive","choices":[{"label":"続ける","next":"find_fugitive"}]},"find_fugitive":{"text":"傾いた木箱の陰。怯えながらも、目に鋭い覚悟を宿した若い男と対峙する。","type":"text","bg_key":"bg_slums","next":"fugitive_story","choices":[{"label":"続ける","next":"fugitive_story"}]},"fugitive_story":{"text":"「……奴は、返済が終わっても新たな嘘で拘束し続ける悪魔だ」","type":"text","bg_key":"bg_slums","speaker_name":"逃亡した男","speaker":"逃亡した男","next":"fugitive_story_detail","choices":[{"label":"続ける","next":"fugitive_story_detail"}]},"fugitive_story_detail":{"text":"「連れ戻されれば、俺は一生あの檻から出られない」","type":"text","bg_key":"bg_slums","speaker_name":"逃亡した男","speaker":"逃亡した男","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"text":"男の目は真実を訴えている。だが、これは依頼だ。どうする？","type":"choice","bg_key":"bg_slums","choices":[{"label":"連れ戻す（依頼通りに）","next":"refuse_mercy"},{"label":"見逃す（逃がしてやる）","next":"let_go"}]},"refuse_mercy":{"text":"「悪いが、これは仕事だ」男の顔が絶望に染まり、外から怒号が響いた。","type":"text","bg_key":"bg_slums","next":"battle_wave1","choices":[{"label":"続ける","next":"battle_wave1"}]},"battle_wave1":{"text":"逃亡者を守るため、集落の用心棒たちが刃を構えて一斉に襲いかかってきた！","type":"battle","bg_key":"bg_slums","bgm":"bgm_battle","enemy_group_id":"423","enemy_name":"集落の用心棒","choices":[{"label":"win","next":"after_wave1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave1"},"after_wave1":{"text":"用心棒を倒した。だが、騒ぎを聞きつけた見張りの暗殺者が行く手を塞ぐ。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_tense","next":"battle_wave2","choices":[{"label":"続ける","next":"battle_wave2"}]},"battle_wave2":{"text":"逃げ場のない狭い路地裏。凄腕の刺客たちとの、息詰まる死闘が始まる！","type":"battle","bg_key":"bg_slums","bgm":"bgm_battle","enemy_group_id":"424","enemy_name":"集落の精鋭","choices":[{"label":"win","next":"capture"},{"label":"lose","next":"end_failure"}],"battle_success_next":"capture"},"capture":{"text":"刺客たちを切り伏せる。逃亡者の男は力なく膝をつき、両手を差し出した。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_calm","next":"drag_back","choices":[{"label":"続ける","next":"drag_back"}]},"drag_back":{"text":"男を縛り、照りつける砂漠を引きずり歩く。背後には住民の呪詛が響いていた。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"deliver_slave","choices":[{"label":"続ける","next":"deliver_slave"}]},"deliver_slave":{"text":"「よくやった！ さあ、この足枷をはめて檻へ叩き込め！」","type":"text","bg_key":"bg_slums","speaker_name":"奴隷商","speaker":"奴隷商","next":"deliver_slave_02","choices":[{"label":"続ける","next":"deliver_slave_02"}]},"deliver_slave_02":{"text":"「これがお前の報酬だ。またいい仕事があれば頼むぞ」","type":"text","bg_key":"bg_slums","speaker_name":"奴隷商","speaker":"奴隷商","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"金袋を受け取る。檻の奥から響く絶望の叫び声が、いつまでも耳を離れない。","type":"end","result":"success","bg_key":"bg_slums","params":{"rewards":{"gold":450,"alignment_shift":{"evil":10,"chaos":5},"exp":100,"reputation":-5}},"choices":[]},"let_go":{"text":"「行け。二度と捕まるな」縄を切ると、男は驚愕の表情を浮かべた。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_calm","next":"fugitive_thanks","choices":[{"label":"続ける","next":"fugitive_thanks"}]},"fugitive_thanks":{"text":"「……感謝する。この恩は、死ぬまで決して忘れない」","type":"text","bg_key":"bg_slums","speaker_name":"逃亡した男","speaker":"逃亡した男","next":"leave_colony","choices":[{"label":"続ける","next":"leave_colony"}]},"leave_colony":{"text":"集落を離れ、帰路につく。奴隷商には『既に他国へ逃亡していた』と報告しよう。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"end_mercy","choices":[{"label":"続ける","next":"end_mercy"}]},"end_mercy":{"text":"報酬は得られなかった。だが、砂漠を吹き抜ける風が、少しだけ心地よい。","type":"end","result":"success","bg_key":"bg_desert","params":{"rewards":{"gold":0,"alignment_shift":{"justice":15},"reputation":10}},"choices":[]},"end_failure":{"text":"無法者の連携に圧倒され、砂泥の中に倒れ伏す。意識は暗闇へと沈んだ。","type":"end","result":"failure","bg_key":"bg_slums","choices":[]}},"short_description":"[捕縛] 借金を踏み倒して逃げた元奴隷を、生死問わず連れ戻す。"}'::jsonb,
    3,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7023: 交易路を脅かす大砂虫討伐 (qst_mar_sandworm)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7023,
    'qst_mar_sandworm',
    '交易路を脅かす大砂虫討伐',
    '[討伐] 流砂の底に潜む巨大な魔獣を誘い出し、オアシスの安全を確保せよ。',
    '交易商会',
    4,
    5,
    4,
    '{"gold":600,"items":[],"alignment_shift":{"chaos":10},"exp":200,"reputation":10}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_marcund']::text[],
    '{"location_tags":["loc_marcund"]}'::jsonb,
    '{"nodes":{"start":{"text":"交易商会の本部。砂嵐に削られた古い石壁に囲まれた部屋で、幹部たちが深刻な顔をしていた。","type":"text","bg_key":"bg_tavern_day","bgm":"bgm_quest_calm","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"机の上に広げられた巨大な砂漠の地図には、赤いインクで通行不能の印がつけられている。","type":"text","bg_key":"bg_tavern_day","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「主要交易路に大砂虫サンドワームが棲みつき、商隊が２つ丸ごと飲み込まれた」","type":"text","bg_key":"bg_tavern_day","speaker_name":"商会の幹部","speaker":"商会の幹部","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「このままでは商売は破滅だ。あのルートを再び開通させねばならん」","type":"text","bg_key":"bg_tavern_day","speaker_name":"商会の幹部","speaker":"商会の幹部","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「囮の荷車の振動で奴を引きずり出し、息の根を止めてほしい。報酬は弾む」","type":"text","bg_key":"bg_tavern_day","speaker_name":"商会の幹部","speaker":"商会の幹部","next":"prepare","choices":[{"label":"続ける","next":"prepare"}]},"prepare":{"text":"「それと……これを持っていけ。錬金術師が作った、対砂虫用の特製爆薬だ」","type":"text","bg_key":"bg_tavern_day","speaker_name":"商会の幹部","speaker":"商会の幹部","next":"prepare_detail","choices":[{"label":"続ける","next":"prepare_detail"}]},"prepare_detail":{"text":"「奴の口内へ叩き込めば、いかなる巨大な外殻だろうと内部から爆破できる」","type":"text","bg_key":"bg_tavern_day","speaker_name":"商会の幹部","speaker":"商会の幹部","next":"receive_explosive","choices":[{"label":"続ける","next":"receive_explosive"}]},"receive_explosive":{"text":"黒い金属筒に入った爆薬を受け取る。独特のツンとした火薬の臭いと、ずっしりとした重みがあった。","type":"reward","bg_key":"bg_tavern_day","params":{"item_id":"item_explosive"},"next":"travel_to_site","choices":[{"label":"続ける","next":"travel_to_site"}]},"travel_to_site":{"text":"砂漠の出没地へ向かう。途中で見かけた商隊の残骸は、押し潰され砂に半ば埋もれていた。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"site_desc","choices":[{"label":"続ける","next":"site_desc"}]},"site_desc":{"text":"現場に到着した。周囲の砂丘は漏斗状に崩れ、巨大な陥没穴が幾つも口を開けている。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"set_bait","choices":[{"label":"続ける","next":"set_bait"}]},"set_bait":{"text":"砂地の上に囮の荷車を据え置く。荷台の隙間に、香辛料の袋をぎっしりと積み上げた。","type":"text","bg_key":"bg_desert","next":"bait_desc","choices":[{"label":"続ける","next":"bait_desc"}]},"bait_desc":{"text":"仕掛けを作動させ、荷車から規則的な振動を発生させる。地面の砂が微かに躍り始めた。","type":"text","bg_key":"bg_desert","next":"wait_1","choices":[{"label":"続ける","next":"wait_1"}]},"wait_1":{"text":"静寂の中、抜剣して待つ。熱い砂を吹き抜ける風の音だけが、耳元で虚しく響いていた。","type":"text","bg_key":"bg_desert","next":"tremor_1","choices":[{"label":"続ける","next":"tremor_1"}]},"tremor_1":{"text":"突如、足元から激しい衝撃。砂の中から、大サソリと小型の砂虫が飛び出してくる。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"scouts_appear","choices":[{"label":"続ける","next":"scouts_appear"}]},"scouts_appear":{"text":"本命の呼び水に引かれた先遣の群れだ。まずはこいつらを素早く排除せよ！","type":"text","bg_key":"bg_desert","next":"battle_wave1","choices":[{"label":"続ける","next":"battle_wave1"}]},"battle_wave1":{"text":"大砂虫の出現に備えつつ、襲いかかるサソリと砂虫を切り伏せろ！","type":"battle","bg_key":"bg_desert","bgm":"bgm_battle","enemy_group_id":"425","enemy_name":"砂漠の先遣隊","choices":[{"label":"win","next":"after_wave1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave1"},"after_wave1":{"text":"先遣隊を撃破した。しかし、本命の接近を示すように地響きは数十倍に膨れ上がる。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"reset_bait","choices":[{"label":"続ける","next":"reset_bait"}]},"reset_bait":{"text":"倒壊しかけた荷車の震動装置を叩き、最大出力で大砂虫をさらにおびき出す。","type":"text","bg_key":"bg_desert","next":"wait_2","choices":[{"label":"続ける","next":"wait_2"}]},"wait_2":{"text":"地表の砂が流砂のように流れ始める。足場が急速に崩れ、逃げ場が失われていく。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"tremor_2","choices":[{"label":"続ける","next":"tremor_2"}]},"tremor_2":{"text":"砂の海が爆発した。天を突く二つの巨大な影が、激しい砂煙と共に急上昇する。","type":"text","bg_key":"bg_desert","next":"boss_emerge","choices":[{"label":"続ける","next":"boss_emerge"}]},"boss_emerge":{"text":"現れたのは二匹の大砂虫。獲物を探すように、粘液に塗れた蛇腹の肉体を捩らせた。","type":"text","bg_key":"bg_desert","next":"boss_desc","choices":[{"label":"続ける","next":"boss_desc"}]},"boss_desc":{"text":"船ほどもある巨体。中心に並ぶ同心円状の白い牙が、鋭い摩擦音を立てている。","type":"text","bg_key":"bg_desert","next":"trap_collapse","choices":[{"label":"続ける","next":"trap_collapse"}]},"trap_collapse":{"text":"砂虫の尾の一撃が地盤を砕いた！ 崩落に巻き込まれ、全身を強打しながら這い上がる。","type":"hp_damage","bg_key":"bg_desert","bgm":"bgm_quest_tense","params":{"hp_percent":50,"percent":50},"next":"battle_wave2","choices":[{"label":"続ける","next":"battle_wave2"}]},"battle_wave2":{"text":"砂漠の覇者との戦い！ 隙を見て、商会から預かった爆薬を叩き込め！","type":"battle","bg_key":"bg_desert","bgm":"bgm_battle_boss","enemy_group_id":"426","enemy_name":"大砂虫","choices":[{"label":"win","next":"after_wave2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave2"},"after_wave2":{"text":"爆煙が消え、巨虫たちは砂の底へ沈んだ。崩れた砂丘には、静寂だけが残される。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"carcass","choices":[{"label":"続ける","next":"carcass"}]},"carcass":{"text":"熱い血の悪臭が漂う。砂漠の脅威は去った。これで再び商隊が往来できるはずだ。","type":"text","bg_key":"bg_desert","next":"return_report","choices":[{"label":"続ける","next":"return_report"}]},"return_report":{"text":"王都に戻り、商会本部に討伐成功を報告した。張り詰めていた幹部たちの顔が和らぐ。","type":"text","bg_key":"bg_tavern_day","next":"knight_reply","choices":[{"label":"続ける","next":"knight_reply"}]},"knight_reply":{"text":"「見事だ！ これでお前は我が商会の最高の恩人。約束の報酬を受け取ってくれ」","type":"text","bg_key":"bg_tavern_day","speaker_name":"商会の幹部","speaker":"商会の幹部","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"重い金袋を懐に収める。砂漠に再びラクダの鈴の音が戻るだろう。","type":"end","result":"success","bg_key":"bg_tavern_day","params":{"rewards":{"gold":600,"alignment_shift":{"chaos":10},"exp":200,"reputation":10}},"choices":[]},"end_failure":{"text":"大砂虫の圧倒的な体躯の前に崩れ落ちた。砂の中に引きずり込まれ、意識が閉じる。","type":"end","result":"failure","bg_key":"bg_desert","choices":[]}},"short_description":"[討伐] 流砂の底に潜む巨大な魔獣を誘い出し、オアシスの安全を確保せよ。"}'::jsonb,
    4,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7024: 闇市オークションの用心棒 (qst_mar_auction)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7024,
    'qst_mar_auction',
    '闇市オークションの用心棒',
    '[防衛] 違法国宝が取引される闇の競売場で、乱入者を排除する。',
    '闇市の元締め',
    3,
    5,
    1,
    '{"gold":500,"items":[],"alignment_shift":{"chaos":10,"evil":5},"exp":120,"reputation":-5}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_marcund']::text[],
    '{"location_tags":["loc_marcund"],"max_reputation":-50}'::jsonb,
    '{"nodes":{"start":{"text":"マルカンドの地下水路の入口。案内の男によって、有無を言わさず目隠しをされた。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_tense","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"男の手を借りて長い螺旋階段を下りていく。下から、微かに香油の匂いが漂う。","type":"text","bg_key":"bg_slums","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"目隠しを外すと、地下広間に豪華な絨毯が敷かれた即席の競売場が広がっていた。","type":"text","bg_key":"bg_mar_auction","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「今夜の客は身分が高いが、厄介なハイエナも引き寄せる。警備を怠るな」","type":"text","bg_key":"bg_mar_auction","speaker_name":"闇市の元締め","speaker":"闇市の元締め","next":"intro_2_warn","choices":[{"label":"続ける","next":"intro_2_warn"}]},"intro_2_warn":{"text":"「騒ぎを起こす余所者が現れたら、音を立てずに素早く始末するのだ」","type":"text","bg_key":"bg_mar_auction","speaker_name":"闇市の元締め","speaker":"闇市の元締め","next":"auction_declare","choices":[{"label":"続ける","next":"auction_declare"}]},"auction_declare":{"text":"燭台に火が灯り、開会を告げる真鍮のベルの音が、地下室の冷たい天井に響いた。","type":"text","bg_key":"bg_mar_auction","next":"wait_outside","choices":[{"label":"続ける","next":"wait_outside"}]},"wait_outside":{"text":"会場の鉄格子の陰で待機する。壁の向こうから、競りの声と金貨の音が響く。","type":"text","bg_key":"bg_mar_auction","next":"wait_outside_think","choices":[{"label":"続ける","next":"wait_outside_think"}]},"wait_outside_think":{"text":"法も光も届かない地下。欲望と虚栄が渦巻く、この街らしい退廃の縮図だ。","type":"text","bg_key":"bg_mar_auction","next":"auction_start","choices":[{"label":"続ける","next":"auction_start"}]},"auction_start":{"text":"競売が始まった。最初の出品は、ある名家の墓から暴かれた黄金の王冠だ。","type":"text","bg_key":"bg_mar_auction","bgm":"bgm_quest_calm","next":"auction_item_1","choices":[{"label":"続ける","next":"auction_item_1"}]},"auction_item_1":{"text":"「金貨３００！ ５００！ ８００！」入札の声が、異常な熱気を帯びて響く。","type":"text","bg_key":"bg_mar_auction","next":"first_alarm","choices":[{"label":"続ける","next":"first_alarm"}]},"first_alarm":{"text":"見張りの一人が青い顔で駆け寄ってきた。水路の奥に侵入者があったという。","type":"text","bg_key":"bg_mar_auction","bgm":"bgm_quest_tense","next":"intruder_1","choices":[{"label":"続ける","next":"intruder_1"}]},"intruder_1":{"text":"地下水路の入口。噂を聞きつけた武装した野盗崩れが、扉をこじ開けていた。","type":"text","bg_key":"bg_mar_auction","next":"intruder_1_talk","choices":[{"label":"続ける","next":"intruder_1_talk"}]},"intruder_1_talk":{"text":"汚い笑い声を上げながら、野盗たちが鉄の棒を振り回して会場を覗き込む。","type":"text","bg_key":"bg_mar_auction","next":"battle_wave1","choices":[{"label":"続ける","next":"battle_wave1"}]},"battle_wave1":{"text":"中の金品を狙う無頼漢どもを排除せよ！ 競売の邪魔をさせてはならない！","type":"battle","bg_key":"bg_mar_auction","bgm":"bgm_battle","enemy_group_id":"427","enemy_name":"乱入者の先遣隊","choices":[{"label":"win","next":"after_wave1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave1"},"after_wave1":{"text":"野盗を撃退した。死体を暗い水路へ突き落とし、石畳の血痕を砂で素早く隠す。","type":"text","bg_key":"bg_mar_auction","bgm":"bgm_quest_calm","next":"after_wave1_report","choices":[{"label":"続ける","next":"after_wave1_report"}]},"after_wave1_report":{"text":"会場の扉から元締めが顔を出し、満足げに頷いてから再び奥へ戻っていった。","type":"text","bg_key":"bg_mar_auction","next":"auction_item_2","choices":[{"label":"続ける","next":"auction_item_2"}]},"auction_item_2":{"text":"競売は進行中。次の商品は、王宮で禁止された美しくも恐ろしい秘薬のようだ。","type":"text","bg_key":"bg_mar_auction","next":"second_alarm","choices":[{"label":"続ける","next":"second_alarm"}]},"second_alarm":{"text":"再び見張りが駆け寄る。今度は震え声だ。「ただの泥棒じゃねえ、手練れだ」","type":"text","bg_key":"bg_mar_auction","bgm":"bgm_quest_tense","next":"intruder_2_desc","choices":[{"label":"続ける","next":"intruder_2_desc"}]},"intruder_2_desc":{"text":"暗い水路の壁を這うように、黒装束の集団が音もなく急速に忍び寄ってきた。","type":"text","bg_key":"bg_mar_auction","next":"intruder_2_talk","choices":[{"label":"続ける","next":"intruder_2_talk"}]},"intruder_2_talk":{"text":"「邪魔をするな。我々の狙いは元締めの首だけだ。退くなら命は助けてやる」","type":"text","bg_key":"bg_mar_auction","speaker_name":"黒装束の男","speaker":"黒装束の男","next":"battle_wave2","choices":[{"label":"続ける","next":"battle_wave2"}]},"battle_wave2":{"text":"元締めの命を狙うプロの暗殺者たちとの、一瞬の油断も許されない死闘だ！","type":"battle","bg_key":"bg_mar_auction","bgm":"bgm_battle","enemy_group_id":"428","enemy_name":"暗殺者の精鋭","choices":[{"label":"win","next":"after_wave2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_wave2"},"after_wave2":{"text":"暗殺者を片付けた。元締めの私兵たちが、素早く死体の痕跡を消していく。","type":"text","bg_key":"bg_mar_auction","bgm":"bgm_quest_calm","next":"after_wave2_think","choices":[{"label":"続ける","next":"after_wave2_think"}]},"after_wave2_think":{"text":"死を日常の一部として処理する彼らの手際に、不気味な寒気を感じた。","type":"text","bg_key":"bg_mar_auction","next":"auction_end","choices":[{"label":"続ける","next":"auction_end"}]},"auction_end":{"text":"深夜、競売が静かに幕を閉じる。買い手たちは再び目隠しをされ退出した。","type":"text","bg_key":"bg_mar_auction","next":"auction_end_desc","choices":[{"label":"続ける","next":"auction_end_desc"}]},"auction_end_desc":{"text":"身分の高そうな客たちは、何事もなかったかのように夜の闇へと消えていく。","type":"text","bg_key":"bg_mar_auction","next":"payment","choices":[{"label":"続ける","next":"payment"}]},"payment":{"text":"「素晴らしい腕前だ。お前のおかげで、今夜の売り上げは最高を記録した」","type":"text","bg_key":"bg_mar_auction","speaker_name":"闇市の元締め","speaker":"闇市の元締め","next":"payment_02","choices":[{"label":"続ける","next":"payment_02"}]},"payment_02":{"text":"「これは約束の取り分だ。口の堅いお前には、また大仕事を回してやろう」","type":"text","bg_key":"bg_mar_auction","speaker_name":"闇市の元締め","speaker":"闇市の元締め","next":"exit_slums","choices":[{"label":"続ける","next":"exit_slums"}]},"exit_slums":{"text":"再び案内人に目隠しをされ、地上へ戻される。外された瞳が夜の星を仰いだ。","type":"text","bg_key":"bg_slums","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"ずっしりと重い金袋を受け取る。この汚れた金が、また次の悲劇を生むのだ。","type":"end","result":"success","bg_key":"bg_slums","params":{"rewards":{"gold":500,"alignment_shift":{"chaos":10,"evil":5},"exp":120,"reputation":-5}},"choices":[]},"end_failure":{"text":"暗殺者の正確無比な刃の前に倒れる。会場が蹂躙されていくのを眺めながら。","type":"end","result":"failure","bg_key":"bg_slums","choices":[]}},"short_description":"[防衛] 違法国宝が取引される闇の競売場で、乱入者を排除する。"}'::jsonb,
    1,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7025: 敵対軍閥への賄賂裏工作 (qst_mar_bribe)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7025,
    'qst_mar_bribe',
    '敵対軍閥への賄賂裏工作',
    '[裏工作] 工作資金と宝石を、密かに敵対軍閥の将校へ手渡してこい。',
    '軍閥の密使',
    2,
    5,
    6,
    '{"gold":350,"items":[],"alignment_shift":{"chaos":10},"exp":100,"reputation":-5}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_marcund']::text[],
    '{"location_tags":["loc_marcund"]}'::jsonb,
    '{"nodes":{"start":{"text":"マルカンドの荒廃した裏通り。強い砂風の中、周囲を警戒しながら待ち合わせの陰に立つ。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_tense","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"顔を隠した男が影から現れ、ずっしりと重い皮袋と封印された革の封筒を差し出した。","type":"text","bg_key":"bg_slums","next":"intro_1","choices":[{"label":"続ける","next":"intro_1"}]},"intro_1":{"text":"「この革袋を、北のオアシスに駐屯する『隻眼のハルム』将校に届けろ」","type":"text","bg_key":"bg_slums","speaker_name":"軍閥の密使","speaker":"軍閥の密使","next":"intro_1_detail","choices":[{"label":"続ける","next":"intro_1_detail"}]},"intro_1_detail":{"text":"「合言葉は『流砂の果て』。必ず彼本人にのみ手渡すのだ」","type":"text","bg_key":"bg_slums","speaker_name":"軍閥の密使","speaker":"軍閥の密使","next":"intro_2","choices":[{"label":"続ける","next":"intro_2"}]},"intro_2":{"text":"「怪しまれれば即座に殺される。荷の底に隠し、行商人に変装して行け」","type":"text","bg_key":"bg_slums","speaker_name":"軍閥の密使","speaker":"軍閥の密使","next":"intro_2_warn","choices":[{"label":"続ける","next":"intro_2_warn"}]},"intro_2_warn":{"text":"「警告しておくが、中身は決して見るな。死にたくなければな」","type":"text","bg_key":"bg_slums","speaker_name":"軍閥の密使","speaker":"軍閥の密使","next":"accept_think","choices":[{"label":"続ける","next":"accept_think"}]},"accept_think":{"text":"関われば命はない裏工作だ。だが、引き受けた以上、もう後戻りはできない。","type":"text","bg_key":"bg_slums","next":"disguise","choices":[{"label":"続ける","next":"disguise"}]},"disguise":{"text":"用意された薄汚れた行商人の衣装に着替える。荷の底に小袋を隠し、香辛料をまぶした。","type":"text","bg_key":"bg_slums","next":"travel_desert","choices":[{"label":"続ける","next":"travel_desert"}]},"travel_desert":{"text":"北のオアシスへ向けて砂漠を進む。炎天下の強烈な熱風が、肌をジリジリと焦がした。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"travel_scenery","choices":[{"label":"続ける","next":"travel_scenery"}]},"travel_scenery":{"text":"道中、軍閥の旗印を掲げた騎馬兵とすれ違う。何食わぬ顔で会釈し、嵐が過ぎるのを待つ。","type":"text","bg_key":"bg_desert","next":"approach_camp","choices":[{"label":"続ける","next":"approach_camp"}]},"approach_camp":{"text":"三日後、オアシスの手前に敵対軍閥の野営地が見えた。厳しい見張りが巡回している。","type":"text","bg_key":"bg_mar_warlord","bgm":"bgm_quest_tense","next":"camp_desc","choices":[{"label":"続ける","next":"camp_desc"}]},"camp_desc":{"text":"正面の柵には武装した兵士が二人。裏手には、険しい岩山へ続く細い獣道がある。","type":"text","bg_key":"bg_mar_warlord","next":"choice_approach","choices":[{"label":"続ける","next":"choice_approach"}]},"choice_approach":{"text":"目の前の野営地へ、どうやって接近する？ 選択が運命を左右する。","type":"choice","bg_key":"bg_mar_warlord","choices":[{"label":"正面から堂々と近づく","next":"front_approach"},{"label":"迂回路で潜入する","next":"sneak_route"}]},"front_approach":{"text":"行商人の卑屈な笑みを浮かべ、正面から野営地へと歩み出た。背中に冷たい汗が流れる。","type":"text","bg_key":"bg_mar_warlord","next":"front_check","choices":[{"label":"続ける","next":"front_check"}]},"front_check":{"text":"「止まれ、行商人。不審な荷だ、改めさせてもらうぞ」","type":"text","bg_key":"bg_mar_warlord","speaker_name":"見張り兵","speaker":"見張り兵","next":"front_check_think","choices":[{"label":"続ける","next":"front_check_think"}]},"front_check_think":{"text":"荷物を手荒にこじ開けられる。このままでは革袋が見つかる。戦うしかない！","type":"text","bg_key":"bg_mar_warlord","next":"battle_militia","choices":[{"label":"続ける","next":"battle_militia"}]},"battle_militia":{"text":"正体を見破った軍閥の見張り兵たちが、武器を抜いて襲いかかってきた！","type":"battle","bg_key":"bg_mar_warlord","bgm":"bgm_battle","enemy_group_id":"429","enemy_name":"軍閥の見張り兵","choices":[{"label":"win","next":"forced_entry"},{"label":"lose","next":"end_failure"}],"battle_success_next":"forced_entry"},"forced_entry":{"text":"見張りを倒した。騒ぎを聞きつけた他の兵が集まる前に、奥の天幕へ急ぐ。","type":"text","bg_key":"bg_mar_warlord","bgm":"bgm_quest_tense","next":"forced_entry_desc","choices":[{"label":"続ける","next":"forced_entry_desc"}]},"forced_entry_desc":{"text":"「曲者だ！ 捕らえろ！」野営地の中に怒号が飛び交い、兵士たちが走り出す。","type":"text","bg_key":"bg_mar_warlord","next":"find_officer_front","choices":[{"label":"続ける","next":"find_officer_front"}]},"find_officer_front":{"text":"一番大きな天幕へ突入する。中には、隻眼の男が驚きの表情で立っていた。","type":"text","bg_key":"bg_camp","next":"deliver_front","choices":[{"label":"続ける","next":"deliver_front"}]},"deliver_front":{"text":"「『流砂の果て』——」合言葉を囁き、血のついた革袋を男の手へ押しつける。","type":"text","bg_key":"bg_camp","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"sneak_route":{"text":"岩肌に身を隠し、這うようにして裏の獣道を進む。小石一つ落とせない緊張感だ。","type":"text","bg_key":"bg_mar_warlord","next":"sneak_desc","choices":[{"label":"続ける","next":"sneak_desc"}]},"sneak_desc":{"text":"見張りの視線の死角を突き、天幕の裏手へと潜り込む。兵士たちは食事中だった。","type":"text","bg_key":"bg_mar_warlord","next":"sneak_close","choices":[{"label":"続ける","next":"sneak_close"}]},"sneak_close":{"text":"旗印が掲げられた将校の天幕を発見した。裏の隙間から中を慎重に覗き込む。","type":"text","bg_key":"bg_mar_warlord","next":"find_officer_sneak","choices":[{"label":"続ける","next":"find_officer_sneak"}]},"find_officer_sneak":{"text":"音もなく天幕の中へ滑り込む。驚く隻眼の将校に、小声で合言葉を告げた。","type":"text","bg_key":"bg_camp","next":"deliver_sneak","choices":[{"label":"続ける","next":"deliver_sneak"}]},"deliver_sneak":{"text":"「『流砂の果て』——」革袋を差し出すと、彼は素早くそれを懐に隠した。","type":"text","bg_key":"bg_camp","next":"officer_reply","choices":[{"label":"続ける","next":"officer_reply"}]},"officer_reply":{"text":"「確かに受け取った。帰りは東の谷を抜けろ。そちらの方が安全だ」","type":"text","bg_key":"bg_camp","speaker_name":"ハルム将校","speaker":"ハルム将校","next":"report","choices":[{"label":"続ける","next":"report"}]},"report":{"text":"無事にマルカンドへ戻り、裏通りに待つ密使に工作の成功を報告した。","type":"text","bg_key":"bg_guild","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"密使から報酬を受け取る。この汚れた金が、新たな戦争を引き起こすのだろう。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":350,"alignment_shift":{"chaos":10},"exp":100,"reputation":-5}},"choices":[]},"end_failure":{"text":"周囲を兵士に完全に包囲され、捕縛された。スパイとして地下牢へ幽閉される。","type":"end","result":"failure","bg_key":"bg_desert","choices":[]}},"short_description":"[裏工作] 工作資金と宝石を、密かに敵対軍閥の将校へ手渡してこい。"}'::jsonb,
    6,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7030: 古道にはびこる妖討伐 (qst_yat_yokai)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7030,
    'qst_yat_yokai',
    '古道にはびこる妖討伐',
    '[討伐] 夜の街道筋に現れる怪異（からかさ小僧や赤鬼）を退治する。',
    '自警団',
    2,
    6,
    3,
    '{"gold":300,"items":[],"exp":100,"alignment_shift":{"justice":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_yatoshin']::text[],
    '{"location_tags":["loc_yatoshin"]}'::jsonb,
    '{"nodes":{"start":{"text":"自警団の詰め所。薄暗い部屋で、ひげ面の団長が苦渋に満ちた表情で語り出す。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"start_desc","choices":[{"label":"続ける","next":"start_desc"}]},"start_desc":{"text":"「ここ数日、夜の古道を越えようとした旅人が、立て続けに神隠しに遭っている」","type":"text","bg_key":"bg_yato_city","speaker_name":"自警団の男","speaker":"自警団の男","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「荷車ごと消えた者もいる。獣ではない、得体の知れない『妖』の仕業だ」","type":"text","bg_key":"bg_yato_city","speaker_name":"自警団の男","speaker":"自警団の男","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"男は怯えた顔で、和紙に包まれた護符の束を差し出した。指先が微かに震えている。","type":"text","bg_key":"bg_yato_city","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"朱墨で呪文が書かれた護符だ。触れるだけで、指先にツンとした冷たい痺れが走る。","type":"text","bg_key":"bg_yato_city","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"「月の出ぬ夜、この護符を持って古道を歩き、奴らを誘い出す囮になってくれ」","type":"text","bg_key":"bg_yato_city","speaker_name":"自警団の男","speaker":"自警団の男","next":"prep_01","choices":[{"label":"続ける","next":"prep_01"}]},"prep_01":{"text":"護符を懐に隠し、夕暮れ前に町を出た。古道へと続く山坂は異様なほど静まり返る。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_field","next":"prep_02","choices":[{"label":"続ける","next":"prep_02"}]},"prep_02":{"text":"陽が落ちると共に木々の影が長く伸び、うごめく蛇のように地面を這い始めた。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_field","next":"patrol_01","choices":[{"label":"続ける","next":"patrol_01"}]},"patrol_01":{"text":"薄暗い夜刀神国の外れ。古道は、一瞬にして墨を流したような深い闇に閉ざされた。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"patrol_02","choices":[{"label":"続ける","next":"patrol_02"}]},"patrol_02":{"text":"手提げ提灯の炎が頼りなく揺れる。先ほどまで響いていた虫の音は消え去っていた。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"patrol_03","choices":[{"label":"続ける","next":"patrol_03"}]},"patrol_03":{"text":"ピタリと風が止んだ。次の瞬間、背筋を凍らせるような湿った冷気が吹き抜ける。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"patrol_04","choices":[{"label":"続ける","next":"patrol_04"}]},"patrol_04":{"text":"足元に白い霧が湧き、提灯の火が青白く変色した。懐の護符がジリジリと熱を帯びる。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"enc_01","choices":[{"label":"続ける","next":"enc_01"}]},"enc_01":{"text":"ガサリ、と行く手の竹藪が大きく揺れ動く。獣にしては位置が高すぎる気配だ。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","next":"enc_02","choices":[{"label":"続ける","next":"enc_02"}]},"enc_02":{"text":"現れたのは、古びた和傘の中央に巨大な一つ目がギョロリと瞬く、異形の妖怪だった。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","next":"enc_03","choices":[{"label":"続ける","next":"enc_03"}]},"enc_03":{"text":"ケケケッ、と人間を嘲笑う下卑た笑い声が静寂を裂く。怪異がこちらへ飛びかかった！","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"からかさ小僧と鬼火の群れが襲いかかってきた！","type":"battle","bg_key":"bg_yato_road","bgm":"bgm_battle","enemy_group_id":"430","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"唐傘の怪異を両断した。足元に転がった残骸は、黒い泥のように融けて消えていく。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"懐の護符が、一枚黒焦げになって崩れ落ちた。奴らの邪気を吸い取ってくれたのだ。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"after_03","choices":[{"label":"続ける","next":"after_03"}]},"after_03":{"text":"残る護符はまだ微光を放つ。だが、空気にまとわりつく嫌な瘴気は晴れていない。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"after_04","choices":[{"label":"続ける","next":"after_04"}]},"after_04":{"text":"それどころか、先ほどの戦いを合図に、周囲の闇が一層濃くなったように感じられた。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"after_05","choices":[{"label":"続ける","next":"after_05"}]},"after_05":{"text":"引き返すなら今だ。だが、元凶を絶たねば、また悲劇が繰り返されるだけだろう。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_mystery","next":"deeper_01","choices":[{"label":"続ける","next":"deeper_01"}]},"deeper_01":{"text":"覚悟を決めて霧の奥へと進む。すると、ズシンと重い地響きのような音が響いた。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","next":"deeper_02","choices":[{"label":"続ける","next":"deeper_02"}]},"deeper_02":{"text":"足音はゆっくりとこちらに近づく。提灯を掲げ、暗闇の先を照らし出した。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","next":"deeper_03","choices":[{"label":"続ける","next":"deeper_03"}]},"deeper_03":{"text":"光の中に浮かび上がったのは、そびえ立つ巨大な赤い肉の壁。鬼の巨躯だった。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","next":"deeper_04","choices":[{"label":"続ける","next":"deeper_04"}]},"deeper_04":{"text":"頭に捻じれた二本の角。丸太のような腕には、血塗られた鉄の金棒が握られている。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","next":"deeper_05","choices":[{"label":"続ける","next":"deeper_05"}]},"deeper_05":{"text":"「ガハハハハ！ 小さな人間め！ 怯えた瞳がたまらんなァ！」","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","speaker_name":"赤鬼","speaker":"赤鬼","next":"deeper_06","choices":[{"label":"続ける","next":"deeper_06"}]},"deeper_06":{"text":"「骨の髄まで啜ってやる！ 美味そうじゃねぇか！」","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_tense","speaker_name":"赤鬼","speaker":"赤鬼","next":"deeper_wind","choices":[{"label":"続ける","next":"deeper_wind"}]},"deeper_wind":{"text":"赤鬼の叫びと共に、血生臭い暴風が顔を打ちつけた。嵐のような威圧感が襲う。","type":"text","bg_key":"bg_yato_road","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"古道の主である巨躯の赤鬼が立ち塞がる！","type":"battle","bg_key":"bg_yato_road","bgm":"bgm_battle_boss","enemy_group_id":"431","choices":[{"label":"win","next":"clear_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"clear_01"},"clear_01":{"text":"重い地響きと共に赤鬼が沈み、手放された金棒が乾いた音を立てて地面に転がった。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_calm","next":"clear_02","choices":[{"label":"続ける","next":"clear_02"}]},"clear_02":{"text":"主を失ったことで、古道を塞いでいた分厚い瘴気が、見る間に消え去っていく。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_calm","next":"clear_03","choices":[{"label":"続ける","next":"clear_03"}]},"clear_03":{"text":"鬼の骸は朝露を浴びた霧のように消え、やがてただの黒い土となって風に散った。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_calm","next":"clear_04","choices":[{"label":"続ける","next":"clear_04"}]},"clear_04":{"text":"澄んだ夜風が吹き抜け、途絶えていた虫の音が、再び山間に美しく響き始めた。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_calm","next":"clear_05","choices":[{"label":"続ける","next":"clear_05"}]},"clear_05":{"text":"懐の護符はすべて灰になっていた。役目を全うしてくれたことに静かに感謝する。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_quest_calm","next":"report_01","choices":[{"label":"続ける","next":"report_01"}]},"report_01":{"text":"夜明けに町へ戻り、自警団の詰所へ。男はこちらの姿を見て、驚愕に目を見張った。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"report_02","choices":[{"label":"続ける","next":"report_02"}]},"report_02":{"text":"「本当に赤鬼を討ち取ったのか！ これで誰もが安心してこの道を通れる」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"自警団の男","speaker":"自警団の男","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"約束の報酬を受け取る。古道に、再び人々の往来と提灯の灯が戻る日も近いだろう。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":300,"exp":100,"alignment_shift":{"justice":5}}},"choices":[]},"end_failure":{"text":"怪異どもの圧倒的な力の前に力尽きる。嗤うような不気味な声が闇に響いていた。","type":"end","result":"failure","bg_key":"bg_yato_road","choices":[]}},"short_description":"[討伐] 夜の街道筋に現れる怪異（からかさ小僧や赤鬼）を退治する。"}'::jsonb,
    3,
    1
