-- Scenario 7031: 隠密の密書傍受 (qst_yat_ninja)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7031,
    'qst_yat_ninja',
    '隠密の密書傍受',
    '[襲撃] 他国の間者を辻斬りのごとく排除し、密書を奪取して届けよ。',
    '忍び衆',
    2,
    6,
    4,
    '{"gold":550,"items":[],"exp":120,"alignment_shift":{"justice":10}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_yatoshin']::text[],
    '{"location_tags":["loc_yatoshin"]}'::jsonb,
    '{"nodes":{"start":{"text":"「夜分に失礼する。腕の立つ冒険者に、非公式な『掃除』を頼みたい」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","speaker_name":"忍び衆の使者","speaker":"忍び衆の使者","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「他国の間者が軍事機密を記した密書を携え、北の関所へ向かっている」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","speaker_name":"忍び衆の使者","speaker":"忍び衆の使者","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"顔を黒布で覆った使者は、感情の読めない冷たい瞳でこちらを見据えている。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「間者は護衛を連れている。お前の任務は、奴らを討ち密書を奪うことだ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","speaker_name":"忍び衆の使者","speaker":"忍び衆の使者","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"「……ただし中身は決して見るな。封が切られていれば命はないと思え」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","speaker_name":"忍び衆の使者","speaker":"忍び衆の使者","next":"prep_01","choices":[{"label":"続ける","next":"prep_01"}]},"prep_01":{"text":"使者は足音一つ立てずに闇へ消えた。警告は本気だろう。命がけの仕事だ。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_mystery","next":"prep_02","choices":[{"label":"続ける","next":"prep_02"}]},"prep_02":{"text":"北の関所への道は一本。先回りして伏兵となるため、獣道を急ぎ北上する。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_mystery","next":"locate_01","choices":[{"label":"続ける","next":"locate_01"}]},"locate_01":{"text":"両脇を深い林に囲まれた細い山道。太い枝の上に身を潜め、獲物を待つ。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_mystery","next":"locate_02","choices":[{"label":"続ける","next":"locate_02"}]},"locate_02":{"text":"月が雲に隠れ、足元すら見えなくなった頃、落ち葉を踏む微かな音がした。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_mystery","next":"locate_03","choices":[{"label":"続ける","next":"locate_03"}]},"locate_03":{"text":"笠を目深に被った男と、その前後を固める、歩みの異様に軽い二人の護衛。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_mystery","next":"locate_04","choices":[{"label":"続ける","next":"locate_04"}]},"locate_04":{"text":"一般の行商人には見えない隙のない陣形。間違いなく、奴らが標的だ。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_mystery","next":"ambush_01","choices":[{"label":"続ける","next":"ambush_01"}]},"ambush_01":{"text":"息を殺し、刀の柄に手をかける。間者がちょうど真下を通り過ぎる瞬間――","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","next":"ambush_02","choices":[{"label":"続ける","next":"ambush_02"}]},"ambush_02":{"text":"木の上から音もなく飛び降り、前衛の護衛の背後へと回り込んで刃を突き立てた。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","next":"ambush_03","choices":[{"label":"続ける","next":"ambush_03"}]},"ambush_03":{"text":"「何者だ！？ ええい、伏兵だ、出会えェッ！」","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","speaker_name":"間者の護衛","speaker":"間者の護衛","next":"ambush_04","choices":[{"label":"続ける","next":"ambush_04"}]},"ambush_04":{"text":"奇襲は防がれた。護衛たちが素早く小太刀を抜き、鋭い殺気で襲いかかる。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","next":"battle_spy","choices":[{"label":"続ける","next":"battle_spy"}]},"battle_spy":{"text":"他国の間者と抜け忍たちが立ちはだかる！","type":"battle","bg_key":"bg_yato_forest","bgm":"bgm_battle","enemy_group_id":"432","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"凄惨な殺し合いの末、護衛の一人が喉を押さえて倒れた。もう動かない。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"残された間者も、絶望の表情を浮かべたまま血だまりの中に倒れ伏している。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"after_03","choices":[{"label":"続ける","next":"after_03"}]},"after_03":{"text":"林の中に再び静寂が戻る。血の匂いが獣を呼ぶ前に、任務を完遂せねば。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"after_04","choices":[{"label":"続ける","next":"after_04"}]},"after_04":{"text":"間者の死体を探る。帯の裏に、不自然な膨らみがあるのを見つけた。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"after_05","choices":[{"label":"続ける","next":"after_05"}]},"after_05":{"text":"布を切り裂くと、厳重に封印された黒い巻物が転がり出た。これが密書だ。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"take_01","choices":[{"label":"続ける","next":"take_01"}]},"take_01":{"text":"封印には見慣れぬ紋様。中を見れば命はないという警告が脳裏をよぎる。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"take_02","choices":[{"label":"続ける","next":"take_02"}]},"take_02":{"text":"好奇心を押し殺し、密書を丁寧に布に包んで懐にしまった。急ぎ撤退する。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"take_document","choices":[{"label":"続ける","next":"take_document"}]},"take_document":{"text":"「封をされた密書」を手に入れた！","type":"reward","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","params":{"item_id":"item_secret_document"},"next":"choice_destination","choices":[{"label":"続ける","next":"choice_destination"}]},"choice_destination":{"text":"手に入れた密書をどう扱うべきか？","type":"choice","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","choices":[{"label":"「約束通り、連絡員のいる裏路地の酒場へ向かう」","next":"return_01"},{"label":"「代官所に通報し、密書を役人に引き渡す」","next":"report_authorities_01"}]},"report_authorities_01":{"text":"忍び衆の不穏な動きを懸念し、都の代官所へ赴き、密書を差し出してすべてを告発した。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"report_authorities_02","choices":[{"label":"続ける","next":"report_authorities_02"}]},"report_authorities_02":{"text":"役人たちは驚愕し、密書を直ちに没収した。そして、この件は一切口外するなと厳命された。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"end_authorities","choices":[{"label":"続ける","next":"end_authorities"}]},"end_authorities":{"text":"代官所を後にする。密書は失ったが、国に潜む影の存在を公にできた。しかし、背後から刺客の視線を感じる……。","type":"end","result":"failure","bg_key":"bg_yato_city","params":{"rewards":{"gold":0,"exp":120,"reputation":10,"alignment_shift":{"justice":15}}},"choices":[]},"return_01":{"text":"夜が明ける前に町へ戻り、指定された裏路地の寂れた酒場へと足を運ぶ。","type":"text","bg_key":"bg_yato_tavern_night","bgm":"bgm_quest_calm","next":"return_02","choices":[{"label":"続ける","next":"return_02"}]},"return_02":{"text":"客のいない薄暗い店内。奥の席で笠を被った男が、静かにこちらを待っていた。","type":"text","bg_key":"bg_yato_tavern_night","bgm":"bgm_quest_calm","next":"return_03","choices":[{"label":"続ける","next":"return_03"}]},"return_03":{"text":"「……ご苦労だった。獲物は仕留めたな。密書を渡してもらおうか」","type":"text","bg_key":"bg_yato_tavern_night","bgm":"bgm_quest_calm","speaker_name":"忍び衆の連絡員","speaker":"忍び衆の連絡員","next":"deliver_document","choices":[{"label":"続ける","next":"deliver_document"}]},"deliver_document":{"text":"黙って懐から密書を取り出し、男の前に置く。彼は封印の無事を確認した。","type":"check_delivery","bg_key":"bg_yato_tavern_night","bgm":"bgm_quest_calm","params":{"item_id":"item_secret_document","quantity":1},"choices":[{"label":"success","next":"deliver_check_ok"},{"label":"failure","next":"deliver_check_fail"}]},"deliver_check_ok":{"text":"「封印は無事か……。よろしい。約束の報酬だ。我らは会わなかった、良いな？」","type":"text","bg_key":"bg_yato_tavern_night","speaker_name":"忍び衆の連絡員","speaker":"忍び衆の連絡員","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"重い金袋を受け取る。彼らが何を企んでいるのか、自分には関係のないことだ。","type":"end","result":"success","bg_key":"bg_yato_tavern_night","params":{"rewards":{"gold":550,"exp":120,"alignment_shift":{"justice":10}}},"choices":[]},"deliver_check_fail":{"text":"「……密書がないだと？ 封を切ったか？ 貴様、我らを愚弄するか！」","type":"text","bg_key":"bg_yato_tavern_night","speaker_name":"忍び衆の連絡員","speaker":"忍び衆の連絡員","next":"end_failure_lost_end","choices":[{"label":"続ける","next":"end_failure_lost_end"}]},"end_failure_lost_end":{"text":"男の目が細まり、複数の殺気が膨れ上がる。ここで生かしてはおかれない。","type":"end","result":"failure","bg_key":"bg_yato_tavern_night","params":{"rewards":{"gold":0}},"choices":[]},"end_failure":{"text":"抜け忍たちの暗器に翻弄され、冷たい刃を胸に受ける。意識は闇に沈んでいった。","type":"end","result":"failure","bg_key":"bg_yato_forest","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[襲撃] 他国の間者を辻斬りのごとく排除し、密書を奪取して届けよ。"}'::jsonb,
    4,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7032: 結界石の修復と奉納 (qst_yat_shrine)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7032,
    'qst_yat_shrine',
    '結界石の修復と奉納',
    '[修復] 神隠しを防ぐため、破られた結界石の破片を集めて祠に納める。',
    '神社',
    2,
    6,
    5,
    '{"gold":400,"items":[],"exp":120,"alignment_shift":{"justice":10}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_yatoshin']::text[],
    '{"location_tags":["loc_yatoshin"]}'::jsonb,
    '{"nodes":{"start":{"text":"「おお、冒険者殿。よくぞ来てくださった。事態は一刻を争うのです」","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","speaker_name":"神主","speaker":"神主","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"老いた神主は、顔を真っ青にしながら、背後にそびえる霊山の山頂を指さした。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「山頂の祠に祀られていた『結界石』が、何者かによって打ち砕かれてしまったのです」","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","speaker_name":"神主","speaker":"神主","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「破片は山中にあるはず。あれがないと、この町に妖が雪崩れ込んでしまう……！」","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","speaker_name":"神主","speaker":"神主","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"「どうか、散逸した三つの破片を集め、再び祠に奉納してくだされ。頼みましたぞ」","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","speaker_name":"神主","speaker":"神主","next":"mountain_01","choices":[{"label":"続ける","next":"mountain_01"}]},"mountain_01":{"text":"依頼を受け、鬱蒼とした霊山へと足を踏み入れた。昼間だというのに、薄暗い霧が立ち込めている。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"mountain_01_02","choices":[{"label":"続ける","next":"mountain_01_02"}]},"mountain_01_02":{"text":"かつては清浄だった参道も、今は邪気によって枯れ葉が腐臭を放っている。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"mountain_01_03","choices":[{"label":"続ける","next":"mountain_01_03"}]},"mountain_01_03":{"text":"木々の隙間から、絶えず奇妙な視線を感じる。しかし振り返っても霧があるだけだ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"mountain_02","choices":[{"label":"続ける","next":"mountain_02"}]},"mountain_02":{"text":"山全体が不気味な静寂に包まれていた。本来この山を守るはずの清浄な気は、完全に失われている。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"mountain_03","choices":[{"label":"続ける","next":"mountain_03"}]},"mountain_03":{"text":"獣道を掻き分けながら、斜面を登っていく。ふと、苔むした大岩の根本に、淡く光るものを見つけた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"mountain_04","choices":[{"label":"続ける","next":"mountain_04"}]},"mountain_04":{"text":"近づいてみると、それは握り拳ほどの大きさの、半透明な石の欠片だった。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"collect_shard_01","choices":[{"label":"続ける","next":"collect_shard_01"}]},"collect_shard_01":{"text":"一つ目の破片を拾い上げた。石は氷のように冷たいが、微かに神聖な脈動を感じる。","type":"random_branch","bg_key":"bg_yato_mountain","bgm":"bgm_field","prob":50,"choices":[{"label":"success","next":"yokai_01"},{"label":"failure","next":"search_02"}]},"yokai_01":{"text":"その時、木々の隙間からヒュードロドロという気味の悪い音が鳴り響いた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"yokai_02","choices":[{"label":"続ける","next":"yokai_02"}]},"yokai_02":{"text":"青白い鬼火が舞い、その奥から奇妙な妖怪たちが姿を現す。結界が破れた影響か！","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"battle_yokai_01","choices":[{"label":"続ける","next":"battle_yokai_01"}]},"battle_yokai_01":{"text":"山に巣食う妖怪の群れが襲いかかってきた！","type":"battle","bg_key":"bg_yato_mountain","bgm":"bgm_battle","enemy_group_id":"430","choices":[{"label":"win","next":"after_battle_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"after_battle_01"},"after_battle_01":{"text":"妖怪たちを斬り伏せると、奴らは霧となって四散した。油断はできない、先を急ごう。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"search_02","choices":[{"label":"続ける","next":"search_02"}]},"search_02":{"text":"さらに険しい山道を登っていく。霧が次第に濃くなり、視界が数歩先までしか効かなくなってきた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"search_02_02","choices":[{"label":"続ける","next":"search_02_02"}]},"search_02_02":{"text":"急斜面を登るにつれ、足元が崩れやすくなってきた。這うようにして崖をよじ登る。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"search_02_03","choices":[{"label":"続ける","next":"search_02_03"}]},"search_02_03":{"text":"胸を圧迫するような重苦しい気が満ちていく。結界の破綻が山を狂わせているのだ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"search_03","choices":[{"label":"続ける","next":"search_03"}]},"search_03":{"text":"ぬかるんだ枯れ沢の跡に出た。そこは山津波で崩れた形跡があり、歩を進めるのも困難だ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"search_04","choices":[{"label":"続ける","next":"search_04"}]},"search_04":{"text":"泥の中に、二つ目の淡い光を見つけた。泥にまみれているが、間違いなく結界石の破片だ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"collect_shard_02","choices":[{"label":"続ける","next":"collect_shard_02"}]},"collect_shard_02":{"text":"布で汚れを拭い取ると、破片は再び清らかな光を取り戻した。これで二つ目だ。","type":"random_branch","bg_key":"bg_yato_mountain","bgm":"bgm_field","prob":50,"choices":[{"label":"success","next":"boss_01"},{"label":"failure","next":"search_05"}]},"boss_01":{"text":"直後、ズンッと地面が揺れた。背後から生暖かい、ひどく血生臭い息が吹き付けられる。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"boss_02","choices":[{"label":"続ける","next":"boss_02"}]},"boss_02":{"text":"「石を集めて何をする……？ まさか、俺を封じようってんじゃねぇだろうなァ！」","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","speaker_name":"赤鬼","speaker":"赤鬼","next":"battle_yokai_02","choices":[{"label":"続ける","next":"battle_yokai_02"}]},"battle_yokai_02":{"text":"霧の中から巨大な赤鬼が立ち塞がった！","type":"battle","bg_key":"bg_yato_mountain","bgm":"bgm_battle_boss","enemy_group_id":"431","choices":[{"label":"win","next":"after_battle_02"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"after_battle_02"},"after_battle_02":{"text":"赤鬼が轟音と共に倒れた。この巨怪ですら、結界がなければ山に居座ってしまうということか。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"search_05","choices":[{"label":"続ける","next":"search_05"}]},"search_05":{"text":"気を取り直し、山頂を目指す。木々がまばらになり、冷たい強風が吹きつけるようになってきた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"search_06","choices":[{"label":"続ける","next":"search_06"}]},"search_06":{"text":"やがて、山頂の開けた場所に出た。そこには、無残に破壊された古い石の祠があった。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"search_06_02","choices":[{"label":"続ける","next":"search_06_02"}]},"search_06_02":{"text":"祠の周囲には、獣のものとも違う、黒い爪痕のような傷が深く刻まれていた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"search_06_03","choices":[{"label":"続ける","next":"search_06_03"}]},"search_06_03":{"text":"破壊された石塔の破片が散らばり、かつての神聖な面影は無残に失われている。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"search_07","choices":[{"label":"続ける","next":"search_07"}]},"search_07":{"text":"祠の台座の横に、最後の破片が転がっている。欠けた部分を合わせれば、元の形になりそうだ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"collect_shard_03","choices":[{"label":"続ける","next":"collect_shard_03"}]},"collect_shard_03":{"text":"最後の破片を拾い上げる。三つの破片が揃うと、互いに共鳴するように暖かな光を放ち始めた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"shrine_01","choices":[{"label":"続ける","next":"shrine_01"}]},"shrine_01":{"text":"破片を抱え、急いで山を駆け下りる。背後で、山そのものが安堵の吐息を漏らしたような気がした。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"shrine_02","choices":[{"label":"続ける","next":"shrine_02"}]},"shrine_02":{"text":"町に降りると、神社の鳥居の前に神主が立っていた。焦燥に駆られた様子でこちらを待っている。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"shrine_03","choices":[{"label":"続ける","next":"shrine_03"}]},"shrine_03":{"text":"「おお、戻られましたか！ その懐の光は、間違いなく結界石……！」","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","speaker_name":"神主","speaker":"神主","next":"return_shrine","choices":[{"label":"続ける","next":"return_shrine"}]},"return_shrine":{"text":"神主に三つの破片を手渡す。老人は震える手で石を受け取り、祭壇へと向かった。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"enshrine_01","choices":[{"label":"続ける","next":"enshrine_01"}]},"enshrine_01":{"text":"古き祝詞が朗々と響き渡る。すると、三つの破片はまばゆい光に包まれ、一つに融合し始めた。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"enshrine_02","choices":[{"label":"続ける","next":"enshrine_02"}]},"enshrine_02":{"text":"完全な球体に戻った結界石が台座に鎮座すると、町を覆っていた重い空気が、ふっと軽くなった。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"enshrine_02_02","choices":[{"label":"続ける","next":"enshrine_02_02"}]},"enshrine_02_02":{"text":"神主は深く息を吐き、祭壇に向かって静かに頭を下げた。山のざわめきが静まっていく。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"感謝の言葉と報酬を受け取り、神社を後にした。だが、結界が破られた原因は謎のままだ。","type":"text","bg_key":"bg_yato_shrine","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「これで、しばらくは神隠しも収まるでしょう。本当に、ありがとうございました」","type":"end","result":"success","bg_key":"bg_yato_shrine","speaker_name":"神主","speaker":"神主","params":{"rewards":{"gold":400,"exp":120,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure_01":{"text":"山の怪異たちの圧倒的な力の前に、傷つき、ついに力尽きて倒れた。","type":"text","bg_key":"bg_yato_mountain","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"意識が薄れる中、誰かが石の破片を拾い上げ、嘲笑う声が聞こえた気がした……。","type":"end","result":"failure","bg_key":"bg_yato_mountain","choices":[]}},"short_description":"[修復] 神隠しを防ぐため、破られた結界石の破片を集めて祠に納める。"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7033: 食い詰めた浪人狩り (qst_yat_ronin)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7033,
    'qst_yat_ronin',
    '食い詰めた浪人狩り',
    '[討伐] 賭場の手入れ。悪事に手を染めた浪人集団を一網打尽にする。',
    '代官所',
    2,
    6,
    2,
    '{"gold":350,"items":[],"exp":100,"alignment_shift":{"justice":10}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_yatoshin']::text[],
    '{"location_tags":["loc_yatoshin"]}'::jsonb,
    '{"nodes":{"start":{"text":"代官所から、封が切られたままの依頼書を受け取った。非公式の裏仕事だ。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"依頼の内容は、繁華街の裏にある賭場に巣食う浪人集団の「掃除」だった。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"彼らは主君を失って食い詰め、今では善良な町人からみかじめ料を脅し取っているらしい。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"代官所の役人が表立って動けば、彼らはクモの子を散らすように逃げてしまう。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"ゆえに、しがらみのない冒険者が単身で乗り込み、一網打尽にする必要があるというわけだ。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"alley_01","choices":[{"label":"続ける","next":"alley_01"}]},"alley_01":{"text":"夜の繁華街は、提灯の明かりと人々の喧騒で溢れかえっている。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_mystery","next":"alley_01_02","choices":[{"label":"続ける","next":"alley_01_02"}]},"alley_01_02":{"text":"夜刀神国の繁栄の裏で、行き場を失った浪人が増え続けている。これも時代の歪みだ。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_mystery","next":"alley_01_03","choices":[{"label":"続ける","next":"alley_01_03"}]},"alley_01_03":{"text":"懐に入れた代官所の書状が微かに重い。汚い仕事だが、背に腹は代えられない。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_mystery","next":"alley_02","choices":[{"label":"続ける","next":"alley_02"}]},"alley_02":{"text":"しかし、大通りから一本外れた路地裏に入ると、途端にむせ返るような生ごみの臭いが漂ってきた。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_mystery","next":"alley_03","choices":[{"label":"続ける","next":"alley_03"}]},"alley_03":{"text":"泥酔して道端に転がる男たちを跨ぎながら、目的の長屋へと向かう。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_mystery","next":"alley_04","choices":[{"label":"続ける","next":"alley_04"}]},"alley_04":{"text":"障子越しに、サイコロの転がる音と、下品な罵声が聞こえてくる。ここが目的の賭場だ。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"enter_gambling_den","choices":[{"label":"続ける","next":"enter_gambling_den"}]},"enter_gambling_den":{"text":"遠慮はいらない。勢いよく蹴破るようにして、賭場の引き戸を開け放った。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"enter_gambling_den_02","choices":[{"label":"続ける","next":"enter_gambling_den_02"}]},"enter_gambling_den_02":{"text":"充満する安酒と煙草の煙。卓を囲む者たちの血走った目が、一斉にこちらを向く。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"enter_gambling_den_03","choices":[{"label":"続ける","next":"enter_gambling_den_03"}]},"enter_gambling_den_03":{"text":"誰もが懐の刀に手をかけている。一瞬の静寂の後、誰かが唾を吐く音が響いた。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"confront_01","choices":[{"label":"続ける","next":"confront_01"}]},"confront_01":{"text":"ピタリ、と場内の動きが止まる。酒と汗の臭いが充満する部屋に、数十人の浪人がひしめいていた。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"confront_02","choices":[{"label":"続ける","next":"confront_02"}]},"confront_02":{"text":"「……なんだテメェ。ここは堅気が来る場所じゃねぇ。命が惜しくば失せな」","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","speaker_name":"浪人","speaker":"浪人","next":"confront_leader_01","choices":[{"label":"続ける","next":"confront_leader_01"}]},"confront_leader_01":{"text":"奥の座敷で杯を傾けていた大柄な浪人が、忌々しげにゆっくりと立ち上がった。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"confront_leader","choices":[{"label":"続ける","next":"confront_leader"}]},"confront_leader":{"text":"「代官所の犬か。血の匂いがプンプンしやがる」","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","speaker_name":"浪人の頭目","speaker":"浪人の頭目","next":"confront_leader_2","choices":[{"label":"続ける","next":"confront_leader_2"}]},"confront_leader_2":{"text":"「野郎ども、やっちまえ！ こいつの首を手土産に逃げるぞ！」","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","speaker_name":"浪人の頭目","speaker":"浪人の頭目","next":"confront_leader_3","choices":[{"label":"続ける","next":"confront_leader_3"}]},"confront_leader_3":{"text":"頭目の合図と共に、殺気立った浪人たちが一斉に抜刀し、こちらへ襲いかかる！","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"battle_ronin_wave_01","choices":[{"label":"続ける","next":"battle_ronin_wave_01"}]},"battle_ronin_wave_01":{"text":"食い詰め浪人たちが群がってきた！","type":"battle","bg_key":"bg_yato_den","bgm":"bgm_battle","enemy_group_id":"433","choices":[{"label":"win","next":"leader_fight_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"leader_fight_01"},"leader_fight_01":{"text":"血飛沫が舞い、障子が破れる。数人の浪人を切り伏せると、残りの者は恐れをなして後退した。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"leader_fight_01_02","choices":[{"label":"続ける","next":"leader_fight_01_02"}]},"leader_fight_01_02":{"text":"息を荒くしながらも、刀の刃こぼれがないかを確認する。敵の数はこちらが圧倒的に不利だ。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"leader_fight_01_03","choices":[{"label":"続ける","next":"leader_fight_01_03"}]},"leader_fight_01_03":{"text":"だが、烏合の衆。統率の取れていない動きは隙だらけで、斬るのに苦労はしない。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"leader_fight_02","choices":[{"label":"続ける","next":"leader_fight_02"}]},"leader_fight_02":{"text":"床には折れた刀と、呻き声を上げる浪人たちが転がっている。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"leader_fight_03","choices":[{"label":"続ける","next":"leader_fight_03"}]},"leader_fight_03":{"text":"「チッ、使えねぇ雑兵どもめ。……だが、俺を只のならず者と思うなよ」","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","speaker_name":"浪人の頭目","speaker":"浪人の頭目","next":"leader_fight_04","choices":[{"label":"続ける","next":"leader_fight_04"}]},"leader_fight_04":{"text":"頭目が懐から取り出したのは、夜刀神国の正規軍が使う名刀だった。奪ったものだろう。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"leader_fight","choices":[{"label":"続ける","next":"leader_fight"}]},"leader_fight":{"text":"「少しは骨があるようだが、所詮は素人よ。この俺の太刀筋、とくと味わえ！」","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","speaker_name":"浪人の頭目","speaker":"浪人の頭目","next":"leader_fight_2","choices":[{"label":"続ける","next":"leader_fight_2"}]},"leader_fight_2":{"text":"歴戦の殺気を放ちながら、頭目が自ら太刀を青眼に構えた。空気がビリビリと震える。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"leader_fight_2_02","choices":[{"label":"続ける","next":"leader_fight_2_02"}]},"leader_fight_2_02":{"text":"頭目の構えに隙はない。かつては名の知れた剣術の道場に身を置いていたのだろう。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"leader_fight_2_03","choices":[{"label":"続ける","next":"leader_fight_2_03"}]},"leader_fight_2_03":{"text":"無駄な動きを削ぎ落とした静かな佇まい。これまでの有象無象とは明らかに違う。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"battle_ronin_leader","choices":[{"label":"続ける","next":"battle_ronin_leader"}]},"battle_ronin_leader":{"text":"浪人の頭目との戦い！","type":"battle","bg_key":"bg_yato_den","bgm":"bgm_battle_boss","enemy_group_id":"434","choices":[{"label":"win","next":"scatter_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"scatter_01"},"scatter_01":{"text":"激しい鍔迫り合いの末、頭目の刀が宙を舞い、その巨体がどうと床に倒れ伏した。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_calm","next":"scatter_02","choices":[{"label":"続ける","next":"scatter_02"}]},"scatter_02":{"text":"頭目が血を吐いて動かなくなると、残っていた浪人たちの顔に絶望の色が浮かんだ。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_calm","next":"scatter_03","choices":[{"label":"続ける","next":"scatter_03"}]},"scatter_03":{"text":"「ひ、ひぃぃっ！ 命だけは！ 命だけはお助けを！」","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_calm","speaker_name":"浪人","speaker":"浪人","next":"scatter_04","choices":[{"label":"続ける","next":"scatter_04"}]},"scatter_04":{"text":"武器を放り出し、彼らは我先にと裏口から逃げ出していく。完全に戦意を喪失している。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_calm","next":"scatter","choices":[{"label":"続ける","next":"scatter"}]},"scatter":{"text":"深追いはしない。これでこの賭場は終わりだ。血振りをして、静かに刀を鞘に収めた。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_calm","next":"report_01","choices":[{"label":"続ける","next":"report_01"}]},"report_01":{"text":"翌朝、代官所の裏門から入り、役人に事の顛末を報告する。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"report_02","choices":[{"label":"続ける","next":"report_02"}]},"report_02":{"text":"役人は満足げに頷き、重みのある金袋を机の上に滑らせた。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"report_02_02","choices":[{"label":"続ける","next":"report_02_02"}]},"report_02_02":{"text":"「中身は確かだ。余計な口さえ叩かなければ、お前には今後も仕事を回してやろう」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"代官所の役人","speaker":"代官所の役人","next":"report_03","choices":[{"label":"続ける","next":"report_03"}]},"report_03":{"text":"「よくやってくれた。これで少しは町も静かになるだろう。また頼むかもしれんぞ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"代官所の役人","speaker":"代官所の役人","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"金袋を受け取り、代官所を後にする。\n裏社会の掃除は気が滅入るが、日銭を稼ぐには悪くない仕事だった。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":350,"exp":100,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure_01":{"text":"多勢に無勢。浪人たちの容赦ない凶刃が、次々とあなたの身体を深く切り裂く。","type":"text","bg_key":"bg_yato_den","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"血の海に倒れ伏す中、頭目の見下すような冷たい視線が、意識の暗闇へと消えていった。","type":"end","result":"failure","bg_key":"bg_yato_den","choices":[]}},"short_description":"[討伐] 賭場の手入れ。悪事に手を染めた浪人集団を一網打尽にする。"}'::jsonb,
    2,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
