-- Scenario 7034: 御前試合の果たし状配達 (qst_yat_shogun)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7034,
    'qst_yat_shogun',
    '御前試合の果たし状配達',
    '[配達] 不吉な血判状を、隣地の剣客道場まで無傷で送り届ける。',
    '剣客道場',
    2,
    6,
    1,
    '{"gold":400,"items":[],"exp":120}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_yatoshin']::text[],
    '{"location_tags":["loc_yatoshin"]}'::jsonb,
    '{"nodes":{"start":{"text":"「腕の立つ冒険者に頼みがある。これを隣の宿場町にある道場へ届けてくれ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"剣客道場の師範","speaker":"剣客道場の師範","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"道場の師範から、重厚な巻紙を手渡された。朱墨で禍々しい血判が押されている。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「これは果たし状だ。武士の面子がかかった、決して遅れを取れぬ代物だ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"剣客道場の師範","speaker":"剣客道場の師範","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「だが情けないことに我が門下生は、途中の峠道で怯え、逃げ帰ってしまった」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"剣客道場の師範","speaker":"剣客道場の師範","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"「峠には何かが出るという噂だが……お前なら問題なかろう。無事に届けてくれ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"剣客道場の師範","speaker":"剣客道場の師範","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"果たし状を懐の奥にしっかりと収め、隣町へと続く寂れた峠道へと向かった。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"空はどんよりと曇り、山間には薄い靄がかかっている。前の使者が二人も逃げ帰ってきた道だ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"travel_02_02","choices":[{"label":"続ける","next":"travel_02_02"}]},"travel_02_02":{"text":"かつてここで戦い死んだ者の怨念が、霧となって峠を覆っているのだろうか。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"travel_02_03","choices":[{"label":"続ける","next":"travel_02_03"}]},"travel_02_03":{"text":"一歩進むたびに、冷たい空気が肌を刺す。果たし状の怨念が共鳴しているようだ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"travel_03","choices":[{"label":"続ける","next":"travel_03"}]},"travel_03":{"text":"気を引き締めて、落ち葉で滑りやすい薄暗い山道へと足を踏み入れた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"travel_04","choices":[{"label":"続ける","next":"travel_04"}]},"travel_04":{"text":"木々の擦れる音しか聞こえない。時折、視界の端を妙な影が横切るような気がする。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"travel_pass","choices":[{"label":"続ける","next":"travel_pass"}]},"travel_pass":{"text":"峠の頂上、最も見晴らしの悪い中間地点に差し掛かった。風がピタリと止む。","type":"random_branch","bg_key":"bg_yato_mountain","bgm":"bgm_field","prob":60,"choices":[{"label":"success","next":"confronted_01"},{"label":"failure","next":"safe_01"}]},"safe_01":{"text":"背筋が寒くなるような気配を感じたが、やがてその気配はスッと消え去った。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"safe_02","choices":[{"label":"続ける","next":"safe_02"}]},"safe_02":{"text":"噂はただの噂だったのだろうか。それとも、単に運が良かっただけか。足早に峠を下る。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_field","next":"deliver_normal_01","choices":[{"label":"続ける","next":"deliver_normal_01"}]},"confronted_01":{"text":"風の音に混じって、どこからか「……かえれ……」という低いうめき声が聞こえた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"confronted_02","choices":[{"label":"続ける","next":"confronted_02"}]},"confronted_02":{"text":"立ち止まって前方を睨むと、狭い山道を塞ぐように、ひとつの人影が立っていた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"confronted_03","choices":[{"label":"続ける","next":"confronted_03"}]},"confronted_03":{"text":"ボロボロの着流しを着た浪人……ではない。その足元は透けており、地面から浮いている。怨霊だ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"choice_action","choices":[{"label":"続ける","next":"choice_action"}]},"choice_action":{"text":"霊は血走った目でこちらを睨みつけ、刀の柄に手をかけている。どうする？","type":"choice","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","choices":[{"label":"落ち着いて話しかける","next":"resolve_01"},{"label":"構わず強行突破する","next":"battle_01"}]},"resolve_01":{"text":"ゆっくりと両手を上げ、敵意がないことを示す。そして静かに、手紙を届けるだけだと告げた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"resolve_02_01","choices":[{"label":"続ける","next":"resolve_02_01"}]},"resolve_02_01":{"text":"霊はピタリと動きを止め、濁った瞳でこちらの懐をじっと見つめた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"resolve_02","choices":[{"label":"続ける","next":"resolve_02"}]},"resolve_02":{"text":"「……お前は、逃げないのだな」","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","speaker_name":"峠の怨霊","speaker":"峠の怨霊","next":"resolve_03","choices":[{"label":"続ける","next":"resolve_03"}]},"resolve_03":{"text":"「……あの果たし状……武士の意地か……ならば、行くが良い」","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","speaker_name":"峠の怨霊","speaker":"峠の怨霊","next":"resolve_03_01","choices":[{"label":"続ける","next":"resolve_03_01"}]},"resolve_03_01":{"text":"霊はどこか寂しげな表情を浮かべると、霧のようにスッと消え去った。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"resolve_03_02","choices":[{"label":"続ける","next":"resolve_03_02"}]},"resolve_03_02":{"text":"怨霊が消え去った場所には、ただ冷たい風が吹き抜けていくだけだった。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"resolve_03_03","choices":[{"label":"続ける","next":"resolve_03_03"}]},"resolve_03_03":{"text":"かつて果たし合いに向かい、ここで力尽きた剣士。その無念が解けたのだろうか。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"deliver_peace_01","choices":[{"label":"続ける","next":"deliver_peace_01"}]},"deliver_peace_01":{"text":"怨霊の無念を背に受けながら、無事に峠を越え、隣町の道場へと到着した。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"deliver_peace_02","choices":[{"label":"続ける","next":"deliver_peace_02"}]},"deliver_peace_02":{"text":"呼び出しに応じた師範に、果たし状を手渡す。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"deliver_peace_02_02","choices":[{"label":"続ける","next":"deliver_peace_02_02"}]},"deliver_peace_02_02":{"text":"師範は朱色の血判を確認し、深く重々しく頷いた。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"deliver_peace_03","choices":[{"label":"続ける","next":"deliver_peace_03"}]},"deliver_peace_03":{"text":"「届いたか。あの峠で何があった？ いや、聞くまい。見事な胆力だ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"宛先の師範","speaker":"宛先の師範","next":"end_success_peace_01","choices":[{"label":"続ける","next":"end_success_peace_01"}]},"end_success_peace_01":{"text":"配達完了。道場から多額の謝礼を受け取った。","type":"text","bg_key":"bg_yato_city","next":"end_success_peace","choices":[{"label":"続ける","next":"end_success_peace"}]},"end_success_peace":{"text":"あの霊は、果たし合いに向かう途中で命を落とした剣客だったのかもしれない。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":400,"exp":0,"alignment_shift":{"justice":10}}},"choices":[]},"battle_01":{"text":"言葉が通じる相手ではない。武器を構え、強行突破の姿勢を見せる。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"その瞬間、霊の顔が怒りに歪み、この世のものとは思えない悲痛な叫び声を上げた！","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"battle_spirit","choices":[{"label":"続ける","next":"battle_spirit"}]},"battle_spirit":{"text":"無念の死を遂げた怨霊が襲いかかってきた！","type":"battle","bg_key":"bg_yato_mountain","bgm":"bgm_battle","enemy_group_id":"435","choices":[{"label":"win","next":"after_fight_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"after_fight_01"},"after_fight_01":{"text":"霊の凶刃を躱し、その半透明な身体を断ち切る。霊は断末魔と共に空気へと溶けていった。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"after_fight_02","choices":[{"label":"続ける","next":"after_fight_02"}]},"after_fight_02":{"text":"嫌な冷気が晴れ、本来の山の空気が戻ってくる。厄介な障害だったが、これで進める。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"after_fight_03","choices":[{"label":"続ける","next":"after_fight_03"}]},"after_fight_03":{"text":"呼吸を整え、衣服の乱れを直すと、隣町を目指して峠を足早に駆け下りた。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_calm","next":"deliver_normal_01","choices":[{"label":"続ける","next":"deliver_normal_01"}]},"deliver_normal_01":{"text":"太陽が高く昇る頃、隣町の道場へ到着し、師範を呼び出して果たし状を手渡した。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"deliver_normal_02","choices":[{"label":"続ける","next":"deliver_normal_02"}]},"deliver_normal_02":{"text":"師範は果たし状の血判を厳しい表情で睨みつけ、ゆっくりと懐へ収めた。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"deliver_normal_03","choices":[{"label":"続ける","next":"deliver_normal_03"}]},"deliver_normal_03":{"text":"「届いたか。前任者たちは逃げ帰ったというのに……お前、肝が据わっているな」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"宛先の師範","speaker":"宛先の師範","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"配達完了。道場から約束の謝礼金を受け取った。","type":"text","bg_key":"bg_yato_city","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"峠の霊が何者だったのか——それは聞かないのが冒険者の知恵だろう。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":400,"exp":120}},"choices":[]},"end_failure_01":{"text":"怨霊の身を凍らせる呪いと圧倒的な執念の前に、なす術なく意識を刈り取られた。","type":"text","bg_key":"bg_yato_mountain","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"果たし状は、誰にも読まれることなく冷たい山道に転がったままだ……。","type":"end","result":"failure","bg_key":"bg_yato_mountain","choices":[]}},"short_description":"[配達] 不吉な血判状を、隣地の剣客道場まで無傷で送り届ける。"}'::jsonb,
    1,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7035: 呪われた武家屋敷の調査 (qst_yat_mansion)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7035,
    'qst_yat_mansion',
    '呪われた武家屋敷の調査',
    '[調査] 怪光が灯る旧領主の武家屋敷を調査する。怨霊の正体を暴け。',
    '代官所',
    3,
    8,
    5,
    '{"gold":400,"items":[],"exp":120,"reputation":5,"alignment_shift":{"justice":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_yatoshin']::text[],
    '{"location_tags":["loc_yatoshin"]}'::jsonb,
    '{"nodes":{"start":{"text":"「あの屋敷には近づくなと何度言っても、子供らが肝試しに行きおる」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"代官","speaker":"代官","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「先月から怪光が酷くなってな。冒険者の手を借りたい」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"代官","speaker":"代官","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"代官の話では、旧領主・影守は三年前の政変で切腹を命じられたという。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"以来、屋敷は封印され、影守の一族の行方も知れぬままだ。依頼を引き受け、山裾へ向かう。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"start_04_02","choices":[{"label":"続ける","next":"start_04_02"}]},"start_04_02":{"text":"かつての繁栄も今は昔。山裾に向かう道は荒れ果て、冷たい風が竹林を揺らしている。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"start_04_03","choices":[{"label":"続ける","next":"start_04_03"}]},"start_04_03":{"text":"近隣の住人は屋敷の方向を指差し、怯えた顔で「あそこには死神が住む」と囁いていた。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"arrive_01","choices":[{"label":"続ける","next":"arrive_01"}]},"arrive_01":{"text":"鬱蒼とした木々の先に、朽ちかけた門が見えた。門扉は半開きで、夕暮れの風に軋んでいた。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_tense","next":"arrive_02","choices":[{"label":"続ける","next":"arrive_02"}]},"arrive_02":{"text":"庭は雑草に覆われ、かつての枯山水の面影は消え失せていた。屋敷の窓からは、微かな青い光が漏れていた。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_tense","next":"arrive_03","choices":[{"label":"続ける","next":"arrive_03"}]},"arrive_03":{"text":"背筋に冷たいものが走った。だが引き返すわけにはいかない。覚悟を決めて、玄関を押し開けた。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_tense","next":"explore_01","choices":[{"label":"続ける","next":"explore_01"}]},"explore_01":{"text":"床板が軋む音だけが響く。埃の積もった廊下に、不自然な足跡が続いている。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_mystery","next":"explore_01_02","choices":[{"label":"続ける","next":"explore_01_02"}]},"explore_01_02":{"text":"湿った空気とカビの臭いが鼻を突く。暗闇の中、どこかで水滴が滴る音が響いている。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_mystery","next":"explore_01_03","choices":[{"label":"続ける","next":"explore_01_03"}]},"explore_01_03":{"text":"天井の梁からは蜘蛛の巣が垂れ下がり、まるで侵入者を拒む網のように行く手を阻む。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_mystery","next":"explore_02","choices":[{"label":"続ける","next":"explore_02"}]},"explore_02":{"text":"足跡は素足だ。しかも、指は五本あるが爪痕が異様に深い。人間のものではない。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_mystery","next":"explore_03","choices":[{"label":"続ける","next":"explore_03"}]},"explore_03":{"text":"足跡を辿ると、奥座敷へと続く渡り廊下に出た。だが渡り廊下の中央で床が崩落している。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_mystery","next":"trap_01","choices":[{"label":"続ける","next":"trap_01"}]},"trap_01":{"text":"腐った床板を踏み抜いた！ 足を切りながらも、なんとか反対側に飛び移る。","type":"hp_damage","bg_key":"bg_yat_haunted","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"trap_02","choices":[{"label":"続ける","next":"trap_02"}]},"trap_02":{"text":"足から血が滲む。だが傷は浅い。先に進めそうだ。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_tense","next":"explore_04","choices":[{"label":"続ける","next":"explore_04"}]},"explore_04":{"text":"奥座敷に辿り着く。襖は全て破れ、畳が捲れ上がっている。壁の掛け軸だけが無傷で残っていた。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_mystery","next":"explore_05","choices":[{"label":"続ける","next":"explore_05"}]},"explore_05":{"text":"掛け軸の裏に何かがある——と思った瞬間、背後から低い唸り声が聞こえた。振り返ると、怨霊が！","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_mystery","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"type":"battle","bg_key":"bg_yat_haunted","bgm":"bgm_battle","enemy_group_id":"450","choices":[{"label":"win","next":"inner_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"inner_01"},"inner_01":{"text":"怨霊を退けた。掛け軸の裏を確認すると、隠し扉があった。その先に地下への階段が続いている。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_mystery","next":"inner_02","choices":[{"label":"続ける","next":"inner_02"}]},"inner_02":{"text":"地下は予想外に広かった。壁に松明の跡が残っているが、今は闇に沈んでいる。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"inner_03","choices":[{"label":"続ける","next":"inner_03"}]},"inner_03":{"text":"松明に火を灯すと、壁一面に無数の名前が刻まれていた。影守の一族の名だ。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"inner_03_02","choices":[{"label":"続ける","next":"inner_03_02"}]},"inner_03_02":{"text":"影守一族……。かつてこの地を治め、人望も厚かったと聞く。彼らの命は儚く散った。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"inner_03_03","choices":[{"label":"続ける","next":"inner_03_03"}]},"inner_03_03":{"text":"壁の文字は、ただの落書きではない。爪で、あるいは血で執念深く刻まれたものだ。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"inner_04","choices":[{"label":"続ける","next":"inner_04"}]},"inner_04":{"text":"名前の下には「無念」「恨」「偽」と血で書かれた文字。彼らは冤罪だったのか……？","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"clue_01","choices":[{"label":"続ける","next":"clue_01"}]},"clue_01":{"text":"地下室の最奥に祭壇がある。祭壇の上に古びた巻物と、一振りの短刀が置かれていた。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","next":"clue_02","choices":[{"label":"続ける","next":"clue_02"}]},"clue_02":{"text":"巻物には、影守一族の冤罪を証明する証拠が記されている。政変の黒幕は現在の重臣の一人だ。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","next":"clue_03","choices":[{"label":"続ける","next":"clue_03"}]},"clue_03":{"text":"巻物を手に取ろうとした瞬間、祭壇の炎が噴き上がり、影守の怨霊が姿を現した！","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"type":"battle","bg_key":"bg_yato_shrine","bgm":"bgm_battle_boss","enemy_group_id":"451","choices":[{"label":"win","next":"reveal_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"reveal_01"},"reveal_01":{"text":"影守の怨霊が膝をつく。怒りが消え、悲しみだけが残った顔で自分を見上げている。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"reveal_02_01","choices":[{"label":"続ける","next":"reveal_02_01"}]},"reveal_02_01":{"text":"影守の怨霊の瞳から憎悪の赤い光が消え、深い哀愁を帯びた声が響く。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"reveal_02","choices":[{"label":"続ける","next":"reveal_02"}]},"reveal_02":{"text":"「我が一族の無念、晴らしてくれるか。それとも浄化して終わらせるか」","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","speaker_name":"影守の怨霊","speaker":"影守の怨霊","next":"choice_resolve","choices":[{"label":"続ける","next":"choice_resolve"}]},"choice_resolve":{"text":"霊の問いかけに対し、どう答える？","type":"choice","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","choices":[{"label":"護符で浄化する。安らかに眠れ","next":"purify_01"},{"label":"巻物を持ち帰り、真相を世に問う","next":"resolve_01"}]},"purify_01":{"text":"護符を額に貼ると、影守は穏やかな顔で光に包まれ、消えていった。巻物は灰になった。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"purify_01_02","choices":[{"label":"続ける","next":"purify_01_02"}]},"purify_01_02":{"text":"影守の怨念が消え去ると、屋敷を支配していた極寒の冷気が和らいでいくのを感じた。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"purify_01_03","choices":[{"label":"続ける","next":"purify_01_03"}]},"purify_01_03":{"text":"かつての怨念は消え、ただ静かな廃墟としての時間が、再びこの場所に流れ始めた。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"purify_02","choices":[{"label":"続ける","next":"purify_02"}]},"purify_02":{"text":"屋敷から出ると、空は既に白み始めていた。もうここに怪光が灯ることはないだろう。","type":"text","bg_key":"bg_yat_haunted","bgm":"bgm_quest_calm","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"代官に報告した。「浄化したか。これで民も安心する。見事な働きであった」","type":"text","bg_key":"bg_yato_city","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"屋敷の怨念は消え去った。だが、不都合な歴史の闇は誰にも知られぬまま……。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":400,"exp":120,"reputation":5,"alignment_shift":{"justice":5}}},"choices":[]},"resolve_01":{"text":"「……感謝する」\n影守は深く頭を下げると、静かに消えていった。巻物を懐に収め、地上に戻る。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","next":"resolve_02","choices":[{"label":"続ける","next":"resolve_02"}]},"resolve_02":{"text":"「これは……影守の冤罪の証拠か。馬鹿な、これが世に出れば大事になるぞ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","speaker_name":"代官","speaker":"代官","next":"resolve_02_02","choices":[{"label":"続ける","next":"resolve_02_02"}]},"resolve_02_02":{"text":"代官は顔を真っ青にしながら、証拠の巻物を震える手で机に置いた。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_tense","next":"end_success_chaos_01","choices":[{"label":"続ける","next":"end_success_chaos_01"}]},"end_success_chaos_01":{"text":"報酬は減額されたが、影守一族の名誉回復の種は、確かに蒔かれた。","type":"text","bg_key":"bg_yato_city","next":"end_success_chaos","choices":[{"label":"続ける","next":"end_success_chaos"}]},"end_success_chaos":{"text":"真実を暴くことと、偽りの安寧を守ること。どちらが正義か、答えは出ない。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":300,"exp":200,"reputation":-5,"alignment_shift":{"chaos":5}}},"choices":[]},"end_failure_01":{"text":"怨霊の放つ絶対的な冷気に意識を奪われ、床に崩れ落ちるように倒れた。","type":"text","bg_key":"bg_yat_haunted","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"朝、屋敷の外で目を覚ました。誰が運んだのか……怨霊の最後の温情だろうか。","type":"end","result":"failure","bg_key":"bg_yat_haunted","choices":[]}},"short_description":"[調査] 怪光が灯る旧領主の武家屋敷を調査する。怨霊の正体を暴け。"}'::jsonb,
    5,
    5
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
