    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7040: 死者の還る山の浄化 (qst_har_jiangshi)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7040,
    'qst_har_jiangshi',
    '死者の還る山の浄化',
    '[討伐] 霊山をうろつくキョンシーたちを護符の力で鎮める。',
    '道士',
    2,
    7,
    5,
    '{"gold":350,"items":[],"exp":100,"alignment_shift":{"chaos":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_haryu']::text[],
    '{"location_tags":["loc_haryu"]}'::jsonb,
    '{"nodes":{"start":{"text":"「ほう、お主が今回引き受けてくれるのか。では、これを」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"道士","speaker":"道士","next":"start_01_02","choices":[{"label":"続ける","next":"start_01_02"}]},"start_01_02":{"text":"老道士から、墨の匂いがきつい黄色い護符の束を受け取った。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「霊山をうろつくキョンシーどもは、額にこの護符を貼れば止まる」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"道士","speaker":"道士","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「爪を剥き出しにして迫る亡者の額に、直接貼る度胸があればの話だがな」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"道士","speaker":"道士","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「それから、鎮めた死者から漂う『死気』を、この壺に集めてきてほしい」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"道士","speaker":"道士","next":"start_05_01","choices":[{"label":"続ける","next":"start_05_01"}]},"start_05_01":{"text":"渡された壺は禍々しい朱色の紋様で覆われ、触れると氷のように冷たかった。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"道士の不気味な笑みに一抹の不安を覚えつつ、霊山へと向かう。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"talisman_01","choices":[{"label":"続ける","next":"talisman_01"}]},"talisman_01":{"text":"護符と壺を懐に収め、霊山の登り口に到着した。空を覆う雲が太陽の光を遮っている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"talisman_02","choices":[{"label":"続ける","next":"talisman_02"}]},"talisman_02":{"text":"山全体から、生き物を寄せ付けない淀んだ空気が流れ出しているのが肌で感じられた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"path_01","choices":[{"label":"続ける","next":"path_01"}]},"path_01":{"text":"苔むした長い石段を登る。道の両脇には、風化して文字も読めなくなった墓標が並んでいる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"path_01_02","choices":[{"label":"続ける","next":"path_01_02"}]},"path_01_02":{"text":"冷たい風が竹林を揺らし、カサカサと不気味な音を立てている。何かが潜んでいる気配だ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"path_01_03","choices":[{"label":"続ける","next":"path_01_03"}]},"path_01_03":{"text":"石段のあちこちに、爪で掻きむしったような跡がある。キョンシーたちの仕業だろう。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"path_02","choices":[{"label":"続ける","next":"path_02"}]},"path_02":{"text":"ふと、不自然な気配を感じて足を止めた。前方にある大樹の影に、人の形をしたものが立っている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"path_03","choices":[{"label":"続ける","next":"path_03"}]},"path_03":{"text":"青白い肌。生気のない瞳。朽ちた官服を着た屍が、両腕を真っ直ぐ前へ突き出している。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"path_04","choices":[{"label":"続ける","next":"path_04"}]},"path_04":{"text":"——動いた。屍は膝を曲げることなく、不気味な跳躍で一直線にこちらへと迫ってくる！","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"graveyard_01","choices":[{"label":"続ける","next":"graveyard_01"}]},"graveyard_01":{"text":"さらに墓地の奥へ進むと、土が不自然に盛り上がり、次々と新たな屍が這い出してきた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"graveyard_01_02","choices":[{"label":"続ける","next":"graveyard_01_02"}]},"graveyard_01_02":{"text":"荒れ果てた墓地にたどり着いた。倒れた墓石の隙間から、青白い霊気が立ち上っている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"graveyard_01_03","choices":[{"label":"続ける","next":"graveyard_01_03"}]},"graveyard_01_03":{"text":"土がモゾモゾと動き、冷たい月明かりの下で屍の手が地中から突き出てくる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"graveyard_02","choices":[{"label":"続ける","next":"graveyard_02"}]},"graveyard_02":{"text":"その中には、ひときわ古い衣装を纏った、長年の死気を溜め込んだ強力な個体も混じっている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"キョンシーの群れが飛びかかってきた！","type":"battle","bg_key":"bg_karyu_mountain","bgm":"bgm_battle","enemy_group_id":"440","choices":[{"label":"win","next":"deeper_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"deeper_01"},"deeper_01":{"text":"亡者たちの額に護符を叩きつけ、動きを封じた。崩れ落ちた死体から黒いモヤが立ち昇る。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"deeper_02","choices":[{"label":"続ける","next":"deeper_02"}]},"deeper_02":{"text":"懐の壺を取り出すと、モヤは吸い込まれるように壺の中へ消えていった。壺が微かに振動している。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"deeper_03","choices":[{"label":"続ける","next":"deeper_03"}]},"deeper_03":{"text":"「死気」の収集は順調だ。さらに霧が濃くなる中、山の奥、頂上付近の霊廟へと足を進める。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"tomb_01_01","choices":[{"label":"続ける","next":"tomb_01_01"}]},"tomb_01_01":{"text":"鬱蒼とした森を抜けると、巨大で豪奢な石造りの古墓が現れた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"tomb_01","choices":[{"label":"続ける","next":"tomb_01"}]},"tomb_01":{"text":"古墓の入口にある石碑には、「華龍六代太守　薛氏一門之墓」と刻まれている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"tomb_02","choices":[{"label":"続ける","next":"tomb_02"}]},"tomb_02":{"text":"墓室の暗がりから、ひどい腐臭と共に三つの青白い眼光が浮かび上がった。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"tomb_02_02","choices":[{"label":"続ける","next":"tomb_02_02"}]},"tomb_02_02":{"text":"霊廟の奥には金銀で飾られた太守の棺があった。しかし蓋は完全に破壊されている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"tomb_02_03","choices":[{"label":"続ける","next":"tomb_02_03"}]},"tomb_02_03":{"text":"太守の遺体は棺にない。代わりに壁には、恨みを書き殴ったような血文字が残されていた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"tomb_03","choices":[{"label":"続ける","next":"tomb_03"}]},"tomb_03":{"text":"太守とその近衛兵だろうか。並のキョンシーとは比べ物にならない、濃厚な死気と殺意を纏っている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"古の太守とその近衛、強力なキョンシーたちが襲いかかる！","type":"battle","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","enemy_group_id":"441","choices":[{"label":"win","next":"purify_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"purify_01"},"purify_01":{"text":"激戦の末、太守の額に最後の一枚を貼り付けた。巨体が硬直して後方に倒れ、地面が大きく揺れる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"purify_02","choices":[{"label":"続ける","next":"purify_02"}]},"purify_02":{"text":"太守の体からあふれ出た膨大な死気を壺が吸い尽くすと、周囲の瘴気が嘘のように薄れていった。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"purify_02_02","choices":[{"label":"続ける","next":"purify_02_02"}]},"purify_02_02":{"text":"浄化された霊魂は、青い光の粒子となって天井へ昇り、闇の中に消えていった。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"purify_02_03","choices":[{"label":"続ける","next":"purify_02_03"}]},"purify_02_03":{"text":"あれほどの執念と怨嗟に満ちていた空間が、今はただの静かな石室に戻っている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"purify_03","choices":[{"label":"続ける","next":"purify_03"}]},"purify_03":{"text":"壺は満杯になり、不吉な紫色の光を放ちながら熱を帯びている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"purify_03_02","choices":[{"label":"続ける","next":"purify_03_02"}]},"purify_03_02":{"text":"この禍々しい力を、あの不気味な道士に渡してしまって良いのだろうか？","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"choice_qi","choices":[{"label":"続ける","next":"choice_qi"}]},"choice_qi":{"text":"壺の中の膨大な死気をどうする？","type":"choice","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","choices":[{"label":"依頼通り、道士に渡す","next":"report_01_01"},{"label":"壺を割り、死気を解放して浄化する","next":"refuse_01"}]},"report_01_01":{"text":"山を下り、待ち構えていた道士に約束通り壺を手渡した。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"report_01","choices":[{"label":"続ける","next":"report_01"}]},"report_01":{"text":"「ヒッヒッヒ……これほどの純粋な死気……なんと素晴らしい」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"道士","speaker":"道士","next":"report_02","choices":[{"label":"続ける","next":"report_02"}]},"report_02":{"text":"道士は恍惚とした表情で壺を愛でている。その顔は亡者よりも恐ろしく見えた。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"任務完了。約束の報酬を受け取り、不気味な道士のもとを去る。","type":"text","bg_key":"bg_guild","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"あの壺の死気が禁術に使われるのかどうか、自分には関係のない話だ。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":350,"exp":100,"alignment_shift":{"chaos":5}}},"choices":[]},"refuse_01":{"text":"こんな悪しき力を利用させてはならない。道士の目の前で、壺を地面の岩に力強く叩きつけた！","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_tense","next":"refuse_02_01","choices":[{"label":"続ける","next":"refuse_02_01"}]},"refuse_02_01":{"text":"パリンという音と共に壺が砕け、死気は陽光に触れて浄化されていく。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_tense","next":"refuse_02","choices":[{"label":"続ける","next":"refuse_02"}]},"refuse_02":{"text":"「な、何をする！ 貴様、何ということを……！ 報酬は減額だ！！」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_tense","speaker_name":"道士","speaker":"道士","next":"end_success_justice_01","choices":[{"label":"続ける","next":"end_success_justice_01"}]},"end_success_justice_01":{"text":"怒り狂う道士から半ば強引に最低限の報酬を奪い取り、山を後にした。","type":"text","bg_key":"bg_guild","next":"end_success_justice","choices":[{"label":"続ける","next":"end_success_justice"}]},"end_success_justice":{"text":"報酬は減ったが、あの世の秩序を守った事実は確かな誇りとして胸に残った。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":250,"exp":100,"alignment_shift":{"justice":5}}},"choices":[]},"end_failure_01":{"text":"キョンシーたちの異常な怪力に圧倒され、冷たい掌に突き飛ばされた。","type":"text","bg_key":"bg_karyu_mountain","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"倒れる中、最後の一枚の護符が手から落ち、絶望の闇が視界を覆った……。","type":"end","result":"failure","bg_key":"bg_karyu_mountain","choices":[]}},"short_description":"[討伐] 霊山をうろつくキョンシーたちを護符の力で鎮める。"}'::jsonb,
    5,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7041: 仙丹の材料となる霊草採集 (qst_har_herb)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7041,
    'qst_har_herb',
    '仙丹の材料となる霊草採集',
    '[納品] 仙丹の材料となる稀少な霊草を宦官へ納品。',
    '宦官',
    2,
    7,
    6,
    '{"gold":300,"items":[],"exp":100,"alignment_shift":{"evil":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_haryu']::text[],
    '{"location_tags":["loc_haryu"]}'::jsonb,
    '{"nodes":{"start":{"text":"「よく来てくれました。他ならぬ、腕利きのあなたに頼みたい儀があるのです」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"宦官","speaker":"宦官","next":"start_01_02","choices":[{"label":"続ける","next":"start_01_02"}]},"start_01_02":{"text":"宮殿の奥深くに通され、宦官から古い図絵と山脈の地図を受け取った。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「皇帝に献上する『仙丹』……その要となる『霊草』を摘んできてほしいのです」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"宦官","speaker":"宦官","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「霊草は茎が折れると薬効を失います。根から引き抜き、慎重に扱ってください」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"宦官","speaker":"宦官","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「それから……この件は内密に。薬の『真の使い道』は聞かぬほうがよろしいかと」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"宦官","speaker":"宦官","next":"start_04_02","choices":[{"label":"続ける","next":"start_04_02"}]},"start_04_02":{"text":"冷たく細められた宦官の目に、底知れぬ悪意の気配を感じた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"leave_01","choices":[{"label":"続ける","next":"leave_01"}]},"leave_01":{"text":"図絵を懐に忍ばせ、宮殿の裏門から人目を避けるようにして都を出る。","type":"text","bg_key":"bg_har_city","bgm":"bgm_field","next":"leave_02","choices":[{"label":"続ける","next":"leave_02"}]},"leave_02":{"text":"地図によれば、霊草の自生地である西方霊山までは、急ぎ足でも片道三日はかかる。","type":"text","bg_key":"bg_har_city","bgm":"bgm_field","next":"leave_03","choices":[{"label":"続ける","next":"leave_03"}]},"leave_03":{"text":"道中の食料と登山用の命綱をしっかりと確認し、長い旅路へと足を踏み出した。","type":"text","bg_key":"bg_har_city","bgm":"bgm_field","next":"approach_01","choices":[{"label":"続ける","next":"approach_01"}]},"approach_01":{"text":"三日後。道なき道を進み、ようやく目的の山麓へと辿り着いた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"approach_01_02","choices":[{"label":"続ける","next":"approach_01_02"}]},"approach_01_02":{"text":"見上げるほどの絶壁がそびえ立つ。山頂付近は白い霧に閉ざされ、冷たい風が吹き降ろしてくる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"approach_01_03","choices":[{"label":"続ける","next":"approach_01_03"}]},"approach_01_03":{"text":"空気は次第に薄くなり、一歩登るごとに心臓が激しく鼓動を打つ。過酷な登山になりそうだ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"approach_02","choices":[{"label":"続ける","next":"approach_02"}]},"approach_02":{"text":"雲の切れ間から、天を衝くような険しい断崖絶壁が覗いている。霊草はあの頂付近にあるという。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"approach_03","choices":[{"label":"続ける","next":"approach_03"}]},"approach_03":{"text":"風は冷たく、空気は薄い。高山病に気をつけながら、慎重に崖に取り付いた。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"climb_01","choices":[{"label":"続ける","next":"climb_01"}]},"climb_01":{"text":"岩肌に指をかけ、少しずつ上を目指す。見下ろせば、目が眩むような奈落が広がっている。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"climb_02","choices":[{"label":"続ける","next":"climb_02"}]},"climb_02":{"text":"山頂に近づくにつれ、湿った濃霧が立ち込め、岩肌が結露で滑りやすくなってきた。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"climb_03","choices":[{"label":"続ける","next":"climb_03"}]},"climb_03":{"text":"中腹のオーバーハングを越えようとしたその時、踏み込んだ岩の表面がボロッと崩れ落ちた！","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_quest_tense","next":"climb_04","choices":[{"label":"続ける","next":"climb_04"}]},"climb_04":{"text":"「くっ……！」\n宙ぶらりんになりながらも、辛うじて別の突起に指を引っ掛け、全体重を支える。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_quest_tense","next":"cliff_danger","choices":[{"label":"続ける","next":"cliff_danger"}]},"cliff_danger":{"type":"hp_damage","bg_key":"bg_har_cliff","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"cliff_danger_02","choices":[{"label":"続ける","next":"cliff_danger_02"}]},"cliff_danger_02":{"text":"息を荒げながら、安全な岩棚へと這い上がる。傷口から滲む血を布で縛り、応急処置を施した。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"cliff_danger_03","choices":[{"label":"続ける","next":"cliff_danger_03"}]},"cliff_danger_03":{"text":"あのまま落ちていれば一貫の終わりだった。気を引き締め直し、さらに崖を登り続ける。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"find_herb_01","choices":[{"label":"続ける","next":"find_herb_01"}]},"find_herb_01":{"text":"ついに頂上付近の岩棚へと到達した。岩の隙間に、仄かに光る白い花が群生している。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"find_herb","choices":[{"label":"続ける","next":"find_herb"}]},"find_herb":{"text":"間違いない、図絵に描かれていた「霊草」だ。","type":"random_branch","bg_key":"bg_har_cliff","bgm":"bgm_field","prob":40,"choices":[{"label":"success","next":"guard_01"},{"label":"failure","next":"collect_01"}]},"guard_01":{"text":"霊草に手を伸ばそうとしたその瞬間、岩陰から「グルル……」と地鳴りのような低い唸り声が響いた。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_quest_tense","next":"guard_02","choices":[{"label":"続ける","next":"guard_02"}]},"guard_02":{"text":"霊草の放つ魔力を浴びて育った、山の「守護獣」。どうやら簡単には持ち帰らせてくれないらしい。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_quest_tense","next":"guard_04","choices":[{"label":"続ける","next":"guard_04"}]},"guard_04":{"text":"獣が前足を高く掲げ、こちらを粉砕すべく怒り狂った咆哮を上げた！","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_quest_tense","next":"battle_guardian","choices":[{"label":"続ける","next":"battle_guardian"}]},"battle_guardian":{"text":"霊草の守護獣が牙を剥いて襲いかかってきた！","type":"battle","bg_key":"bg_har_cliff","bgm":"bgm_battle","enemy_group_id":"442","choices":[{"label":"win","next":"collect_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"collect_01"},"collect_01":{"text":"周囲の安全を確保し、ようやく霊草の前に膝をつく。これ以上傷つけないよう慎重に周囲の土を掘る。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_quest_calm","next":"collect_02","choices":[{"label":"続ける","next":"collect_02"}]},"collect_02":{"text":"宦官の言葉通り、茎を折らないように根元からそっと引き抜き、持参した柔らかい布で優しく包み込んだ。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_quest_calm","next":"collect_03","choices":[{"label":"続ける","next":"collect_03"}]},"collect_03":{"text":"採取は無さに完了した。しかし、まだ仕事は半分だ。これを萎れる前に都まで持ち帰らねばならない。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_quest_calm","next":"collect","choices":[{"label":"続ける","next":"collect"}]},"collect":{"text":"「霊草」を手に入れた！","type":"reward","bg_key":"bg_har_cliff","bgm":"bgm_quest_calm","params":{"item_id":"item_spirit_herb"},"next":"descent_01","choices":[{"label":"続ける","next":"descent_01"}]},"descent_01":{"text":"霊草を大切に懐へ収め、登りよりもさらに気を使いながら、危険な断崖を慎重に下っていく。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"descent_02","choices":[{"label":"続ける","next":"descent_02"}]},"descent_02":{"text":"崖を下りきった後は、休む間もなく都への帰路を急いだ。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"descent_02_02","choices":[{"label":"続ける","next":"descent_02_02"}]},"descent_02_02":{"text":"夜を徹して走り続け、ようやく山のふもとの街道まで戻ってきた。霊草の鮮度は保たれている。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"descent_02_03","choices":[{"label":"続ける","next":"descent_02_03"}]},"descent_02_03":{"text":"背後を振り返ると、あの過酷な山脈が朝日に照らされていた。息を整え、都への道を急ぐ。","type":"text","bg_key":"bg_har_cliff","bgm":"bgm_field","next":"choice_sell_herb","choices":[{"label":"続ける","next":"choice_sell_herb"}]},"choice_sell_herb":{"text":"都の入り口まで戻ってきた。この霊草は稀少な薬草だ。宮殿に届ける前に、薬屋に売ることもできるが……","type":"choice","bg_key":"bg_har_city","bgm":"bgm_field","choices":[{"label":"約束通り、宮殿の宦官のもとへ向かう","next":"descent_03"},{"label":"都の薬屋に霊草を高く売り払う","next":"sell_to_apothecary_01"}]},"sell_to_apothecary_01":{"text":"誘惑に負け、都の薬屋に立ち寄って霊草をすべて売却し、想定以上の大金を手に入れた。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"sell_to_apothecary_02","choices":[{"label":"続ける","next":"sell_to_apothecary_02"}]},"sell_to_apothecary_02":{"text":"しかし、霊草が民間の薬屋に流れた噂は、すぐに宮殿の宦官の耳に入ってしまった。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_tense","next":"end_apothecary","choices":[{"label":"続ける","next":"end_apothecary"}]},"end_apothecary":{"text":"宦官の私兵に捕らえられ、売却で得た金はすべて没収された上、都から追放された。ただ、薬屋の間では腕利きとして名が知られた。","type":"end","result":"failure","bg_key":"bg_har_city","params":{"rewards":{"gold":0,"exp":100,"reputation":10,"alignment_shift":{"chaos":15}}},"choices":[]},"descent_03":{"text":"三日後。夜陰に乗じて宮殿の裏門へと戻り、待ち構えていた宦官の元へと赴く。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"deliver","choices":[{"label":"続ける","next":"deliver"}]},"deliver":{"text":"布に包まれた霊草を机の上に置く。宦官は震える手でそれを開き、恍惚とした表情を浮かべた。","type":"check_delivery","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","params":{"item_id":"item_spirit_herb","quantity":3},"choices":[{"label":"success","next":"deliver_02"},{"label":"failure","next":"end_failure_lost_01"}]},"deliver_02":{"text":"「見事な出来だ。一片の傷もない。これで最高の上薬が練れましょう……」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"宦官","speaker":"宦官","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"薄ら笑いを浮かべる宦官から、ずっしりと重い金袋を受け取る。","type":"text","bg_key":"bg_har_city","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"あの薬が何をもたらすのか、自分には関係のない話だ。","type":"end","result":"success","bg_key":"bg_har_city","params":{"rewards":{"gold":300,"exp":100,"alignment_shift":{"evil":5}}},"choices":[]},"end_failure_lost_01":{"text":"「霊草がない？ まさか、折ってしまったのではあるまいな？ 役立たずめ！」","type":"text","bg_key":"bg_karyu_palace","speaker_name":"宦官","speaker":"宦官","next":"end_failure_lost","choices":[{"label":"続ける","next":"end_failure_lost"}]},"end_failure_lost":{"text":"「約束は果たされなかった。報酬は一切払えん。とっとと立ち去るが良い」","type":"end","result":"failure","bg_key":"bg_karyu_palace","speaker_name":"宦官","speaker":"宦官","params":{"rewards":{"gold":0}},"choices":[]},"end_failure_01":{"text":"守護獣の圧倒的な怪力と牙の前に、無情にも膝を突き、意識が薄れていく。","type":"text","bg_key":"bg_har_cliff","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"倒れる中、崖に咲く白い霊草が、風に揺れて遠くに霞んで見える……。","type":"end","result":"failure","bg_key":"bg_har_cliff","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[納品] 仙丹の材料となる稀少な霊草を宦官へ納品。"}'::jsonb,
    6,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7042: 辺境農民の反乱鎮圧 (qst_har_rebel)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7042,
    'qst_har_rebel',
    '辺境農民の反乱鎮圧',
    '[鎮圧] 重税に苦しむ農民の反乱軍を容赦なく根絶やしにする。',
    '地方太守',
    2,
    7,
    4,
    '{"gold":450,"items":[],"exp":100,"alignment_shift":{"evil":10}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_haryu']::text[],
    '{"location_tags":["loc_haryu"],"max_reputation":-50}'::jsonb,
    '{"nodes":{"start":{"text":"「よく来てくれた、裏稼業の者よ。内密に頼みたい汚れ仕事があるのだ」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","speaker_name":"地方太守","speaker":"地方太守","next":"start_01_02","choices":[{"label":"続ける","next":"start_01_02"}]},"start_01_02":{"text":"館の中は肥沃な香が焚かれ、贅を尽くした料理が並ぶ。飢餓に喘ぐ辺境とは正反対の世界だ。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"start_01_03","choices":[{"label":"続ける","next":"start_01_03"}]},"start_01_03":{"text":"太守の脂ぎった顔が、目の前の山積みの金貨を指し示す。欲望と冷酷さが透けて見えた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"start_01_04","choices":[{"label":"続ける","next":"start_01_04"}]},"start_01_04":{"text":"きらびやかな装飾の太守の館で、肥え太った役人が冷酷な笑みを浮かべていた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「辺境の農村で、税の取り立てに反発した農民どもが竹槍を持って暴れ回っておる」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","speaker_name":"地方太守","speaker":"地方太守","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「正規兵を動かせば上に知れる。荒くれ者のお前たちに、奴らを黙らせてほしい」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","speaker_name":"地方太守","speaker":"地方太守","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「奴らは暴徒と化している。情けは無用だ、一人残らず根絶やしにせよ」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","speaker_name":"地方太守","speaker":"地方太守","next":"start_05_01","choices":[{"label":"続ける","next":"start_05_01"}]},"start_05_01":{"text":"太守は面倒くさそうに手を振り、大量の金貨が入った袋を机の上に投げ出した。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_field","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"目的地である辺境の農村まで、ここから東に二日ほどの旅路だ。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_field","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"辺境へと続く街道は、見るも無惨に荒れ果てていた。道端には飢え死にした者たちの白骨が転がっている。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"田畑は完全に乾ききり、用水路も枯れている。これでは税など払えるはずもない。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_field","next":"travel_03","choices":[{"label":"続ける","next":"travel_03"}]},"travel_03":{"text":"すれ違ったぼろ布を纏う老婆が、こちらの武装を見てひどく怯えた目を向けた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_field","next":"travel_03_02","choices":[{"label":"続ける","next":"travel_03_02"}]},"travel_03_02":{"text":"すれ違う村人たちの目は、どれも生気を失い、この世の終わりのような絶望に満ちていた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_field","next":"travel_03_03","choices":[{"label":"続ける","next":"travel_03_03"}]},"travel_03_03":{"text":"重税という名の暴力が、この美しい辺境をゆっくりと、確実に死に追いやっているのだ。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_field","next":"travel_04","choices":[{"label":"続ける","next":"travel_04"}]},"travel_04":{"text":"「……アンタ、まさか……太守様が送ってきた手先かい？ ヒィィッ！」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_field","speaker_name":"村の老婆","speaker":"村の老婆","next":"arrive_01","choices":[{"label":"続ける","next":"arrive_01"}]},"arrive_01":{"text":"村の入り口に到着した。広場には農具や竹槍を手にした農民がバリケードを築いている。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"arrive_02","choices":[{"label":"続ける","next":"arrive_02"}]},"arrive_02":{"text":"皆一様に頬がこけ、目は落ち窪んでいる。正規兵ではない、ただの飢えた人間の群れだ。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"arrive_03","choices":[{"label":"続ける","next":"arrive_03"}]},"arrive_03":{"text":"こちらの接近に気づいた農民たちが、怯えと憎悪の入り混じった顔で一斉に竹槍を向けてきた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"arrive_04_01","choices":[{"label":"続ける","next":"arrive_04_01"}]},"arrive_04_01":{"text":"バリケードの先頭に立つ初老の男が、血を吐くような凄まじい声で叫んだ。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"arrive_04","choices":[{"label":"続ける","next":"arrive_04"}]},"arrive_04":{"text":"「太守の犬め！ もう俺たちからは何も奪えないぞ！」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","speaker_name":"農民の首謀者","speaker":"農民の首謀者","next":"arrive_05","choices":[{"label":"続ける","next":"arrive_05"}]},"arrive_05":{"text":"「頼む、見逃してくれ！ 家族にひもじい思いをさせたくないだけなんだ！」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","speaker_name":"農民の首謀者","speaker":"農民の首謀者","next":"face_mob","choices":[{"label":"続ける","next":"face_mob"}]},"face_mob":{"text":"刃を向ける相手は、魔物ではなく飢えた弱者たちだ。冒険者として太守の命令を遂行するか？","type":"choice","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","choices":[{"label":"容赦なく制圧する——これが仕事だ","next":"charge_01"},{"label":"武器を収め、引き下がる","next":"withdraw_01"}]},"charge_01":{"text":"感情を殺し、無言のまま武器を構える。それが裏社会を生きる者のルールだ。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"charge_02_01","choices":[{"label":"続ける","next":"charge_02_01"}]},"charge_02_01":{"text":"武器を構えたあなたを見て、男たちの表情が絶望から狂気的な殺意へと変わる。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"charge_02","choices":[{"label":"続ける","next":"charge_02"}]},"charge_02":{"text":"「……話し合いは通じないってわけか！ やるしかねぇ！」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","speaker_name":"農民の首謀者","speaker":"農民の首謀者","next":"charge_03","choices":[{"label":"続ける","next":"charge_03"}]},"charge_03":{"text":"「逃げるな！ 退いたら村中の女子供が殺されるぞ！ 全員でかかれェッ！！」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","speaker_name":"農民の首謀者","speaker":"農民の首謀者","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"飢えた農民たちが捨て身の覚悟で突進してきた！","type":"battle","bg_key":"bg_karyu_village","bgm":"bgm_battle","enemy_group_id":"443","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"after_01"},"after_01":{"text":"怒号と悲鳴が入り混じる中、農民たちを次々と血祭りに上げる。血が乾いた土を赤く染めていく。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"数名の死体を作ると、暴徒たちは恐れをなして後ずさった。だが、首謀者の男だけは血まみれで立っている。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"leader_01","choices":[{"label":"続ける","next":"leader_01"}]},"leader_01":{"text":"「長男は重税のための強制労働で死んだ。次男は餓死した。娘は太守に売られた……！」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","speaker_name":"農民の首謀者","speaker":"農民の首謀者","next":"leader_02","choices":[{"label":"続ける","next":"leader_02"}]},"leader_02":{"text":"「これ以上、何を奪うって言うんだ！ 殺すなら、俺を殺してからにしろォォッ！！」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","speaker_name":"農民の首謀者","speaker":"農民の首謀者","next":"leader_03","choices":[{"label":"続ける","next":"leader_03"}]},"leader_03":{"text":"男は折れた竹槍を強く握り直し、鬼気迫る形相でこちらへ突進してきた。彼の目にもう死への恐怖はない。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"首謀者が死に物狂いで襲いかかってきた！","type":"battle","bg_key":"bg_karyu_village","bgm":"bgm_battle_boss","enemy_group_id":"444","choices":[{"label":"win","next":"clear_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"clear_01"},"clear_01":{"text":"首謀者が倒れ伏す。それを見た農民たちは、戦意を喪失して散り散りに逃げ去った。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"clear_02","choices":[{"label":"続ける","next":"clear_02"}]},"clear_02":{"text":"広場には死体にすがりつく女や子供だけが残された。反乱は完全に制圧された。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"血塗られた手で太守の館へと戻り、任務完了の報告と共に多額の報酬を受け取る。","type":"text","bg_key":"bg_karyu_palace","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"背中の奥で、村人たちの呪詛の泣き声がいつまでも響いているような気がした。","type":"end","result":"success","bg_key":"bg_karyu_palace","params":{"rewards":{"gold":450,"exp":100,"alignment_shift":{"evil":10}}},"choices":[]},"withdraw_01":{"text":"静かに武器を下ろし、背を向けた。いくら金のためとはいえ、飢えた者たちを狩る真似はできない。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"withdraw_02_01","choices":[{"label":"続ける","next":"withdraw_02_01"}]},"withdraw_02_01":{"text":"踵を返して歩き出した背中に、首謀者の震えるような感謝の声が聞こえてきた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"withdraw_02","choices":[{"label":"続ける","next":"withdraw_02"}]},"withdraw_02":{"text":"「……ありがとう……ありがとう、見逃してくれて……」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","speaker_name":"農民の首謀者","speaker":"農民の首謀者","next":"withdraw_03","choices":[{"label":"続ける","next":"withdraw_03"}]},"withdraw_03":{"text":"来た道を引き返す。太守には「手強くて制圧に失敗した」とでも言えばいい。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"withdraw_03_02","choices":[{"label":"続ける","next":"withdraw_03_02"}]},"withdraw_03_02":{"text":"自分の選択が正しいのかは分からない。しかし、良心の呵責に怯えるよりは遥かにマシだ。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"withdraw_03_03","choices":[{"label":"続ける","next":"withdraw_03_03"}]},"withdraw_03_03":{"text":"空はどんよりと曇り、冷たい雨が降り始めた。それはまるで、辺境の運命を嘆く涙のようであった。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"withdraw_04","choices":[{"label":"続ける","next":"withdraw_04"}]},"withdraw_04":{"text":"村人がその後どうなるかは分からない。だが、少なくとも自分の手で彼らの命を奪わずに済んだ。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"end_success_withdraw_01","choices":[{"label":"続ける","next":"end_success_withdraw_01"}]},"end_success_withdraw_01":{"text":"「役立たずのクズめ！ 報酬など一銭も払わん！ とっとと失せろ！」","type":"text","bg_key":"bg_karyu_palace","speaker_name":"地方太守","speaker":"地方太守","next":"end_success_withdraw","choices":[{"label":"続ける","next":"end_success_withdraw"}]},"end_success_withdraw":{"text":"太守から激しく罵倒された。だが、胸の奥には確かな誇りが残っている。","type":"end","result":"success","bg_key":"bg_karyu_palace","params":{"rewards":{"exp":50,"alignment_shift":{"justice":5},"reputation":-10}},"choices":[]},"end_failure_01":{"text":"武具の力は勝っていたが、彼らの「生きるための覚悟」がそれを上回った。","type":"text","bg_key":"bg_karyu_village","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"無数の竹槍に貫かれ、冷たい泥に倒れる。因果応報、仕方のない結末だろう。","type":"end","result":"failure","bg_key":"bg_karyu_village","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[鎮圧] 重税に苦しむ農民の反乱軍を容赦なく根絶やしにする。"}'::jsonb,
    4,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
