    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 7043: 巡検使の護衛と汚職隠蔽 (qst_har_official)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7043,
    'qst_har_official',
    '巡検使の護衛と汚職隠蔽',
    '[護衛] 悪徳官僚を暗殺者の刃から守り抜く。',
    '悪徳官僚',
    2,
    7,
    6,
    '{"gold":500,"items":[],"exp":120,"alignment_shift":{"chaos":10,"evil":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_haryu']::text[],
    '{"location_tags":["loc_haryu"]}'::jsonb,
    '{"nodes":{"start":{"text":"都の豪邸の奥座敷。脂肪で顔を膨らませた官僚、薛（せつ）が絹の椅子に身を沈めていた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「明日から三日、都より『巡検使』が視察に来る。私の帳簿の不備を調べるらしい」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","speaker_name":"薛","speaker":"薛","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「だが、真の目的は帳簿ではない。政敵が私を消すため、暗殺者を送ってきたのだ」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","speaker_name":"薛","speaker":"薛","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「巡検使が去るまでの三日三晩、この屋敷にとどまり、私を刺客から守り抜いてほしい」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","speaker_name":"薛","speaker":"薛","next":"start_05_01","choices":[{"label":"続ける","next":"start_05_01"}]},"start_05_01":{"text":"薛は、机の上に金の延べ棒がぎっしりと詰まった箱を滑らせた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"「報酬は弾もう。私の命は何より高いからな」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","speaker_name":"薛","speaker":"薛","next":"join_official_01","choices":[{"label":"続ける","next":"join_official_01"}]},"join_official_01":{"text":"「私は文官ですから。戦いはすべて任せますよ」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"薛","speaker":"薛","next":"join_official","choices":[{"label":"続ける","next":"join_official"}]},"join_official":{"text":"悪徳官僚・薛が護衛対象としてパーティに加わった。","type":"guest_join","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","params":{"guest_id":"npc_corrupt_official","is_escort_target":true},"next":"join_official_02","choices":[{"label":"続ける","next":"join_official_02"}]},"join_official_02":{"text":"薛は満足げに頷くと、使用人を呼び寄せて冷たいお茶を用意させた。警戒感の薄い男だ。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"join_official_03","choices":[{"label":"続ける","next":"join_official_03"}]},"join_official_03":{"text":"だが、その背後に漂う殺気は本物だ。屋敷の隅々に配置された護衛の数も十分ではない。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"tour_01","choices":[{"label":"続ける","next":"tour_01"}]},"tour_01":{"text":"案内された屋敷の庭園は、華龍の一般市民が一生働いても作れないほど広大だった。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"tour_02","choices":[{"label":"続ける","next":"tour_02"}]},"tour_02":{"text":"金魚が優雅に泳ぐ池と、宝石を散りばめたような灯籠。まさに汚職の象徴である。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"tour_03","choices":[{"label":"続ける","next":"tour_03"}]},"tour_03":{"text":"すれ違った使用人が小声で教えてくれた。既に前の護衛が二名、毒針で暗殺されたのだという。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"night_01","choices":[{"label":"続ける","next":"night_01"}]},"night_01":{"text":"初日の夜。豪華な寝所で震える薛の部屋の前に立ち、屋敷の巡回と警護を開始する。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"night_01_02","choices":[{"label":"続ける","next":"night_01_02"}]},"night_01_02":{"text":"冷たい夜風が廊下を吹き抜け、提灯の明かりが不規則に揺れる。影が奇妙に引き伸ばされた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"night_01_03","choices":[{"label":"続ける","next":"night_01_03"}]},"night_01_03":{"text":"薛の寝所からは、時折小さないびきが聞こえてくる。彼は己の危機の近さを理解していない。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"night_02","choices":[{"label":"続ける","next":"night_02"}]},"night_02":{"text":"月明かりが庭園の池を美しく照らしている。虫の音しか聞こえない、静寂に包まれた夜だ。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"night_03","choices":[{"label":"続ける","next":"night_03"}]},"night_03":{"text":"だが、自分の勘が危険を告げた。風もないのに、水面に映る月が不自然に波打っている。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"night_04","choices":[{"label":"続ける","next":"night_04"}]},"night_04":{"text":"池の底から、竹の筒を使って息を潜めていた影が、水飛沫と共に次々と跳び上がった！","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"ambush_01","choices":[{"label":"続ける","next":"ambush_01"}]},"ambush_01":{"text":"黒装束に身を包んだ刺客たち。手には毒の塗られた短刀が鈍く光っている。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"ambush_02","choices":[{"label":"続ける","next":"ambush_02"}]},"ambush_02":{"text":"一人、二人、三人……。彼らの標的は明らかに、奥の部屋にいる薛だ。行かせるわけにはいかない。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"暗殺者の第1波が侵入してきた！","type":"battle","bg_key":"bg_karyu_palace","bgm":"bgm_battle","enemy_group_id":"445","choices":[{"label":"win","next":"morning_01_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"morning_01_01"},"morning_01_01":{"text":"暗殺者たちを斬り捨て、死体を裏門から処分する。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"morning_01","choices":[{"label":"続ける","next":"morning_01"}]},"morning_01":{"text":"夜が明けると、薛は何事もなかったように豪華な朝食を摂っていた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"morning_02","choices":[{"label":"続ける","next":"morning_02"}]},"morning_02":{"text":"「おお、無事だったか。さすがだな。今夜も頼むぞ」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"薛","speaker":"薛","next":"morning_02_02","choices":[{"label":"続ける","next":"morning_02_02"}]},"morning_02_02":{"text":"悪びれる様子もないその態度に、微かな嫌悪感を覚える。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"inspect_01_01","choices":[{"label":"続ける","next":"inspect_01_01"}]},"inspect_01_01":{"text":"二日目の昼。ついに都から巡検使の一団が屋敷に到着した。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"inspect_01","choices":[{"label":"続ける","next":"inspect_01"}]},"inspect_01":{"text":"先頭に立つのは、鋭い鷹のような目をした痩せぎすの男だ。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"inspect_02","choices":[{"label":"続ける","next":"inspect_02"}]},"inspect_02":{"text":"巡検使は挨拶もそこそこに、薛の帳簿を開き、一行ずつ厳しい目で確認を始めた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"inspect_02_02","choices":[{"label":"続ける","next":"inspect_02_02"}]},"inspect_02_02":{"text":"巡検使の鋭い質問が飛ぶたびに、薛の呼吸が乱れる。帳簿の改ざんはあまりに稚拙だ。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"inspect_02_03","choices":[{"label":"続ける","next":"inspect_02_03"}]},"inspect_02_03":{"text":"視線のやり取り。巡検使の部下たちが、部屋の警備状況を観察している様子が窺える。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"inspect_03","choices":[{"label":"続ける","next":"inspect_03"}]},"inspect_03":{"text":"部屋の隅で護衛として控える。薛の額には、隠しきれないほどの冷や汗が浮かんでいる。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"evening_01","choices":[{"label":"続ける","next":"evening_01"}]},"evening_01":{"text":"そして三日目の夕方。巡検使の厳しい追及をどうにか躱し、視察もいよいよ終わりに近づいていた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"evening_02","choices":[{"label":"続ける","next":"evening_02"}]},"evening_02":{"text":"だが、急激に胸騒ぎがする。風の音が止み、鳥たちが一斉に屋敷の森から飛び去った。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"evening_02_02","choices":[{"label":"続ける","next":"evening_02_02"}]},"evening_02_02":{"text":"気配が屋敷の周囲を幾重にも囲んでいく。彼らはただの刺客ではない、本物のプロだ。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"evening_02_03","choices":[{"label":"続ける","next":"evening_02_03"}]},"evening_02_03":{"text":"音もなく忍び寄る影。月光に照らされた屋根の上に、数人の武装した影が浮かび上がった。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"evening_03","choices":[{"label":"続ける","next":"evening_03"}]},"evening_03":{"text":"塀の外に、初日とは比べ物にならないほど多くの、そして研ぎ澄まされた殺気を感じる。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"evening_04","choices":[{"label":"続ける","next":"evening_04"}]},"evening_04":{"text":"障子を突き破り、上級の暗殺者たちが一斉になだれ込んできた！","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"政敵の放った精鋭の刺客部隊が襲来した！","type":"battle","bg_key":"bg_karyu_palace","bgm":"bgm_battle_boss","enemy_group_id":"446","choices":[{"label":"win","next":"over_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"over_01"},"over_01":{"text":"激しい斬り合いの末、最後の刺客が崩れ落ちた。屋敷は血と破壊 of 痕にまみれている。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"over_02","choices":[{"label":"続ける","next":"over_02"}]},"over_02":{"text":"翌朝。帳簿の改ざんを最後まで見抜けなかった巡検使は、不満げに屋敷を去っていった。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"over_03","choices":[{"label":"続ける","next":"over_03"}]},"over_03":{"text":"「はぁ……はぁ……助かった……」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"薛","speaker":"薛","next":"over_03_02","choices":[{"label":"続ける","next":"over_03_02"}]},"over_03_02":{"text":"薛は膝から崩れ落ち、へたり込んで安堵の息を吐いた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"over_04","choices":[{"label":"続ける","next":"over_04"}]},"over_04":{"text":"「約束の報酬だ。今後も私の身に何かあれば、必ずお前を頼る」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","speaker_name":"薛","speaker":"薛","next":"over_04_02","choices":[{"label":"続ける","next":"over_04_02"}]},"over_04_02":{"text":"薛から、約束通り金の延べ棒が詰まった重い袋を渡された。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"leave_official","choices":[{"label":"続ける","next":"leave_official"}]},"leave_official":{"text":"薛がパーティから離脱した。三日三晩、暗殺者の凶刃からこの男の命を守り抜いた。","type":"leave","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","params":{"guest_id":"npc_corrupt_official"},"next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"屋敷を後にする。重い金袋の感触だけが手元に残った。","type":"text","bg_key":"bg_har_city","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"守ったのは悪人であり、華龍国の腐敗は続く。だが自分には関係ない。","type":"end","result":"success","bg_key":"bg_har_city","params":{"rewards":{"gold":500,"exp":120,"alignment_shift":{"chaos":10,"evil":5}}},"choices":[]},"end_failure_01":{"text":"刺客の変幻自在な動きに翻弄され、守備網を突破されてしまった。","type":"text","bg_key":"bg_karyu_palace","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"背後で薛の断末魔の悲鳴が響き、屋敷は深い静寂に包まれた……。","type":"end","result":"failure","bg_key":"bg_karyu_palace","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[護衛] 悪徳官僚を暗殺者の刃から守り抜く。"}'::jsonb,
    6,
    4
