-- Scenario 7044: 沿岸を荒らす海賊の討伐 (qst_har_pirate)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7044,
    'qst_har_pirate',
    '沿岸を荒らす海賊の討伐',
    '[討伐] 水賊の拠点へ奇襲をかけ、略奪品を奪い返す。',
    '港町の長',
    2,
    7,
    5,
    '{"gold":400,"items":[],"exp":120,"alignment_shift":{"chaos":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_haryu']::text[],
    '{"location_tags":["loc_haryu"]}'::jsonb,
    '{"nodes":{"start":{"text":"華龍国の南沿岸にある港町。その顔役である長から、手書きの海図と討伐の依頼書を受け取った。","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「沿岸を荒らしている忌々しい水賊どもめ。奴らの本拠地がようやく割れた」","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_quest_calm","speaker_name":"港町の長","speaker":"港町の長","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「水賊の船は入り江に停泊している。奪われた荷は一つ残らず港に返してくれ」","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_quest_calm","speaker_name":"港町の長","speaker":"港町の長","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"そう言う長の目は、正義感からではなく、計算高く欲深い光を帯びていた。","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_quest_calm","next":"intel_01","choices":[{"label":"続ける","next":"intel_01"}]},"intel_01":{"text":"奇襲をかける前に、港の薄汚れた酒場で水賊たちの情報を集めることにした。","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_field","next":"intel_01_02","choices":[{"label":"続ける","next":"intel_01_02"}]},"intel_01_02":{"text":"酒場には塩気と安酒の臭いが漂っている。片目の船乗りたちがこちらを値踏みするように見た。","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_field","next":"intel_01_03","choices":[{"label":"続ける","next":"intel_01_03"}]},"intel_01_03":{"text":"銅貨を数枚カウンターに滑らせると、主人は周囲を気にしながら身を乗り出してきた。","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_field","next":"intel_02","choices":[{"label":"続ける","next":"intel_02"}]},"intel_02":{"text":"酔客の話によると、水賊は中型のガレオン船を三隻所有する大規模な集団らしい。","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_field","next":"intel_03","choices":[{"label":"続ける","next":"intel_03"}]},"intel_03":{"text":"頭目は「黒鰐（くろわに）」と呼ばれる大男で、元帝国海軍の将校だったという噂だ。","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_field","next":"intel_04","choices":[{"label":"続ける","next":"intel_04"}]},"intel_04":{"text":"「単なるならず者じゃない。戦い方は一流の軍人のそれだ」","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_field","speaker_name":"酒場の主人","speaker":"酒場の主人","next":"intel_04_02","choices":[{"label":"続ける","next":"intel_04_02"}]},"intel_04_02":{"text":"酒場の主人が青ざめた顔でそう忠告してくれた。","type":"text","bg_key":"bg_karyu_port","bgm":"bgm_field","next":"night_01","choices":[{"label":"続ける","next":"night_01"}]},"night_01":{"text":"夜半過ぎ。月が雲に隠れたのを見計らい、用意した小舟を静かに漕ぎ出す。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_mystery","next":"night_02","choices":[{"label":"続ける","next":"night_02"}]},"night_02":{"text":"岬を大回りして迂回する。海は墨を流したように暗く、潮の匂いが鼻をつく。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_mystery","next":"night_03","choices":[{"label":"続ける","next":"night_03"}]},"night_03":{"text":"波の音だけが響く中、遠くの暗闇にポツンと浮かぶ入り江の松明が見えてきた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_mystery","next":"cove_01","choices":[{"label":"続ける","next":"cove_01"}]},"cove_01":{"text":"入り江の奥に接近する。情報通り、三隻 of 船が寄り添うように停泊していた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"cove_02","choices":[{"label":"続ける","next":"cove_02"}]},"cove_02":{"text":"一番巨大な旗艦の舷側から、太い錨の鎖が海面に向かってぶら下がっている。あそこから登れそうだ。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"climb_01","choices":[{"label":"続ける","next":"climb_01"}]},"climb_01":{"text":"小舟を密かに接舷させ、濡れて滑る重い鎖を力一杯握りしめる。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"climb_01_02","choices":[{"label":"続ける","next":"climb_01_02"}]},"climb_01_02":{"text":"冷たい夜露と潮水が鎖を滑りやすくしている。一歩誤れば暗い海へ真っ逆さまだ。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"climb_01_03","choices":[{"label":"続ける","next":"climb_01_03"}]},"climb_01_03":{"text":"波が船体にぶつかる音が、こちらの登る音をかき消してくれている。運は味方している。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"climb_02","choices":[{"label":"続ける","next":"climb_02"}]},"climb_02":{"text":"海に落ちないよう慎重に這い上がり、甲板の縁に指をかけた。見張りの足音が遠ざかる……今だ。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"surprise_01","choices":[{"label":"続ける","next":"surprise_01"}]},"surprise_01":{"text":"音もなく甲板に翻り、背を向けていた見張りの口を塞いで一瞬で組み伏せた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"surprise_02","choices":[{"label":"続ける","next":"surprise_02"}]},"surprise_02":{"text":"しかし、マストの上にいたもう一人の見張りがこちらの存在に気づいた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"surprise_03","choices":[{"label":"続ける","next":"surprise_03"}]},"surprise_03":{"text":"「敵だ！ 甲板に侵入者だ！ 野郎ども起きろォッ！！」","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","speaker_name":"水賊","speaker":"水賊","next":"surprise_03_02","choices":[{"label":"続ける","next":"surprise_03_02"}]},"surprise_03_02":{"text":"銅鑼の音がけたたましく鳴り響き、船全体が揺れるような怒号が巻き起こった。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"battle_deck","choices":[{"label":"続ける","next":"battle_deck"}]},"battle_deck":{"text":"寝込みを襲われた水賊たちが、武器を手に群がってきた！","type":"battle","bg_key":"bg_karyu_coast","bgm":"bgm_battle","enemy_group_id":"447","choices":[{"label":"win","next":"clear_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"clear_01"},"clear_01":{"text":"血塗られた甲板。雑兵どもを海へと蹴り落とし、船の上層部の制圧を完了した。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"clear_02","choices":[{"label":"続ける","next":"clear_02"}]},"clear_02":{"text":"静まり返った甲板に、真下の船倉から地鳴りのような重い足音と怒号が響いてきた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"ship_01","choices":[{"label":"続ける","next":"ship_01"}]},"ship_01":{"text":"階段を下り、船長室の分厚いオーク材の扉を蹴り開ける。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"ship_01_02","choices":[{"label":"続ける","next":"ship_01_02"}]},"ship_01_02":{"text":"船室の廊下は薄暗く、ランプの光が左右に揺れている。火薬と血の臭いが濃くなってきた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"ship_01_03","choices":[{"label":"続ける","next":"ship_01_03"}]},"ship_01_03":{"text":"突き当たりにある豪奢な扉の向こうから、荒い呼吸と戦斧を研ぐ不気味な音が響いている。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"ship_02","choices":[{"label":"続ける","next":"ship_02"}]},"ship_02":{"text":"室内には、全身に無数の刀傷を刻んだ筋骨隆々の大男が、巨大な戦斧を手にして仁王立ちしていた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","next":"ship_03","choices":[{"label":"続ける","next":"ship_03"}]},"ship_03":{"text":"「たかが冒険者一人で俺の船に乗り込むとは、いい度胸だ。海の藻屑にしてやる！！」","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_tense","speaker_name":"水賊の頭目「黒鰐」","speaker":"水賊の頭目「黒鰐」","next":"battle_captain","choices":[{"label":"続ける","next":"battle_captain"}]},"battle_captain":{"text":"水賊の頭目「黒鰐」との戦い！","type":"battle","bg_key":"bg_karyu_coast","bgm":"bgm_battle_boss","enemy_group_id":"448","choices":[{"label":"win","next":"captain_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"captain_01"},"captain_01":{"text":"激しい戦斧の猛攻を紙一重で躱し、大男の急所に刃を突き立てた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","next":"captain_02","choices":[{"label":"続ける","next":"captain_02"}]},"captain_02":{"text":"「ガハッ……見事だ……」","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","speaker_name":"水賊の頭目「黒鰐」","speaker":"水賊の頭目「黒鰐」","next":"captain_02_02","choices":[{"label":"続ける","next":"captain_02_02"}]},"captain_02_02":{"text":"黒鰐が重い音を立てて膝をついた。血まみれだが、軍人としての誇り高い目は死んでいない。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","next":"captain_03","choices":[{"label":"続ける","next":"captain_03"}]},"captain_03":{"text":"「長に言っておけ。俺が襲った船の利益の二割は、あの男の懐に入っていたと」","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","speaker_name":"水賊の頭目「黒鰐」","speaker":"水賊の頭目「黒鰐」","next":"captain_03_02","choices":[{"label":"続ける","next":"captain_03_02"}]},"captain_03_02":{"text":"どうやら長の目的は、上前を撥ねていた自分たちの秘密を闇に葬ることだったらしい。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","next":"choice_captain","choices":[{"label":"続ける","next":"choice_captain"}]},"choice_captain":{"text":"膝をつき、死を覚悟した黒鰐に止めを刺すか？","type":"choice","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","choices":[{"label":"止めを刺す——悪党の事情は関係ない","next":"cargo_01"},{"label":"見逃す——長を強請るための手駒にする","next":"deal_01"}]},"cargo_01":{"text":"誰が裏で糸を引いていようと、自分の仕事は依頼の完遂だ。無言で刃を振り下ろし、黒鰐の首を刎ねた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","next":"cargo_02","choices":[{"label":"続ける","next":"cargo_02"}]},"cargo_02":{"text":"船倉には絹布などの略奪品が山積みにされていた。生き残った水賊に操縦させ帰還する。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"水賊討伐完了。港町の長から、安堵の表情と共に報酬を受け取った。","type":"text","bg_key":"bg_karyu_port","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「これで港も静かになる。本当にありがたい」","type":"end","result":"success","bg_key":"bg_karyu_port","speaker_name":"港町の長","speaker":"港町の長","params":{"rewards":{"gold":400,"exp":120,"alignment_shift":{"chaos":5}}},"choices":[]},"deal_01":{"text":"刃を下ろし、黒鰐を見逃す代わりに「長との裏取引の証拠」を渡すよう持ちかけた。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","next":"deal_02","choices":[{"label":"続ける","next":"deal_02"}]},"deal_02":{"text":"「ククッ……欲の皮が突っ張った面白い冒険者だな。いいだろう」","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","speaker_name":"水賊の頭目「黒鰐」","speaker":"水賊の頭目「黒鰐」","next":"deal_02_02","choices":[{"label":"続ける","next":"deal_02_02"}]},"deal_02_02":{"text":"黒鰐は血まみれの顔で笑い、隠し金庫から分厚い帳簿を取り出して渡した。","type":"text","bg_key":"bg_karyu_coast","bgm":"bgm_quest_calm","next":"end_success_deal_01","choices":[{"label":"続ける","next":"end_success_deal_01"}]},"end_success_deal_01":{"text":"長には「頭目は逃げたが荷は奪い返した」と報告し、一部の報酬を受け取る。","type":"text","bg_key":"bg_karyu_port","next":"end_success_deal","choices":[{"label":"続ける","next":"end_success_deal"}]},"end_success_deal":{"text":"悪人の間を泳ぎ、利益を掠め取る。この国で生き残るには、これが一番賢い。","type":"end","result":"success","bg_key":"bg_karyu_port","params":{"rewards":{"gold":250,"exp":120,"alignment_shift":{"evil":5}}},"choices":[]},"end_failure_01":{"text":"黒鰐の振るう戦斧の一撃をまともに受け、身体が宙に浮き、海へと叩き落とされた。","type":"text","bg_key":"bg_karyu_coast","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"塩水に肺を焼かれながら、意識は深い海の底へとゆっくり沈んでいった……。","type":"end","result":"failure","bg_key":"bg_karyu_coast","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[討伐] 水賊の拠点へ奇襲をかけ、略奪品を奪い返す。"}'::jsonb,
    5,
    3
