-- Scenario 7045: 妖狐の嫁入り (qst_har_foxwed)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    7045,
    'qst_har_foxwed',
    '妖狐の嫁入り',
    '[救出] 妖狐に攫われた青年を救い出すか、人と妖の共存を模索せよ。',
    '村の長老',
    3,
    9,
    6,
    '{"gold":400,"items":[],"exp":120,"reputation":5,"alignment_shift":{"justice":5}}'::jsonb,
    false,
    'normal',
    '{}'::jsonb,
    ARRAY['loc_haryu']::text[],
    '{"location_tags":["loc_haryu"]}'::jsonb,
    '{"nodes":{"start":{"text":"「阿明が戻らん。あの子は村一番の薬師だというのに……」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","speaker_name":"長老","speaker":"長老","next":"start_01_02","choices":[{"label":"続ける","next":"start_01_02"}]},"start_01_02":{"text":"村の広場は、静まり返っている。薬師のいなくなった村の空気は、どこか冷たい。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「三日前の夕暮れ、山道で花嫁行列と歩いておったのを見た者がおる」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","speaker_name":"長老","speaker":"長老","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（花嫁行列？ この山奥の村で、こんな時期に婚礼など聞いたこともないが）","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「花嫁行列はこの村の者ではない。あれは妖狐の嫁入り行列よ」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","speaker_name":"長老","speaker":"長老","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"長老は声を潜め、震える手で山の山頂を指さした。周囲の者たちも青ざめている。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"青年を取り戻すには、妖異が支配する霧深き山道へ踏み込まねばならない。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"start_04_02","choices":[{"label":"続ける","next":"start_04_02"}]},"start_04_02":{"text":"（妖狐の嫁入りか。ただの迷信とは思えない。念のため、銀の武器を磨いておくか）","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"覚悟を決め、背嚢を背負う。冷たい小雨が降り始める中、山道へと足を踏み入れた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"road_01","choices":[{"label":"続ける","next":"road_01"}]},"road_01":{"text":"山道に入ると、たちまち濃い霧が立ち込めてきた。視界は数歩先すらおぼつかない。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"road_01_02","choices":[{"label":"続ける","next":"road_01_02"}]},"road_01_02":{"text":"ふと足元を見ると、季節外れの桃の花びらが、湿った土の上に散らばっている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"road_02","choices":[{"label":"続ける","next":"road_02"}]},"road_02":{"text":"霧の奥から、ぼんやりと赤い光が浮かび上がる。道沿いに並ぶ古びた提灯だ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"road_02_02","choices":[{"label":"続ける","next":"road_02_02"}]},"road_02_02":{"text":"（風もないのに、炎が生き物のように揺らめいている……歓迎されていないな）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"road_03","choices":[{"label":"続ける","next":"road_03"}]},"road_03":{"text":"提灯の火が不規則に瞬き、行く手が二股に分かれた。どちらも暗い霧に消えている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"road_03_02","choices":[{"label":"続ける","next":"road_03_02"}]},"road_03_02":{"text":"（妖狐の術か。立ち止まれば幻惑される。直感を信じて進むしかない）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"random_fog","choices":[{"label":"続ける","next":"random_fog"}]},"random_fog":{"type":"random_branch","bg_key":"bg_karyu_mountain","prob":50,"choices":[{"label":"success","next":"road_04"},{"label":"failure","next":"lost_01"}]},"road_04":{"text":"意を決して左 of 細道を選ぶ。不意に霧が薄れ、せせらぎの音が聞こえてきた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"road_04_02","choices":[{"label":"続ける","next":"road_04_02"}]},"road_04_02":{"text":"（どうやら正しい道を選べたようだ。だが、この空気の重さは何だ？）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"road_05","choices":[{"label":"続ける","next":"road_05"}]},"road_05":{"text":"提灯の列は途切れ、周囲には蛍のような淡い光が漂い始めた。妖しき狐火だ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"road_05_02","choices":[{"label":"続ける","next":"road_05_02"}]},"road_05_02":{"text":"（狐火が道を案内しているかのようだな。それとも、罠へ誘い込んでいるのか？）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"road_06","choices":[{"label":"続ける","next":"road_06"}]},"road_06":{"text":"光に導かれるように歩みを進めると、谷間に架かる一本の太鼓橋が見えてきた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"bridge_01","choices":[{"label":"続ける","next":"bridge_01"}]},"lost_01":{"text":"右の道を進んだが、いつの間にか元の分岐点へと戻っていた。完全に迷ったのだ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"lost_01_02","choices":[{"label":"続ける","next":"lost_01_02"}]},"lost_01_02":{"text":"（くそ、幻術に足元をすくわれたか。焦るな、周囲の気配をよく探るんだ）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"lost_02","choices":[{"label":"続ける","next":"lost_02"}]},"lost_02":{"text":"霧の中に踏み出すと、足元に銀色に光る細い糸が、蜘蛛の巣のように張られていた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"lost_trap","choices":[{"label":"続ける","next":"lost_trap"}]},"lost_trap":{"text":"妖力を帯びた糸が肌に触れた瞬間、激しい痺れが走り、体力が削られていく。","type":"hp_damage","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"lost_03","choices":[{"label":"続ける","next":"lost_03"}]},"lost_03":{"text":"痺れる足を引きずりながら、必死に霧の中を走る。ようやく水音が聞こえてきた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"lost_03_02","choices":[{"label":"続ける","next":"lost_03_02"}]},"lost_03_02":{"text":"這い出た先には、小川を跨ぐ古びた橋があった。何とか幻術の領域を脱したようだ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"bridge_01","choices":[{"label":"続ける","next":"bridge_01"}]},"bridge_01":{"text":"朱塗りの太鼓橋が、闇の中に浮かび上がっている。欄干には狐の彫刻が刻まれている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"bridge_01_02","choices":[{"label":"続ける","next":"bridge_01_02"}]},"bridge_01_02":{"text":"（この橋の向こうが、奴らの隠れ里……。引き返すなら、今のうちだが）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"bridge_02","choices":[{"label":"続ける","next":"bridge_02"}]},"bridge_02":{"text":"橋を渡ろうとした瞬間、対岸から素早い獣の影——二頭の妖狐が姿を現した。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"bridge_02_02","choices":[{"label":"続ける","next":"bridge_02_02"}]},"bridge_02_02":{"text":"狐たちは鋭い牙を剥き出し、低く唸り声を上げる。通す気は微塵もないようだ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"type":"battle","bg_key":"bg_karyu_mountain","bgm":"bgm_battle","enemy_group_id":"452","choices":[{"label":"win","next":"grove_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"grove_01"},"grove_01":{"text":"妖狐たちを退け、橋を渡りきる。と、目の前に信じがたい光景が広がった。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"grove_01_02","choices":[{"label":"続ける","next":"grove_01_02"}]},"grove_01_02":{"text":"そこは、満月の光を浴びて、桃の花が満開に咲き乱れる静寂の林だった。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"grove_02","choices":[{"label":"続ける","next":"grove_02"}]},"grove_02":{"text":"花びらが雪のように舞い散る中、小さな狐たちが、行儀よく一列に並んでいる。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"grove_02_02","choices":[{"label":"続ける","next":"grove_02_02"}]},"grove_02_02":{"text":"小狐たちは皆、小さな赤い提灯を掲げ、じっとこちらを見つめている。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"grove_03","choices":[{"label":"続ける","next":"grove_03"}]},"grove_03":{"text":"その奇妙な行列の突き当たりに、ひときわ白く輝く衣を纏った女性が立っていた。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"grove_03_02","choices":[{"label":"続ける","next":"grove_03_02"}]},"grove_03_02":{"text":"（あれが花嫁……いや、頭部から生える白い耳、そして怪しく光る金色の瞳）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"grove_04","choices":[{"label":"続ける","next":"grove_04"}]},"grove_04":{"text":"彼女こそが、この山を統べる妖狐の姫だった。凛とした佇まいでこちらを見据える。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"grove_05","choices":[{"label":"続ける","next":"grove_05"}]},"grove_05":{"text":"「人の子よ、何用だ。これは我らの祝いの儀。無用な立ち入りは許さぬ」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","speaker_name":"妖狐の姫","speaker":"妖狐の姫","next":"reunion_01","choices":[{"label":"続ける","next":"reunion_01"}]},"reunion_01":{"text":"「あ……冒険者さん！？ なぜ、こんな危険な場所にまで……！」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","speaker_name":"阿明","speaker":"阿明","next":"reunion_01_02","choices":[{"label":"続ける","next":"reunion_01_02"}]},"reunion_01_02":{"text":"姫の傍らに、行方不明になっていた阿明が立っていた。傷を負った様子はない。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"reunion_02","choices":[{"label":"続ける","next":"reunion_02"}]},"reunion_02":{"text":"「僕は無理やり連れ去られたわけじゃない。彼女は昔、僕が救った狐なんだ」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","speaker_name":"阿明","speaker":"阿明","next":"reunion_02_02","choices":[{"label":"続ける","next":"reunion_02_02"}]},"reunion_02_02":{"text":"（助けた狐が恩返しに？ 昔話のようなことが、本当に起きているというのか）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"reunion_03","choices":[{"label":"続ける","next":"reunion_03"}]},"reunion_03":{"text":"「この者は私の命の恩人。その優しさに惹かれ、共に生きると誓い合ったのだ」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","speaker_name":"妖狐の姫","speaker":"妖狐の姫","next":"reunion_03_02","choices":[{"label":"続ける","next":"reunion_03_02"}]},"reunion_03_02":{"text":"姫は阿明の手を優しく取り、微笑んだ。その表情には、確かな慈愛が宿っていた。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","choices":[{"label":"「人は人の世で暮らすべきだ。青年を返してもらう」","next":"battle_02"},{"label":"「二人の意思を尊重する。村には事情を伝えよう」","next":"coexist_01"}]},"battle_02":{"type":"battle","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","enemy_group_id":"453","choices":[{"label":"win","next":"rescue_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"rescue_01"},"rescue_01":{"text":"激闘の末、姫が膝をつく。「……やはり、人と妖が相容れることは叶わぬか」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"rescue_01_02","choices":[{"label":"続ける","next":"rescue_01_02"}]},"rescue_01_02":{"text":"姫の目からこぼれ落ちた涙は、桃の花びらとなって風に溶けて消えていった。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"rescue_02","choices":[{"label":"続ける","next":"rescue_02"}]},"rescue_02":{"text":"うつむく阿明の手を引き、山を下りる。二度と振り返ろうとはしなかった。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"rescue_02_02","choices":[{"label":"続ける","next":"rescue_02_02"}]},"rescue_02_02":{"text":"背後を振り返ると、満開だった桃の林は消え去り、ただの枯れ木が立っていた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"end_success_01","choices":[{"label":"続ける","next":"end_success_01"}]},"end_success_01":{"text":"村へ戻り、長老に阿明を引き渡す。長老は涙を流して感謝の言葉を繰り返した。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"だが、阿明の虚ろな瞳が物語っていた。彼が本当に心を残してきた場所を。","type":"end","result":"success","bg_key":"bg_karyu_village","params":{"rewards":{"gold":400,"exp":120,"reputation":5,"alignment_shift":{"justice":5}}},"choices":[]},"coexist_01":{"text":"「人の子よ……その寛大さに感謝する。この護符を旅の守りとせよ」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","speaker_name":"妖狐の姫","speaker":"妖狐の姫","next":"coexist_02","choices":[{"label":"続ける","next":"coexist_02"}]},"coexist_02":{"text":"姫から青白く輝く「狐火の護符」を手渡された。ほんのりと温かい。","type":"reward","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","params":{"item_id":"item_foxfire_charm"},"next":"coexist_02_02","choices":[{"label":"続ける","next":"coexist_02_02"}]},"coexist_02_02":{"text":"二人の姿は霧の中に消えていった。だが、その背中は幸福に満ちていた。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"coexist_03","choices":[{"label":"続ける","next":"coexist_03"}]},"coexist_03":{"text":"村に戻り、長老に事情を伝える。長老は驚いたが、深くため息をついて頷いた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"coexist_03_02","choices":[{"label":"続ける","next":"coexist_03_02"}]},"coexist_03_02":{"text":"「そうか……阿明が選んだ道なら、引き留めることはできまいな」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","speaker_name":"長老","speaker":"長老","next":"end_success_chaos_01","choices":[{"label":"続ける","next":"end_success_chaos_01"}]},"end_success_chaos_01":{"text":"阿明は時折、村の薬草置き場に珍しい薬草を届けてくれるようになったという。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"end_success_chaos","choices":[{"label":"続ける","next":"end_success_chaos"}]},"end_success_chaos":{"text":"人と妖が共に歩む道。それが過ちか、あるいは新たな夜明けか、誰にも分からぬ。","type":"end","result":"success","bg_key":"bg_karyu_village","params":{"rewards":{"gold":350,"exp":120,"reputation":-5,"alignment_shift":{"chaos":5}}},"choices":[]},"end_failure_01":{"text":"妖狐たちの放つ強烈な妖気に呑まれ、意識は深い闇の中へと引きずり込まれた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"気づけば山麓に倒れていた。腕の引っ掻き傷だけが、あの奇妙な夢の証だった。","type":"end","result":"failure","bg_key":"bg_karyu_mountain","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[救出] 妖狐に攫われた青年を救い出すか、人と妖の共存を模索せよ。"}'::jsonb,
    6,
    6
) ON CONFLICT (id) DO UPDATE SET
