    ARRAY[]::text[],
    '{"location_id":"loc_border_town","min_level":1}'::jsonb,
    '{"nodes":{"start":{"text":"肌を焦がすような乾いた風が、荒涼たる砂丘を撫でるように吹き抜ける。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"ここはローランド聖王国の最辺境。王国の威光も届かぬ寂れた地だ。","type":"text","bg_key":"bg_road_day","next":"village_01","choices":[{"label":"続ける","next":"village_01"}]},"village_01":{"text":"崩れかけた土壁、痩せ細った家畜、そして泥水がわずかに底に溜まる井戸。","type":"text","bg_key":"bg_road_day","next":"village_02","choices":[{"label":"続ける","next":"village_02"}]},"village_02":{"text":"そんな行き止まりのような境界の村から——君の物語は静かに始まる。","type":"text","bg_key":"bg_road_day","next":"board_01","choices":[{"label":"続ける","next":"board_01"}]},"board_01":{"text":"村の入口に立つ古びた掲示板。風雨に晒され、黄ばんだ羊皮紙が留められている。","type":"text","bg_key":"bg_road_day","next":"board_02","choices":[{"label":"続ける","next":"board_02"}]},"board_02":{"text":"『傭兵募集——王国軍輸送部隊の護衛。報酬は銀貨十五枚。死亡保障なし』","type":"text","bg_key":"bg_road_day","next":"board_03","choices":[{"label":"続ける","next":"board_03"}]},"board_03":{"text":"銀貨十五枚。これだけあれば一ヶ月は食いつなげる。迷う理由はなかった。","type":"text","bg_key":"bg_road_day","next":"cargo_01","choices":[{"label":"続ける","next":"cargo_01"}]},"cargo_01":{"text":"手配された荷馬車は三台。積まれた木箱には『軍需物資』とだけ書かれていた。","type":"text","bg_key":"bg_road_day","next":"cargo_02","choices":[{"label":"続ける","next":"cargo_02"}]},"cargo_02":{"text":"護衛にあたる兵士は六人。全員が疲弊し、その目はどんよりと濁っている。","type":"text","bg_key":"bg_road_day","next":"gawain_01","choices":[{"label":"続ける","next":"gawain_01"}]},"gawain_01":{"text":"荷の数を確認しようとした時、背後からしゃがれた太い声が降ってきた。","type":"text","bg_key":"bg_road_day","next":"gawain_02","choices":[{"label":"続ける","next":"gawain_02"}]},"gawain_02":{"text":"「おい、そこの新入り！ぼんやりするな。野盗の餌食になりたいのか？」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_03","choices":[{"label":"続ける","next":"gawain_03"}]},"gawain_03":{"text":"振り返ると、砂埃にまみれた甲冑をまとう巨漢が立っていた。額に古い傷がある。","type":"text","bg_key":"bg_road_day","next":"gawain_04","choices":[{"label":"続ける","next":"gawain_04"}]},"gawain_04":{"text":"「ほう、お前が今日の新しい肉壁か。剣の腕は少しは期待できるんだろうな」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"choice1","choices":[{"label":"続ける","next":"choice1"}]},"choice1":{"type":"choice","bg_key":"bg_road_day","choices":[{"label":"「急いで積み込みます」","next":"react_01"},{"label":"「あんたはここで指図するだけか？」","next":"react_01"}]},"react_01":{"text":"男は鼻で笑った。だが、兜の奥の鋭い眼光は一切笑っていなかった。","type":"text","bg_key":"bg_road_day","next":"react_02","choices":[{"label":"続ける","next":"react_02"}]},"react_02":{"text":"「威勢はいいが、口だけの奴から戦場で冷たくなっていく。忘れるなよ」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"name_01","choices":[{"label":"続ける","next":"name_01"}]},"name_01":{"text":"「俺はガウェイン。この小隊の長だ。死にたくなければ俺の背から離れるな」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"name_02","choices":[{"label":"続ける","next":"name_02"}]},"name_02":{"text":"ガウェインは砂漠の地平線を見つめた。その瞳に深い哀愁が滲んでいた。","type":"text","bg_key":"bg_road_day","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_gawain"},"next":"alarm_01","choices":[{"label":"続ける","next":"alarm_01"}]},"alarm_01":{"text":"ガウェインが何かを言いかけた、まさにその瞬間——","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"alarm_02","choices":[{"label":"続ける","next":"alarm_02"}]},"alarm_02":{"text":"風の唸りを超えて、複数の怒声と馬の嘶きがこちらへ迫ってきた！","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"scout_01","choices":[{"label":"続ける","next":"scout_01"}]},"scout_01":{"text":"「武装集団が接近！野盗です！」","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","speaker_name":"斥候兵","speaker":"斥候兵","next":"order_01","choices":[{"label":"続ける","next":"order_01"}]},"order_01":{"text":"ガウェインが素早く大剣を引き抜く。「各自武器を取れ！荷を死守するぞ！」","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"taunt_01","choices":[{"label":"続ける","next":"taunt_01"}]},"taunt_01":{"text":"「おい王国の犬ども、荷を置いて失せな！」","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","speaker_name":"野盗の頭目","speaker":"野盗の頭目","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","enemy_group_id":"200","choices":[{"label":"win","next":"post_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"post_01"},"post_01":{"text":"大剣を振り抜き、最後の野盗を沈めた。息が荒く、手が小刻みに震えている。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"dying_01","choices":[{"label":"続ける","next":"dying_01"}]},"dying_01":{"text":"足元に倒れ伏した野盗が、息絶え絶えの状態でこちらを見上げてきた。","type":"text","bg_key":"bg_road_day","next":"dying_02","choices":[{"label":"続ける","next":"dying_02"}]},"dying_02":{"text":"「やるな……だが、俺たちにこの荷を襲うよう依頼したのは……王国の官僚だ」","type":"text","bg_key":"bg_road_day","speaker_name":"瀕死の野盗","speaker":"瀕死の野盗","next":"dying_03","choices":[{"label":"続ける","next":"dying_03"}]},"dying_03":{"text":"男は血を吐き、そのまま静かに事切れた。その言葉だけが重く残る。","type":"text","bg_key":"bg_road_day","next":"look_01","choices":[{"label":"続ける","next":"look_01"}]},"look_01":{"text":"ガウェインは死体を見下ろした。その表情は、鬼のように険しかった。","type":"text","bg_key":"bg_road_day","next":"praise_01","choices":[{"label":"続ける","next":"praise_01"}]},"praise_01":{"text":"「……悪くない太刀筋だ。新兵の初陣としてはな。生き残ったことを誇れ」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"praise_02","choices":[{"label":"続ける","next":"praise_02"}]},"praise_02":{"text":"老騎士は一度だけ肩を叩いた。まるで大岩のような、温かく重い手だった。","type":"text","bg_key":"bg_road_day","next":"depart_01","choices":[{"label":"続ける","next":"depart_01"}]},"depart_01":{"text":"「荷馬車を出すぞ。日が暮れる前に、次の宿場町へ滑り込まねばならん」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"farewell","choices":[{"label":"続ける","next":"farewell"}]},"farewell":{"text":"「また戦場で会おう。生き延びろよ、新入り。お前にはまだ先がある」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"type":"leave","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_gawain"},"next":"end_01","choices":[{"label":"続ける","next":"end_01"}]},"end_01":{"text":"宿場に着き任務は完了した。老騎士の背中が、砂埃の向こうへ消えていく。","type":"text","bg_key":"bg_road_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"「王国の連中が依頼した」——野盗の遺言が、いつまでも耳から離れない。","type":"end","result":"success","bg_key":"bg_road_day","params":{"rewards":{"exp":80,"gold":150,"reputation":5,"alignment_shift":{"order":5}}},"choices":[]},"end_failure_01":{"text":"野盗の包囲を崩せず、無数に浴びた刃の傷に崩れ落ちる。意識が混濁していく……","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"初陣の地が墓標となった。守るべき物資も、野盗の手に落ちてしまった。","type":"end","result":"failure","bg_key":"bg_road_day","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第1話"}'::jsonb,
    2,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6002: 第2話「砂礫の国境線」 (main_ep02)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6002,
    'main_ep02',
    '第2話「砂礫の国境線」',
    'メインシナリオ第2話',
    '王国軍',
    1,
    2,
    2,
    '{"gold":200,"items":[],"reputation":10,"alignment_shift":{"order":5},"move_to":"loc_oasis"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep01","location_id":"loc_border_town"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep01","location_id":"loc_border_town"}'::jsonb,
    '{"nodes":{"start":{"text":"野盗撃退の働きが認められ、ガウェインの推薦で国境警備任務に配属された。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"配属先はローランドとマルカンドの国境地帯。赤茶けた荒野が地平線まで続く。","type":"text","bg_key":"bg_road_day","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_gawain"},"next":"patrol_01","choices":[{"label":"続ける","next":"patrol_01"}]},"patrol_01":{"text":"吹き荒れる砂風を避けながら、ガウェインと共に国境沿いの岩場を進む。","type":"text","bg_key":"bg_road_day","next":"patrol_02","choices":[{"label":"続ける","next":"patrol_02"}]},"patrol_02":{"text":"周囲を歩く警備兵たちの間に、かつてないほど重苦しい緊張が漂っていた。","type":"text","bg_key":"bg_road_day","next":"suspicion_01","choices":[{"label":"続ける","next":"suspicion_01"}]},"suspicion_01":{"text":"「最近、国境を荒らす野盗どもはただのゴロツキにしちゃ統率が取れすぎている」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"suspicion_02","choices":[{"label":"続ける","next":"suspicion_02"}]},"suspicion_02":{"text":"「まるで訓練された軍人のような身のこなしだ。武器も妙に上等な物を使っている」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"suspicion_03","choices":[{"label":"続ける","next":"suspicion_03"}]},"suspicion_03":{"text":"「さらに、捕らえた奴らの懐から、どこかで見たような軍の携行食が出てきた」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"hunch_01","choices":[{"label":"続ける","next":"hunch_01"}]},"hunch_01":{"text":"「嫌な予感がするな。戦場で二十年生き延びてきた俺の直感が、そう言っている」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"choice1","choices":[{"label":"続ける","next":"choice1"}]},"choice1":{"type":"choice","bg_key":"bg_road_day","choices":[{"label":"「隣国マルカンドの兵士では？」","next":"reply_01"},{"label":"「誰であろうと、斬るだけです」","next":"reply_01"}]},"reply_01":{"text":"「隣国マルカンドの正規兵か、あるいは……。どちらにせよ、キナ臭い話だ」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"reply_02","choices":[{"label":"続ける","next":"reply_02"}]},"reply_02":{"text":"「もしこれが国家間の密命だとしたら、俺たちは巨大な陰謀の渦中にいることになる」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"reply_03","choices":[{"label":"続ける","next":"reply_03"}]},"reply_03":{"text":"「まあいい、目の前の境界を守るのが俺たちの役目だ。警戒を怠るなよ」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"approach_01","choices":[{"label":"続ける","next":"approach_01"}]},"approach_01":{"text":"その時、遠方の陽炎の向こうから、黒い布で顔を覆った集団が現れた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"approach_02","choices":[{"label":"続ける","next":"approach_02"}]},"approach_02":{"text":"彼らは馬を巧みに操り、我々を半包囲するような陣形で急速に接近してくる！","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"formation_01","choices":[{"label":"続ける","next":"formation_01"}]},"formation_01":{"text":"「敵襲だ！ 陣形を崩すな！ 荷馬車を囲んで盾を作れ！」","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"formation_02","choices":[{"label":"続ける","next":"formation_02"}]},"formation_02":{"text":"「新入り、俺の左翼を任せる。抜けさせるなよ！」","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"enemy_01","choices":[{"label":"続ける","next":"enemy_01"}]},"enemy_01":{"text":"黒布の男たちから鋭い口笛が響く。先頭の男が冷徹に手を下ろした。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"enemy_02","choices":[{"label":"続ける","next":"enemy_02"}]},"enemy_02":{"text":"「全員殺せ。証拠は一切残すな。ローランドの兵にこの地を渡すな！」","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","speaker_name":"黒装束の指揮官","speaker":"黒装束の指揮官","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle","enemy_group_id":"202","choices":[{"label":"win","next":"post_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"post_01"},"post_01":{"text":"辛くも敵を撃退した。だが、敵の遺体から見つかったのは野盗の所持品ではない。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"post_02","choices":[{"label":"続ける","next":"post_02"}]},"post_02":{"text":"黒い布を引き剥がすと、現れたのはまだ若い兵士の顔だった。軍の制服だ。","type":"text","bg_key":"bg_road_day","next":"dying_01","choices":[{"label":"続ける","next":"dying_01"}]},"dying_01":{"text":"「無駄だ……もう止まらない……」","type":"text","bg_key":"bg_road_day","speaker_name":"瀕死の襲撃兵","speaker":"瀕死の襲撃兵","next":"dying_02","choices":[{"label":"続ける","next":"dying_02"}]},"dying_02":{"text":"「我々は……上からの命令に従っただけだ……逆らえば、家族が消される……」","type":"text","bg_key":"bg_road_day","speaker_name":"瀕死の襲撃兵","speaker":"瀕死の襲撃兵","next":"corpse_01","choices":[{"label":"続ける","next":"corpse_01"}]},"corpse_01":{"text":"男は事切れた。ガウェインがその死体が持っていた剣を拾い上げ、凝視する。","type":"text","bg_key":"bg_road_day","next":"corpse_02","choices":[{"label":"続ける","next":"corpse_02"}]},"corpse_02":{"text":"剣の根元。鋭利な刃で削り潰されているが、ローランド正規軍の紋章の跡が見える。","type":"text","bg_key":"bg_road_day","next":"silent_01","choices":[{"label":"続ける","next":"silent_01"}]},"silent_01":{"text":"ガウェインは無言でその紋章をなぞった。彼の大きな手が震えている。","type":"text","bg_key":"bg_road_day","next":"silent_02","choices":[{"label":"続ける","next":"silent_02"}]},"silent_02":{"text":"「……削り跡の下は、我が国の聖印だ。こいつらは……いや、よそう」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"report_01","choices":[{"label":"続ける","next":"report_01"}]},"report_01":{"text":"「このままでは大変なことになる。俺は至急、本隊へ戻って報告を入れる」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"farewell_01","choices":[{"label":"続ける","next":"farewell_01"}]},"farewell_01":{"text":"「新入り、お前も巻き込まれるなよ。次の警備地でまた合流しよう」","type":"text","bg_key":"bg_road_day","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"type":"leave","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_gawain"},"next":"end_01","choices":[{"label":"続ける","next":"end_01"}]},"end_01":{"text":"宿場町への道を急ぐ。風に舞う砂塵が、行く先を煙らせていた。","type":"text","bg_key":"bg_road_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"「家族が殺される」——死にゆく敵の言葉が、砂漠の風に溶けて消えた。","type":"end","result":"success","bg_key":"bg_road_day","params":{"rewards":{"exp":100,"gold":200,"reputation":5,"alignment_shift":{"order":5}}},"choices":[]},"end_failure_01":{"text":"統率された包囲網に切り刻まれ、膝をつく。意識が砂塵の底へ沈んでいく……","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"国境の荒野に骸が晒された。陰謀の真実が暴かれることはなかった。","type":"end","result":"failure","bg_key":"bg_road_day","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第2話"}'::jsonb,
    3,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6003: 第3話「オアシスの陰謀」 (main_ep03)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6003,
    'main_ep03',
    '第3話「オアシスの陰謀」',
    'メインシナリオ第3話',
    '交易商会',
    1,
    3,
    2,
    '{"gold":300,"items":[],"reputation":10,"alignment_shift":{"justice":5},"move_to":"loc_plains_city"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep02","location_id":"loc_oasis"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep02","location_id":"loc_oasis"}'::jsonb,
    '{"nodes":{"start":{"text":"砂塵の王国マルカンドのオアシスの街。活気ある市場に辿り着いた。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"色とりどりの布屋根が並び、商人たちの呼び声が響く。だがどこか様子が違う。","type":"text","bg_key":"bg_marcund","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"水売りたちの顔には焦燥が浮かび、市民の間には不穏な囁きが交わされていた。","type":"text","bg_key":"bg_marcund","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"type":"guest_join","bg_key":"bg_marcund","params":{"guest_id":"npc_guest_gawain"},"next":"suspicion_01","choices":[{"label":"続ける","next":"suspicion_01"}]},"suspicion_01":{"text":"「街の人間の目が明らかに警戒の色を帯びている。オアシスで何かあったな」","type":"text","bg_key":"bg_marcund","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"suspicion_02","choices":[{"label":"続ける","next":"suspicion_02"}]},"suspicion_02":{"text":"「特に水売りの奴らだ。さっきから一滴も水を売ろうとせず、頭を抱えている」","type":"text","bg_key":"bg_marcund","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"suspicion_03","choices":[{"label":"続ける","next":"suspicion_03"}]},"suspicion_03":{"text":"市場の片隅にあるオアシスの池へ向かうと、そこには異様な光景が広がっていた。","type":"text","bg_key":"bg_marcund","next":"water_01","choices":[{"label":"続ける","next":"water_01"}]},"water_01":{"text":"「おい、見ろ……池の水が赤黒く変色している。間違いない、毒を撒かれた」","type":"text","bg_key":"bg_marcund","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"water_02","choices":[{"label":"続ける","next":"water_02"}]},"water_02":{"text":"オアシスの周りには警備兵が立ち塞がり、市民の接近を厳しく阻んでいた。","type":"text","bg_key":"bg_marcund","next":"trace_01","choices":[{"label":"続ける","next":"trace_01"}]},"trace_01":{"text":"「水脈の源流を遡るぞ」ガウェインに促され、オアシスの水源洞窟へ潜り込む。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"trace_02","choices":[{"label":"続ける","next":"trace_02"}]},"trace_02":{"text":"湿った岩肌を進むと、洞窟の奥からかすかな話し声と薬品の臭いが漂ってきた。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"trace_03","choices":[{"label":"続ける","next":"trace_03"}]},"trace_03":{"text":"暗がりの陰から覗くと、紫色の液体を水脈に注ぎ込もうとしている男たちがいる。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"spy_01","choices":[{"label":"続ける","next":"spy_01"}]},"spy_01":{"text":"「これでこの都市の水は全滅だ。次は……」","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","speaker_name":"謎の工作員","speaker":"謎の工作員","next":"spy_02","choices":[{"label":"続ける","next":"spy_02"}]},"spy_02":{"text":"「もう三つの都市に仲間が散っている。砂漠の国を混乱に陥れるのだ」","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","speaker_name":"謎の工作員","speaker":"謎の工作員","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle","enemy_group_id":"201","choices":[{"label":"win","next":"dying_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"dying_01"},"dying_01":{"text":"工作員たちを制圧した。息絶えかけた男が、懐から何かを取り出そうとする。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"dying_02","choices":[{"label":"続ける","next":"dying_02"}]},"dying_02":{"text":"「フフ……遅い……我々の大義はすでに果たされつつある……」","type":"text","bg_key":"bg_crypt","speaker_name":"瀕死の工作員","speaker":"瀕死の工作員","next":"emblem_01","choices":[{"label":"続ける","next":"emblem_01"}]},"emblem_01":{"text":"男の手からこぼれ落ちたのは、金属製の小さな紋章の欠片だった。","type":"text","bg_key":"bg_crypt","next":"emblem_02","choices":[{"label":"続ける","next":"emblem_02"}]},"emblem_02":{"text":"「これは……ローランド聖王国の特務機関『白百合の影』の紋章……！」","type":"text","bg_key":"bg_crypt","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"emblem_03","choices":[{"label":"続ける","next":"emblem_03"}]},"emblem_03":{"text":"「なぜだ、なぜ我が国が砂漠の民のオアシスに毒を撒かねばならんのだ」","type":"text","bg_key":"bg_crypt","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"shock_01","choices":[{"label":"続ける","next":"shock_01"}]},"shock_01":{"text":"「もし本当に王国の仕業だとしたら、俺たちは何を信じて剣を振るってきた」","type":"text","bg_key":"bg_crypt","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"shock_02","choices":[{"label":"続ける","next":"shock_02"}]},"shock_02":{"text":"「俺の誇りも、信じてきた秩序も、すべてただの欺瞞だったというのか」","type":"text","bg_key":"bg_crypt","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"shock_03","choices":[{"label":"続ける","next":"shock_03"}]},"shock_03":{"text":"ガウェインは拳を強く握りしめた。その額には、悔し涙のような汗が滲んでいた。","type":"text","bg_key":"bg_crypt","next":"farewell_01","choices":[{"label":"続ける","next":"farewell_01"}]},"farewell_01":{"text":"「敵が残した解毒剤の処方箋だ。これを持って、至急街の薬師を動かそう」","type":"text","bg_key":"bg_crypt","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"type":"leave","bg_key":"bg_crypt","params":{"guest_id":"npc_guest_gawain"},"next":"end_01","choices":[{"label":"続ける","next":"end_01"}]},"end_01":{"text":"水源の浄化は進んだ。だが、手に残る紋章の冷たさは、消えることがない。","type":"text","bg_key":"bg_marcund","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"砂塵の王国マルカンド。その美しいオアシスに潜む闇は、あまりに深かった。","type":"end","result":"success","bg_key":"bg_marcund","params":{"rewards":{"exp":120,"gold":300,"reputation":5,"alignment_shift":{"order":5}}},"choices":[]},"end_failure_01":{"text":"工作員たちの奇襲をかわせず、猛毒の塗られた刃に倒れる。視界が暗転する……","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"オアシスの水脈は完全に毒に染まり、オアシスの街は死の都と化した。","type":"end","result":"failure","bg_key":"bg_marcund","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第3話"}'::jsonb,
    3,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6004: 第4話「砂塵の激突」 (main_ep04)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6004,
    'main_ep04',
    '第4話「砂塵の激突」',
    'メインシナリオ第4話',
    '交易商会',
    1,
    4,
    2,
    '{"gold":400,"items":[],"reputation":10,"alignment_shift":{"justice":10},"move_to":"loc_meridia"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep03","location_id":"loc_plains_city"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep03","location_id":"loc_plains_city"}'::jsonb,
    '{"nodes":{"start":{"text":"毒物事件から数日。我々はマルカンド領内の交易路巡回任務についていた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"type":"guest_join","bg_key":"bg_desert","params":{"guest_id":"npc_guest_gawain"},"next":"patrol_01","choices":[{"label":"続ける","next":"patrol_01"}]},"patrol_01":{"text":"「交易路だというのに、静かすぎる。すれ違うキャラバンが妙に少ない」","type":"text","bg_key":"bg_desert","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"patrol_02","choices":[{"label":"続ける","next":"patrol_02"}]},"patrol_02":{"text":"「数日前から、多くの商人が忽然と姿を消しているという噂があるな」","type":"text","bg_key":"bg_desert","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"rumor_01","choices":[{"label":"続ける","next":"rumor_01"}]},"rumor_01":{"text":"砂風の向こうから、血まみれの男がよろめきながらこちらへ走ってきた。","type":"text","bg_key":"bg_desert","next":"rumor_02","choices":[{"label":"続ける","next":"rumor_02"}]},"rumor_02":{"text":"「助けてくれ！ 謎の賞金稼ぎどもが……我が商隊を襲撃した！」","type":"text","bg_key":"bg_desert","speaker_name":"血まみれの商人","speaker":"血まみれの商人","next":"merchant_01","choices":[{"label":"続ける","next":"merchant_01"}]},"merchant_01":{"text":"男はそう叫ぶと崩れ落ちた。ガウェインが男の応急手当を施す。","type":"text","bg_key":"bg_desert","next":"merchant_02","choices":[{"label":"続ける","next":"merchant_02"}]},"merchant_02":{"text":"「傷は深いが命に別条はない。商隊が襲われたのはどのあたりだ？」","type":"text","bg_key":"bg_desert","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"plea_01","choices":[{"label":"続ける","next":"plea_01"}]},"plea_01":{"text":"「あそこだ……皆殺しにされる……」","type":"text","bg_key":"bg_desert","speaker_name":"血まみれの商人","speaker":"血まみれの商人","next":"plea_02","choices":[{"label":"続ける","next":"plea_02"}]},"plea_02":{"text":"「新入り、行くぞ。これ以上の被害者を出すわけにはいかん」","type":"text","bg_key":"bg_desert","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"analysis_01","choices":[{"label":"続ける","next":"analysis_01"}]},"analysis_01":{"text":"「消えた商人たちの共通点は、ローランドとの和平に反対していたことだ」","type":"text","bg_key":"bg_desert","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"analysis_02","choices":[{"label":"続ける","next":"analysis_02"}]},"analysis_02":{"text":"「つまり、和平派にとって都合の悪い人間が、裏で消されているわけだ」","type":"text","bg_key":"bg_desert","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"trail_01","choices":[{"label":"続ける","next":"trail_01"}]},"trail_01":{"text":"砂漠の東へ進む。荒涼とした岩場に、破壊された荷馬車の残骸が散らばる。","type":"text","bg_key":"bg_wasteland","next":"trail_02","choices":[{"label":"続ける","next":"trail_02"}]},"trail_02":{"text":"残骸の周囲には新しい足跡がある。襲撃者たちはまだ近くにいるはずだ。","type":"text","bg_key":"bg_wasteland","next":"ambush_01","choices":[{"label":"続ける","next":"ambush_01"}]},"ambush_01":{"text":"岩陰から覗き込む。黒い装束の集団が、生存者の商人を包囲していた。","type":"text","bg_key":"bg_wasteland","next":"ambush_02","choices":[{"label":"続ける","next":"ambush_02"}]},"ambush_02":{"text":"その集団のリーダーの腰に、見覚えのあるローランド王国の公印が見える。","type":"text","bg_key":"bg_wasteland","next":"hunter_01","choices":[{"label":"続ける","next":"hunter_01"}]},"hunter_01":{"text":"「お前たちの交易はこれで終わりだ」","type":"text","bg_key":"bg_wasteland","speaker_name":"暗殺部隊のリーダー","speaker":"暗殺部隊のリーダー","next":"hunter_02","choices":[{"label":"続ける","next":"hunter_02"}]},"hunter_02":{"text":"「王国にとって不都合な商人は、すべて砂の塵となってもらう」","type":"text","bg_key":"bg_wasteland","speaker_name":"暗殺部隊のリーダー","speaker":"暗殺部隊のリーダー","next":"hunter_03","choices":[{"label":"続ける","next":"hunter_03"}]},"hunter_03":{"text":"「やはり王国の息がかかった暗殺部隊か……。許すわけにはいかん！」","type":"text","bg_key":"bg_wasteland","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"hunter_04","choices":[{"label":"続ける","next":"hunter_04"}]},"hunter_04":{"text":"ガウェインが雄叫びと共に飛び出した。我々もそれに続いて武器を構える！","type":"text","bg_key":"bg_wasteland","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_wasteland","bgm":"bgm_battle","enemy_group_id":"230","choices":[{"label":"win","next":"post_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"post_01"},"post_01":{"text":"賞金稼ぎたちを討ち果たした。リーダーの胸元から身分証を回収する。","type":"text","bg_key":"bg_wasteland","bgm":"bgm_quest_calm","next":"post_02","choices":[{"label":"続ける","next":"post_02"}]},"post_02":{"text":"身分証には『ローランド聖王国第三遠征大隊・元伍長』と記されていた。","type":"text","bg_key":"bg_wasteland","next":"identity_01","choices":[{"label":"続ける","next":"identity_01"}]},"identity_01":{"text":"王国が解雇した元軍人を雇い、裏で暗殺をさせていた決定的な証拠だ。","type":"text","bg_key":"bg_wasteland","next":"identity_02","choices":[{"label":"続ける","next":"identity_02"}]},"identity_02":{"text":"「……汚いやり方だ。国のために戦った男たちを、暗殺者に仕立てるなど」","type":"text","bg_key":"bg_wasteland","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"omen_01","choices":[{"label":"続ける","next":"omen_01"}]},"omen_01":{"text":"「これは局地的な事件じゃない。本格的な戦争へのカウントダウンだ」","type":"text","bg_key":"bg_wasteland","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"omen_02","choices":[{"label":"続ける","next":"omen_02"}]},"omen_02":{"text":"「王国の上層部は、何が何でもマルカンドとの開戦を望んでいるらしい」","type":"text","bg_key":"bg_wasteland","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"omen_03","choices":[{"label":"続ける","next":"omen_03"}]},"omen_03":{"text":"ガウェインの眼光は鋭く、かつてないほどの決意を秘めていた。","type":"text","bg_key":"bg_wasteland","next":"farewell_01","choices":[{"label":"続ける","next":"farewell_01"}]},"farewell_01":{"text":"「この証拠を持ち帰り、軍の良識派に告発する。時間がない、急ぐぞ」","type":"text","bg_key":"bg_wasteland","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"farewell_02","choices":[{"label":"続ける","next":"farewell_02"}]},"farewell_02":{"text":"「お前も気をつけて戻れ。王都の影は、俺たちが思うより広い」","type":"text","bg_key":"bg_wasteland","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"type":"leave","bg_key":"bg_wasteland","params":{"guest_id":"npc_guest_gawain"},"next":"end_01","choices":[{"label":"続ける","next":"end_01"}]},"end_01":{"text":"砂漠の風が強まる。戦争という巨大な怪物の足音が、すぐ後ろまで迫っていた。","type":"text","bg_key":"bg_wasteland","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"真実を知ってしまった以上、もうただの傭兵としては生きられない。","type":"end","result":"success","bg_key":"bg_wasteland","params":{"rewards":{"exp":150,"gold":400,"reputation":10,"alignment_shift":{"order":5}}},"choices":[]},"end_failure_01":{"text":"元軍人の組織的な連携に圧倒され、岩場に崩れ落ちる。意識が混濁する……","type":"text","bg_key":"bg_wasteland","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"商隊は全滅し、王国の不正を暴く証拠も砂塵の彼方に消え去った。","type":"end","result":"failure","bg_key":"bg_wasteland","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第4話"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6005: 第5話「大義という名の虚妄」 (main_ep05)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
