    '{"gold":500,"items":[501],"reputation":10,"alignment_shift":{"justice":10},"move_to":"loc_frontier_village"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep04","location_id":"loc_meridia"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep04","location_id":"loc_meridia"}'::jsonb,
    '{"nodes":{"start":{"text":"王国がガウェインを「反逆者」として公表した。我々は山に逃げ込んだ。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_tense","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"告発しようとした良識派の将軍は暗殺され、証拠も奪い去られたらしい。","type":"text","bg_key":"bg_camp","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"そして今、我々を捕縛するための王国軍鉄騎隊が、山麓に集結しつつある。","type":"text","bg_key":"bg_camp","next":"gawain_join","choices":[{"label":"続ける","next":"gawain_join"}]},"gawain_join":{"type":"guest_join","bg_key":"bg_camp","params":{"guest_id":"npc_guest_gawain"},"next":"ambush_01","choices":[{"label":"続ける","next":"ambush_01"}]},"ambush_01":{"text":"「逃げ道を塞がれたか」森の各所から、重厚な甲冑の擦れる音が響く。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_crisis","next":"ambush_02","choices":[{"label":"続ける","next":"ambush_02"}]},"ambush_02":{"text":"鉄騎隊の包囲網。前方に立ちふさがったのは、王国軍精鋭部隊の将校だ。","type":"text","bg_key":"bg_camp","next":"commander_01","choices":[{"label":"続ける","next":"commander_01"}]},"commander_01":{"text":"「反逆者ガウェイン。ここで処断する」","type":"text","bg_key":"bg_camp","speaker_name":"王国軍将校","speaker":"王国軍将校","next":"commander_02","choices":[{"label":"続ける","next":"commander_02"}]},"commander_02":{"text":"「新入りの傭兵とやらも同罪だ。捕らえる必要はない、その場で斬れ！」","type":"text","bg_key":"bg_camp","speaker_name":"王国軍将校","speaker":"王国軍将校","next":"resolve_01","choices":[{"label":"続ける","next":"resolve_01"}]},"resolve_01":{"text":"「……どうやら本気だな。新入り、ここは俺が防ぐ。お前は東へ走れ」","type":"text","bg_key":"bg_camp","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"resolve_02","choices":[{"label":"続ける","next":"resolve_02"}]},"resolve_02":{"text":"「この森を抜ければ夜刀の国境だ。あそこなら王国の手も容易には届かん」","type":"text","bg_key":"bg_camp","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"resolve_03","choices":[{"label":"続ける","next":"resolve_03"}]},"resolve_03":{"text":"「嫌です」と叫ぼうとした我々を、ガウェインの眼光が力強く制した。","type":"text","bg_key":"bg_camp","next":"wave_01","choices":[{"label":"続ける","next":"wave_01"}]},"wave_01":{"text":"「お前の命はここで捨てるにゃ惜しい！ 来るぞ、まずは前衛を叩く！」","type":"text","bg_key":"bg_camp","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"type":"battle","bg_key":"bg_camp","bgm":"bgm_battle_strong","enemy_group_id":"203","choices":[{"label":"win","next":"clear_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"clear_01"},"clear_01":{"text":"前衛の兵士たちを退けた。だが、奥からさらに第二波の重装歩兵が現れる。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_crisis","next":"clear_02","choices":[{"label":"続ける","next":"clear_02"}]},"clear_02":{"text":"「きりがないな……。おい新入り、俺の指示を聞け。絶対に生き延びろ」","type":"text","bg_key":"bg_camp","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"second_01","choices":[{"label":"続ける","next":"second_01"}]},"second_01":{"text":"「お前が真実を世界の果てまで届けるんだ。……いくぞ、これが最後だ！」","type":"text","bg_key":"bg_camp","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"type":"battle","bg_key":"bg_camp","bgm":"bgm_battle_strong","enemy_group_id":"203","choices":[{"label":"win","next":"last_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"last_01"},"last_01":{"text":"激闘の末、囲みを突破した。だがガウェインの背中には三本の矢が深く刺さっていた。","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_calm","next":"last_02","choices":[{"label":"続ける","next":"last_02"}]},"last_02":{"text":"「ガウェイン！」駆け寄ろうとする我々を、彼は片手で強く押し止めた。","type":"text","bg_key":"bg_camp","next":"last_03","choices":[{"label":"続ける","next":"last_03"}]},"last_03":{"text":"「来るな！ 背中を見せて走れ！ ……お前は生き延びねばならんのだ」","type":"text","bg_key":"bg_camp","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"last_04","choices":[{"label":"続ける","next":"last_04"}]},"last_04":{"text":"「世界の果てを見届けろ。……そして、自由な風になれ……！」","type":"text","bg_key":"bg_camp","speaker_name":"ガウェイン","speaker":"ガウェイン","next":"gawain_leave","choices":[{"label":"続ける","next":"gawain_leave"}]},"gawain_leave":{"type":"leave","bg_key":"bg_camp","params":{"guest_id":"npc_guest_gawain"},"next":"run_01","choices":[{"label":"続ける","next":"run_01"}]},"run_01":{"text":"大剣を杖代わりに立ち上がった老騎士。その背中が迫り来る兵士の前に立ちはだかる。","type":"text","bg_key":"bg_camp","next":"run_02","choices":[{"label":"続ける","next":"run_02"}]},"run_02":{"text":"涙で視界が滲む中、我々はただ東へ走った。背後から激しい金属音と叫び声が響く。","type":"text","bg_key":"bg_camp","next":"run_03","choices":[{"label":"続ける","next":"run_03"}]},"run_03":{"text":"やがて——恐ろしいほどの静寂が、深い森の奥へと満ちていった。","type":"text","bg_key":"bg_camp","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"生き延びて、世界の果てを見届けろ。老騎士の最期の言葉が、胸に突き刺さっている。","type":"end","result":"success","bg_key":"bg_camp","params":{"rewards":{"exp":200,"gold":500,"reputation":15,"alignment_shift":{"order":5}}},"choices":[]},"end_failure_01":{"text":"鉄騎隊の圧倒的な重圧に押し潰され、地に伏す。老騎士を守ることもできず……","type":"text","bg_key":"bg_camp","bgm":"bgm_quest_crisis","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"反逆の徒として森の露と消えた。真実は闇へ葬られ、老騎士の背中も失われた。","type":"end","result":"failure","bg_key":"bg_camp","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第5話"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6006: 第6話「逃亡者の道」 (main_ep06)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6006,
    'main_ep06',
    '第6話「逃亡者の道」',
    'メインシナリオ第6話',
    '忍び衆',
    1,
    6,
    2,
    '{"gold":600,"items":[],"reputation":10,"alignment_shift":{"chaos":5},"move_to":"loc_temple_town"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep05","location_id":"loc_frontier_village"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep05","location_id":"loc_frontier_village"}'::jsonb,
    '{"nodes":{"start":{"text":"敗残兵の群れに紛れ、我々は東への逃走を続けていた。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"鬱そうとした密林。ローランドと夜刀神国の国境を隔てる魔の森だ。","type":"text","bg_key":"bg_forest_day","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"追っ手の警戒網をかいくぐり、なんとか国境域の深部へと到達する。","type":"text","bg_key":"bg_forest_day","next":"wound_01","choices":[{"label":"続ける","next":"wound_01"}]},"wound_01":{"text":"切り裂かれた肩の傷が、熱を帯て激しく痛む。呼吸が荒くなる。","type":"text","bg_key":"bg_forest_day","next":"wound_02","choices":[{"label":"続ける","next":"wound_02"}]},"wound_02":{"text":"だが、立ち止まることは許されない。ここで倒れるわけにはいかない。","type":"text","bg_key":"bg_forest_day","next":"flash_01","choices":[{"label":"続ける","next":"flash_01"}]},"flash_01":{"text":"目を閉じると、あの凄絶な戦いと、ガウェインの最期の背中が脳裏をよぎる。","type":"text","bg_key":"bg_forest_day","next":"flash_02","choices":[{"label":"続ける","next":"flash_02"}]},"flash_02":{"text":"「生き延びて、世界の果てを見届けろ」——その言葉が体を動かす。","type":"text","bg_key":"bg_forest_day","next":"pursuit_01","choices":[{"label":"続ける","next":"pursuit_01"}]},"pursuit_01":{"text":"背後。遠くの茂みから、金属の擦れる音と犬の荒い鼻息が聞こえた。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"pursuit_02","choices":[{"label":"続ける","next":"pursuit_02"}]},"pursuit_02":{"text":"王国軍が放った軍用犬だ。こちらの血の臭いを追ってきているに違いない。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"dogs_01","choices":[{"label":"続ける","next":"dogs_01"}]},"dogs_01":{"text":"目前の獣道が左右に分かれている。どちらを選べば生き延びられるか。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"dogs_02","choices":[{"label":"続ける","next":"dogs_02"}]},"dogs_02":{"text":"険しい山道を行くか、それとも距離を稼げる平坦な川沿いを突っ走るか。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"choice1","choices":[{"label":"続ける","next":"choice1"}]},"choice1":{"type":"choice","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","choices":[{"label":"「険しいけもの道を進む」","next":"hard_01"},{"label":"「川沿いを急ぐ」","next":"river_01"}]},"hard_01":{"text":"道なき道。鋭い棘を持つ茨が、容赦なく服を破り肌を切り裂く！","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"hard_trap","choices":[{"label":"続ける","next":"hard_trap"}]},"hard_trap":{"text":"茨の森を進み、全身に手痛い裂傷を負った！","type":"hp_damage","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"hard_02","choices":[{"label":"続ける","next":"hard_02"}]},"hard_02":{"text":"激しい痛みに耐えながら、高低差のある岩場をよじ登り、追っ手を撒く。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_calm","next":"hard_03","choices":[{"label":"続ける","next":"hard_03"}]},"hard_03":{"text":"軍用犬の吠え声が遠ざかっていく。地形を利用した隠密が功を奏した。","type":"text","bg_key":"bg_forest_day","next":"hard_04","choices":[{"label":"続ける","next":"hard_04"}]},"hard_04":{"text":"ついに、遠方に夜刀神国の関所「黒金門」の巨大な影が見えてきた。","type":"text","bg_key":"bg_forest_day","next":"dying_01","choices":[{"label":"続ける","next":"dying_01"}]},"river_01":{"text":"川の急流に沿って全力で疾走する。水しぶきが顔にかかり、視界を塞ぐ。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"river_02","choices":[{"label":"続ける","next":"river_02"}]},"river_02":{"text":"だが、前方から数人の甲冑兵が立ちふさがった。待ち伏せだ！","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"ambush_01","choices":[{"label":"続ける","next":"ambush_01"}]},"ambush_01":{"text":"「いたぞ！ 反逆者の片割れだ！ 逃がすな、ここで仕留めろ！」","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","speaker_name":"王国軍兵士","speaker":"王国軍兵士","next":"ambush_02","choices":[{"label":"続ける","next":"ambush_02"}]},"ambush_02":{"text":"彼らの背後の森から、さらに無数の気配がこちらへ接近してくる！","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"taunt_01","choices":[{"label":"続ける","next":"taunt_01"}]},"taunt_01":{"text":"「後ろにもう三十人控えている。大人しく降伏しろ」","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","speaker_name":"王国軍将校","speaker":"王国軍将校","next":"taunt_02","choices":[{"label":"続ける","next":"taunt_02"}]},"taunt_02":{"text":"「断る！」死地を切り開くため、満身創痍の体で刃を構える！","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_forest_day","bgm":"bgm_battle","enemy_group_id":"406","choices":[{"label":"win","next":"dying_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"dying_01"},"dying_01":{"text":"立ちふさがる追手を切り伏せた。だが、背後からは大部隊の足音が迫る。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_calm","next":"dying_02","choices":[{"label":"続ける","next":"dying_02"}]},"dying_02":{"text":"休む暇はない。傷口を押さえながら、遮二無二森の奥へと走り続ける。","type":"text","bg_key":"bg_forest_day","next":"run_01","choices":[{"label":"続ける","next":"run_01"}]},"run_01":{"text":"激しい息遣いの中、木々の隙間からついに巨大な門のシルエットが覗く。","type":"text","bg_key":"bg_forest_day","next":"run_02","choices":[{"label":"続ける","next":"run_02"}]},"run_02":{"text":"夜刀神国の国境関所。あそこまで行けば、王国の追手も手を出せない。","type":"text","bg_key":"bg_forest_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"関所の影に辿り着いた。生きている。ガウェイン、自分はまだ生きている。","type":"end","result":"success","bg_key":"bg_forest_day","params":{"rewards":{"exp":150,"gold":200,"reputation":5,"alignment_shift":{"order":5}}},"choices":[]},"end_failure_01":{"text":"怪我と疲労で体が動かず、追討部隊の刃をかわせない。その場に崩れ落ちた。","type":"text","bg_key":"bg_forest_day","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"夜刀の門を目の前にして、逃亡劇は終わった。老騎士の願いも潰えた。","type":"end","result":"failure","bg_key":"bg_forest_day","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第6話"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6007: 第7話「刃の掟」 (main_ep07)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6007,
    'main_ep07',
    '第7話「刃の掟」',
    'メインシナリオ第7話',
    '代官所',
    1,
    7,
    2,
    '{"gold":700,"items":[],"reputation":10,"alignment_shift":{"justice":5},"move_to":"loc_yato"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep06","location_id":"loc_temple_town"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep06","location_id":"loc_temple_town"}'::jsonb,
    '{"nodes":{"start":{"text":"夜の闇が、険しい国境の山嶺を深く包み込んでいる。","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_mystery","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"黒金門。夜刀神国の威容を示す、巨大な鉄製の門が立ち塞がる。","type":"text","bg_key":"bg_road_night","next":"gate_01","choices":[{"label":"続ける","next":"gate_01"}]},"gate_01":{"text":"松明の炎が風に揺れ、警備に立つ東洋の甲冑を着た衛兵たちを照らす。","type":"text","bg_key":"bg_road_night","next":"gate_02","choices":[{"label":"続ける","next":"gate_02"}]},"gate_02":{"text":"門をくぐれば夜刀神国だが、手元に通行証はない。","type":"text","bg_key":"bg_road_night","next":"doc_01","choices":[{"label":"続ける","next":"doc_01"}]},"doc_01":{"text":"懐を探ると、途中で息絶えた夜刀の斥候から託された書状に指が触れた。","type":"text","bg_key":"bg_road_night","next":"doc_02","choices":[{"label":"続ける","next":"doc_02"}]},"doc_02":{"text":"厳重に封印された書状。そこには極めて秘匿性の高い軍事機密が記されている。","type":"text","bg_key":"bg_road_night","next":"guard_01","choices":[{"label":"続ける","next":"guard_01"}]},"guard_01":{"text":"「待て。これより先は夜刀神国領だ。通行証の提示を求める」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"guard_02","choices":[{"label":"続ける","next":"guard_02"}]},"guard_02":{"text":"「持たぬ者は引き返せ。無理に通るならば、即刻切り捨てだ」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"choice1","choices":[{"label":"続ける","next":"choice1"}]},"choice1":{"type":"choice","bg_key":"bg_road_night","choices":[{"label":"「機密書を渡して通る」","next":"betray_01"},{"label":"「傭兵として雇ってもらう」","next":"normal_01"}]},"betray_01":{"text":"「……通行証はないが、これを見れば態度が変わるはずだ」","type":"text","bg_key":"bg_road_night","next":"betray_02","choices":[{"label":"続ける","next":"betray_02"}]},"betray_02":{"text":"懐から血痕のついた軍事機密書を取り出し、衛兵に手渡す。","type":"text","bg_key":"bg_road_night","next":"betray_03","choices":[{"label":"続ける","next":"betray_03"}]},"betray_03":{"text":"「これは……我が国の印章。まさか、行方不明になっていた斥候の物か！」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"betray_04","choices":[{"label":"続ける","next":"betray_04"}]},"betray_04":{"text":"「内容を確認する……よし、間違いない。我らにとって極めて重要な書状だ」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"betray_05","choices":[{"label":"続ける","next":"betray_05"}]},"betray_05":{"text":"「書状をもたらした功績に免じ、特別に通してやろう。だが口は慎めよ」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"betray_06","choices":[{"label":"続ける","next":"betray_06"}]},"betray_06":{"text":"死者の託した想いを、己の安全のために売り渡した。胸に暗い泥が沈む。","type":"text","bg_key":"bg_road_night","next":"betray_rep","choices":[{"label":"続ける","next":"betray_rep"}]},"betray_rep":{"type":"modify_reputation","bg_key":"bg_road_night","params":{"amount":-30},"next":"end_betray","choices":[{"label":"続ける","next":"end_betray"}]},"end_betray":{"text":"重い門扉が軋みながら開く。良心の呵責を抱え、あなたは門をくぐった。","type":"end","result":"success","bg_key":"bg_road_night","params":{"rewards":{"exp":180,"gold":300,"reputation":10,"alignment_shift":{"order":5}}},"choices":[]},"normal_01":{"text":"「通行証はないが、旅の傭兵だ。門の内側で何か手伝える仕事はないか？」","type":"text","bg_key":"bg_road_night","next":"normal_02","choices":[{"label":"続ける","next":"normal_02"}]},"normal_02":{"text":"「ただの素浪人か。ふん、腕に自信があると言うのだな？」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"normal_03","choices":[{"label":"続ける","next":"normal_03"}]},"normal_03":{"text":"衛兵は腕を組み、ニヤリと不敵な笑みを浮かべた。","type":"text","bg_key":"bg_road_night","next":"normal_04","choices":[{"label":"続ける","next":"normal_04"}]},"normal_04":{"text":"「ならばちょうどいい。黒金門の裏山に、人喰いの天狗が巣食っておる」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"normal_05","choices":[{"label":"続ける","next":"normal_05"}]},"normal_05":{"text":"「そ奴を退治し、証拠に天狗の羽を持ち帰れ。さすれば通行を許そう」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"normal_06","choices":[{"label":"続ける","next":"normal_06"}]},"normal_06":{"text":"天狗退治。命がけの試練だが、正当に門を通るには受ける他ない。","type":"text","bg_key":"bg_road_night","next":"tengu_01","choices":[{"label":"続ける","next":"tengu_01"}]},"tengu_01":{"text":"風が吠える裏山へと分け入る。木々が怪異の形をして揺れていた。","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_tense","next":"tengu_02","choices":[{"label":"続ける","next":"tengu_02"}]},"tengu_02":{"text":"上空から、バサバサと巨大な翼の羽音が降りてくる。","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_tense","next":"tengu_03","choices":[{"label":"続ける","next":"tengu_03"}]},"tengu_03":{"text":"「侵入者め……我が巣を荒らすか！」","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_tense","speaker_name":"天狗","speaker":"天狗","next":"tengu_04","choices":[{"label":"続ける","next":"tengu_04"}]},"tengu_04":{"text":"月光の逆光を浴びて、恐るべき天狗の影が崖の上に降り立った。","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_tense","next":"tengu_05","choices":[{"label":"続ける","next":"tengu_05"}]},"tengu_05":{"text":"鋭い鉤爪がこちらを狙う。逃げ場はない。武器を構えて迎え撃つ！","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_tense","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_road_night","bgm":"bgm_battle","enemy_group_id":"205","choices":[{"label":"win","next":"dead_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"dead_01"},"dead_01":{"text":"息絶えた天狗の骸から、黒く輝く大羽を一本引き抜いた。","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_calm","next":"dead_02","choices":[{"label":"続ける","next":"dead_02"}]},"dead_02":{"text":"確かな戦果を手に、冷え切った夜の山道を黒金門へと引き返す。","type":"text","bg_key":"bg_road_night","next":"dead_03","choices":[{"label":"続ける","next":"dead_03"}]},"dead_03":{"text":"「おお、戻ったか！……まさか、本当に天狗の羽を持ち帰るとはな」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"dead_04","choices":[{"label":"続ける","next":"dead_04"}]},"dead_04":{"text":"衛兵は羽を受け取り、驚愕と感嘆の眼差しをこちらに向けた。","type":"text","bg_key":"bg_road_night","next":"dead_05","choices":[{"label":"続ける","next":"dead_05"}]},"dead_05":{"text":"「見事な腕前だ。約束通り、お前の実力を認め、通行を許可する」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"dead_06","choices":[{"label":"続ける","next":"dead_06"}]},"dead_06":{"text":"「ようこそ夜刀神国へ。腕の立つ傭兵なら、都でいくらでも仕事があるぞ」","type":"text","bg_key":"bg_road_night","speaker_name":"黒金門の警備兵","speaker":"黒金門の警備兵","next":"dead_07","choices":[{"label":"続ける","next":"dead_07"}]},"dead_07":{"text":"鉄の門が重々しく開かれ、その先に新たな異国への道が広がっていた。","type":"text","bg_key":"bg_road_night","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"試練を乗り越え、あなたは堂々と夜刀神国の地へと足を踏み入れた。","type":"end","result":"success","bg_key":"bg_road_night","params":{"rewards":{"exp":180,"gold":300,"reputation":10,"alignment_shift":{"order":5}}},"choices":[]},"end_failure_01":{"text":"天狗の鋭い突風と爪の前に、地面に叩きつけられ動けなくなった。","type":"text","bg_key":"bg_road_night","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"薄れゆく意識の中、黒金門の関所を目の前にして力尽きた。","type":"end","result":"failure","bg_key":"bg_road_night","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第7話"}'::jsonb,
    3,
    2
) ON CONFLICT (id) DO UPDATE SET
