-- Scenario 6008: 第8話「夜霧の凶刃」 (main_ep08)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6008,
    'main_ep08',
    '第8話「夜霧の凶刃」',
    'メインシナリオ第8話',
    'なし',
    2,
    8,
    1,
    '{"gold":350,"items":[],"reputation":10,"alignment_shift":{"order":5},"move_to":"loc_valley"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep07","location_id":"loc_yato"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep07","location_id":"loc_yato"}'::jsonb,
    '{"nodes":{"start":{"text":"夜刀神国の辺境にある宿屋の一室。部屋の中は暗い。","type":"text","bg_key":"bg_yato_tavern_night","bgm":"bgm_quest_tense","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"窓の外には、すべてを覆い隠すような深い夜霧が立ち込めている。","type":"text","bg_key":"bg_yato_tavern_night","next":"rest_01","choices":[{"label":"続ける","next":"rest_01"}]},"rest_01":{"text":"激しい戦いの連続で、あなたの体には疲労が濃く溜まっていた。","type":"text","bg_key":"bg_yato_tavern_night","next":"rest_02","choices":[{"label":"続ける","next":"rest_02"}]},"rest_02":{"text":"しかし、どれほど休息を求めようとも、警戒は解けない。","type":"text","bg_key":"bg_yato_tavern_night","next":"alert_01","choices":[{"label":"続ける","next":"alert_01"}]},"alert_01":{"text":"枕元に愛用の武器を引き寄せ、いつでも動けるよう横になる。","type":"text","bg_key":"bg_yato_tavern_night","next":"alert_02","choices":[{"label":"続ける","next":"alert_02"}]},"alert_02":{"text":"闇の中に神経を研ぎ澄まし、わずかな音をも逃すまいと努める。","type":"text","bg_key":"bg_yato_tavern_night","next":"sound_01","choices":[{"label":"続ける","next":"sound_01"}]},"sound_01":{"text":"深夜、静まり返った宿の屋根で、瓦がわずかに擦れる音がした。","type":"text","bg_key":"bg_yato_tavern_night","next":"sound_02","choices":[{"label":"続ける","next":"sound_02"}]},"sound_02":{"text":"刺客の気配だ。一か所ではなく、部屋を包むように近づく。","type":"text","bg_key":"bg_yato_tavern_night","next":"analysis_01","choices":[{"label":"続ける","next":"analysis_01"}]},"analysis_01":{"text":"気配は極めて薄い。忍びの術を心得た夜刀の暗部だろう。","type":"text","bg_key":"bg_yato_tavern_night","next":"analysis_02","choices":[{"label":"続ける","next":"analysis_02"}]},"analysis_02":{"text":"寝台から音もなく滑り落ち、部屋の隅の暗闇に身を潜めた。","type":"text","bg_key":"bg_yato_tavern_night","next":"break_01","choices":[{"label":"続ける","next":"break_01"}]},"break_01":{"text":"ガラスが粉々に砕け散り、部屋の中に黒い塊が投げ込まれる。","type":"text","bg_key":"bg_yato_tavern_night","next":"break_02","choices":[{"label":"続ける","next":"break_02"}]},"break_02":{"text":"たちまち白煙が部屋に満ち、視界と呼吸が奪われていく。","type":"text","bg_key":"bg_yato_tavern_night","next":"enemy_voice_01","choices":[{"label":"続ける","next":"enemy_voice_01"}]},"enemy_voice_01":{"text":"「寝台を囲め！逃がすな、ここで息の根を止めてやる！」","type":"text","bg_key":"bg_yato_tavern_night","speaker_name":"黒装束の刺客","speaker":"黒装束の刺客","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"type":"battle","bg_key":"bg_yato_tavern_night","bgm":"bgm_battle","enemy_group_id":"206","choices":[{"label":"win","next":"wave_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"wave_01"},"wave_01":{"text":"鋭い踏み込みで白煙を切り裂き、襲いかかる影を薙ぎ払う。","type":"text","bg_key":"bg_yato_tavern_night","next":"wave_02","choices":[{"label":"続ける","next":"wave_02"}]},"wave_02":{"text":"床に倒れ伏した刺客たちの懐から、特有の紋章が覗いていた。","type":"text","bg_key":"bg_yato_tavern_night","next":"wave_03","choices":[{"label":"続ける","next":"wave_03"}]},"wave_03":{"text":"それは夜刀神国の有力者が飼う、暗部組織の印に他ならない。","type":"text","bg_key":"bg_yato_tavern_night","next":"wave_04","choices":[{"label":"続ける","next":"wave_04"}]},"wave_04":{"text":"しかし、安堵する時間はない。廊下の奥からさらに重い足音が響く。","type":"text","bg_key":"bg_yato_tavern_night","next":"wave_05","choices":[{"label":"続ける","next":"wave_05"}]},"wave_05":{"text":"障子が乱暴に引き裂かれ、大柄な男が部屋へと踏み込んできた。","type":"text","bg_key":"bg_yato_tavern_night","next":"elite_01","choices":[{"label":"続ける","next":"elite_01"}]},"elite_01":{"text":"男が手にする漆黒の野太刀から、禍々しい闘気が立ち上っている。","type":"text","bg_key":"bg_yato_tavern_night","next":"elite_02","choices":[{"label":"続ける","next":"elite_02"}]},"elite_02":{"text":"前衛の刺客たちとは明らかに格が違う。この襲撃の指揮官か。","type":"text","bg_key":"bg_yato_tavern_night","next":"elite_03","choices":[{"label":"続ける","next":"elite_03"}]},"elite_03":{"text":"「雑魚どもでは役不足だったか。この俺の刃で塵にしてくれよう」","type":"text","bg_key":"bg_yato_tavern_night","speaker_name":"暗殺者頭領","speaker":"暗殺者頭領","next":"elite_04","choices":[{"label":"続ける","next":"elite_04"}]},"elite_04":{"text":"あなたは武器をしっかりと構え、真っ向から敵を見据えた。","type":"text","bg_key":"bg_yato_tavern_night","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"type":"battle","bg_key":"bg_yato_tavern_night","bgm":"bgm_battle","enemy_group_id":"207","choices":[{"label":"win","next":"silence_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"silence_01"},"silence_01":{"text":"激しい刃の応酬の末、あなたの渾身の一撃が頭領を捉えた。","type":"text","bg_key":"bg_yato_tavern_night","next":"silence_02","choices":[{"label":"続ける","next":"silence_02"}]},"silence_02":{"text":"頭領は野太刀を杖代わりに突き、激しく血を吐きながら嗤う。","type":"text","bg_key":"bg_yato_tavern_night","next":"silence_03","choices":[{"label":"続ける","next":"silence_03"}]},"silence_03":{"text":"「これで……終わりだと思うな……。夜刀の闇は深いぞ……」","type":"text","bg_key":"bg_yato_tavern_night","speaker_name":"暗殺者頭領","speaker":"暗殺者頭領","next":"silence_04","choices":[{"label":"続ける","next":"silence_04"}]},"silence_04":{"text":"頭領はそのまま動かなくなった。部屋は再び静寂に包まれる。","type":"text","bg_key":"bg_yato_tavern_night","next":"silence_05","choices":[{"label":"続ける","next":"silence_05"}]},"silence_05":{"text":"息を整えながら、崩れ落ちた頭領の懐を慎重に探る。","type":"text","bg_key":"bg_yato_tavern_night","next":"check_relic","choices":[{"label":"続ける","next":"check_relic"}]},"check_relic":{"text":"血に染まった書簡が見つかった。そこには密命が記されている。","type":"text","bg_key":"bg_yato_tavern_night","next":"check_relic_02","choices":[{"label":"続ける","next":"check_relic_02"}]},"check_relic_02":{"text":"『標的を排除し、計画の妨げとなる芽を摘め』と書かれていた。","type":"text","bg_key":"bg_yato_tavern_night","next":"end_01","choices":[{"label":"続ける","next":"end_01"}]},"end_01":{"text":"宿の窓から、ようやく夜霧の薄れかけた朝の光が差し込む。","type":"text","bg_key":"bg_yato_tavern_night","bgm":"bgm_quest_calm","next":"end_02","choices":[{"label":"続ける","next":"end_02"}]},"end_02":{"text":"追っ手はこれからも現れるだろう。ここに留まるのは危険だ。","type":"text","bg_key":"bg_yato_tavern_night","next":"end_03","choices":[{"label":"続ける","next":"end_03"}]},"end_03":{"text":"荷物をまとめ、あなたは静かに荒れ果てた宿を後にした。","type":"text","bg_key":"bg_yato_tavern_night","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"朝霧の中、あなたは新たな戦いに向けて歩みを進めた。","type":"end","result":"success","bg_key":"bg_yato_tavern_night","params":{"rewards":{"exp":200,"gold":350,"reputation":10,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"深い霧の中、あなたは静かに力尽き、闇へと沈んでいった。","type":"end","result":"failure","bg_key":"bg_yato_tavern_night","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第8話"}'::jsonb,
    1,
    1
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6009: 第9話「大名行列の護衛」 (main_ep09)
