    ARRAY[]::text[],
    '{"completed_quest":"main_ep08","location_id":"loc_valley"}'::jsonb,
    '{"nodes":{"start":{"text":"夜刀神国のとある宿。あなたは地元の役人から呼び出された。","type":"text","bg_key":"bg_yato_tavern_night","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"内容は、領主である大名の輸送行列を護衛せよというものだ。","type":"text","bg_key":"bg_yato_tavern_night","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"『近頃、領地で不穏な動きがある。腕利きの力が必要だ』と。","type":"text","bg_key":"bg_yato_tavern_night","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"提示された報酬は破格だった。あなたは静かに依頼を引き受けた。","type":"text","bg_key":"bg_yato_tavern_night","next":"proc_01","choices":[{"label":"続ける","next":"proc_01"}]},"proc_01":{"text":"数日後、鬱蒼とした木々に囲まれた急峻な山道を行列が進む。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"proc_02","choices":[{"label":"続ける","next":"proc_02"}]},"proc_02":{"text":"荷馬車の数は十数台。積まれているのは大量の米俵のはずだ。","type":"text","bg_key":"bg_mountain","next":"proc_03","choices":[{"label":"続ける","next":"proc_03"}]},"proc_03":{"text":"だが、厳重すぎる警備と荷の重さに、あなたは違和感を抱く。","type":"text","bg_key":"bg_mountain","next":"proc_04","choices":[{"label":"続ける","next":"proc_04"}]},"proc_04":{"text":"周囲の茂みから、鳥の羽ばたきとは異なる不自然な音が聞こえた。","type":"text","bg_key":"bg_mountain","next":"captain_01","choices":[{"label":"続ける","next":"captain_01"}]},"captain_01":{"text":"「おい、気を引き締めろ！このあたりは山賊が出没する！」","type":"text","bg_key":"bg_mountain","speaker_name":"護衛団長","speaker":"護衛団長","next":"captain_02","choices":[{"label":"続ける","next":"captain_02"}]},"captain_02":{"text":"「特に今回は領主様の命がかかっている。決して遅れを取るな」","type":"text","bg_key":"bg_mountain","speaker_name":"護衛団長","speaker":"護衛団長","next":"captain_03","choices":[{"label":"続ける","next":"captain_03"}]},"captain_03":{"text":"「もし荷に傷をつけてみろ、ただの処分では済まないからな」","type":"text","bg_key":"bg_mountain","speaker_name":"護衛団長","speaker":"護衛団長","next":"mountain_01","choices":[{"label":"続ける","next":"mountain_01"}]},"mountain_01":{"text":"突如、前方からゴロゴロと巨大な岩が転がり落ちてきた！","type":"text","bg_key":"bg_mountain","next":"mountain_02","choices":[{"label":"続ける","next":"mountain_02"}]},"mountain_02":{"text":"悲鳴を上げる馬たち。行列は狭い山道で立ち往生する。","type":"text","bg_key":"bg_mountain","next":"mob_01","choices":[{"label":"続ける","next":"mob_01"}]},"mob_01":{"text":"茂みをかき分け、ボロをまとった集団が次々と姿を現した。","type":"text","bg_key":"bg_mountain","next":"mob_02","choices":[{"label":"続ける","next":"mob_02"}]},"mob_02":{"text":"その手にあるのは剣や槍ではなく、錆びついた鍬や鎌だった。","type":"text","bg_key":"bg_mountain","next":"mob_03","choices":[{"label":"続ける","next":"mob_03"}]},"mob_03":{"text":"集団の中には、痩せ細った老人や年若い子供の姿も混ざっている。","type":"text","bg_key":"bg_mountain","next":"mob_04","choices":[{"label":"続ける","next":"mob_04"}]},"mob_04":{"text":"彼らの瞳にあるのは狂暴さではなく、追い詰められた絶望だ。","type":"text","bg_key":"bg_mountain","next":"leader_01","choices":[{"label":"続ける","next":"leader_01"}]},"leader_01":{"text":"「米を返せ！それは我々が血と汗を流して育てた年貢米だ！」","type":"text","bg_key":"bg_mountain","speaker_name":"一揆の首謀者","speaker":"一揆の首謀者","next":"leader_02","choices":[{"label":"続ける","next":"leader_02"}]},"leader_02":{"text":"「このままでは村全員が餓死する！頼む、見逃してくれ！」","type":"text","bg_key":"bg_mountain","speaker_name":"一揆の首謀者","speaker":"一揆の首謀者","next":"leader_03","choices":[{"label":"続ける","next":"leader_03"}]},"leader_03":{"text":"「奪われたものを返すまで、我々はここを一歩も動かない！」","type":"text","bg_key":"bg_mountain","speaker_name":"一揆の首謀者","speaker":"一揆の首謀者","next":"rage_01","choices":[{"label":"続ける","next":"rage_01"}]},"rage_01":{"text":"「黙れ、薄汚い逆賊どもめ！領主様の荷に手を出すな！」","type":"text","bg_key":"bg_mountain","speaker_name":"護衛団長","speaker":"護衛団長","next":"rage_02","choices":[{"label":"続ける","next":"rage_02"}]},"rage_02":{"text":"「冒険者よ、こいつらを排除しろ！一人残らず斬り捨てろ！」","type":"text","bg_key":"bg_mountain","speaker_name":"護衛団長","speaker":"護衛団長","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_mountain","bgm":"bgm_battle","enemy_group_id":"404","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"圧倒的な武力の前に、農民たちは次々と地面へ伏せていく。","type":"text","bg_key":"bg_mountain","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"地に流れる赤い血が、山道の泥を黒く染めていった。","type":"text","bg_key":"bg_mountain","next":"after_03","choices":[{"label":"続ける","next":"after_03"}]},"after_03":{"text":"「ああ……これで村は終わりだ……子供たちに、飯を……」","type":"text","bg_key":"bg_mountain","speaker_name":"息絶え絶えの農民","speaker":"息絶え絶えの農民","next":"after_04","choices":[{"label":"続ける","next":"after_04"}]},"after_04":{"text":"助けを求めるように伸ばされた手が、やがて力なく崩れ落ちる。","type":"text","bg_key":"bg_mountain","next":"after_05","choices":[{"label":"続ける","next":"after_05"}]},"after_05":{"text":"静まり返った山道に、護衛団長の品のない高笑いが響き渡る。","type":"text","bg_key":"bg_mountain","next":"reward_01","choices":[{"label":"続ける","next":"reward_01"}]},"reward_01":{"text":"「よくやった！さすがは噂に聞く冒険者だな！」","type":"text","bg_key":"bg_mountain","speaker_name":"護衛団長","speaker":"護衛団長","next":"reward_02","choices":[{"label":"続ける","next":"reward_02"}]},"reward_02":{"text":"「これで荷の安全は保たれた。大名様もさぞお喜びになる」","type":"text","bg_key":"bg_mountain","speaker_name":"護衛団長","speaker":"護衛団長","next":"reward_03","choices":[{"label":"続ける","next":"reward_03"}]},"reward_03":{"text":"団長は満足げにうなずき、倒れた農民の体を冷酷に踏みつけた。","type":"text","bg_key":"bg_mountain","next":"tools_01","choices":[{"label":"続ける","next":"tools_01"}]},"tools_01":{"text":"ふと見ると、一揆の衝撃で壊れた荷箱から中身がこぼれている。","type":"text","bg_key":"bg_mountain","next":"tools_02","choices":[{"label":"続ける","next":"tools_02"}]},"tools_02":{"text":"それは米ではなく、他国と密売するための高級な織物だった。","type":"text","bg_key":"bg_mountain","next":"tools_03","choices":[{"label":"続ける","next":"tools_03"}]},"tools_03":{"text":"農民から奪った米を売り払い、私腹を肥やす大名の欺瞞。","type":"text","bg_key":"bg_mountain","next":"end_01","choices":[{"label":"続ける","next":"end_01"}]},"end_01":{"text":"差し出された報酬の金貨袋が、異様に重く感じられた。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"end_02","choices":[{"label":"続ける","next":"end_02"}]},"end_02":{"text":"自分が守ったものは何だったのか。答えは霧の中に消えた。","type":"text","bg_key":"bg_mountain","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"あなたは無言で山道を下り、大名の街へと戻っていった。","type":"end","result":"success","bg_key":"bg_mountain","params":{"rewards":{"exp":250,"gold":500,"reputation":15,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"乱戦の中、あなたは刃に倒れ、山道の肥やしとなった。","type":"end","result":"failure","bg_key":"bg_mountain","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第9話"}'::jsonb,
    3,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6010: 第10話「世界の底が抜ける日」 (main_ep10)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6010,
    'main_ep10',
    '第10話「世界の底が抜ける日」',
    'メインシナリオ第10話',
    'なし',
    2,
    10,
    2,
    '{"gold":500,"items":[502],"reputation":15,"alignment_shift":{"justice":10},"move_to":"loc_charon"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep09","location_id":"loc_yato"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep09","location_id":"loc_yato"}'::jsonb,
    '{"nodes":{"start":{"text":"立ち入りを禁じられた古代神殿の奥。そこは静まり返っている。","type":"text","bg_key":"bg_boss_altar","bgm":"bgm_quest_crisis","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"足音が不気味に響き、周囲の古い石柱を震わせた。","type":"text","bg_key":"bg_boss_altar","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"神殿の最奥には、怪しく光る巨大な水晶の祭壇が鎮座する。","type":"text","bg_key":"bg_boss_altar","next":"interior_01","choices":[{"label":"続ける","next":"interior_01"}]},"interior_01":{"text":"あなたが近づくと、水晶の輝きが激しさを増していった。","type":"text","bg_key":"bg_boss_altar","next":"interior_02","choices":[{"label":"続ける","next":"interior_02"}]},"interior_02":{"text":"光の中に、信じがたい光景が次々と浮かび上がる。","type":"text","bg_key":"bg_boss_altar","next":"vision_01","choices":[{"label":"続ける","next":"vision_01"}]},"vision_01":{"text":"炎に包まれて崩れ去るマルカンドのオアシスの街。","type":"text","bg_key":"bg_boss_altar","next":"vision_02","choices":[{"label":"続ける","next":"vision_02"}]},"vision_02":{"text":"血に染まった剣を握りしめ、冷たく伏せる兵士たちの群れ。","type":"text","bg_key":"bg_boss_altar","next":"vision_03","choices":[{"label":"続ける","next":"vision_03"}]},"vision_03":{"text":"痩せ細った腕を伸ばし、泥水を求めて這い回る人々。","type":"text","bg_key":"bg_boss_altar","next":"vision_04","choices":[{"label":"続ける","next":"vision_04"}]},"vision_04":{"text":"それらはすべて、あなたが旅の途中で目にした光景だった。","type":"text","bg_key":"bg_boss_altar","next":"vision_05","choices":[{"label":"続ける","next":"vision_05"}]},"vision_05":{"text":"まるで世界の破滅が、あらかじめ決められていたかのように。","type":"text","bg_key":"bg_boss_altar","next":"voice_01","choices":[{"label":"続ける","next":"voice_01"}]},"voice_01":{"text":"「穢れの蓄積値が規定量を超過。第3浄化段階へ移行します」","type":"text","bg_key":"bg_boss_altar","speaker_name":"祭壇の声","speaker":"祭壇の声","next":"voice_02","choices":[{"label":"続ける","next":"voice_02"}]},"voice_02":{"text":"「これより地上の一切の生命を消去し、世界を初期化します」","type":"text","bg_key":"bg_boss_altar","speaker_name":"祭壇の声","speaker":"祭壇の声","next":"voice_03","choices":[{"label":"続ける","next":"voice_03"}]},"voice_03":{"text":"「すべては天上の神々の意志。反論は受け付けられません」","type":"text","bg_key":"bg_boss_altar","speaker_name":"祭壇の声","speaker":"祭壇の声","next":"real_01","choices":[{"label":"続ける","next":"real_01"}]},"real_01":{"text":"無機質な声が神殿内に響き渡る。あなたは驚愕に息を呑む。","type":"text","bg_key":"bg_boss_altar","next":"real_02","choices":[{"label":"続ける","next":"real_02"}]},"real_02":{"text":"人々が戦い、血を流し、苦しんできたすべての歴史。","type":"text","bg_key":"bg_boss_altar","next":"real_03","choices":[{"label":"続ける","next":"real_03"}]},"real_03":{"text":"それは神々が描いた、単なる『間引き』の脚本に過ぎない。","type":"text","bg_key":"bg_boss_altar","next":"real_04","choices":[{"label":"続ける","next":"real_04"}]},"real_04":{"text":"人間はただの操り人形だったのか。胸の奥から怒りが湧く。","type":"text","bg_key":"bg_boss_altar","next":"rage_01","choices":[{"label":"続ける","next":"rage_01"}]},"rage_01":{"text":"あなたは静かに剣を引き抜いた。刃が水晶の光を反射する。","type":"text","bg_key":"bg_boss_altar","next":"rage_02","choices":[{"label":"続ける","next":"rage_02"}]},"rage_02":{"text":"誰が定めた運命だ。自分たちの命を勝手に消させてたまるか。","type":"text","bg_key":"bg_boss_altar","next":"rage_03","choices":[{"label":"続ける","next":"rage_03"}]},"rage_03":{"text":"刃の先を真っ直ぐに祭壇へ向け、強く足を踏み出した。","type":"text","bg_key":"bg_boss_altar","next":"dragon_01","choices":[{"label":"続ける","next":"dragon_01"}]},"dragon_01":{"text":"その瞬間、水晶が激しく脈動し、神殿の空間自体が歪む。","type":"text","bg_key":"bg_boss_altar","next":"dragon_02","choices":[{"label":"続ける","next":"dragon_02"}]},"dragon_02":{"text":"裂け目から、純白の鱗を持つ巨大な生物が姿を現した。","type":"text","bg_key":"bg_boss_altar","next":"dragon_03","choices":[{"label":"続ける","next":"dragon_03"}]},"dragon_03":{"text":"神代より祭壇を守護してきた、伝説の白竜である。","type":"text","bg_key":"bg_boss_altar","next":"dragon_04","choices":[{"label":"続ける","next":"dragon_04"}]},"dragon_04":{"text":"白竜の黄金の瞳が、反逆者たるあなたを静かに見下ろす。","type":"text","bg_key":"bg_boss_altar","next":"dragon_05","choices":[{"label":"続ける","next":"dragon_05"}]},"dragon_05":{"text":"「神の法に背く愚かなる人よ。その身をもって罪を贖え」","type":"text","bg_key":"bg_boss_altar","speaker_name":"神代の守護竜","speaker":"神代の守護竜","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_boss_altar","bgm":"bgm_battle_boss","enemy_group_id":"209","choices":[{"label":"win","next":"after_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_01"},"after_01":{"text":"激闘の末、大剣が竜の急所を貫き、守護竜は崩れ落ちた。","type":"text","bg_key":"bg_boss_altar","next":"after_02","choices":[{"label":"続ける","next":"after_02"}]},"after_02":{"text":"竜の消滅とともに、祭壇の水晶は砕け散り、光を失う。","type":"text","bg_key":"bg_boss_altar","next":"after_03","choices":[{"label":"続ける","next":"after_03"}]},"after_03":{"text":"静寂が戻った神殿の床に、一本の白い牙が落ちていた。","type":"text","bg_key":"bg_boss_altar","next":"after_04","choices":[{"label":"続ける","next":"after_04"}]},"after_04":{"text":"それは守護竜の力が宿る牙だ。あなたはそれを拾い上げた。","type":"text","bg_key":"bg_boss_altar","next":"end_01","choices":[{"label":"続ける","next":"end_01"}]},"end_01":{"text":"大浄化は一時的に防がれた。だが、本質は何も変わらない。","type":"text","bg_key":"bg_boss_altar","bgm":"bgm_quest_calm","next":"end_02","choices":[{"label":"続ける","next":"end_02"}]},"end_02":{"text":"神々の真意を確かめねばならない。あなたは西を目指す。","type":"text","bg_key":"bg_boss_altar","next":"end_03","choices":[{"label":"続ける","next":"end_03"}]},"end_03":{"text":"華龍神朝へ。新たな答えを求めて、あなたは旅立つ。","type":"text","bg_key":"bg_boss_altar","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"暗闇の神殿を背に、あなたは新たな一歩を踏み出した。","type":"end","result":"success","bg_key":"bg_boss_altar","params":{"rewards":{"exp":300,"gold":600,"reputation":20,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"守護竜の圧倒的な爪牙の前に、あなたの意識は消え去った。","type":"end","result":"failure","bg_key":"bg_boss_altar","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第10話"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

