    ARRAY[]::text[],
    '{"completed_quest":"main_ep10","location_id":"loc_charon"}'::jsonb,
    '{"nodes":{"start":{"text":"華龍神朝の広大な穀倉地帯を行く街道。のどかな風景。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"karyu_01","choices":[{"label":"続ける","next":"karyu_01"}]},"karyu_01":{"text":"しかし、吹き抜ける風にはどこか不穏な冷たさがあった。","type":"text","bg_key":"bg_road_day","next":"karyu_02","choices":[{"label":"続ける","next":"karyu_02"}]},"karyu_02":{"text":"街道を進むあなたの足元で、突然大地が小さく震える。","type":"text","bg_key":"bg_road_day","next":"sky_01","choices":[{"label":"続ける","next":"sky_01"}]},"sky_01":{"text":"見上げた空に異変が起きた。雲が黄金色に輝き始める。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_crisis","next":"sky_02","choices":[{"label":"続ける","next":"sky_02"}]},"sky_02":{"text":"天空に二つ目の太陽、そして三つ目の太陽が出現する。","type":"text","bg_key":"bg_ruins_field","next":"sky_03","choices":[{"label":"続ける","next":"sky_03"}]},"sky_03":{"text":"異様な光に照らされ、街道の木々が一瞬で立ち枯れた。","type":"text","bg_key":"bg_ruins_field","next":"villagers_01","choices":[{"label":"続ける","next":"villagers_01"}]},"villagers_01":{"text":"「天罰だ……！神々が我らを滅ぼしに来たのだ！」","type":"text","bg_key":"bg_ruins_field","speaker_name":"怯える農民","speaker":"怯える農民","next":"villagers_02","choices":[{"label":"続ける","next":"villagers_02"}]},"villagers_02":{"text":"「おしまいだ、どこにも逃げ場所なんてない……！」","type":"text","bg_key":"bg_ruins_field","speaker_name":"怯える農民","speaker":"怯える農民","next":"voice_01","choices":[{"label":"続ける","next":"voice_01"}]},"voice_01":{"text":"天空から、鼓膜を裂くような無機質な声が鳴り響いた。","type":"text","bg_key":"bg_ruins_field","next":"voice_02","choices":[{"label":"続ける","next":"voice_02"}]},"voice_02":{"text":"「地上ノ穢レタ種ヨ。大イナル浄化ノ光ヲ受ケ入れヨ」","type":"text","bg_key":"bg_ruins_field","speaker_name":"天の啓示","speaker":"天の啓示","next":"angels_01","choices":[{"label":"続ける","next":"angels_01"}]},"angels_01":{"text":"光の輪を頭上に戴く、無数の人型の怪物――使徒が降下する。","type":"text","bg_key":"bg_ruins_field","next":"angels_02","choices":[{"label":"続ける","next":"angels_02"}]},"angels_02":{"text":"奴らの手から放たれる熱線が、村の家々を次々と焼き払う。","type":"text","bg_key":"bg_ruins_field","next":"angels_03","choices":[{"label":"続ける","next":"angels_03"}]},"angels_03":{"text":"悲鳴を上げて逃げ惑う人々。阿鼻叫喚の地獄絵図が広がる。","type":"text","bg_key":"bg_ruins_field","next":"slaughter_01","choices":[{"label":"続ける","next":"slaughter_01"}]},"slaughter_01":{"text":"逃げ遅れた子供に、使徒が冷酷にその手を伸ばした。","type":"text","bg_key":"bg_ruins_field","next":"stand_01","choices":[{"label":"続ける","next":"stand_01"}]},"stand_01":{"text":"あなたは迷わず駆け出し、使徒の前に立ちはだかった。","type":"text","bg_key":"bg_ruins_field","next":"stand_02","choices":[{"label":"続ける","next":"stand_02"}]},"stand_02":{"text":"迫り来る天の軍勢を睨みつけ、大剣を鋭く構える。","type":"text","bg_key":"bg_ruins_field","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle","enemy_group_id":"210","choices":[{"label":"win","next":"post_battle"},{"label":"lose","next":"end_failure"}],"battle_success_next":"post_battle"},"post_battle":{"text":"なんとか一体を撃破した。しかし、周囲の使徒が集まる。","type":"text","bg_key":"bg_ruins_field","next":"post_02","choices":[{"label":"続ける","next":"post_02"}]},"post_02":{"text":"さらに上空から、十数体の使徒が新たに舞い降りてきた。","type":"text","bg_key":"bg_ruins_field","next":"wave_01","choices":[{"label":"続ける","next":"wave_01"}]},"wave_01":{"text":"息を荒くしながら、あなたは再び武器を握り直した。","type":"text","bg_key":"bg_ruins_field","next":"wave_02","choices":[{"label":"続ける","next":"wave_02"}]},"wave_02":{"text":"退路を確保するため、押し寄せる光の軍勢に挑みかかる。","type":"text","bg_key":"bg_ruins_field","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle","enemy_group_id":"210","choices":[{"label":"win","next":"retreat_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"retreat_01"},"retreat_01":{"text":"敵の包囲網を強引にこじ開け、森の奥へと走り込んだ。","type":"text","bg_key":"bg_ruins_field","next":"retreat_02","choices":[{"label":"続ける","next":"retreat_02"}]},"retreat_02":{"text":"満身創痍になりながらも、あなたは追跡を振り切った。","type":"text","bg_key":"bg_ruins_field","next":"volg_01","choices":[{"label":"続ける","next":"volg_01"}]},"volg_01":{"text":"たどり着いたのは、険しい岩肌が露出した山の中だった。","type":"text","bg_key":"bg_bandit_camp","bgm":"bgm_quest_calm","next":"volg_02","choices":[{"label":"続ける","next":"volg_02"}]},"volg_02":{"text":"周囲には、頭の輪が砕かれた使徒の骸が何体も転がっている。","type":"text","bg_key":"bg_bandit_camp","next":"volg_03","choices":[{"label":"続ける","next":"volg_03"}]},"volg_03":{"text":"骸を椅子代わりに腰掛ける、身の丈を超える大柄な男。","type":"text","bg_key":"bg_bandit_camp","next":"volg_04","choices":[{"label":"続ける","next":"volg_04"}]},"volg_04":{"text":"大剣を肩に担ぎ、獰猛な肉食獣のような瞳でこちらを見る。","type":"text","bg_key":"bg_bandit_camp","next":"volg_05","choices":[{"label":"続ける","next":"volg_05"}]},"volg_05":{"text":"「あの使徒どもを相手に生き延びたか。見所はあるな」","type":"text","bg_key":"bg_bandit_camp","speaker_name":"不死の傭兵ヴォルグ","speaker":"不死の傭兵ヴォルグ","next":"volg_06","choices":[{"label":"続ける","next":"volg_06"}]},"volg_06":{"text":"「だが、俺の足手まといになるような雑魚は必要ねえ」","type":"text","bg_key":"bg_bandit_camp","speaker_name":"不死の傭兵ヴォルグ","speaker":"不死の傭兵ヴォルグ","next":"volg_07","choices":[{"label":"続ける","next":"volg_07"}]},"volg_07":{"text":"「お前が天の奴らと戦う覚悟があるか、試させてもらう」","type":"text","bg_key":"bg_bandit_camp","speaker_name":"不死の傭兵ヴォルグ","speaker":"不死の傭兵ヴォルグ","next":"battle3","choices":[{"label":"続ける","next":"battle3"}]},"battle3":{"type":"battle","bg_key":"bg_bandit_camp","bgm":"bgm_battle_strong","enemy_group_id":"213","choices":[{"label":"win","next":"close_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"close_01"},"close_01":{"text":"激しい金属音が山に響く。あなたは男の一撃を受け止めた。","type":"text","bg_key":"bg_bandit_camp","next":"approve_01","choices":[{"label":"続ける","next":"approve_01"}]},"approve_01":{"text":"男は大剣を引き、面白そうに喉を鳴らして笑った。","type":"text","bg_key":"bg_bandit_camp","next":"approve_02","choices":[{"label":"続ける","next":"approve_02"}]},"approve_02":{"text":"「合格だ。これなら背中を預けても退屈しなさそうだな」","type":"text","bg_key":"bg_bandit_camp","speaker_name":"不死の傭兵ヴォルグ","speaker":"不死の傭兵ヴォルグ","next":"decision_01","choices":[{"label":"続ける","next":"decision_01"}]},"decision_01":{"text":"「俺の名はヴォルグ。天の野郎どもの大掃除を邪魔してやる」","type":"text","bg_key":"bg_bandit_camp","speaker_name":"不死の傭兵ヴォルグ","speaker":"不死の傭兵ヴォルグ","next":"decision_02","choices":[{"label":"続ける","next":"decision_02"}]},"decision_02":{"text":"「次は砂漠の国、マルカンドが狙われているらしい」","type":"text","bg_key":"bg_bandit_camp","speaker_name":"不死の傭兵ヴォルグ","speaker":"不死の傭兵ヴォルグ","next":"depart_01","choices":[{"label":"続ける","next":"depart_01"}]},"depart_01":{"text":"ヴォルグは立ち上がり、使徒の死体を蹴り飛ばした。","type":"text","bg_key":"bg_bandit_camp","next":"depart_02","choices":[{"label":"続ける","next":"depart_02"}]},"depart_02":{"text":"黄金都市イスハークを守るため、あなたは決意を固める。","type":"text","bg_key":"bg_bandit_camp","next":"end_01","choices":[{"label":"続ける","next":"end_01"}]},"end_01":{"text":"不死の傭兵と共に、あなたは砂漠の国への路を急いだ。","type":"text","bg_key":"bg_bandit_camp","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"神々への反逆の旅が、ここに本格的に開始された。","type":"end","result":"success","bg_key":"bg_bandit_camp","params":{"rewards":{"exp":300,"gold":1200,"reputation":15,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"天の光に貫かれ、あなたは灰となって風に散った。","type":"end","result":"failure","bg_key":"bg_ruins_field","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第11話"}'::jsonb,
    3,
    2
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
