    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6012: 第12話「炎の審判者」 (main_ep12)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6012,
    'main_ep12',
    '第12話「炎の審判者」',
    'メインシナリオ第12話',
    'なし',
    3,
    12,
    2,
    '{"gold":1500,"items":[],"reputation":15,"alignment_shift":{"order":5},"move_to":"loc_charon"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep11","location_id":"loc_meridia"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep11","location_id":"loc_meridia"}'::jsonb,
    '{"nodes":{"start":{"text":"砂塵の王国マルカンドの荒野。地平線の先から黒煙が昇る。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"街道には、傷ついた体で逃げ延びてきた避難民の列が続く。","type":"text","bg_key":"bg_desert","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「どうやら間に合ったようだが、ひでえ有り様だな」","type":"text","bg_key":"bg_desert","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_join","choices":[{"label":"続ける","next":"volg_join"}]},"volg_join":{"type":"guest_join","bg_key":"bg_desert","params":{"guest_id":"npc_guest_volg"},"next":"arrival_01","choices":[{"label":"続ける","next":"arrival_01"}]},"arrival_01":{"text":"黄金の都市イスハークへ入る。かつての栄華は見る影もない。","type":"text","bg_key":"bg_ishaq_ruined","bgm":"bgm_quest_crisis","next":"arrival_02","choices":[{"label":"続ける","next":"arrival_02"}]},"arrival_02":{"text":"空から絶え間なく炎の矢が降り注ぎ、街全体を焼き尽くす。","type":"text","bg_key":"bg_ishaq_ruined","next":"arrival_03","choices":[{"label":"続ける","next":"arrival_03"}]},"arrival_03":{"text":"崩れ落ちる建物と、人々の悲鳴が渦巻く地獄と化していた。","type":"text","bg_key":"bg_ishaq_ruined","next":"flames_01","choices":[{"label":"続ける","next":"flames_01"}]},"flames_01":{"text":"炎の壁に阻まれ、身動きが取れなくなった一団を見つける。","type":"text","bg_key":"bg_ishaq_ruined","next":"flames_02","choices":[{"label":"続ける","next":"flames_02"}]},"flames_02":{"text":"その背後から、光り輝く使徒の群れが荒々しく迫っていた。","type":"text","bg_key":"bg_ishaq_ruined","next":"refugees_01","choices":[{"label":"続ける","next":"refugees_01"}]},"refugees_01":{"text":"あなたはヴォルグと目配せし、一斉に敵の前に躍り出る。","type":"text","bg_key":"bg_ishaq_ruined","next":"refugees_02","choices":[{"label":"続ける","next":"refugees_02"}]},"refugees_02":{"text":"「天の雑魚どもが、俺の獲物に手を出すんじゃねえ！」","type":"text","bg_key":"bg_ishaq_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_fury_01","choices":[{"label":"続ける","next":"volg_fury_01"}]},"volg_fury_01":{"text":"ヴォルグの大剣が一閃し、先頭の使徒を一撃で叩き伏せた。","type":"text","bg_key":"bg_ishaq_ruined","next":"volg_fury_02","choices":[{"label":"続ける","next":"volg_fury_02"}]},"volg_fury_02":{"text":"残された使徒たちが激昂し、あなたたちを取り囲む。","type":"text","bg_key":"bg_ishaq_ruined","next":"plaza_01","choices":[{"label":"続ける","next":"plaza_01"}]},"plaza_01":{"text":"避難民を逃がすための時間を稼ぐため、剣を強く握る。","type":"text","bg_key":"bg_ishaq_ruined","next":"plaza_02","choices":[{"label":"続ける","next":"plaza_02"}]},"plaza_02":{"text":"燃え盛る広場の中で、包囲する使徒たちと対峙した。","type":"text","bg_key":"bg_ishaq_ruined","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"type":"battle","bg_key":"bg_ishaq_ruined","bgm":"bgm_battle","enemy_group_id":"502","choices":[{"label":"win","next":"clear_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"clear_01"},"clear_01":{"text":"息を合わせ、襲いかかる使徒の群れをすべて撃退した。","type":"text","bg_key":"bg_ishaq_ruined","next":"clear_02","choices":[{"label":"続ける","next":"clear_02"}]},"clear_02":{"text":"だがその時、上空の炎の渦が凝縮し、強烈な光を放つ。","type":"text","bg_key":"bg_ishaq_ruined","next":"uriel_01","choices":[{"label":"続ける","next":"uriel_01"}]},"uriel_01":{"text":"炎の翼を広げ、燃え盛る大剣を手にした大天使が舞い降りる。","type":"text","bg_key":"bg_ishaq_ruined","next":"uriel_02","choices":[{"label":"続ける","next":"uriel_02"}]},"uriel_02":{"text":"その圧倒的な威圧感の前に、周囲の炎さえもひれ伏す。","type":"text","bg_key":"bg_ishaq_ruined","next":"uriel_03","choices":[{"label":"続ける","next":"uriel_03"}]},"uriel_03":{"text":"「穢レタ砂ノ都ヨ。天ノ炎ニヨリ、スベテ清メラレヨ」","type":"text","bg_key":"bg_ishaq_ruined","speaker_name":"大天使ウリエル","speaker":"大天使ウリエル","next":"uriel_04","choices":[{"label":"続ける","next":"uriel_04"}]},"uriel_04":{"text":"ウリエルの剣から、超高熱の劫火が放たれようとしていた。","type":"text","bg_key":"bg_ishaq_ruined","next":"volg_charge_01","choices":[{"label":"続ける","next":"volg_charge_01"}]},"volg_charge_01":{"text":"「へっ、清めるだと？ そのふざけた翼をむしってやる！」","type":"text","bg_key":"bg_ishaq_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_charge_02","choices":[{"label":"続ける","next":"volg_charge_02"}]},"volg_charge_02":{"text":"ヴォルグは咆哮と共に、真っ向から大天使へ突撃する。","type":"text","bg_key":"bg_ishaq_ruined","next":"volg_charge_03","choices":[{"label":"続ける","next":"volg_charge_03"}]},"volg_charge_03":{"text":"あなたも後に続き、炎を切り裂いて大天使へ肉薄した。","type":"text","bg_key":"bg_ishaq_ruined","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"type":"battle","bg_key":"bg_ishaq_ruined","bgm":"bgm_battle_strong","enemy_group_id":"9040","choices":[{"label":"win","next":"retreat_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"retreat_01"},"retreat_01":{"text":"大天使の盾を砕き、ウリエルを怯ませる。","type":"text","bg_key":"bg_ishaq_ruined","next":"retreat_02","choices":[{"label":"続ける","next":"retreat_02"}]},"retreat_02":{"text":"ウリエルは傷ついた翼を広げ、ゆっくりと上空へ退いた。","type":"text","bg_key":"bg_ishaq_ruined","next":"retreat_03","choices":[{"label":"続ける","next":"retreat_03"}]},"retreat_03":{"text":"「審判ハ下サレタ……。次ハ華龍ノ都、龍京ナリ……」","type":"text","bg_key":"bg_ishaq_ruined","speaker_name":"大天使ウリエル","speaker":"大天使ウリエル","next":"aftermath_01","choices":[{"label":"続ける","next":"aftermath_01"}]},"aftermath_01":{"text":"ウリエルは雲の彼方へと消え、街の炎も次第に収まっていく。","type":"text","bg_key":"bg_ishaq_ruined","bgm":"bgm_quest_calm","next":"aftermath_02","choices":[{"label":"続ける","next":"aftermath_02"}]},"aftermath_02":{"text":"黄金都市は傷ついたが、多くの人々が命を永らえた。","type":"text","bg_key":"bg_ishaq_ruined","next":"volg_next_01","choices":[{"label":"続ける","next":"volg_next_01"}]},"volg_next_01":{"text":"「チッ、逃げ足の速い野郎だ。次は龍京に向かったか」","type":"text","bg_key":"bg_ishaq_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_next_02","choices":[{"label":"続ける","next":"volg_next_02"}]},"volg_next_02":{"text":"「俺は一足先に龍京へ行く。手遅れになる前に来いよ」","type":"text","bg_key":"bg_ishaq_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_leave","choices":[{"label":"続ける","next":"volg_leave"}]},"volg_leave":{"type":"leave","bg_key":"bg_ishaq_ruined","params":{"guest_id":"npc_guest_volg"},"next":"next_01","choices":[{"label":"続ける","next":"next_01"}]},"next_01":{"text":"ヴォルグは風のように去っていった。あなたも後に続く。","type":"text","bg_key":"bg_ishaq_ruined","next":"next_02","choices":[{"label":"続ける","next":"next_02"}]},"next_02":{"text":"次の標的である龍京を守るため、あなたは走り出した。","type":"text","bg_key":"bg_ishaq_ruined","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"砂塵の都に復興の兆しを残し、あなたの旅は続く。","type":"end","result":"success","bg_key":"bg_ishaq_ruined","params":{"rewards":{"exp":350,"gold":1500,"reputation":15,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"大天使の無慈悲な業火に包まれ、すべては灰に帰した。","type":"end","result":"failure","bg_key":"bg_ishaq_ruined","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第12話"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6013: 第13話「癒しの暴君」 (main_ep13)
