    ARRAY[]::text[],
    '{"completed_quest":"main_ep12","location_id":"loc_charon"}'::jsonb,
    '{"nodes":{"start":{"text":"華龍神朝の首都、龍京へと続く街道を進む。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"約束の場所で、ヴォルグが待っていた。","type":"text","bg_key":"bg_road_day","next":"volg_join","choices":[{"label":"続ける","next":"volg_join"}]},"volg_join":{"type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_volg"},"next":"arrival_01","choices":[{"label":"続ける","next":"arrival_01"}]},"arrival_01":{"text":"龍京の城門に到着するが、門兵の姿が見当たらない。","type":"text","bg_key":"bg_ryukyo_ruined","bgm":"bgm_quest_tense","next":"arrival_02","choices":[{"label":"続ける","next":"arrival_02"}]},"arrival_02":{"text":"都の中に一歩踏み入ると、異様な静寂が支配していた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"silence_01","choices":[{"label":"続ける","next":"silence_01"}]},"silence_01":{"text":"見ると、路傍に多くの人々が横たわっている。","type":"text","bg_key":"bg_ryukyo_ruined","next":"silence_02","choices":[{"label":"続ける","next":"silence_02"}]},"silence_02":{"text":"皆、穏やかな表情で深い眠りに落ちていた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"sleeping_01","choices":[{"label":"続ける","next":"sleeping_01"}]},"sleeping_01":{"text":"声をかけても、体を揺すっても、起きる気配はない。","type":"text","bg_key":"bg_ryukyo_ruined","next":"sleeping_02","choices":[{"label":"続ける","next":"sleeping_02"}]},"sleeping_02":{"text":"都全体が、呪われた眠りに包まれているかのようだ。","type":"text","bg_key":"bg_ryukyo_ruined","next":"volg_01","choices":[{"label":"続ける","next":"volg_01"}]},"volg_01":{"text":"「死体じゃねえな。だが、眠ったまま起きやしねえ」","type":"text","bg_key":"bg_ryukyo_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_02","choices":[{"label":"続ける","next":"volg_02"}]},"volg_02":{"text":"上空から、光る緑の微粒子が静かに舞い降りてくる。","type":"text","bg_key":"bg_ryukyo_ruined","next":"soldier_01","choices":[{"label":"続ける","next":"soldier_01"}]},"soldier_01":{"text":"粒子を浴びた瞬間、激しい睡魔があなたを襲った。","type":"text","bg_key":"bg_ryukyo_ruined","next":"soldier_02","choices":[{"label":"続ける","next":"soldier_02"}]},"soldier_02":{"text":"意識が遠のき、立っていることさえ困難になる。","type":"text","bg_key":"bg_ryukyo_ruined","next":"presence_01","choices":[{"label":"続ける","next":"presence_01"}]},"presence_01":{"text":"広場の中心に、眠りの粒子を撒く奇妙な使徒が現れる。","type":"text","bg_key":"bg_ryukyo_ruined","next":"presence_02","choices":[{"label":"続ける","next":"presence_02"}]},"presence_02":{"text":"睡魔を払うため、あなたは強く奥歯を噛み締めた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"presence_03","choices":[{"label":"続ける","next":"presence_03"}]},"presence_03":{"text":"使徒を排除しなければ、この眠りからは逃れられない。","type":"text","bg_key":"bg_ryukyo_ruined","next":"guard_01","choices":[{"label":"続ける","next":"guard_01"}]},"guard_01":{"text":"あなたは武器を構え、使徒に向かって踏み出す。","type":"text","bg_key":"bg_ryukyo_ruined","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"type":"battle","bg_key":"bg_ryukyo_ruined","bgm":"bgm_battle","enemy_group_id":"503","choices":[{"label":"win","next":"throne_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"throne_01"},"throne_01":{"text":"使徒を撃破したが、睡魔の源はまだ消えていない。","type":"text","bg_key":"bg_ryukyo_ruined","next":"throne_02","choices":[{"label":"続ける","next":"throne_02"}]},"throne_02":{"text":"宮殿の奥から、さらに濃厚な眠りの霧が溢れ出す。","type":"text","bg_key":"bg_ryukyo_ruined","next":"raphael_01","choices":[{"label":"続ける","next":"raphael_01"}]},"raphael_01":{"text":"光の粒子が寄り集まり、大天使ラファエルが降臨した。","type":"text","bg_key":"bg_ryukyo_ruined","next":"raphael_02","choices":[{"label":"続ける","next":"raphael_02"}]},"raphael_02":{"text":"慈愛に満ちた瞳で、大天使はあなたたちを見つめる。","type":"text","bg_key":"bg_ryukyo_ruined","next":"raphael_03","choices":[{"label":"続ける","next":"raphael_03"}]},"raphael_03":{"text":"「苦シミハモウ終ワリニシヨウ。全テ眠リノ中デ癒サレル」","type":"text","bg_key":"bg_ryukyo_ruined","speaker_name":"大天使ラファエル","speaker":"大天使ラファエル","next":"raphael_04","choices":[{"label":"続ける","next":"raphael_04"}]},"raphael_04":{"text":"甘い声が脳裏に響き、体に吸い込まれるように眠気が増す。","type":"text","bg_key":"bg_ryukyo_ruined","next":"volg_rage_01","choices":[{"label":"続ける","next":"volg_rage_01"}]},"volg_rage_01":{"text":"ヴォルグもまた、睡魔に膝を突きそうになっていた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"volg_rage_02","choices":[{"label":"続ける","next":"volg_rage_02"}]},"volg_rage_02":{"text":"その時、ヴォルグは大剣で自らの腕を切り裂いた！","type":"text","bg_key":"bg_ryukyo_ruined","next":"volg_rage_03","choices":[{"label":"続ける","next":"volg_rage_03"}]},"volg_rage_03":{"text":"「ぐっ……！ 痛みで目が覚めたぜ。安らぎなんざ不要だ！」","type":"text","bg_key":"bg_ryukyo_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_rage_04","choices":[{"label":"続ける","next":"volg_rage_04"}]},"volg_rage_04":{"text":"あなたも己の頬を強く叩き、無理やり意識を繋ぎ止める。","type":"text","bg_key":"bg_ryukyo_ruined","next":"volg_rage_05","choices":[{"label":"続ける","next":"volg_rage_05"}]},"volg_rage_05":{"text":"大天使がもたらす『偽りの救い』を拒み、剣を構えた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"type":"battle","bg_key":"bg_ryukyo_ruined","bgm":"bgm_battle_strong","enemy_group_id":"9041","choices":[{"label":"win","next":"retreat_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"retreat_01"},"retreat_01":{"text":"激闘の末、大天使の防御を突き崩し、その身に傷を負わせる。","type":"text","bg_key":"bg_ryukyo_ruined","next":"retreat_02","choices":[{"label":"続ける","next":"retreat_02"}]},"retreat_02":{"text":"ラファエルは光の粒子となって、天空へと退却した。","type":"text","bg_key":"bg_ryukyo_ruined","next":"retreat_03","choices":[{"label":"続ける","next":"retreat_03"}]},"retreat_03":{"text":"「偽リノ覚醒ハ苦痛ノミナリ……。次ハ夜刀ノ出雲ヘ……」","type":"text","bg_key":"bg_ryukyo_ruined","speaker_name":"大天使ラファエル","speaker":"大天使ラファエル","next":"awaken_01","choices":[{"label":"続ける","next":"awaken_01"}]},"awaken_01":{"text":"大天使の撤退と共に、都を覆っていた眠りの霧が晴れる。","type":"text","bg_key":"bg_ryukyo_ruined","bgm":"bgm_quest_calm","next":"awaken_02","choices":[{"label":"続ける","next":"awaken_02"}]},"awaken_02":{"text":"眠っていた人々が、一人、また一人と目を覚まし始めた。","type":"text","bg_key":"bg_ryukyo_ruined","next":"volg_leave","choices":[{"label":"続ける","next":"volg_leave"}]},"volg_leave":{"type":"leave","bg_key":"bg_ryukyo_ruined","params":{"guest_id":"npc_guest_volg"},"next":"next_01","choices":[{"label":"続ける","next":"next_01"}]},"next_01":{"text":"「次は出雲だな。天の奴ら、次々と面倒を起こしやがる」","type":"text","bg_key":"bg_ryukyo_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"next_02","choices":[{"label":"続ける","next":"next_02"}]},"next_02":{"text":"ヴォルグは腕の傷を包帯で縛り、早くも次の地へ歩み出す。","type":"text","bg_key":"bg_ryukyo_ruined","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"都の覚醒を見届け、あなたは出雲への路を急いだ。","type":"end","result":"success","bg_key":"bg_ryukyo_ruined","params":{"rewards":{"exp":350,"gold":1800,"reputation":20,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"心地よい睡魔に身を委ね、あなたは二度と目覚めなかった。","type":"end","result":"failure","bg_key":"bg_ryukyo_ruined","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第13話"}'::jsonb,
    3,
    2
) ON CONFLICT (id) DO UPDATE SET
