-- Scenario 6014: 第14話「啓示の使者」 (main_ep14)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6014,
    'main_ep14',
    '第14話「啓示の使者」',
    'メインシナリオ第14話',
    'なし',
    3,
    14,
    2,
    '{"gold":2000,"items":[],"reputation":20,"alignment_shift":{"order":5},"move_to":"loc_regalia"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep13","location_id":"loc_yato"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep13","location_id":"loc_yato"}'::jsonb,
    '{"nodes":{"start":{"text":"夜刀神国の美しい神社が並ぶ出雲の街へと向かう。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"隣を歩くヴォルグは、無言で大剣を磨いている。","type":"text","bg_key":"bg_road_day","next":"volg_join","choices":[{"label":"続ける","next":"volg_join"}]},"volg_join":{"type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_volg"},"next":"arrival_01","choices":[{"label":"続ける","next":"arrival_01"}]},"arrival_01":{"text":"出雲に到着した。しかし、街は異様な熱気に包まれている。","type":"text","bg_key":"bg_izumo_ruined","bgm":"bgm_quest_tense","next":"arrival_02","choices":[{"label":"続ける","next":"arrival_02"}]},"arrival_02":{"text":"あちこちで怒号が響き渡り、煙が立ち上っていた。","type":"text","bg_key":"bg_izumo_ruined","next":"chaos_01","choices":[{"label":"続ける","next":"chaos_01"}]},"chaos_01":{"text":"住民たちが武器を手にし、互いを罵り合っている。","type":"text","bg_key":"bg_izumo_ruined","next":"chaos_02","choices":[{"label":"続ける","next":"chaos_02"}]},"chaos_02":{"text":"「お前が天の敵だ！殺さなければ俺たちが滅ぼされる！」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"錯乱した住民","speaker":"錯乱した住民","next":"chaos_03","choices":[{"label":"続ける","next":"chaos_03"}]},"chaos_03":{"text":"「天の声が聞こえた！こいつを裏切り者として排除しろ！」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"錯乱した住民","speaker":"錯乱した住民","next":"chaos_04","choices":[{"label":"続ける","next":"chaos_04"}]},"chaos_04":{"text":"狂気に囚われた人々は、かつての友人に刃を向けている。","type":"text","bg_key":"bg_izumo_ruined","next":"volg_01","choices":[{"label":"続ける","next":"volg_01"}]},"volg_01":{"text":"「けっ、互いに殺し合いか。悪趣味極まりねえな」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_02","choices":[{"label":"続ける","next":"volg_02"}]},"volg_02":{"text":"その時、あなたの頭の中に不気味な囁き声が響いた。","type":"text","bg_key":"bg_izumo_ruined","next":"shrine_01","choices":[{"label":"続ける","next":"shrine_01"}]},"shrine_01":{"text":"「「背後ノ男ハオ前ヲ裏切ロウトシテイル。先ニ殺セ」」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"謎の声","speaker":"謎の声","next":"shrine_02","choices":[{"label":"続ける","next":"shrine_02"}]},"shrine_02":{"text":"見ると、ヴォルグもまたあなたの背後を疑わしげに見る。","type":"text","bg_key":"bg_izumo_ruined","next":"whisper_01","choices":[{"label":"続ける","next":"whisper_01"}]},"whisper_01":{"text":"互いの手が、ゆっくりと武器の柄へと伸びかける。","type":"text","bg_key":"bg_izumo_ruined","next":"whisper_02","choices":[{"label":"続ける","next":"whisper_02"}]},"whisper_02":{"text":"しかし、あなたは強く頭を振り、その囁きを否定した。","type":"text","bg_key":"bg_izumo_ruined","next":"whisper_03","choices":[{"label":"続ける","next":"whisper_03"}]},"whisper_03":{"text":"ヴォルグもまた大剣から手を離し、不敵に鼻で笑う。","type":"text","bg_key":"bg_izumo_ruined","next":"whisper_04","choices":[{"label":"続ける","next":"whisper_04"}]},"whisper_04":{"text":"「安っぽい細工だ。俺たちが仲間割れすると思ったかよ」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"whisper_05","choices":[{"label":"続ける","next":"whisper_05"}]},"whisper_05":{"text":"二人は再び信頼を取り戻し、前方の敵を見据える。","type":"text","bg_key":"bg_izumo_ruined","next":"whisper_06","choices":[{"label":"続ける","next":"whisper_06"}]},"whisper_06":{"text":"広場の奥から、囁きをまき散らす使徒が姿を現した。","type":"text","bg_key":"bg_izumo_ruined","next":"guard_01","choices":[{"label":"続ける","next":"guard_01"}]},"guard_01":{"text":"幻聴の源を叩くため、あなたは武器を構えて突撃する。","type":"text","bg_key":"bg_izumo_ruined","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"type":"battle","bg_key":"bg_izumo_ruined","bgm":"bgm_battle","enemy_group_id":"504","choices":[{"label":"win","next":"inner_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"inner_01"},"inner_01":{"text":"使徒を撃退した。だが、囁きは止むどころか強まる。","type":"text","bg_key":"bg_izumo_ruined","next":"inner_02","choices":[{"label":"続ける","next":"inner_02"}]},"inner_02":{"text":"神殿の奥から、まばゆい鏡の光が溢れ出してきた。","type":"text","bg_key":"bg_izumo_ruined","next":"gabriel_01","choices":[{"label":"続ける","next":"gabriel_01"}]},"gabriel_01":{"text":"鏡の翼を持ち、あらゆる言葉を反射する大天使が降臨する。","type":"text","bg_key":"bg_izumo_ruined","next":"gabriel_02","choices":[{"label":"続ける","next":"gabriel_02"}]},"gabriel_02":{"text":"大天使ガブリエルは、冷ややかな瞳で人間を見下ろした。","type":"text","bg_key":"bg_izumo_ruined","next":"gabriel_03","choices":[{"label":"続ける","next":"gabriel_03"}]},"gabriel_03":{"text":"「人間ハ互イヲ信用シテナイ。少シ囁ケバ勝手ニ殺シ合ウ」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"大天使ガブリエル","speaker":"大天使ガブリエル","next":"gabriel_04","choices":[{"label":"続ける","next":"gabriel_04"}]},"gabriel_04":{"text":"「貴様らも、いつ背後から刺されるか恐ろしいのだろう？」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"大天使ガブリエル","speaker":"大天使ガブリエル","next":"volg_defiance_01","choices":[{"label":"続ける","next":"volg_defiance_01"}]},"volg_defiance_01":{"text":"「ハッ！ 誰がいつ裏切ろうが知るかよ。今は戦うだけだ！」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_defiance_02","choices":[{"label":"続ける","next":"volg_defiance_02"}]},"volg_defiance_02":{"text":"「お前のお喋りは聞き飽きた。その鏡を叩き割ってやる！」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"volg_defiance_03","choices":[{"label":"続ける","next":"volg_defiance_03"}]},"volg_defiance_03":{"text":"ヴォルグは咆哮と共に、大天使に向かって跳躍した。","type":"text","bg_key":"bg_izumo_ruined","next":"volg_defiance_04","choices":[{"label":"続ける","next":"volg_defiance_04"}]},"volg_defiance_04":{"text":"あなたも剣を強く握り、大天使ガブリエルへ挑みかかる。","type":"text","bg_key":"bg_izumo_ruined","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"type":"battle","bg_key":"bg_izumo_ruined","bgm":"bgm_battle_strong","enemy_group_id":"9042","choices":[{"label":"win","next":"retreat_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"retreat_01"},"retreat_01":{"text":"大天使の鏡の翼を切り裂き、その防御を打ち破る。","type":"text","bg_key":"bg_izumo_ruined","next":"retreat_02","choices":[{"label":"続ける","next":"retreat_02"}]},"retreat_02":{"text":"ガブリエルは翼を抱えるようにして、天へと去っていく。","type":"text","bg_key":"bg_izumo_ruined","next":"retreat_03","choices":[{"label":"続ける","next":"retreat_03"}]},"retreat_03":{"text":"「残ル都ハ聖王都レガリアナリ……。そこデ終焉ヲ迎エヨ」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"大天使ガブリエル","speaker":"大天使ガブリエル","next":"sanity_01","choices":[{"label":"続ける","next":"sanity_01"}]},"sanity_01":{"text":"大天使の去った後、人々の瞳から狂気の光が消えていった。","type":"text","bg_key":"bg_izumo_ruined","bgm":"bgm_quest_calm","next":"sanity_02","choices":[{"label":"続ける","next":"sanity_02"}]},"sanity_02":{"text":"静けさを取り戻した出雲で、ヴォルグが不敵に笑う。","type":"text","bg_key":"bg_izumo_ruined","next":"volg_leave","choices":[{"label":"続ける","next":"volg_leave"}]},"volg_leave":{"type":"leave","bg_key":"bg_izumo_ruined","params":{"guest_id":"npc_guest_volg"},"next":"next_01","choices":[{"label":"続ける","next":"next_01"}]},"next_01":{"text":"「最後の決戦は聖王都レガリアだな。先に行って待ってるぜ」","type":"text","bg_key":"bg_izumo_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"next_02","choices":[{"label":"続ける","next":"next_02"}]},"next_02":{"text":"ヴォルグを見送り、あなたも旅の終わりへ向け決意する。","type":"text","bg_key":"bg_izumo_ruined","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"聖王都レガリアを目指し、あなたの最後の旅が始まった。","type":"end","result":"success","bg_key":"bg_izumo_ruined","params":{"rewards":{"exp":400,"gold":2000,"reputation":20,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"疑心暗鬼の闇に飲まれ、あなたは仲間と相討ちとなった。","type":"end","result":"failure","bg_key":"bg_izumo_ruined","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第14話"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
