    4,
    15,
    2,
    '{"gold":2500,"items":[503],"reputation":30,"alignment_shift":{"order":5},"move_to":"loc_border_town"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep14","location_id":"loc_regalia"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep14","location_id":"loc_regalia"}'::jsonb,
    '{"nodes":{"start":{"text":"三体の大天使を辛くも退けたが、地上の破滅を告げる神の足音は止まらない。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_crisis","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"イスハーク、龍京、出雲――傷だらけの都と人々は、絶望の淵で喘いでいる。","type":"text","bg_key":"bg_road_day","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"残る最後の一体は、天軍を統べる最強の長である大天使ミカエル。","type":"text","bg_key":"bg_road_day","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"（奴の無慈悲なる刃が狙うのは、あの白亜の聖王都レガリアか……）","type":"text","bg_key":"bg_road_day","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"滅びの神威に包まれる王都を救うため、あなたは焦燥を抱き、馬を駆る。","type":"text","bg_key":"bg_road_day","next":"volg_join","choices":[{"label":"続ける","next":"volg_join"}]},"volg_join":{"text":"道中、大剣を担いだ不死のヴォルグが隣に並び、獰猛な笑みを浮かべた。","type":"guest_join","bg_key":"bg_road_day","params":{"guest_id":"npc_guest_volg"},"next":"text_arrival","choices":[{"label":"続ける","next":"text_arrival"}]},"text_arrival":{"text":"辿り着いた王都レガリアは、かつての白亜の美しさを完全に失っていた。","type":"text","bg_key":"bg_regalia_ruined","next":"text_arrival_02","choices":[{"label":"続ける","next":"text_arrival_02"}]},"text_arrival_02":{"text":"かつて堅牢無比を誇った巨石の城壁は、紙細工のように無惨に崩壊している。","type":"text","bg_key":"bg_regalia_ruined","next":"text_arrival_04","choices":[{"label":"続ける","next":"text_arrival_04"}]},"text_arrival_04":{"text":"（死のような静寂のなか、崩れた城門に瓦礫がうず高く積もっているな）","type":"text","bg_key":"bg_regalia_ruined","next":"text_devastation","choices":[{"label":"続ける","next":"text_devastation"}]},"text_devastation":{"text":"（ウリエルの炎ともラファエルの呪眠とも異なる、あまりに無慈悲な破壊の跡）","type":"text","bg_key":"bg_regalia_ruined","next":"text_devastation_02","choices":[{"label":"続ける","next":"text_devastation_02"}]},"text_devastation_02":{"text":"ミカエルは圧倒的な「神威の武力」のみで都を叩き潰したのだろう。","type":"text","bg_key":"bg_regalia_ruined","next":"text_devastation_03","choices":[{"label":"続ける","next":"text_devastation_03"}]},"text_devastation_03":{"text":"巨大な光の刃で大路ごと薙ぎ払ったような、深々とした剣痕が大地を裂く。","type":"text","bg_key":"bg_regalia_ruined","next":"text_soldiers_last","choices":[{"label":"続ける","next":"text_soldiers_last"}]},"text_soldiers_last":{"text":"崩壊した大聖堂へ続く大通りの陰に、血に塗れた聖騎士たちが身を潜めていた。","type":"text","bg_key":"bg_regalia_ruined","next":"text_soldiers_02","choices":[{"label":"続ける","next":"text_soldiers_02"}]},"text_soldiers_02":{"text":"（彼らの誇り高き白銀の鎧はことごとく砕け、絶望的な死臭が漂っている）","type":"text","bg_key":"bg_regalia_ruined","next":"text_soldiers_03","choices":[{"label":"続ける","next":"text_soldiers_03"}]},"text_soldiers_03":{"text":"「……応援か？ だが、遅すぎた。我らの刃では奴の影すら斬れんのだ」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"負傷した衛兵隊長","speaker":"負傷した衛兵隊長","next":"text_soldiers_04","choices":[{"label":"続ける","next":"text_soldiers_04"}]},"text_soldiers_04":{"text":"「ミカエルは大聖堂にいる。この地に残る希望 of 種を全て刈り取るためにな」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"負傷した衛兵隊長","speaker":"負傷した衛兵隊長","next":"text_volg_resolve","choices":[{"label":"続ける","next":"text_volg_resolve"}]},"text_volg_resolve":{"text":"「最後の一体、天軍の長か。闘気の格が今までの奴らとは段違いだぜ」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_volg_resolve_02","choices":[{"label":"続ける","next":"text_volg_resolve_02"}]},"text_volg_resolve_02":{"text":"「だが関係ねえ。俺たちが行く先々で大天使どもを蹴散らしてきたんだ」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_volg_resolve_03","choices":[{"label":"続ける","next":"text_volg_resolve_03"}]},"text_volg_resolve_03":{"text":"「最強の天使だろうが、やることは同じだ。その傲慢な首を切り落とす」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_cathedral","choices":[{"label":"続ける","next":"text_cathedral"}]},"text_cathedral":{"text":"あなたはヴォルグと共に、犠牲者の血で染まった大聖堂の石段を駆け上がる。","type":"text","bg_key":"bg_regalia_ruined","next":"text_cathedral_02","choices":[{"label":"続ける","next":"text_cathedral_02"}]},"text_cathedral_02":{"text":"かつて荘厳を誇った白亜の尖塔は半壊し、砕け散った硝子が月光に煌めく.","type":"text","bg_key":"bg_regalia_ruined","next":"text_cathedral_03","choices":[{"label":"続ける","next":"text_cathedral_03"}]},"text_cathedral_03":{"text":"（聖者の彫像すら首から上を失っている。神々の無慈悲さに胸が痛むな）","type":"text","bg_key":"bg_regalia_ruined","next":"text_cathedral_04","choices":[{"label":"続ける","next":"text_cathedral_04"}]},"text_cathedral_04":{"text":"聖堂の前に広がる礼拝広場には、天を貫くほどの巨大な神威 of 光柱が聳える。","type":"text","bg_key":"bg_regalia_ruined","next":"text_michael_throne","choices":[{"label":"続ける","next":"text_michael_throne"}]},"text_michael_throne":{"text":"砕け散った聖者の石像を積み上げた、即席の玉座に傲然と腰掛ける巨軀。","type":"text","bg_key":"bg_regalia_ruined","next":"text_michael_throne_02","choices":[{"label":"続ける","next":"text_michael_throne_02"}]},"text_michael_throne_02":{"text":"背に翻るのは輝く白銀の六翼。その手には凄まじい熱線の光刃が握られている。","type":"text","bg_key":"bg_regalia_ruined","next":"text_michael_throne_03","choices":[{"label":"続ける","next":"text_michael_throne_03"}]},"text_michael_throne_03":{"text":"（他の大天使とは存在感が違う。見るだけで膝が折れそうな威圧感だ）","type":"text","bg_key":"bg_regalia_ruined","next":"text_apostle_elite","choices":[{"label":"続ける","next":"text_apostle_elite"}]},"text_apostle_elite":{"text":"ミカエルが放つ圧倒的な威圧に呼応し、光の盾を構えた精鋭使徒たちが現れる。","type":"text","bg_key":"bg_regalia_ruined","next":"text_apostle_elite_02","choices":[{"label":"続ける","next":"text_apostle_elite_02"}]},"text_apostle_elite_02":{"text":"（ここを突破しなければ届かない。自分は武器を強く握り直した）","type":"text","bg_key":"bg_regalia_ruined","next":"battle1","choices":[{"label":"続ける","next":"battle1"}]},"battle1":{"type":"battle","bg_key":"bg_regalia_ruined","bgm":"bgm_battle","enemy_group_id":"211","choices":[{"label":"win","next":"text_michael_descend"},{"label":"lose","next":"end_failure"}],"battle_success_next":"text_michael_descend"},"text_michael_descend":{"text":"死闘の末に親衛隊を切り伏せたが、眼前にある神の威容は未だ揺らぎもしない。","type":"text","bg_key":"bg_regalia_ruined","next":"text_michael_descend_02","choices":[{"label":"続ける","next":"text_michael_descend_02"}]},"text_michael_descend_02":{"text":"ゆっくりとミカエルが立ち上がる。その一動作だけで、大地全体が激しく鳴動した。","type":"text","bg_key":"bg_regalia_ruined","next":"text_michael_voice","choices":[{"label":"続ける","next":"text_michael_voice"}]},"text_michael_voice":{"text":"「同胞タル三体ヲ屠リ、此処ニ至ッタ人間ヨ。認メヨウ、汝ラノ武ハ強イ」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"大天使ミカエル","speaker":"大天使ミカエル","next":"text_michael_declaration","choices":[{"label":"続ける","next":"text_michael_declaration"}]},"text_michael_declaration":{"text":"「ダガ、汝ラノ足掻キハ秩序ニハ届カヌ。神威ノ光剣ニテ、大イナル裁キヲ与エン」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"大天使ミカエル","speaker":"大天使ミカエル","next":"text_volg_final","choices":[{"label":"続ける","next":"text_volg_final"}]},"text_volg_final":{"text":"「秩序だあ？ 人間を家畜のようにならし、跪かせるのがテメエらの秩序かよ」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_volg_final_02","choices":[{"label":"続ける","next":"text_volg_final_02"}]},"text_volg_final_02":{"text":"「悪ぃが俺たちは飢えた野良犬だ。首輪をはめられる気はねえ。来い、天の長」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"battle2","choices":[{"label":"続ける","next":"battle2"}]},"battle2":{"type":"battle","bg_key":"bg_regalia_ruined","bgm":"bgm_spot_final_boss","enemy_group_id":"9043","choices":[{"label":"win","next":"text_michael_retreat"},{"label":"lose","next":"end_failure"}],"battle_success_next":"text_michael_retreat"},"text_michael_retreat":{"text":"あなたとヴォルグの捨て身の同時攻撃が、ミカエルの光の大剣を粉々に叩き砕いた。","type":"text","bg_key":"bg_regalia_ruined","next":"text_michael_retreat_02","choices":[{"label":"続ける","next":"text_michael_retreat_02"}]},"text_michael_retreat_02":{"text":"「マサカ、矮小ナル人間ガ我ガ大剣ヲ……。ダガ、天ノ主ノ御心ハ既ニ……」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"大天使ミカエル","speaker":"大天使ミカエル","next":"text_city_saved","choices":[{"label":"続ける","next":"text_city_saved"}]},"text_city_saved":{"text":"まばゆい光の粒子となってミカエルが消滅し、上空を覆う十字架が崩壊していく。","type":"text","bg_key":"bg_regalia_ruined","next":"text_city_saved_02","choices":[{"label":"続ける","next":"text_city_saved_02"}]},"text_city_saved_02":{"text":"（暗雲の隙間から夕陽が差し込む。四つの都は傷つきながらも、生き残ったのだ）","type":"text","bg_key":"bg_regalia_ruined","next":"volg_leave","choices":[{"label":"続ける","next":"volg_leave"}]},"volg_leave":{"text":"大剣を地面に突き立て、ヴォルグが血と汗に塗れた体を支えるように深く息を吐く。","type":"leave","bg_key":"bg_regalia_ruined","params":{"guest_id":"npc_guest_volg"},"next":"text_volg_farewell","choices":[{"label":"続ける","next":"text_volg_farewell"}]},"text_volg_farewell":{"text":"「……大掃除は終わったな。だが、あのデカブツが言った通り天の上には上がいる」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_volg_farewell_02","choices":[{"label":"続ける","next":"text_volg_farewell_02"}]},"text_volg_farewell_02":{"text":"「神の救いや許しを請うより、俺たちは人間らしく泥を這って生き抜くべきだ。じゃあな」","type":"text","bg_key":"bg_regalia_ruined","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"神々の軍勢に人類の強固な意志を示し、瓦礫の街から次なる時代への歩みが始まる。","type":"end","result":"success","bg_key":"bg_road_day","params":{"rewards":{"gold":2500,"reputation":30,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"（ミカエルが放つ無慈悲な光の刃に貫かれ、自分の意識は純白の光の中に消え去った）","type":"end","result":"failure","bg_key":"bg_regalia_ruined","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第15話"}'::jsonb,
    7,
    4
) ON CONFLICT (id) DO UPDATE SET
