    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6016: 第16話「英霊の石碑」 (main_ep16)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6016,
    'main_ep16',
    '第16話「英霊の石碑」',
    'メインシナリオ第16話',
    'なし',
    4,
    16,
    2,
    '{"gold":3000,"items":[],"reputation":20,"alignment_shift":{"order":5},"move_to":"loc_meridia"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep15","required_generations":2,"location_id":"loc_border_town"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep15","required_generations":2,"location_id":"loc_border_town"}'::jsonb,
    '{"nodes":{"start":{"text":"大天使たちの激しい侵攻は、遠い過去の出来事となりつつあった。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"四つの首都は完全に復興し、かつての美しい姿を取り戻した。","type":"text","bg_key":"bg_road_day","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"だが、あなたの胸の奥には、常に不穏な予感があった。","type":"text","bg_key":"bg_road_day","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"神そのものには、人間はまだ誰も届いていないのだ。","type":"text","bg_key":"bg_road_day","next":"text_peace","choices":[{"label":"続ける","next":"text_peace"}]},"text_peace":{"text":"いつまた新たな「大浄化」の裁きが降るかわからない。","type":"text","bg_key":"bg_road_day","next":"text_peace_02","choices":[{"label":"続ける","next":"text_peace_02"}]},"text_peace_02":{"text":"自分の中に眠る、かつての記憶の断片が、平和という名の欺瞞を冷徹に囁いていた。","type":"text","bg_key":"bg_road_day","next":"text_border_town","choices":[{"label":"続ける","next":"text_border_town"}]},"text_border_town":{"text":"ある日、あなたの足は自然と、国境の町へと向かっていた。","type":"text","bg_key":"bg_road_day","next":"text_border_town_02","choices":[{"label":"続ける","next":"text_border_town_02"}]},"text_border_town_02":{"text":"そこはローランドとマルカンドの国境に位置する町。","type":"text","bg_key":"bg_road_day","next":"text_border_town_03","choices":[{"label":"続ける","next":"text_border_town_03"}]},"text_border_town_03":{"text":"町外れの静かな丘へ、誘われるように登り始める。","type":"text","bg_key":"bg_road_day","next":"text_strange_pull","choices":[{"label":"続ける","next":"text_strange_pull"}]},"text_strange_pull":{"text":"生い茂る草を掻き分けると、風化した古い石碑が佇んでいた。","type":"text","bg_key":"bg_road_day","next":"text_strange_pull_02","choices":[{"label":"続ける","next":"text_strange_pull_02"}]},"text_strange_pull_02":{"text":"苔むした表面には、かすかに不思議な紋様が刻まれている。","type":"text","bg_key":"bg_road_day","next":"text_strange_pull_03","choices":[{"label":"続ける","next":"text_strange_pull_03"}]},"text_strange_pull_03":{"text":"脈打つように、石碑があなたを呼び寄せている。","type":"text","bg_key":"bg_road_day","next":"text_stele_discovery","choices":[{"label":"続ける","next":"text_stele_discovery"}]},"text_stele_discovery":{"text":"石碑の前に立つと、紋様が強く淡い光を放ち始めた。","type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_tense","next":"text_stele_discovery_02","choices":[{"label":"続ける","next":"text_stele_discovery_02"}]},"text_stele_discovery_02":{"text":"そっと手を伸ばして表面に触れると、温もりを感じる。","type":"text","bg_key":"bg_heroic_stele","next":"text_stele_discovery_03","choices":[{"label":"続ける","next":"text_stele_discovery_03"}]},"text_stele_discovery_03":{"text":"吸い寄せられるように、さらに強くその石碑へ触れた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"触れた瞬間、意識が激しく彼方へ引き剥がされた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch_02","choices":[{"label":"続ける","next":"text_touch_02"}]},"text_touch_02":{"text":"次に目を開けた時、見知らぬ荒涼とした大地に立っていた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch_03","choices":[{"label":"続ける","next":"text_touch_03"}]},"text_touch_03":{"text":"それは、かつて神と戦った「先代」の英霊の記憶だった。","type":"text","bg_key":"bg_heroic_stele","next":"text_vision_start","choices":[{"label":"続ける","next":"text_vision_start"}]},"text_vision_start":{"text":"記憶の中で、一人の戦士が神の軍勢を相手に大剣を振るう。","type":"text","bg_key":"bg_heroic_stele","next":"text_vision_start_02","choices":[{"label":"続ける","next":"text_vision_start_02"}]},"text_vision_start_02":{"text":"この英霊の意志が、継承者であるあなたに受け継がれている。","type":"text","bg_key":"bg_heroic_stele","next":"text_vision_hero","choices":[{"label":"続ける","next":"text_vision_hero"}]},"text_vision_hero":{"text":"「……やっと目覚めたか。我が力を継ぎし者よ」","type":"text","bg_key":"bg_heroic_stele","speaker_name":"英霊の声","speaker":"英霊の声","next":"text_vision_hero_02","choices":[{"label":"続ける","next":"text_vision_hero_02"}]},"text_vision_hero_02":{"text":"「お前の中に眠る俺の力の欠片は、まだ少なすぎる」","type":"text","bg_key":"bg_heroic_stele","speaker_name":"英霊の声","speaker":"英霊の声","next":"text_vision_hero_03","choices":[{"label":"続ける","next":"text_vision_hero_03"}]},"text_vision_hero_03":{"text":"「散らばる四つの石碑を巡り、遺産と記憶を回収せよ」","type":"text","bg_key":"bg_heroic_stele","speaker_name":"英霊の声","speaker":"英霊の声","next":"text_vision_end","choices":[{"label":"続ける","next":"text_vision_end"}]},"text_vision_end":{"text":"「イスハーク、龍京、出雲、レガリアの近くにある」","type":"text","bg_key":"bg_heroic_stele","speaker_name":"英霊の声","speaker":"英霊の声","next":"text_vision_end_02","choices":[{"label":"続ける","next":"text_vision_end_02"}]},"text_vision_end_02":{"text":"「天の奴らもお前の覚醒に気づき始めている。急ぐのだ」","type":"text","bg_key":"bg_heroic_stele","speaker_name":"英霊の声","speaker":"英霊の声","next":"text_awakening","choices":[{"label":"続ける","next":"text_awakening"}]},"text_awakening":{"text":"はっと意識が戻ると、現実の石碑の前で膝をついていた。","type":"text","bg_key":"bg_heroic_stele","bgm":"bgm_quest_calm","next":"text_awakening_02","choices":[{"label":"続ける","next":"text_awakening_02"}]},"text_awakening_02":{"text":"全身の奥底から、熱く微かな力が滾り出している。","type":"text","bg_key":"bg_heroic_stele","next":"text_awakening_03","choices":[{"label":"続ける","next":"text_awakening_03"}]},"text_awakening_03":{"text":"英霊の継承者という、呪わしくも強大な宿命が、冷えた体を芯から温めていく。","type":"text","bg_key":"bg_heroic_stele","next":"text_inheritance","choices":[{"label":"続ける","next":"text_inheritance"}]},"text_inheritance":{"text":"その力を確かめるように、あなたはその場に立ち上がった。","type":"text","bg_key":"bg_heroic_stele","next":"text_inheritance_02","choices":[{"label":"続ける","next":"text_inheritance_02"}]},"text_inheritance_02":{"text":"やるべきことは決まった。神の座を引きずり下ろすための遺産を、この手にかき集めるのだ。","type":"text","bg_key":"bg_heroic_stele","next":"text_ambush_warning","choices":[{"label":"続ける","next":"text_ambush_warning"}]},"text_ambush_warning":{"text":"突然、丘の上の気温が急激に下がり、殺気が満ちてきた。","type":"text","bg_key":"bg_heroic_stele","next":"text_ambush_warning_02","choices":[{"label":"続ける","next":"text_ambush_warning_02"}]},"text_ambush_warning_02":{"text":"茂みを引き裂き、黒い翼を持った堕天使たちが現れる。","type":"text","bg_key":"bg_heroic_stele","next":"text_fallen_descent","choices":[{"label":"続ける","next":"text_fallen_descent"}]},"text_fallen_descent":{"text":"三体の堕天使が舞い降り、あなたを完全に包囲した。","type":"text","bg_key":"bg_heroic_stele","next":"text_fallen_taunt","choices":[{"label":"続ける","next":"text_fallen_taunt"}]},"text_fallen_taunt":{"text":"「英霊ノ継承者メ。覚醒スル前ニ、此処デ屠ッテクレヨウ」","type":"text","bg_key":"bg_heroic_stele","speaker_name":"堕天使","speaker":"堕天使","next":"text_fallen_taunt_02","choices":[{"label":"続ける","next":"text_fallen_taunt_02"}]},"text_fallen_taunt_02":{"text":"「天ノ秩序ニ仇ナス芽ハ、今ノ内ニ摘ミ取ルノミダ」","type":"text","bg_key":"bg_heroic_stele","speaker_name":"堕天使","speaker":"堕天使","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_heroic_stele","bgm":"bgm_battle","enemy_group_id":"211","choices":[{"label":"win","next":"text_aftermath"},{"label":"lose","next":"end_failure"}],"battle_success_next":"text_aftermath"},"text_aftermath":{"text":"激しい戦いの末、襲撃してきた堕天使たちを切り伏せた。","type":"text","bg_key":"bg_heroic_stele","next":"text_aftermath_02","choices":[{"label":"続ける","next":"text_aftermath_02"}]},"text_aftermath_02":{"text":"堕天使の体は黒い霧となって消え、静寂が戻る。","type":"text","bg_key":"bg_heroic_stele","next":"text_guidance","choices":[{"label":"続ける","next":"text_guidance"}]},"text_guidance":{"text":"残された石碑の紋様が、進むべき方向へ輝いている。","type":"text","bg_key":"bg_heroic_stele","next":"text_guidance_02","choices":[{"label":"続ける","next":"text_guidance_02"}]},"text_guidance_02":{"text":"天の追撃を嘲笑いながら、四都市の遺産をすべて回収せねばならない。","type":"text","bg_key":"bg_heroic_stele","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"宿命を胸に抱き、あなたは丘を降りて旅へ出発した。","type":"end","result":"success","bg_key":"bg_heroic_stele","params":{"rewards":{"gold":3000,"reputation":20,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"堕天使の黒き刃に貫かれ、冷たい地面に崩れ落ちる。継承の灯火は、再び闇に閉ざされた。","type":"end","result":"failure","bg_key":"bg_heroic_stele","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第16話"}'::jsonb,
    3,
    2
