-- Scenario 6017: 第17話「冥府の門」 (main_ep17)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6017,
    'main_ep17',
    '第17話「冥府の門」',
    'メインシナリオ第17話',
    'なし',
    4,
    17,
    2,
    '{"gold":3500,"items":[505],"reputation":25,"alignment_shift":{"order":5},"move_to":"loc_charon"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep16","location_id":"loc_meridia"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep16","location_id":"loc_meridia"}'::jsonb,
    '{"nodes":{"start":{"text":"二つ目の石碑の導きに従い、あなたはレガリアから旅立つ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"マルカンドの砂漠を越え、黄金都市イスハークへと向かった。","type":"text","bg_key":"bg_road_day","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"イスハークには活気が戻っているが、石碑は街の中にはない。","type":"text","bg_key":"bg_road_day","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"灼熱の砂塵の中にそびえ立つ、巨大な墓所。その冷酷な石造りの佇まいは、数多の墓泥棒を拒絶してきた。","type":"text","bg_key":"bg_road_day","next":"text_ishaq","choices":[{"label":"続ける","next":"text_ishaq"}]},"text_ishaq":{"text":"砂に半ば埋もれた古代の巨大ピラミッドに到着した。","type":"text","bg_key":"bg_desert","next":"text_ishaq_02","choices":[{"label":"続ける","next":"text_ishaq_02"}]},"text_ishaq_02":{"text":"冷気と静寂に包まれたピラミッドの内部へ潜る。","type":"text","bg_key":"bg_desert","next":"text_ishaq_03","choices":[{"label":"続ける","next":"text_ishaq_03"}]},"text_ishaq_03":{"text":"松明の炎が、風化した古い石壁に重苦しい影を投げかける。","type":"text","bg_key":"bg_desert","next":"text_pyramid","choices":[{"label":"続ける","next":"text_pyramid"}]},"text_pyramid":{"text":"ピラミッドの狭い通路を進むと、壁画が描かれていた。","type":"text","bg_key":"bg_catacombs","next":"text_pyramid_02","choices":[{"label":"続ける","next":"text_pyramid_02"}]},"text_pyramid_02":{"text":"それは人間が、翼を持つ神々の秩序に牙を剥いた、太古の反逆の記録であった。","type":"text","bg_key":"bg_catacombs","next":"text_pyramid_03","choices":[{"label":"続ける","next":"text_pyramid_03"}]},"text_pyramid_03":{"text":"崩れかけた石壁の奥から、冷たい風が吹き抜けてくる。","type":"text","bg_key":"bg_catacombs","next":"text_hidden_passage","choices":[{"label":"続ける","next":"text_hidden_passage"}]},"text_hidden_passage":{"text":"行き止まりの壁の一部に、石碑と同じ紋様を見つける。","type":"text","bg_key":"bg_catacombs","next":"text_hidden_passage_02","choices":[{"label":"続ける","next":"text_hidden_passage_02"}]},"text_hidden_passage_02":{"text":"紋様に手を当てると、石壁が音を立ててスライドし始めた。","type":"text","bg_key":"bg_catacombs","next":"text_hidden_passage_03","choices":[{"label":"続ける","next":"text_hidden_passage_03"}]},"text_hidden_passage_03":{"text":"何千年も光を拒んできた奥底から、淡く冷たい光が漏れ出ている。","type":"text","bg_key":"bg_catacombs","next":"text_chamber","choices":[{"label":"続ける","next":"text_chamber"}]},"text_chamber":{"text":"通路の先には、広大な地下室が広がっていた。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","next":"text_chamber_02","choices":[{"label":"続ける","next":"text_chamber_02"}]},"text_chamber_02":{"text":"天井が高く、壁面全体に光る紋様が刻まれている。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_chamber_03","choices":[{"label":"続ける","next":"text_chamber_03"}]},"text_chamber_03":{"text":"その部屋の中央に、二つ目の英霊の石碑が佇んでいた。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"text":"石碑の前に立つと、読めない古代文字が理解できた。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_stele_found_02","choices":[{"label":"続ける","next":"text_stele_found_02"}]},"text_stele_found_02":{"text":"「試練を受けよ」とある。冷たい表面に手を触れた。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"触れた瞬間、脳裏に強烈な光が走り、意識が切り離される。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_touch_02","choices":[{"label":"続ける","next":"text_touch_02"}]},"text_touch_02":{"text":"目を開けると、砂漠の中の美しいオアシスにいた。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_touch_03","choices":[{"label":"続ける","next":"text_touch_03"}]},"text_touch_03":{"text":"それは先代の英霊の記憶。だが、吹き抜けるのは骨まで凍らせるような死の冷気だ。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_memory_start","choices":[{"label":"続ける","next":"text_memory_start"}]},"text_memory_start":{"text":"泉の底から突如として闇が噴き出し、地面に亀裂が走る。","type":"text","bg_key":"bg_memory_oasis","next":"text_memory_start_02","choices":[{"label":"続ける","next":"text_memory_start_02"}]},"text_memory_start_02":{"text":"泉の水が黒く染まり、紫の霧が吹き荒れ門が開いた。","type":"text","bg_key":"bg_memory_oasis","next":"text_memory_oasis","choices":[{"label":"続ける","next":"text_memory_oasis"}]},"text_memory_oasis":{"text":"闇の門の奥から、ゆっくりと一つの影が歩み出てくる。","type":"text","bg_key":"bg_memory_oasis","next":"text_memory_oasis_02","choices":[{"label":"続ける","next":"text_memory_oasis_02"}]},"text_memory_oasis_02":{"text":"黒い霧が結実し、蒼白い肌を持つ荘厳な男の姿となった。","type":"text","bg_key":"bg_memory_oasis","next":"text_hades_appear","choices":[{"label":"続ける","next":"text_hades_appear"}]},"text_hades_appear":{"text":"闇の衣を纏い、手には骸骨が彫られた黒い錫杖を持つ。","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_battle_strong","next":"text_hades_appear_02","choices":[{"label":"続ける","next":"text_hades_appear_02"}]},"text_hades_appear_02":{"text":"冥王ハデス。生と死の境界を守る冷酷なる神。","type":"text","bg_key":"bg_memory_oasis","next":"text_hades_appear_03","choices":[{"label":"続ける","next":"text_hades_appear_03"}]},"text_hades_appear_03":{"text":"ハデスが錫杖を構え、あなたを冷たく見下ろした。","type":"text","bg_key":"bg_memory_oasis","next":"text_hades_voice","choices":[{"label":"続ける","next":"text_hades_voice"}]},"text_hades_voice":{"text":"「また来たか。先代も死を恐れぬ目をしていたな」","type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","speaker":"冥王ハデス","next":"text_hades_voice_02","choices":[{"label":"続ける","next":"text_hades_voice_02"}]},"text_hades_voice_02":{"text":"「だが、死を恐れぬことと、死を超えることは別物だ」","type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","speaker":"冥王ハデス","next":"text_hades_challenge","choices":[{"label":"続ける","next":"text_hades_challenge"}]},"text_hades_challenge":{"text":"「我が門を守る者。汝の魂の軽さ、ここで測ってくれよう」","type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","speaker":"冥王ハデス","next":"text_hades_challenge_02","choices":[{"label":"続ける","next":"text_hades_challenge_02"}]},"text_hades_challenge_02":{"text":"「我が冥府の暗闇に耐えられるか、証明してみせよ」","type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","speaker":"冥王ハデス","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_memory_oasis","bgm":"bgm_battle","enemy_group_id":"9050","choices":[{"label":"win","next":"text_hades_defeat"},{"label":"lose","next":"end_failure"}],"battle_success_next":"text_hades_defeat"},"text_hades_defeat":{"text":"死の霧を切り裂き、渾身の刃が冥王の喉元を捉えた。一歩間違えれば、己がそちら側へ逝くところだった。","type":"text","bg_key":"bg_memory_oasis","next":"text_hades_defeat_02","choices":[{"label":"続ける","next":"text_hades_defeat_02"}]},"text_hades_defeat_02":{"text":"「見事。死の恐怖を越えたか。我が力を授けよう」","type":"text","bg_key":"bg_memory_oasis","speaker_name":"冥王ハデス","speaker":"冥王ハデス","next":"text_talisman","choices":[{"label":"続ける","next":"text_talisman"}]},"text_talisman":{"text":"ハデスが去ると共に意識が現実に戻り、あなたは地下室にいた。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_talisman_02","choices":[{"label":"続ける","next":"text_talisman_02"}]},"text_talisman_02":{"text":"石碑の足元に、黒い「冥王の護符」が静かに落ちている。","type":"text","bg_key":"bg_pyramid_chamber","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"text":"手にした護符をしまい、あなたは地下室を後にした。","type":"text","bg_key":"bg_catacombs","bgm":"bgm_quest_calm","next":"text_return_02","choices":[{"label":"続ける","next":"text_return_02"}]},"text_return_02":{"text":"あなたは次の目的地であるマルカンドの「カロン」へ向かう。","type":"text","bg_key":"bg_catacombs","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"冥王ハデスの試練を乗り越え、力を手に入れた。","type":"end","result":"success","bg_key":"bg_catacombs","params":{"rewards":{"gold":3500,"reputation":25,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"絶対的な死の力には抗えなかった。あなたの魂は冥界の底へと引きずり込まれ、二度と浮上することはなかった。","type":"end","result":"failure","bg_key":"bg_pyramid_chamber","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第17話"}'::jsonb,
    5,
    3
) ON CONFLICT (id) DO UPDATE SET
