-- Scenario 6018: 第18話「戦神の洗礼」 (main_ep18)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6018,
    'main_ep18',
    '第18話「戦神の洗礼」',
    'メインシナリオ第18話',
    'なし',
    4,
    18,
    2,
    '{"gold":3500,"items":[506],"reputation":25,"alignment_shift":{"order":5},"move_to":"loc_yato"}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep16","location_id":"loc_charon"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep16","location_id":"loc_charon"}'::jsonb,
    '{"nodes":{"start":{"text":"英霊の導きに従い、あなたは商業都市カロンへと向かった。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"かつてメインシナリオでヴォルグと戦った日々が思い出される。","type":"text","bg_key":"bg_desert","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"神に届くための戦神の遺産が、カロンの熱砂のどこかに眠っている。","type":"text","bg_key":"bg_desert","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"砂乗りの船頭から、誰も近づかない「流砂の孤島」を聞き出す。","type":"text","bg_key":"bg_desert","next":"text_port","choices":[{"label":"続ける","next":"text_port"}]},"text_port":{"text":"カロンの砂船乗り場で、頑丈な砂ソリの船を借り受けた。","type":"text","bg_key":"bg_desert","next":"text_port_02","choices":[{"label":"続ける","next":"text_port_02"}]},"text_port_02":{"text":"船頭は「砂嵐が狂い、方位磁石も効かない」と首を振る。","type":"text","bg_key":"bg_desert","next":"text_port_03","choices":[{"label":"続ける","next":"text_port_03"}]},"text_port_03":{"text":"余計な忠告を背中で聞き流し、あなたは砂船の帆を張り、狂った熱風の中へと滑り出した。","type":"text","bg_key":"bg_desert","next":"text_voyage","choices":[{"label":"続ける","next":"text_voyage"}]},"text_voyage":{"text":"砂ソリを滑らせて数刻。流砂が激しく渦巻く境界域に達した。","type":"text","bg_key":"bg_desert","next":"text_voyage_02","choices":[{"label":"続ける","next":"text_voyage_02"}]},"text_voyage_02":{"text":"巨大な砂嵐が視界を遮るが、紋様が嵐の裂け目を示していた。","type":"text","bg_key":"bg_desert","next":"text_voyage_03","choices":[{"label":"続ける","next":"text_voyage_03"}]},"text_voyage_03":{"text":"荒れ狂う砂の波濤をねじ伏せ、ついにその孤島へと上陸を果たす。","type":"text","bg_key":"bg_desert","next":"text_island_arrival","choices":[{"label":"続ける","next":"text_island_arrival"}]},"text_island_arrival":{"text":"上陸した場所は、砂漠の真ん中に隠された古いオアシスだった。","type":"text","bg_key":"bg_island","bgm":"bgm_quest_tense","next":"text_island_arrival_02","choices":[{"label":"続ける","next":"text_island_arrival_02"}]},"text_island_arrival_02":{"text":"枯れかけた椰子の木と、砂に半ば埋もれた石造りの古い床。","type":"text","bg_key":"bg_island","next":"text_island_arrival_03","choices":[{"label":"続ける","next":"text_island_arrival_03"}]},"text_island_arrival_03":{"text":"この場所の奥から、ビリビリと肌を刺す闘気が漏れていた。","type":"text","bg_key":"bg_island","next":"text_jungle","choices":[{"label":"続ける","next":"text_jungle"}]},"text_jungle":{"text":"密林を掻き分け進むと、砂に埋もれた古い石段が姿を現した。","type":"text","bg_key":"bg_island","next":"text_jungle_02","choices":[{"label":"続ける","next":"text_jungle_02"}]},"text_jungle_02":{"text":"石段を登り詰めると、円形の闘技場のような広場に出る。","type":"text","bg_key":"bg_island","next":"text_jungle_03","choices":[{"label":"続ける","next":"text_jungle_03"}]},"text_jungle_03":{"text":"その中央に、熱を帯びて赤く輝く三つ目の石碑が立っていた。","type":"text","bg_key":"bg_island","next":"text_ruins","choices":[{"label":"続ける","next":"text_ruins"}]},"text_ruins":{"text":"祭壇の周囲には、無数の古びた武器が地面に突き立てられている。","type":"text","bg_key":"bg_island","next":"text_ruins_02","choices":[{"label":"続ける","next":"text_ruins_02"}]},"text_ruins_02":{"text":"刃が欠け錆びついた剣。これらすべてが、神という不条理に挑み、敗れ去った戦士たちの墓標だ。","type":"text","bg_key":"bg_island","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"text":"石碑に近づくと、赤く輝く古代文字が空中に浮かび上がった。","type":"text","bg_key":"bg_heroic_stele","next":"text_stele_found_02","choices":[{"label":"続ける","next":"text_stele_found_02"}]},"text_stele_found_02":{"text":"「強者との誓いの記憶に触れよ」とある。手を石碑に触れた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"脳裏に激しい衝撃が走り、意識が熱砂の戦場へと引き剥がされる。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch_02","choices":[{"label":"続ける","next":"text_touch_02"}]},"text_touch_02":{"text":"それは先代英霊とヴォルグが共に戦った、共闘の記憶だった。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch_03","choices":[{"label":"続ける","next":"text_touch_03"}]},"text_touch_03":{"text":"「おい、ぼさっとすんな。俺たちの戦いはこれからだぜ」","type":"text","bg_key":"bg_heroic_stele","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_memory_forest","choices":[{"label":"続ける","next":"text_memory_forest"}]},"text_memory_forest":{"text":"雨が激しく降り注ぐ、暗い森の奥。無数の使徒に包囲されていた。","type":"text","bg_key":"bg_memory_forest","next":"text_memory_forest_02","choices":[{"label":"続ける","next":"text_memory_forest_02"}]},"text_memory_forest_02":{"text":"体は傷だらけで限界に近い。しかし、ヴォルグは笑っている。","type":"text","bg_key":"bg_memory_forest","next":"text_memory_forest_03","choices":[{"label":"続ける","next":"text_memory_forest_03"}]},"text_memory_forest_03":{"text":"「ハッ、いい絶望感だ。おい、相棒、背中は任せたぞ！」","type":"text","bg_key":"bg_memory_forest","speaker_name":"ヴォルグ","speaker":"ヴォルグ","next":"text_ares_appear","choices":[{"label":"続ける","next":"text_ares_appear"}]},"text_ares_appear":{"text":"使徒たちの奥から、圧倒的な闘気を纏う赤銅色の巨影が現れた。","type":"text","bg_key":"bg_memory_forest","bgm":"bgm_battle_strong","next":"text_ares_appear_02","choices":[{"label":"続ける","next":"text_ares_appear_02"}]},"text_ares_appear_02":{"text":"巨剣を片手で軽々と提げた男。軍神アレスが立ち塞がっていた。","type":"text","bg_key":"bg_memory_forest","next":"text_ares_appear_03","choices":[{"label":"続ける","next":"text_ares_appear_03"}]},"text_ares_appear_03":{"text":"ヴォルグがその闘気に応じるように、大剣を強く握り直す。","type":"text","bg_key":"bg_memory_forest","next":"text_ares_voice","choices":[{"label":"続ける","next":"text_ares_voice"}]},"text_ares_voice":{"text":"「クハハ！ 面白い人間どもだ。俺の眷属をここまで屠るとはな」","type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","speaker":"軍神アレス","next":"text_ares_voice_02","choices":[{"label":"続ける","next":"text_ares_voice_02"}]},"text_ares_voice_02":{"text":"「特にそこの不死の男、お前の闘志はいい色に滾っているぞ」","type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","speaker":"軍神アレス","next":"text_ares_challenge","choices":[{"label":"続ける","next":"text_ares_challenge"}]},"text_ares_challenge":{"text":"「我が名はアレス。二人で我に挑むか。よかろう！」","type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","speaker":"軍神アレス","next":"text_ares_challenge_02","choices":[{"label":"続ける","next":"text_ares_challenge_02"}]},"text_ares_challenge_02":{"text":"「その歪な絆と、限界を超えた闘争を我に見せてみよ！」","type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","speaker":"軍神アレス","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_memory_forest","bgm":"bgm_spot_final_boss","enemy_group_id":"9051","choices":[{"label":"win","next":"text_ares_defeat"},{"label":"lose","next":"end_failure"}],"battle_success_next":"text_ares_defeat"},"text_ares_defeat":{"text":"ヴォルグの剛撃とあなたの渾身の一撃が、戦神アレスの無敵を誇る赤銅の鎧を叩き斬った。","type":"text","bg_key":"bg_memory_forest","next":"text_ares_defeat_02","choices":[{"label":"続ける","next":"text_ares_defeat_02"}]},"text_ares_defeat_02":{"text":"「見事！ これぞ闘争の極み！ 人間ども、大いに楽しんだぞ！」","type":"text","bg_key":"bg_memory_forest","speaker_name":"軍神アレス","speaker":"軍神アレス","next":"text_sword","choices":[{"label":"続ける","next":"text_sword"}]},"text_sword":{"text":"光が収まり、意識は現実の遺跡へと引き戻されていた。","type":"text","bg_key":"bg_island","next":"text_sword_02","choices":[{"label":"続ける","next":"text_sword_02"}]},"text_sword_02":{"text":"石碑の足元には、真っ赤に熱を帯びた「軍神の剣」が刺さっている。","type":"text","bg_key":"bg_island","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"text":"手にした剣を握り締め、あなたは砂船でカロンへと帰還した。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"text_return_02","choices":[{"label":"続ける","next":"text_return_02"}]},"text_return_02":{"text":"残る石碑はあと二つ。あなたは次の目的地「出雲」へ向かう。","type":"text","bg_key":"bg_desert","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"アレスの試練を乗り越え、遺産である「軍神の剣」を得た。","type":"end","result":"success","bg_key":"bg_desert","params":{"rewards":{"gold":3500,"reputation":25,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"アレスの圧倒的な神威の前に力尽き、あなたとヴォルグは熱砂に倒れ伏す。死神にすら見放された暗闇へと、意識は沈んだ。","type":"end","result":"failure","bg_key":"bg_memory_forest","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第18話"}'::jsonb,
    7,
    4
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

