    ARRAY[]::text[],
    '{"completed_quest":"main_ep16","location_id":"loc_yato"}'::jsonb,
    '{"nodes":{"start":{"text":"四つ目の石碑の導きに従い、あなたは首都・出雲を出発した。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"古き神々への信仰が息づく山脈を目指し、旅路を急ぐ。","type":"text","bg_key":"bg_road_day","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"求める秘境は、より深く険しい場所にある。","type":"text","bg_key":"bg_road_day","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"古老から、誰も戻らない「神隠しの谷」の噂を聞き出した。","type":"text","bg_key":"bg_road_day","next":"text_izumo","choices":[{"label":"続ける","next":"text_izumo"}]},"text_izumo":{"text":"出雲の北に幾重にも連なる深い山脈へ、足を踏み入れた。","type":"text","bg_key":"bg_mountain","next":"text_izumo_02","choices":[{"label":"続ける","next":"text_izumo_02"}]},"text_izumo_02":{"text":"杉の大木が空を覆い尽くし、真昼であるにもかかわらず薄暗い。","type":"text","bg_key":"bg_mountain","next":"text_izumo_03","choices":[{"label":"続ける","next":"text_izumo_03"}]},"text_izumo_03":{"text":"獣道すら途切れた山の中で、人の気配は完全に途絶えた。","type":"text","bg_key":"bg_mountain","next":"text_mountain_path","choices":[{"label":"続ける","next":"text_mountain_path"}]},"text_mountain_path":{"text":"眼前に立ちはだかる険しい斜面と、崩れやすい岩場を登る。","type":"text","bg_key":"bg_mountain","next":"text_mountain_path_02","choices":[{"label":"続ける","next":"text_mountain_path_02"}]},"text_mountain_path_02":{"text":"滑りやすい木の根に足を取られながら、慎重に進む。","type":"text","bg_key":"bg_mountain","next":"text_mountain_path_03","choices":[{"label":"続ける","next":"text_mountain_path_03"}]},"text_mountain_path_03":{"text":"腕の紋様が脈打つように青く光り、正しい山道を示していた。","type":"text","bg_key":"bg_mountain","next":"text_fog","choices":[{"label":"続ける","next":"text_fog"}]},"text_fog":{"text":"標高が上がるにつれ、突然、辺り一面に濃い霧が立ち込める。","type":"text","bg_key":"bg_mountain","next":"text_fog_02","choices":[{"label":"続ける","next":"text_fog_02"}]},"text_fog_02":{"text":"ただの自然現象ではない。この濃霧は、石碑が無関係な凡百の人間を拒むために張った結界だ。","type":"text","bg_key":"bg_mountain","next":"text_fog_03","choices":[{"label":"続ける","next":"text_fog_03"}]},"text_fog_03":{"text":"結界の霧を恐れることなく、紋様の輝きを頼りに直進する。","type":"text","bg_key":"bg_mountain","next":"text_shrine_gate","choices":[{"label":"続ける","next":"text_shrine_gate"}]},"text_shrine_gate":{"text":"深い霧の壁を抜けると、不意に視界が開け、谷間の底に出た。","type":"text","bg_key":"bg_mountain_shrine","bgm":"bgm_quest_tense","next":"text_shrine_gate_02","choices":[{"label":"続ける","next":"text_shrine_gate_02"}]},"text_shrine_gate_02":{"text":"入口には、誰に顧みられることもなく朽ち果てた古代の木製鳥居が、苔を纏ってひっそりと佇む。","type":"text","bg_key":"bg_mountain_shrine","next":"text_shrine_gate_03","choices":[{"label":"続ける","next":"text_shrine_gate_03"}]},"text_shrine_gate_03":{"text":"鳥居の奥からは、静かだが非常に清浄な銀の光が放たれていた。","type":"text","bg_key":"bg_mountain_shrine","next":"text_valley","choices":[{"label":"続ける","next":"text_valley"}]},"text_valley":{"text":"朽ちた鳥居をくぐり、清流のせせらぎが響く谷の奥深くへ進む。","type":"text","bg_key":"bg_mountain_shrine","next":"text_valley_02","choices":[{"label":"続ける","next":"text_valley_02"}]},"text_valley_02":{"text":"湿った石段を降りると、そこには石碑が静かに佇んでいた。","type":"text","bg_key":"bg_mountain_shrine","next":"text_valley_03","choices":[{"label":"続ける","next":"text_valley_03"}]},"text_valley_03":{"text":"この谷の底だけは、月光のような美しい光が満ちている。","type":"text","bg_key":"bg_mountain_shrine","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"text":"石碑の表面に刻まれた紋様が、あなたを歓迎するように輝く。","type":"text","bg_key":"bg_heroic_stele","next":"text_stele_found_02","choices":[{"label":"続ける","next":"text_stele_found_02"}]},"text_stele_found_02":{"text":"「月光の試練を越えよ」とあり、あなたは銀の表面に手を触れた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"触れた瞬間、意識が急激に銀色の閃光に飲み込まれていく。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch_02","choices":[{"label":"続ける","next":"text_touch_02"}]},"text_touch_02":{"text":"気がつくと、あなたは冷たい夜風が吹く月明かりの山道にいた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch_03","choices":[{"label":"続ける","next":"text_touch_03"}]},"text_touch_03":{"text":"それは先代の英霊が、狩りの女神の冷酷な狩猟の的とされ、追い詰められた決戦の記憶。","type":"text","bg_key":"bg_heroic_stele","next":"text_memory_mountain","choices":[{"label":"続ける","next":"text_memory_mountain"}]},"text_memory_mountain":{"text":"記憶のビジョンが再生される。月夜の山道を駆ける英霊。","type":"text","bg_key":"bg_memory_mountain","next":"text_memory_mountain_02","choices":[{"label":"続ける","next":"text_memory_mountain_02"}]},"text_memory_mountain_02":{"text":"木々の隙間から、音も気配もなく銀色の矢が次々と放たれた。","type":"text","bg_key":"bg_memory_mountain","next":"text_memory_mountain_03","choices":[{"label":"続ける","next":"text_memory_mountain_03"}]},"text_memory_mountain_03":{"text":"急所を狙い澄ました銀色の矢が、地響きをたてて地面に突き刺さる。","type":"text","bg_key":"bg_memory_mountain","next":"text_artemis_appear","choices":[{"label":"続ける","next":"text_artemis_appear"}]},"text_artemis_appear":{"text":"月光の柱が降り注ぎ、その光の中から一人の影が歩み出た。","type":"text","bg_key":"bg_memory_mountain","bgm":"bgm_battle_strong","next":"text_artemis_appear_02","choices":[{"label":"続ける","next":"text_artemis_appear_02"}]},"text_artemis_appear_02":{"text":"銀の長髪に、すべてを見透かすような冷酷なるサファイアの瞳。","type":"text","bg_key":"bg_memory_mountain","next":"text_artemis_appear_03","choices":[{"label":"続ける","next":"text_artemis_appear_03"}]},"text_artemis_appear_03":{"text":"月と狩猟を司る女神アルテミス。絶対の射手である。","type":"text","bg_key":"bg_memory_mountain","next":"text_artemis_voice","choices":[{"label":"続ける","next":"text_artemis_voice"}]},"text_artemis_voice":{"text":"「我が月光の射程から、逃れられると思うな」","type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","speaker":"女神アルテミス","next":"text_artemis_voice_02","choices":[{"label":"続ける","next":"text_artemis_voice_02"}]},"text_artemis_voice_02":{"text":"「先代の力を受け継ぐ者よ。その魂ごと射抜いてみせよう」","type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","speaker":"女神アルテミス","next":"text_artemis_challenge","choices":[{"label":"続ける","next":"text_artemis_challenge"}]},"text_artemis_challenge":{"text":"「神の弓矢の前に、人間がどこまで抗えるかを示すが良い」","type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","speaker":"女神アルテミス","next":"text_artemis_challenge_02","choices":[{"label":"続ける","next":"text_artemis_challenge_02"}]},"text_artemis_challenge_02":{"text":"「逃げるのをやめ、汝の武器を構えて立ち向かうがいい」","type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","speaker":"女神アルテミス","next":"battle","choices":[{"label":"続ける","next":"battle"}]},"battle":{"type":"battle","bg_key":"bg_memory_mountain","bgm":"bgm_spot_final_boss","enemy_group_id":"9052","choices":[{"label":"win","next":"text_artemis_defeat"},{"label":"lose","next":"end_failure"}],"battle_success_next":"text_artemis_defeat"},"text_artemis_defeat":{"text":"光の矢の豪雨をすり抜け、決死の踏み込みが女神の銀の弓を叩き落とした。","type":"text","bg_key":"bg_memory_mountain","next":"text_artemis_defeat_02","choices":[{"label":"続ける","next":"text_artemis_defeat_02"}]},"text_artemis_defeat_02":{"text":"「実に見事。我が敗北を認め、月光の衣を授けよう」","type":"text","bg_key":"bg_memory_mountain","speaker_name":"女神アルテミス","speaker":"女神アルテミス","next":"text_armor","choices":[{"label":"続ける","next":"text_armor"}]},"text_armor":{"text":"まばゆい光が消え去り、意識は現実の静かな谷底へと戻った。","type":"text","bg_key":"bg_heroic_stele","next":"text_armor_02","choices":[{"label":"続ける","next":"text_armor_02"}]},"text_armor_02":{"text":"石碑の足元には、銀色に優しく輝く「女神の鎧」がある。","type":"text","bg_key":"bg_heroic_stele","next":"text_return","choices":[{"label":"続ける","next":"text_return"}]},"text_return":{"text":"これで三つの遺産を手に入れた。残る石碑はあと一つだ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"text_return_02","choices":[{"label":"続ける","next":"text_return_02"}]},"text_return_02":{"text":"あなたは山脈を降り、最後の石碑が眠る王都レガリアを目指す。","type":"text","bg_key":"bg_mountain","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"女神アルテミスの試練を乗り越え、「女神の鎧」を得た。","type":"end","result":"success","bg_key":"bg_mountain","params":{"rewards":{"gold":3500,"reputation":25,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"アルテミスの放った銀の矢が、あなたの胸を寸分の狂いなく貫く。氷のような冷気が全身を侵食し、意識は永久に消失した。","type":"end","result":"failure","bg_key":"bg_heroic_stele","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第19話"}'::jsonb,
    5,
    3
