-- Scenario 6020: 第20話「蒼暁の剣」 (main_ep20)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6020,
    'main_ep20',
    '第20話「蒼暁の剣」',
    'メインシナリオ第20話',
    'なし',
    5,
    25,
    2,
    '{"gold":15000,"items":[504],"reputation":50,"alignment_shift":{"order":5}}'::jsonb,
    true,
    'special',
    '{"completed_quest":"main_ep17||main_ep18||main_ep19","location_id":"loc_regalia"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep17||main_ep18||main_ep19","location_id":"loc_regalia"}'::jsonb,
    '{"nodes":{"start":{"text":"英霊の遺産を集める旅も、いよいよ最後の行程に達した。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"集めた遺産を手に、最後の石碑があるレガリア郊外の遺跡へ向かう。","type":"text","bg_key":"bg_road_day","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"そこには英霊の最後の記憶と、全能神ゼウスが待ち受ける。","type":"text","bg_key":"bg_road_day","next":"text_regalia","choices":[{"label":"続ける","next":"text_regalia"}]},"text_regalia":{"text":"王都レガリアの街を抜け、のどかな郊外の平原へと出る。","type":"text","bg_key":"bg_road_day","next":"text_regalia_02","choices":[{"label":"続ける","next":"text_regalia_02"}]},"text_regalia_02":{"text":"大天使ミカエルがもたらした破壊の傷跡から復興し、活気を取り戻した白亜の王都。だが、神がその玉座に居座り続ける限り、この平和は仮初めにすぎない。","type":"text","bg_key":"bg_road_day","next":"text_regalia_03","choices":[{"label":"続ける","next":"text_regalia_03"}]},"text_regalia_03":{"text":"平和を取り戻した都市を背に、遺跡のある荒野へと馬を進めた。","type":"text","bg_key":"bg_road_day","next":"text_outskirts","choices":[{"label":"続ける","next":"text_outskirts"}]},"text_outskirts":{"text":"レガリアの郊外、荒涼とした丘陵地帯の先に遺跡が見えてきた。","type":"text","bg_key":"bg_ruins_field","next":"text_outskirts_02","choices":[{"label":"続ける","next":"text_outskirts_02"}]},"text_outskirts_02":{"text":"ここは英霊が最期の魂の欠片と記憶を封じた絶対の場所。","type":"text","bg_key":"bg_ruins_field","next":"text_outskirts_03","choices":[{"label":"続ける","next":"text_outskirts_03"}]},"text_outskirts_03":{"text":"遺跡の奥底から放たれる、雷鳴のような強い波動を感じ取る。","type":"text","bg_key":"bg_ruins_field","next":"text_ruins_entrance","choices":[{"label":"続ける","next":"text_ruins_entrance"}]},"text_ruins_entrance":{"text":"遺跡の入口に立つ。全身を押し潰すような、かつて体験したことのない神の重圧が漂う。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_crisis","next":"text_ruins_entrance_02","choices":[{"label":"続ける","next":"text_ruins_entrance_02"}]},"text_ruins_entrance_02":{"text":"空気がピリピリと震え、大気中に微かな静電気が生じている。","type":"text","bg_key":"bg_ruins_field","next":"text_ruins_entrance_03","choices":[{"label":"続ける","next":"text_ruins_entrance_03"}]},"text_ruins_entrance_03":{"text":"深く息を吐いて精神を研ぎ澄まし、あなたはゆっくりと神殿の闇へと踏み入った。","type":"text","bg_key":"bg_ruins_field","next":"text_descent","choices":[{"label":"続ける","next":"text_descent"}]},"text_descent":{"text":"薄暗い石段を下りていく。松明の光が石壁の壁画を揺らした。","type":"text","bg_key":"bg_catacombs","next":"text_descent_02","choices":[{"label":"続ける","next":"text_descent_02"}]},"text_descent_02":{"text":"そこには二人の人間が背中を合わせ、巨神と戦う姿がある。","type":"text","bg_key":"bg_catacombs","next":"text_descent_03","choices":[{"label":"続ける","next":"text_descent_03"}]},"text_descent_03":{"text":"彼らの前に立ちはだかるのは、雷を手にする天空の王の姿。","type":"text","bg_key":"bg_catacombs","next":"text_final_chamber","choices":[{"label":"続ける","next":"text_final_chamber"}]},"text_final_chamber":{"text":"最奥に位置する、円形の広大な神殿跡にたどり着いた。","type":"text","bg_key":"bg_boss_altar","next":"text_final_chamber_02","choices":[{"label":"続ける","next":"text_final_chamber_02"}]},"text_final_chamber_02":{"text":"天井が崩落しており、そこから降り注ぐ陽光が石碑を照らす。","type":"text","bg_key":"bg_boss_altar","next":"text_final_chamber_03","choices":[{"label":"続ける","next":"text_final_chamber_03"}]},"text_final_chamber_03":{"text":"これまで手にした三つの遺産が、激しく共鳴を始めた。","type":"text","bg_key":"bg_boss_altar","next":"text_stele_found","choices":[{"label":"続ける","next":"text_stele_found"}]},"text_stele_found":{"text":"石碑に近づくと、赤く輝く文字が浮かび上がった。","type":"text","bg_key":"bg_heroic_stele","next":"text_stele_found_02","choices":[{"label":"続ける","next":"text_stele_found_02"}]},"text_stele_found_02":{"text":"「すべてを終わらせる力を受け継げ」とあり、石碑に触れた。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch","choices":[{"label":"続ける","next":"text_touch"}]},"text_touch":{"text":"触れた瞬間、意識が強く閃光に飲み込まれ、現実が消失する。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch_02","choices":[{"label":"続ける","next":"text_touch_02"}]},"text_touch_02":{"text":"目を開けると、そこは荒涼とした雷鳴轟く記憶の原野だった。","type":"text","bg_key":"bg_heroic_stele","next":"text_touch_03","choices":[{"label":"続ける","next":"text_touch_03"}]},"text_touch_03":{"text":"そして、記憶の中のあなたの隣には、大剣を担いだ戦士がいた。","type":"text","bg_key":"bg_heroic_stele","next":"text_memory_gawain","choices":[{"label":"続ける","next":"text_memory_gawain"}]},"text_memory_gawain":{"text":"その姿は、老騎士ガウェインの若き日の姿そのものだった。","type":"text","bg_key":"bg_memory_gawain","next":"text_memory_gawain_02","choices":[{"label":"続ける","next":"text_memory_gawain_02"}]},"text_memory_gawain_02":{"text":"彼はかつて英霊の右腕として、最終決戦を共に戦っていたのだ。","type":"text","bg_key":"bg_memory_gawain","next":"text_memory_comrade","choices":[{"label":"続ける","next":"text_memory_comrade"}]},"text_memory_comrade":{"text":"「相棒。あの雷の野郎が最後だ。全部終わらせようぜ」","type":"text","bg_key":"bg_memory_gawain","speaker_name":"若きガウェイン","speaker":"若きガウェイン","next":"text_memory_comrade_02","choices":[{"label":"続ける","next":"text_memory_comrade_02"}]},"text_memory_comrade_02":{"text":"あなたはかつての先代の魂と完全に同調し、剣を掲げた。","type":"text","bg_key":"bg_memory_gawain","next":"text_zeus_appear","choices":[{"label":"続ける","next":"text_zeus_appear"}]},"text_zeus_appear":{"text":"天空から直撃した巨大な雷柱の中から、神々の王が現れた。","type":"text","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","next":"text_zeus_appear_02","choices":[{"label":"続ける","next":"text_zeus_appear_02"}]},"text_zeus_appear_02":{"text":"雷霆を手に握り、純白の衣を纏った全能神ゼウスである。","type":"text","bg_key":"bg_memory_gawain","next":"text_zeus_voice","choices":[{"label":"続ける","next":"text_zeus_voice"}]},"text_zeus_voice":{"text":"「我が前に立つ愚者どもよ。汝らが集めし欠片、見定める」","type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","speaker":"全能神ゼウス","next":"text_zeus_voice_02","choices":[{"label":"続ける","next":"text_zeus_voice_02"}]},"text_zeus_voice_02":{"text":"「すべての遺産無き者に、我が雷を下す資格など無し」","type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","speaker":"全能神ゼウス","next":"text_zeus_challenge","choices":[{"label":"続ける","next":"text_zeus_challenge"}]},"text_zeus_challenge":{"text":"「我が雷の前に、その器が本物であるかを示してみせよ！」","type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","speaker":"全能神ゼウス","next":"check_items","choices":[{"label":"続ける","next":"check_items"}]},"check_items":{"text":"集めた遺産を掲げる。三つの遺産は揃っているだろうか。","type":"check_flags","bg_key":"bg_memory_gawain","choices":[{"label":"items_all_relics","next":"text_relics_glow"},{"label":"items_missing","next":"text_relics_missing"}]},"text_relics_glow":{"text":"護符、剣、鎧。三つの遺産が共鳴し、光の壁を作る。","type":"text","bg_key":"bg_memory_gawain","next":"text_relics_glow_02","choices":[{"label":"続ける","next":"text_relics_glow_02"}]},"text_relics_glow_02":{"text":"三つの神の力がゼウスの雷霆を切り裂き、神の王へと肉薄する好機が訪れた！","type":"text","bg_key":"bg_memory_gawain","next":"battle_weak","choices":[{"label":"続ける","next":"battle_weak"}]},"battle_weak":{"type":"battle","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","enemy_group_id":"9053","choices":[{"label":"win","next":"text_zeus_defeat"},{"label":"lose","next":"end_failure"}],"battle_success_next":"text_zeus_defeat"},"text_relics_missing":{"text":"集めた遺産が足りない。加護なき身のまま、神々の王に挑む無謀を受け入れるしかない。","type":"text","bg_key":"bg_memory_gawain","next":"text_relics_missing_02","choices":[{"label":"続ける","next":"text_relics_missing_02"}]},"text_relics_missing_02":{"text":"ゼウスの狂気的な全天の雷霆が、容赦なく降り注ぐ！","type":"text","bg_key":"bg_memory_gawain","next":"battle_strong","choices":[{"label":"続ける","next":"battle_strong"}]},"battle_strong":{"type":"battle","bg_key":"bg_memory_gawain","bgm":"bgm_spot_final_boss","enemy_group_id":"9054","choices":[{"label":"win","next":"text_zeus_defeat"},{"label":"lose","next":"end_failure"}],"battle_success_next":"text_zeus_defeat"},"text_zeus_defeat":{"text":"満身創痍になりながらも、ゼウスに最後の一撃を突き刺した。","type":"text","bg_key":"bg_memory_gawain","next":"text_zeus_defeat_02","choices":[{"label":"続ける","next":"text_zeus_defeat_02"}]},"text_zeus_defeat_02":{"text":"「見事。人間が神を越えたか。我が剣、お前に託そう」","type":"text","bg_key":"bg_memory_gawain","speaker_name":"全能神ゼウス","speaker":"全能神ゼウス","next":"text_dawn_sword","choices":[{"label":"続ける","next":"text_dawn_sword"}]},"text_dawn_sword":{"text":"雷光となってゼウスが昇り、意識は現実の遺跡へと戻った。","type":"text","bg_key":"bg_boss_altar","next":"text_dawn_sword_02","choices":[{"label":"続ける","next":"text_dawn_sword_02"}]},"text_dawn_sword_02":{"text":"石碑の足元にある、黎明の光を放つ「蒼暁の剣」を引き抜いた。","type":"text","bg_key":"bg_boss_altar","next":"text_epilogue","choices":[{"label":"続ける","next":"text_epilogue"}]},"text_epilogue":{"text":"蒼暁の剣を抱え、あなたは遺跡を後にし、レガリアへ戻る。","type":"text","bg_key":"bg_boss_altar","bgm":"bgm_quest_calm","next":"text_epilogue_02","choices":[{"label":"続ける","next":"text_epilogue_02"}]},"text_epilogue_02":{"text":"神々を打倒し、真の平和を勝ち取るための本当の戦いが始まる。","type":"text","bg_key":"bg_road_day","next":"end_node","choices":[{"label":"続ける","next":"end_node"}]},"end_node":{"text":"すべての遺産と記憶を完全に受け継ぎ、神に届く力を得た。","type":"end","result":"success","bg_key":"bg_road_day","params":{"rewards":{"gold":15000,"reputation":50,"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"ゼウスの圧倒的な雷霆に焼き尽くされ、あなたの体は塵となって散った。神に届くための足掻きは、ここで完全に灰に帰した。","type":"end","result":"failure","bg_key":"bg_boss_altar","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"メインシナリオ第20話"}'::jsonb,
    8,
    5
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
