-- Scenario 6101: 忘却の五英霊 (qst_spot_roland)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6101,
    'qst_spot_roland',
    '忘却の五英霊',
    '聖王国スポット: 封印された英霊たちが暴走。王都を守り五英霊に決着をつけよ。',
    '王国軍',
    5,
    20,
    7,
    '{"gold":10000,"items":[602],"reputation":200,"exp":500}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep08","nation_id":"loc_holy_empire","min_alignment_pct":{"alignment":"order","min_pct":50}}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep08","nation_id":"loc_holy_empire","min_alignment_pct":{"alignment":"order","min_pct":50}}'::jsonb,
    '{"nodes":{"start":{"text":"王都レガリアの中央広場。かつて清らかな水を湛えていた噴水は、今や赤黒い血のような液体で染まり、不気味に沸き立っていた。","type":"text","bg_key":"bg_spot_roland_fire","bgm":"bgm_roland","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"広場の奥から、一人の聖騎士が血まみれになって走ってくる。その白銀の甲冑は、何者かの凄まじい力によって無残に歪められ、押し潰されていた。","type":"text","bg_key":"bg_spot_roland_fire","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「ゴハッ……！ に、逃げろ！ 奴らは……奴らは人間などではない！」","type":"text","bg_key":"bg_spot_roland_fire","speaker_name":"負傷した聖騎士","speaker":"負傷した聖騎士","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「王家が封印したはずの……かつての守護者『五英霊』が蘇り、街を滅ぼそうとしているんだ……！」","type":"text","bg_key":"bg_spot_roland_fire","speaker_name":"負傷した聖騎士","speaker":"負傷した聖騎士","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"その言葉をかき消すように、大聖堂が轟音と共に爆発する。立ち上る粉塵の向こうに、青白く光る五つの人影が静かに浮かび上がった。","type":"text","bg_key":"bg_spot_roland_fire","next":"start_06","choices":[{"label":"続ける","next":"start_06"}]},"start_06":{"text":"先頭に立つ聖女の影が静かに手を翳すと、その指先から放たれた魔力によって、立ち向かおうとした聖騎士たち次々と膝から崩れ落ちていく。","type":"text","bg_key":"bg_spot_roland_fire","next":"start_07","choices":[{"label":"続ける","next":"start_07"}]},"start_07":{"text":"これほどの神威を前に、もはやまともに対峙することすら不可能だった。あなたは王都の混乱を抜け、薄暗い地下墓所へと逃げ込んだ。","type":"text","bg_key":"bg_spot_roland_fire","next":"start_monologue","choices":[{"label":"続ける","next":"start_monologue"}]},"start_monologue":{"text":"（大聖堂が文字通り一瞬で吹き飛ぶとは……。あの五つの影が、王国の裏歴史に隠された『五英霊』なのか。今の力では勝負にならん、墓所で活路を探すしかない！）","type":"text","bg_key":"bg_spot_roland_fire","next":"escape_underground","choices":[{"label":"続ける","next":"escape_underground"}]},"escape_underground":{"text":"避難民の怒号と悲鳴が反響する暗闇を抜け、あなたは地下墓所の最も深い区画へと辿り着いた。","type":"text","bg_key":"bg_spot_roland_tomb","bgm":"bgm_quest_mystery","next":"escape_underground_02","choices":[{"label":"続ける","next":"escape_underground_02"}]},"escape_underground_02":{"text":"並び立つ古い石棺の間を走るうち、苔むした壁の一角に、かつて隠された通路への隙間と空気の流れがあることに気づく。","type":"text","bg_key":"bg_spot_roland_tomb","next":"escape_underground_03","choices":[{"label":"続ける","next":"escape_underground_03"}]},"escape_underground_03":{"text":"壁の隠しスイッチを押し込むと、静かに石壁がスライドし、隠し祭壇が現れた。そこには、歴史から抹消されたはずの英雄たちの名が刻まれていた。","type":"text","bg_key":"bg_spot_roland_tomb","next":"escape_underground_04","choices":[{"label":"続ける","next":"escape_underground_04"}]},"escape_underground_04":{"text":"祭壇へ一歩近づいた瞬間、周囲の石壁から砂埃を巻き上げ、巨大な石造りの守護巨人が這い出てきて行く手を阻んだ。","type":"text","bg_key":"bg_spot_roland_tomb","next":"battle_protos","choices":[{"label":"続ける","next":"battle_protos"}]},"battle_protos":{"type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"300","choices":[{"label":"win","next":"get_promise"},{"label":"lose","next":"end_failure"}],"battle_success_next":"get_promise"},"get_promise":{"text":"激しい戦いの末、守護者の石体がガラガラと崩れ落ちる。その大石の中から、淡く明滅する五角形の不思議な宝珠が現れた。","type":"reward","bg_key":"bg_spot_roland_tomb","bgm":"bgm_quest_mystery","params":{"item_id":"601"},"next":"get_promise_02","choices":[{"label":"続ける","next":"get_promise_02"}]},"get_promise_02":{"text":"あなたが宝珠に触れて手に入れた瞬間、脳裏に直接、哀切を帯びた英霊の声が響き渡る。","type":"text","bg_key":"bg_spot_roland_tomb","next":"get_promise_03","choices":[{"label":"続ける","next":"get_promise_03"}]},"get_promise_03":{"text":"「我らは……王家に裏切られた。この石に込められた誓約の力で、暴走する我らの魂を止めてくれ……」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"英霊の声","speaker":"英霊の声","next":"get_promise_04","choices":[{"label":"続ける","next":"get_promise_04"}]},"get_promise_04":{"text":"英霊たちの悔恨の意思があなたに流れ込み、パッシブスキル『五英霊の誓約』が魂に刻まれた。","type":"text","bg_key":"bg_spot_roland_tomb","next":"get_promise_monologue","choices":[{"label":"続ける","next":"get_promise_monologue"}]},"get_promise_monologue":{"text":"（五英霊の誓約……。彼らは国を守りながらも裏切られ、怨嗟の力で無理やり蘇らされたのか。この宝珠の力を使えば、彼らを止められるかもしれないな）","type":"text","bg_key":"bg_spot_roland_tomb","next":"eluka_intro","choices":[{"label":"続ける","next":"eluka_intro"}]},"eluka_intro":{"text":"暗い通路を奥へと進むと、青白い光を放ちながら、白い法衣をまとった女性の霊体が宙に浮かんでいるのが見えた。","type":"text","bg_key":"bg_spot_roland_tomb","bgm":"bgm_quest_mystery","next":"eluka_intro_02","choices":[{"label":"続ける","next":"eluka_intro_02"}]},"eluka_intro_02":{"text":"「……あなた、生きているのね。珍しいこともあるものね」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"聖女エルーカ","speaker":"聖女エルーカ","next":"eluka_intro_03","choices":[{"label":"続ける","next":"eluka_intro_03"}]},"eluka_intro_03":{"text":"彼女はかつて疫病から多くの民を救ったが、その聖なる血を惜しんだ王家により、死ぬまで地下牢で血を抜かれ続けた悲劇の聖女だった。","type":"text","bg_key":"bg_spot_roland_tomb","next":"eluka_intro_04","choices":[{"label":"続ける","next":"eluka_intro_04"}]},"eluka_intro_04":{"text":"「私が暗闇で乾いていく時、誰も助けには来なかった。それでもまだ、私に『慈愛』を求めるというの？」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"聖女エルーカ","speaker":"聖女エルーカ","next":"battle_eluka","choices":[{"label":"続ける","next":"battle_eluka"}]},"battle_eluka":{"type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"301","choices":[{"label":"win","next":"baram_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"baram_intro"},"baram_intro":{"text":"（民を救い続けた聖女の末路がこれか……。救いを求めたはずの人間に裏切られ、怨嗟の英霊と化すなど、あまりにも残酷だな）","type":"text","bg_key":"bg_spot_roland_tomb","next":"baram_intro_02","choices":[{"label":"続ける","next":"baram_intro_02"}]},"baram_intro_02":{"text":"複雑な思いを胸に次の通路へと進むと、青白く光る魔法陣の中心で、古い書物をめくる男の影があった。","type":"text","bg_key":"bg_spot_roland_tomb","next":"baram_intro_03","choices":[{"label":"続ける","next":"baram_intro_03"}]},"baram_intro_03":{"text":"「客人か。最後にこうして人と対面して喋ったのは、処刑される前日のことだったな」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"賢者バラム","speaker":"賢者バラム","next":"baram_intro_04","choices":[{"label":"続ける","next":"baram_intro_04"}]},"baram_intro_04":{"text":"「私の生涯の研究は全て王家に強奪され、名さえも消された。まあよい、死後の退屈な暇つぶしとしよう」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"賢者バラム","speaker":"賢者バラム","next":"battle_baram","choices":[{"label":"続ける","next":"battle_baram"}]},"battle_baram":{"type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"302","choices":[{"label":"win","next":"shirasu_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"shirasu_intro"},"shirasu_intro":{"text":"バラムは研究者らしい冷静さで「敗北の数式を解くのも悪くない」と言い残し、霧のように消え去った。","type":"text","bg_key":"bg_spot_roland_tomb","bgm":"bgm_quest_mystery","next":"shirasu_intro_monologue","choices":[{"label":"続ける","next":"shirasu_intro_monologue"}]},"shirasu_intro_monologue":{"text":"（国のために知恵を絞り尽くした賢者を処刑し、その成果だけを奪う。この国の歴史は、英雄たちの屍の上に成り立っているのか）","type":"text","bg_key":"bg_spot_roland_tomb","next":"shirasu_intro_02","choices":[{"label":"続ける","next":"shirasu_intro_02"}]},"shirasu_intro_02":{"text":"堅牢な石造りの門をくぐると、巨大な盾を構え、微動だにせず通路を塞ぐ巨漢の騎士が立ち塞がっていた。","type":"text","bg_key":"bg_spot_roland_tomb","next":"shirasu_intro_03","choices":[{"label":"続ける","next":"shirasu_intro_03"}]},"shirasu_intro_03":{"text":"「俺は己の身を盾にして王を守り抜いて死んだ。だが、王は俺が死んだ後、俺の家族を冷酷に見捨てて処刑した」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"盾のシラス","speaker":"盾のシラス","next":"shirasu_intro_04","choices":[{"label":"続ける","next":"shirasu_intro_04"}]},"shirasu_intro_04":{"text":"「もはや語るべき言葉などない。お前が王家の眷属を名乗るなら、我が大盾がその肉を叩き潰すのみだ」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"盾のシラス","speaker":"盾のシラス","next":"battle_shirasu","choices":[{"label":"続ける","next":"battle_shirasu"}]},"battle_shirasu":{"type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"303","choices":[{"label":"win","next":"lyra_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"lyra_intro"},"lyra_intro":{"text":"シラスは、はるか遠い家族の安息を祈るように祈りを捧げ、静かに石化して崩れ去った。","type":"text","bg_key":"bg_spot_roland_tomb","bgm":"bgm_quest_mystery","next":"lyra_intro_monologue","choices":[{"label":"続ける","next":"lyra_intro_monologue"}]},"lyra_intro_monologue":{"text":"（命を賭して王を守った結果が、家族の処刑か。この騎士が抱える絶望の重さは、測り知れんな）","type":"text","bg_key":"bg_spot_roland_tomb","next":"lyra_intro_02","choices":[{"label":"続ける","next":"lyra_intro_02"}]},"lyra_intro_02":{"text":"冷たい風が吹き抜ける大広間。薄暗闇の中から、鋭い殺気を放つ長弓を引いた女性の英霊があなたを狙い定めていた。","type":"text","bg_key":"bg_spot_roland_tomb","next":"lyra_intro_03","choices":[{"label":"続ける","next":"lyra_intro_03"}]},"lyra_intro_03":{"text":"「英雄なんて、王家にとっては使い捨ての都合の良い道具に過ぎないわ。用が済めば、邪魔者として消されるだけ」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"射手リラ","speaker":"射手リラ","next":"lyra_intro_04","choices":[{"label":"続ける","next":"lyra_intro_04"}]},"lyra_intro_04":{"text":"「私がその生きた証拠。裏切りの痛みを、お前の身体に矢として突き刺してあげるわ！」","type":"text","bg_key":"bg_spot_roland_tomb","speaker_name":"射手リラ","speaker":"射手リラ","next":"battle_lyra","choices":[{"label":"続ける","next":"battle_lyra"}]},"battle_lyra":{"type":"battle","bg_key":"bg_spot_roland_tomb","bgm":"bgm_battle_strong","enemy_group_id":"304","choices":[{"label":"win","next":"alvin_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"alvin_intro"},"alvin_intro":{"text":"リラは「少しだけ、お前を信じてみるのもいいかもね……」と呟き、安らかな表情で消滅していった。","type":"text","bg_key":"bg_spot_roland_tomb","bgm":"bgm_quest_mystery","next":"alvin_intro_monologue","choices":[{"label":"続ける","next":"alvin_intro_monologue"}]},"alvin_intro_monologue":{"text":"最深部。王国のシンボルたる冠を被り、虚ろな光を放つ瞳をした「不滅の王」アルヴィンが、大剣を地面に突き立てて待っていた。","type":"text","bg_key":"bg_spot_roland_core","next":"alvin_intro_03","choices":[{"label":"続ける","next":"alvin_intro_03"}]},"alvin_intro_03":{"text":"「……俺はかつて国を守るため、大義の名の下に、四人の無二の友を裏切り、その手を血で汚して殺した」","type":"text","bg_key":"bg_spot_roland_core","speaker_name":"不滅の王アルヴィン","speaker":"不滅の王アルヴィン","next":"alvin_intro_04","choices":[{"label":"続ける","next":"alvin_intro_04"}]},"alvin_intro_04":{"text":"「その裏切りの罪と友を殺した悔恨は、何度我が肉体が滅び、魂が磨り減ろうとも決して消えることはない」","type":"text","bg_key":"bg_spot_roland_core","speaker_name":"不滅の王アルヴィン","speaker":"不滅の王アルヴィン","next":"alvin_intro_05","choices":[{"label":"続ける","next":"alvin_intro_05"}]},"alvin_intro_05":{"text":"「だからこそ、ここで俺を殺し、友らの怒りを鎮めてくれ！ 俺を止められる継承者よ、全力で来い！」","type":"text","bg_key":"bg_spot_roland_core","speaker_name":"不滅の王アルヴィン","speaker":"不滅の王アルヴィン","next":"battle_alvin","choices":[{"label":"続ける","next":"battle_alvin"}]},"battle_alvin":{"type":"battle","bg_key":"bg_spot_roland_core","bgm":"bgm_spot_final_boss","enemy_group_id":"305","choices":[{"label":"win","next":"alvin_defeated"},{"label":"lose","next":"end_failure"}],"battle_success_next":"alvin_defeated"},"alvin_defeated":{"text":"激闘の末、アルヴィンの巨躯が大剣を支えに深く膝をついた。その胸で輝く核が、限界を迎えて激しく明滅し始める。","type":"text","bg_key":"bg_spot_roland_core","bgm":"bgm_spot_final_choice","next":"king_appear","choices":[{"label":"続ける","next":"king_appear"}]},"king_appear":{"text":"静寂が戻ろうとしたその時、墓所の入口から無数の兵士を引き連れ、現ローランド国王が冷酷な笑みを浮かべて現れた。","type":"text","bg_key":"bg_spot_roland_core","next":"king_talk","choices":[{"label":"続ける","next":"king_talk"}]},"king_talk":{"text":"「よくやった、旅人よ。これで英霊の魔力は再び我が国の管理下に入る。彼らの魂を回収し、国の強大なる資源とするのだ」","type":"text","bg_key":"bg_spot_roland_core","speaker_name":"ローランド国王","speaker":"ローランド国王","next":"alvin_talk","choices":[{"label":"続ける","next":"alvin_talk"}]},"alvin_talk":{"text":"「う、うおおお……！ また俺たちを、王家の便利極まる道具として呪縛するつもりか……！ 頼む、お前が決めてくれ……！」","type":"text","bg_key":"bg_spot_roland_core","speaker_name":"不滅の王アルヴィン","speaker":"不滅の王アルヴィン","next":"choice_node","choices":[{"label":"続ける","next":"choice_node"}]},"choice_node":{"text":"目の前で兵を構える国王と、魂の解放を願うアルヴィン。あなたはどのような決断を下すだろうか。","type":"choice","bg_key":"bg_spot_roland_core","bgm":"bgm_spot_final_choice","choices":[{"label":"王の命令に従い討伐する","next":"end_kill"},{"label":"誓約の力で彼らを安らかに封印する","next":"end_seal"}]},"end_kill":{"text":"あなたは国王の命令に従い、アルヴィンの核を完全に叩き割った。五英霊の魂は霧散し、王家は再びその魔力を手に入れた。","type":"text","bg_key":"bg_spot_roland_core","bgm":"bgm_quest_calm","next":"end_kill_02","choices":[{"label":"続ける","next":"end_kill_02"}]},"end_kill_02":{"text":"王都の危機を救ったとして、あなたは新たな英雄と祭り上げられた。しかし、使い潰された五英霊の歴史を知るあなたに、その称賛はひたすら虚しく響くだけだった。口止め料として『神の法衣』を授けられた。","type":"end","result":"success","bg_key":"bg_spot_roland_core","params":{"rewards":{"exp":500,"gold":10000,"reputation":200,"alignment_shift":{"order":5}}},"choices":[]},"end_seal":{"text":"あなたは国王の兵たちを睨み退け、誓約の宝珠を掲げた。宝珠から放たれた温かい光がアルヴィンと四人の魂を優しく包み込み、呪縛を解いていく。","type":"text","bg_key":"bg_spot_roland_core","bgm":"bgm_quest_calm","next":"end_seal_02","choices":[{"label":"続ける","next":"end_seal_02"}]},"end_seal_02":{"text":"「感謝する……」と残し、五つの光は今度こそ安らかに天へと消えていった。国王は激怒したが、託された力は奪われない。固有スキル『五星の加護』を手に入れた！","type":"end","result":"success","bg_key":"bg_spot_roland_core","params":{"rewards":{"exp":500,"reputation":-100,"skills":[3071],"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"冷たい石の床へと倒れ伏す。全身を蝕む英霊の圧倒的な魔力の前に、あなたの意識は凍りつき、冷たい暗闇の中へと溶けて消え去った。","type":"end","result":"failure","bg_key":"bg_spot_roland_tomb","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"聖王国スポット: 封印された英霊たちが暴走。王都を守り五英霊に決着をつけよ。"}'::jsonb,
    7,
    5
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
