    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6102: 冥食の残滓 (qst_spot_yato)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6102,
    'qst_spot_yato',
    '冥食の残滓',
    '夜刀スポット: 冥食の夜。生贄の少女を護衛し冥の門の四大妖怪を退けよ。',
    '忍び衆',
    5,
    20,
    7,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep09","nation_id":"loc_yatoshin","min_alignment_pct":{"alignment":"justice","min_pct":50}}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep09","nation_id":"loc_yatoshin","min_alignment_pct":{"alignment":"justice","min_pct":50}}'::jsonb,
    '{"nodes":{"start":{"text":"夜刀神国の天を覆う空が、赤黒く染まり始める。まるで血のように妖しく輝く月が昇る、百年に一度の災厄「冥食」が訪れたのだ。","type":"text","bg_key":"bg_spot_yato_eclipse","bgm":"bgm_yato","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"ざわつく里の広場で、隠れ里の長老が長い白髪を夜風になびかせ、重苦しい表情であなたに近づいてきた。","type":"text","bg_key":"bg_spot_yato_eclipse","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「異界とこちらを繋ぐ『冥の門』が開こうとしておる。門を完全に封じ、この国に太陽を取り戻すには、尊き贄が必要じゃ」","type":"text","bg_key":"bg_spot_yato_eclipse","speaker_name":"隠れ里の長老","speaker":"隠れ里の長老","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「宿命の子として育てられた『撫子』を、門の最深部にある儀式の壇まで連れて行ってくれ。それが我ら里の、そしてお主の任務じゃ」","type":"text","bg_key":"bg_spot_yato_eclipse","speaker_name":"隠れ里の長老","speaker":"隠れ里の長老","next":"join_nadeshiko","choices":[{"label":"続ける","next":"join_nadeshiko"}]},"join_nadeshiko":{"text":"里の裏手の鬱蒼とした森。白い神聖な装束に身を包み、幼さの残る面持ちの少女が、静かにあなたの到着を待っていた。","type":"guest_join","bg_key":"bg_spot_yato_eclipse","params":{"guest_id":"npc_nadeshiko"},"next":"join_nadeshiko_02","choices":[{"label":"続ける","next":"join_nadeshiko_02"}]},"join_nadeshiko_02":{"text":"「……撫子と申します。冥の門の最深部まで、お供をさせていただきます」","type":"text","bg_key":"bg_spot_yato_eclipse","speaker_name":"撫子","speaker":"撫子","next":"join_nadeshiko_03","choices":[{"label":"続ける","next":"join_nadeshiko_03"}]},"join_nadeshiko_03":{"text":"「大丈夫です。贄としての覚悟は……里の皆を守るための決意は、とうにできていますから。行きましょう」","type":"text","bg_key":"bg_spot_yato_eclipse","speaker_name":"撫子","speaker":"撫子","next":"join_monologue","choices":[{"label":"続ける","next":"join_monologue"}]},"join_monologue":{"text":"（覚悟はできている、か。こんな幼い少女にそこまで背負わせる理不尽な因習が、本当に正しいというのだろうか……）","type":"text","bg_key":"bg_spot_yato_eclipse","next":"spider1_intro","choices":[{"label":"続ける","next":"spider1_intro"}]},"spider1_intro":{"text":"薄暗く不気味な妖気が渦巻く「冥の門」の入口。生暖かい風が吹き抜けた瞬間、天井から巨大な鬼蜘蛛が糸を垂らして降りてきた。","type":"text","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","next":"battle_spider_1","choices":[{"label":"続ける","next":"battle_spider_1"}]},"battle_spider_1":{"type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"310","choices":[{"label":"win","next":"spider2_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"spider2_intro"},"spider2_intro":{"text":"一匹目の残骸を越えて暗い岩道を進むと、壁や天井の至る所がざわざわと波打つように蠢き出し、さらなる群れが現れた。","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle_spider_2","choices":[{"label":"続ける","next":"battle_spider_2"}]},"battle_spider_2":{"type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"311","choices":[{"label":"win","next":"spider3_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"spider3_intro"},"spider3_intro":{"text":"倒しても倒しても、壁の無数の隙間から、赤い瞳を光らせた蜘蛛の群れが次々と這い出だして行く手を塞ぐ。","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle_spider_3","choices":[{"label":"続ける","next":"battle_spider_3"}]},"battle_spider_3":{"type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"312","choices":[{"label":"win","next":"spider4_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"spider4_intro"},"spider4_intro":{"text":"ようやく群れを突破しかけたその時、ひときわ巨大で硬質な外殻を持った、蜘蛛たちの主のような個体が立ちはだかる。","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle_spider_4","choices":[{"label":"続ける","next":"battle_spider_4"}]},"battle_spider_4":{"type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"313","choices":[{"label":"win","next":"wani_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"wani_intro"},"spider_clear_monologue":{"text":"（ふう、さすがにこれだけ群れが続くと骨が折れる。だが、撫子は怯えながらも、じっと私の背中を信じてついてきてくれているな）","type":"text","bg_key":"bg_spot_yato_entrance","next":"wani_intro","choices":[{"label":"続ける","next":"wani_intro"}]},"wani_intro":{"text":"粘着質な蜘蛛の巣を切り払い奥へ進むと、暗闇のなかに広大な地下の濁った水場が広がっているのが見えた。","type":"text","bg_key":"bg_spot_yato_entrance","next":"wani_intro_02","choices":[{"label":"続ける","next":"wani_intro_02"}]},"wani_intro_02":{"text":"水面が突如激しく波立ち、硬質な甲羅と鋭い牙を剥き出しにした巨大な魔獣「大鰐」が唸りを上げて浮上する。","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle_wani","choices":[{"label":"続ける","next":"battle_wani"}]},"battle_wani":{"type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"314","choices":[{"label":"win","next":"reward_magatama_1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"reward_magatama_1"},"reward_magatama_1":{"text":"大鰐が水底深くへと沈んでいくと、その水面から赤い光が浮かび上がる。あなたは儀式に必要な朱色の勾玉を手に入れた。","type":"reward","bg_key":"bg_spot_yato_entrance","params":{"item_id":"611"},"next":"tori_intro","choices":[{"label":"続ける","next":"tori_intro"}]},"tori_intro":{"text":"湿った水場を越えると、天井からかすかに地上の赤月光が差し込む、広大な吹き抜けの大空洞に差し掛かった。","type":"text","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","next":"tori_intro_02","choices":[{"label":"続ける","next":"tori_intro_02"}]},"tori_intro_02":{"text":"空洞の天井近くから、鋭い鳴き声と共に、凶鳥「以津真天」が撫子の小さな体を狙って急降下してきた。","type":"text","bg_key":"bg_spot_yato_entrance","next":"battle_tori","choices":[{"label":"続ける","next":"battle_tori"}]},"battle_tori":{"type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"315","choices":[{"label":"win","next":"reward_magatama_2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"reward_magatama_2"},"reward_magatama_2":{"text":"凶鳥が羽毛を散らして撃ち落とされると、その後に青く冷たい光が残された。あなたは蒼の勾玉を手に入れた。","type":"reward","bg_key":"bg_spot_yato_entrance","params":{"item_id":"612"},"next":"kuruma_intro","choices":[{"label":"続ける","next":"kuruma_intro"}]},"kuruma_intro":{"text":"狭い通路の先から、激しい轟音と共に地を穿ち、怨念の炎を身に纏った巨大な妖怪「朧車」が突進してくる。","type":"text","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","next":"kuruma_intro_02","choices":[{"label":"続ける","next":"kuruma_intro_02"}]},"kuruma_intro_02":{"text":"「気をつけてください！ あれをまともに受ければひとたまりもありません！ 壊すしかありません！」","type":"text","bg_key":"bg_spot_yato_entrance","speaker_name":"撫子","speaker":"撫子","next":"battle_kuruma","choices":[{"label":"続ける","next":"battle_kuruma"}]},"battle_kuruma":{"type":"battle","bg_key":"bg_spot_yato_entrance","bgm":"bgm_battle_strong","enemy_group_id":"316","choices":[{"label":"win","next":"reward_magatama_3"},{"label":"lose","next":"end_failure"}],"battle_success_next":"reward_magatama_3"},"reward_magatama_3":{"text":"朧車が激しい破砕音と共に粉々に砕け散り、その破片から翠色の光がこぼれ出た。あなたは翠の勾玉を手に入れた。","type":"reward","bg_key":"bg_spot_yato_entrance","params":{"item_id":"613"},"next":"shuten_intro","choices":[{"label":"続ける","next":"shuten_intro"}]},"shuten_intro":{"text":"いよいよ冥の門の最奥。古びた朱塗りの扉の前に、巨大な大盃を傍らに置き、角を持つ一人の男が不敵に座していた。","type":"text","bg_key":"bg_spot_yato_gate","bgm":"bgm_spot_final_boss","next":"shuten_intro_02","choices":[{"label":"続ける","next":"shuten_intro_02"}]},"shuten_intro_02":{"text":"「ハハッ、やっと少しは骨のある奴が来たか。贄の娘を連れて、この俺を楽しませてみせろ！」","type":"text","bg_key":"bg_spot_yato_gate","speaker_name":"酒呑童子","speaker":"酒呑童子","next":"shuten_intro_03","choices":[{"label":"続ける","next":"shuten_intro_03"}]},"shuten_intro_03":{"text":"伝説の鬼がゆっくりと立ち上がる。その全身から、息が詰まるほどの圧倒的な闘気が放たれた。","type":"text","bg_key":"bg_spot_yato_gate","next":"battle_shuten","choices":[{"label":"続ける","next":"battle_shuten"}]},"battle_shuten":{"type":"battle","bg_key":"bg_spot_yato_gate","bgm":"bgm_spot_final_boss","enemy_group_id":"317","choices":[{"label":"win","next":"reward_magatama_4"},{"label":"lose","next":"end_failure"}],"battle_success_next":"reward_magatama_4"},"reward_magatama_4":{"text":"酒呑童子が「満足したぞ……」と笑いながら闇に消え去ると、黄金色に輝く黄の勾玉が床に残された。","type":"reward","bg_key":"bg_spot_yato_gate","params":{"item_id":"614"},"next":"final_choice","choices":[{"label":"続ける","next":"final_choice"}]},"final_choice":{"text":"四つの勾玉が共鳴して強烈な光を放つと、前方に立ち塞がっていた朱塗りの巨大な扉が、重苦しい音を立ててゆっくりと開き始める。","type":"text","bg_key":"bg_spot_yato_gate","bgm":"bgm_spot_final_choice","next":"final_choice_02","choices":[{"label":"続ける","next":"final_choice_02"}]},"final_choice_02":{"text":"「……開きましたね。ここから先は、私一人で行きます。これが私の、宿命の子としてのお役目ですから」","type":"text","bg_key":"bg_spot_yato_gate","speaker_name":"撫子","speaker":"撫子","next":"final_choice_03","choices":[{"label":"続ける","next":"final_choice_03"}]},"final_choice_03":{"text":"「短い間でしたけれど、あなたに会えて本当によかった。私をここまで守ってくれて、ありがとうございました」","type":"text","bg_key":"bg_spot_yato_gate","speaker_name":"撫子","speaker":"撫子","next":"final_choice_monologue","choices":[{"label":"続ける","next":"final_choice_monologue"}]},"final_choice_monologue":{"text":"（少女の背中が、重い扉の向こうの闇へと歩み出そうとしている。このまま静かに送り出して里を救うのが、本当に冒険者としての正義なのか……？）","type":"text","bg_key":"bg_spot_yato_gate","next":"choice_node","choices":[{"label":"続ける","next":"choice_node"}]},"choice_node":{"text":"門へと進む撫子を見送るか、それともその手を掴むか。あなたは決断を迫られる。","type":"choice","bg_key":"bg_spot_yato_gate","bgm":"bgm_spot_final_choice","choices":[{"label":"儀式を完遂させる（撫子を送り出す）","next":"end_sacrifice_intro"},{"label":"因習を打ち砕く（撫子を救う）","next":"end_save_intro"}]},"end_sacrifice_intro":{"text":"あなたは拳を握りしめ、静かに彼女の背中を見送った。撫子の白い装束は、門の向こうの底知れぬ闇の中へと吸い込まれるように消え去った。","type":"text","bg_key":"bg_spot_yato_gate","bgm":"bgm_quest_calm","next":"leave_nadeshiko","choices":[{"label":"続ける","next":"leave_nadeshiko"}]},"leave_nadeshiko":{"text":"撫子がパーティから離脱した。","type":"leave","bg_key":"bg_spot_yato_gate","params":{"guest_id":"npc_nadeshiko"},"next":"end_sacrifice","choices":[{"label":"続ける","next":"end_sacrifice"}]},"end_sacrifice":{"text":"重厚な朱塗りの扉が閉まり、空には赤月が消えて平穏な太陽の光が戻った。里は救われ、長老からは感謝と共に『冥界の護符』が贈られた。しかし、あなたの心には消えない翳りが残された。","type":"end","result":"success","bg_key":"bg_spot_yato_gate","params":{"rewards":{"exp":500,"gold":10000,"reputation":200,"alignment_shift":{"order":5}}},"choices":[]},"end_save_intro":{"text":"あなたは門に足を踏み入れようとした撫子の手を強く掴み、引き戻した。そして、手にした武器を振るい、開いた門の結界を強引に破壊した。","type":"text","bg_key":"bg_spot_yato_gate","bgm":"bgm_quest_calm","next":"end_save","choices":[{"label":"続ける","next":"end_save"}]},"end_save":{"text":"「え……？ あ、ああっ……」と撫子は驚き、あなたの胸で声を上げて泣いた。門は閉ざされ、国は太陽を失う危機に直面するが、あなたは一人の少女の命を救い、固有スキル『冥食の理』を手に入れた！","type":"end","result":"success","bg_key":"bg_spot_yato_gate","params":{"rewards":{"exp":500,"reputation":-100,"skills":[3072],"alignment_shift":{"order":5}}},"choices":[]},"end_failure":{"text":"奈落の闇の中に倒れ伏す。周囲を取り囲む妖怪たちの嘲笑が遠のいていく中、必死にあなたの名前を呼ぶ撫子の泣き声に応える力は、もう残されていなかった。","type":"end","result":"failure","bg_key":"bg_spot_yato_entrance","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"夜刀スポット: 冥食の夜。生贄の少女を護衛し冥の門の四大妖怪を退けよ。"}'::jsonb,
    7,
    3
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
