    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6103: 天を衝く塔 (qst_spot_karyu)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6103,
    'qst_spot_karyu',
    '天を衝く塔',
    '華龍スポット: 霊山に虚無の塔が出現。四神を退け頂の神に挑め。',
    '地方太守',
    5,
    20,
    7,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep12","nation_id":"loc_haryu","min_alignment_pct":{"alignment":"evil","min_pct":50}}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep12","nation_id":"loc_haryu","min_alignment_pct":{"alignment":"evil","min_pct":50}}'::jsonb,
    '{"nodes":{"start":{"text":"華龍神朝の都の外れ、荒涼とした大地にそびえ立つ。雲を突き抜けて天へと伸びる巨塔の前に、盲目の老人が静かに佇んでいた。","type":"text","bg_key":"bg_spot_karyu_tower","bgm":"bgm_karyu","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「あの塔の頂上には、あらゆる願いを叶える楽園があるとされる。だが、挑んだ者は誰一人として生きて戻ってこない」","type":"text","bg_key":"bg_spot_karyu_tower","speaker_name":"天命の使者","speaker":"天命の使者","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「塔を封じる強固な結界を解くには、華龍の四方に座す青龍、白虎、朱雀、玄武の四神を全て討ち破らねばならぬ」","type":"text","bg_key":"bg_spot_karyu_tower","speaker_name":"天命の使者","speaker":"天命の使者","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「すべては、天の頂きで退屈を貪る『あれ』が仕掛けた、残酷な遊戯に過ぎんのだよ……」","type":"text","bg_key":"bg_spot_karyu_tower","speaker_name":"天命の使者","speaker":"天命の使者","next":"start_monologue","choices":[{"label":"続ける","next":"start_monologue"}]},"start_monologue":{"text":"（神の仕掛けた遊戯、か。神獣たちを討ち払わねば上へは登れんというわけだな。受けて立とう、その神とやらの面を拝みにな！）","type":"text","bg_key":"bg_spot_karyu_tower","next":"choose_path","choices":[{"label":"続ける","next":"choose_path"}]},"choose_path":{"text":"そびえ立つ塔の足元。結界を解くため、まずはどの神獣の試練へと向かうべきだろうか。","type":"choice","bg_key":"bg_spot_karyu_tower","bgm":"bgm_quest_mystery","choices":[{"label":"東の青龍","next":"trap_seiryu"},{"label":"西の白虎","next":"trap_byakko"},{"label":"南の朱雀","next":"trap_suzaku"},{"label":"北の玄武","next":"trap_genbu"},{"label":"中央の塔へ進む","next":"check_orbs"}]},"trap_seiryu":{"text":"東の荒野を進むと、突如暗雲が立ち込め、天から巨大な落雷があなたを直撃した。激しい衝撃が全身を貫き、HPにダメージを受ける。","type":"hp_damage","bg_key":"bg_spot_karyu_thunder","params":{"hp_percent":-20,"percent":-20},"next":"boss_seiryu","choices":[{"label":"続ける","next":"boss_seiryu"}]},"boss_seiryu":{"text":"激しく渦巻く雷雲の中から、青く輝く鱗と長い髭を持つ、畏怖の巨龍・青龍がその巨躯を現した。","type":"text","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","next":"boss_seiryu_02","choices":[{"label":"続ける","next":"boss_seiryu_02"}]},"boss_seiryu_02":{"text":"「……千年も同じ番をし続けて、退屈極まっていたのだ。我を楽しませ、その命の輝きを見せてみよ！」","type":"text","bg_key":"bg_spot_karyu_thunder","speaker_name":"青龍","speaker":"青龍","next":"battle_seiryu","choices":[{"label":"続ける","next":"battle_seiryu"}]},"battle_seiryu":{"type":"battle","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","enemy_group_id":"320","choices":[{"label":"win","next":"reward_orb_1"},{"label":"lose","next":"end_failure"}],"battle_success_next":"reward_orb_1"},"reward_orb_1":{"text":"激闘の末、雷鳴が収まり青龍が崩れ去る。あなたは蒼く強く輝く『青龍の宝珠』を手に入れた。","type":"reward","bg_key":"bg_spot_karyu_thunder","params":{"item_id":"621"},"next":"post_seiryu_monologue","choices":[{"label":"続ける","next":"post_seiryu_monologue"}]},"post_seiryu_monologue":{"text":"（雷を司る東の青龍を討ったか。宝珠から凄まじい力が流れ込んでくる。残る神獣はあと三体だな）","type":"text","bg_key":"bg_spot_karyu_thunder","next":"final_choice_02","choices":[{"label":"続ける","next":"final_choice_02"}]},"trap_byakko":{"text":"西の険しい山道に踏み入ると、猛烈な吹雪が吹き荒れ、厳しい凍傷があなたを襲った。全身の感覚が麻痺し、HPにダメージを受ける。","type":"hp_damage","bg_key":"bg_spot_karyu_thunder","params":{"hp_percent":-20,"percent":-20},"next":"boss_byakko","choices":[{"label":"続ける","next":"boss_byakko"}]},"boss_byakko":{"text":"立ち込める白い雪煙を切り裂き、鋭い白銀の牙と漆黒の紋様を持つ、俊敏なる獣王・白虎が姿を現した。","type":"text","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","next":"boss_byakko_02","choices":[{"label":"続ける","next":"boss_byakko_02"}]},"boss_byakko_02":{"text":"「我らの闘争に、無駄な言葉は要らぬ。その肉を牙で引き裂き、どちらが強者かを語るのが我の流儀だ！」","type":"text","bg_key":"bg_spot_karyu_thunder","speaker_name":"白虎","speaker":"白虎","next":"battle_byakko","choices":[{"label":"続ける","next":"battle_byakko"}]},"battle_byakko":{"type":"battle","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","enemy_group_id":"321","choices":[{"label":"win","next":"reward_orb_2"},{"label":"lose","next":"end_failure"}],"battle_success_next":"reward_orb_2"},"reward_orb_2":{"text":"白虎の猛攻を凌ぎ切り、その巨躯を討ち果たす。雪煙が消え去った跡に、白く鋭く輝く『白虎の宝珠』が残された。","type":"reward","bg_key":"bg_spot_karyu_thunder","params":{"item_id":"622"},"next":"post_byakko_monologue","choices":[{"label":"続ける","next":"post_byakko_monologue"}]},"post_byakko_monologue":{"text":"（これで西の白虎を倒した。凄まじい闘志を秘めた宝珠だ。体が熱く滾ってくるのを感じるぞ）","type":"text","bg_key":"bg_spot_karyu_thunder","next":"final_choice_02","choices":[{"label":"続ける","next":"final_choice_02"}]},"trap_suzaku":{"text":"南の火山地帯へ向かうと、足元の亀裂から火柱が吹き上がり、業火があなたを包み込んだ。激しい熱風に焼かれ、HPにダメージを受ける。","type":"hp_damage","bg_key":"bg_spot_karyu_thunder","params":{"hp_percent":-20,"percent":-20},"next":"boss_suzaku","choices":[{"label":"続ける","next":"boss_suzaku"}]},"boss_suzaku":{"text":"揺らめく陽炎の奥底から、青い神聖な炎を全身に灯した、美しくも恐ろしい不死鳥・朱雀が優雅に舞い降りてきた。","type":"text","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","next":"boss_suzaku_02","choices":[{"label":"続ける","next":"boss_suzaku_02"}]},"boss_suzaku_02":{"text":"「消えぬ命、尽きぬ炎は重い呪い。お主の刃が、この退屈な輪廻から我を消し去ってくれることを願うよ」","type":"text","bg_key":"bg_spot_karyu_thunder","speaker_name":"朱雀","speaker":"朱雀","next":"battle_suzaku","choices":[{"label":"続ける","next":"battle_suzaku"}]},"battle_suzaku":{"type":"battle","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","enemy_group_id":"322","choices":[{"label":"win","next":"reward_orb_3"},{"label":"lose","next":"end_failure"}],"battle_success_next":"reward_orb_3"},"reward_orb_3":{"text":"激しい炎の舞を退け、朱雀を灰へと還す。その静寂の中に、紅く温かく輝く『朱雀の宝珠』が現れた。","type":"reward","bg_key":"bg_spot_karyu_thunder","params":{"item_id":"623"},"next":"post_suzaku_monologue","choices":[{"label":"続ける","next":"post_suzaku_monologue"}]},"post_suzaku_monologue":{"text":"（南の朱雀の魂を解放したか。彼らにとって、この試練の番人であることは苦痛でしかなかったようだな）","type":"text","bg_key":"bg_spot_karyu_thunder","next":"final_choice_02","choices":[{"label":"続ける","next":"final_choice_02"}]},"trap_genbu":{"text":"北の湿地帯。激しい地響きと共に崩落した巨大な岩片が頭上から降り注ぎ、あなたの身体を打ち据え、HPにダメージを受ける。","type":"hp_damage","bg_key":"bg_spot_karyu_thunder","params":{"hp_percent":-20,"percent":-20},"next":"boss_genbu","choices":[{"label":"続ける","next":"boss_genbu"}]},"boss_genbu":{"text":"盛り上がった泥土を突き破り、蛇の尾を背負い、巨大な甲羅を持つ大地の巨亀・玄武が重苦しく現れた。","type":"text","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","next":"boss_genbu_02","choices":[{"label":"続ける","next":"boss_genbu_02"}]},"boss_genbu_02":{"text":"「神の遊戯に対する恨みはあるが、我らは結界を守る番人。手加減はできぬ、全力で参るぞ！」","type":"text","bg_key":"bg_spot_karyu_thunder","speaker_name":"玄武","speaker":"玄武","next":"battle_genbu","choices":[{"label":"続ける","next":"battle_genbu"}]},"battle_genbu":{"type":"battle","bg_key":"bg_spot_karyu_thunder","bgm":"bgm_battle_strong","enemy_group_id":"323","choices":[{"label":"win","next":"reward_orb_4"},{"label":"lose","next":"end_failure"}],"battle_success_next":"reward_orb_4"},"reward_orb_4":{"text":"堅牢な守りを破り、玄武の甲羅を打ち砕く。崩れ去る大地の底から、深い緑色をした『玄武の宝珠』を手に入れた。","type":"reward","bg_key":"bg_spot_karyu_thunder","params":{"item_id":"624"},"next":"post_genbu_monologue","choices":[{"label":"続ける","next":"post_genbu_monologue"}]},"post_genbu_monologue":{"text":"（これで青龍、白虎、朱雀、玄武、すべての四神を討ち取った。中央の塔の結界が完全に解けたはずだ）","type":"text","bg_key":"bg_spot_karyu_thunder","next":"final_choice_02","choices":[{"label":"続ける","next":"final_choice_02"}]},"check_orbs":{"text":"四神の宝珠がすべて揃っているかを確認する。","type":"check_flags","bg_key":"bg_spot_karyu_tower","choices":[]},"kami_intro":{"text":"塔の最上階。黄金の碁盤を前に、静かに座っている十歳ほどの無垢な瞳をした少年がいた。彼こそが、この塔の支配者であった。","type":"text","bg_key":"bg_spot_karyu_throne","bgm":"bgm_spot_final_boss","next":"kami_intro_02","choices":[{"label":"続ける","next":"kami_intro_02"}]},"kami_intro_02":{"text":"「やっとここまで来たか、旅人よ。千年もこうして一人で碁を打つのに、すっかり飽き果てていたのだ」","type":"text","bg_key":"bg_spot_karyu_throne","speaker_name":"神の少年","speaker":"神の少年","next":"kami_intro_03","choices":[{"label":"続ける","next":"kami_intro_03"}]},"kami_intro_03":{"text":"「今まで楽園を夢見て登ってきた者は、全員途中で死んだ。お前は、俺をこの退屈から救い出してくれるか？」","type":"text","bg_key":"bg_spot_karyu_throne","speaker_name":"神の少年","speaker":"神の少年","next":"kami_intro_04","choices":[{"label":"続ける","next":"kami_intro_04"}]},"kami_intro_04":{"text":"そう微笑む少年の全身から、空間そのものを歪めるほどの圧倒的で冷酷な神威が放たれ、塔が激しく震えだす。","type":"text","bg_key":"bg_spot_karyu_throne","next":"battle_kami","choices":[{"label":"続ける","next":"battle_kami"}]},"battle_kami":{"type":"battle","bg_key":"bg_spot_karyu_throne","bgm":"bgm_spot_final_boss","enemy_group_id":"324","choices":[{"label":"win","next":"final_choice"},{"label":"lose","next":"end_failure"}],"battle_success_next":"final_choice"},"final_choice":{"text":"激闘の果てに少年は膝をつき、「負けるのも、悪くない棋譜だった……」と満足そうに微笑み、光となって消え去っていった。","type":"text","bg_key":"bg_spot_karyu_throne","bgm":"bgm_spot_final_choice","next":"final_choice_02","choices":[{"label":"続ける","next":"final_choice_02"}]},"final_choice_02":{"text":"「さあ、この力を手に入れて新たな神の代理人として世界を統べるか、それとも塔ごとすべてを破壊し去るか、選ぶといい」","type":"text","bg_key":"bg_spot_karyu_throne","speaker_name":"神の少年の残響","speaker":"神の少年の残響","next":"final_choice_monologue","choices":[{"label":"続ける","next":"final_choice_monologue"}]},"final_choice_monologue":{"text":"（神の座を継ぎ秩序を統べるか、あるいは神の理そのものを破壊して人間として自由に生きるか……。運命の選択だな）","type":"text","bg_key":"bg_spot_karyu_throne","next":"choice_node","choices":[{"label":"続ける","next":"choice_node"}]},"choice_node":{"text":"神が残した最後の問い。あなたはどの未来を選択するだろうか。","type":"choice","bg_key":"bg_spot_karyu_throne","bgm":"bgm_spot_final_choice","choices":[{"label":"神の代理人として統べる","next":"end_rule"},{"label":"神の理を破壊し自由を掴む","next":"end_destroy"}]},"end_rule":{"text":"あなたは少年の残した光の座を受け入れ、静かに王座へと腰掛けた。その瞬間、世界中の全ての生命の鼓動が脳裏に流れ込んでくる。","type":"text","bg_key":"bg_spot_karyu_throne","bgm":"bgm_quest_calm","next":"end_rule_02","choices":[{"label":"続ける","next":"end_rule_02"}]},"end_rule_02":{"text":"世界の秩序を維持する神の代理人としての重き宿命を引き受け、あなたは神の力を宿した『天道の薙刀』を手に入れた。","type":"end","result":"success","bg_key":"bg_spot_karyu_throne","params":{"rewards":{"exp":500,"gold":10000,"reputation":200}},"choices":[]},"end_destroy":{"text":"あなたは黄金の碁盤を力任せに粉砕し、神の王座を破壊した。塔の結界が完全に崩壊し、崩れ落ちる巨塔から地上へと必死に脱出する。","type":"text","bg_key":"bg_spot_karyu_throne","bgm":"bgm_quest_calm","next":"end_destroy_02","choices":[{"label":"続ける","next":"end_destroy_02"}]},"end_destroy_02":{"text":"背後で音を立てて崩壊する巨塔を見つめながら、あなたは神の支配から抜け出し、人間の自由と固有スキル『神殺しの光芒』を手に入れた。","type":"end","result":"success","bg_key":"bg_spot_karyu_tower","params":{"rewards":{"exp":500,"reputation":-100}},"choices":[]},"end_failure":{"text":"神の圧倒的な力に押し潰され、あなたは冷たい石畳の上に力なく倒れ伏した。薄れゆく意識の中、少年の冷ややかな嘲笑が響き渡る。\n「やはり、退屈しのぎにもならなかったな。次の挑戦者を待つとしよう」","type":"end","result":"failure","bg_key":"bg_spot_karyu_throne","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"華龍スポット: 霊山に虚無の塔が出現。四神を退け頂の神に挑め。"}'::jsonb,
    7,
    3
