-- Scenario 6104: 黄金の沈黙 (qst_spot_markand)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6104,
    'qst_spot_markand',
    '黄金の沈黙',
    'マルカンドスポット: 禁忌の王墓が出現。罠と守護者を越え無名王の呪いを断て。',
    '交易商会',
    5,
    20,
    7,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep10","nation_id":"loc_marcund","min_alignment_pct":{"alignment":"chaos","min_pct":50}}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep10","nation_id":"loc_marcund","min_alignment_pct":{"alignment":"chaos","min_pct":50}}'::jsonb,
    '{"nodes":{"start":{"text":"マルカンドの活気ある市場。そこで突如、人々の肌が砂のように崩れ落ちる奇病「砂の病」が発生し、恐怖が広がっていた。","type":"text","bg_key":"bg_spot_markand_ruins","bgm":"bgm_markand","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"喧騒の冷めやらぬ酒場の片隅。砂漠の歴史を知る語り部の老人が、砂嵐の彼方に眠る廃墟を指差した。","type":"text","bg_key":"bg_spot_markand_ruins","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「この病の源は、三千年前に封印された無名王の王墓にある。不可視の呪いを解かねば、誰も生きて戻れんぞ」","type":"text","bg_key":"bg_spot_markand_ruins","speaker_name":"砂漠の語り部","speaker":"砂漠の語り部","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"人々の命を救い、奇病の元凶を断つため、あなたは手がかりを胸に禁忌の墓所へと足を踏み入れた。","type":"text","bg_key":"bg_spot_markand_ruins","next":"start_monologue","choices":[{"label":"続ける","next":"start_monologue"}]},"start_monologue":{"text":"（砂の病か……。三千年前の呪いが今になって活性化したのには何か理由があるはず。罠に気をつけながら進むとしよう）","type":"text","bg_key":"bg_spot_markand_ruins","next":"trap_01","choices":[{"label":"続ける","next":"trap_01"}]},"trap_01":{"text":"第一の試練。「鏡の間」。薄暗い石室の中央に、それぞれ異なる姿勢をとった三体の不気味な石像が並び立っている。","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","next":"trap_01_02","choices":[{"label":"続ける","next":"trap_01_02"}]},"trap_01_02":{"text":"石壁には「太陽はどの姿を照らすか。姿を誤れば、鏡の牙が汝を切り裂く」と太古の文字が刻まれていた。","type":"text","bg_key":"bg_spot_markand_mirror","next":"choice_trap_01","choices":[{"label":"続ける","next":"choice_trap_01"}]},"choice_trap_01":{"text":"どの石像を選ぶべきか。足元には、過去に罠にかかったと思われる多くの白骨が散らばっている。","type":"choice","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","choices":[{"label":"目を伏せた像（謙譲）","next":"trap_02"},{"label":"両手を広げた像（傲慢）","next":"battle_trap_01_intro"}]},"battle_trap_01_intro":{"text":"傲慢の像に触れた瞬間、壁の巨大な鏡が怪しく歪み、中からあなたと全く同じ姿と能力を持った光の幻影が現れて襲いかかってきた。","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","next":"battle_trap_01","choices":[{"label":"続ける","next":"battle_trap_01"}]},"battle_trap_01":{"type":"battle","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","enemy_group_id":"330","choices":[{"label":"win","next":"trap_02"},{"label":"lose","next":"end_failure"}],"battle_success_next":"trap_02"},"trap_02":{"text":"第二の試練。「秤の間」。奥へと続く扉の前に、天をも支えるような意匠の施された、巨大な黄金の天秤が設置されている。","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","next":"trap_02_02","choices":[{"label":"続ける","next":"trap_02_02"}]},"trap_02_02":{"text":"壁の銘板には「汝が手に持つ、最も重き物を天秤に乗せよ」とあり、傍らにはいくつかの箱が置かれていた。","type":"text","bg_key":"bg_spot_markand_mirror","next":"choice_trap_02","choices":[{"label":"続ける","next":"choice_trap_02"}]},"choice_trap_02":{"text":"どの箱を天秤に乗せるべきか。最も多くの死者の骨が転がっているのは、煌びやかな宝石の箱の前である。","type":"choice","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","choices":[{"label":"空の箱を選ぶ（沈黙）","next":"trap_03"},{"label":"宝石の箱を選ぶ（欲望）","next":"battle_trap_02_intro"}]},"battle_trap_02_intro":{"text":"宝石の箱を天秤に乗せた瞬間、激しい不協和音と共に箱から呪われた砂が噴き出し、強大な砂のゴーレムとなって襲いかかった。","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","next":"battle_trap_02","choices":[{"label":"続ける","next":"battle_trap_02"}]},"battle_trap_02":{"type":"battle","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","enemy_group_id":"331","choices":[{"label":"win","next":"trap_03"},{"label":"lose","next":"end_failure"}],"battle_success_next":"trap_03"},"trap_03":{"text":"第三の試練。「棺の間」。部屋の中央に置かれた空の王棺の蓋に、文字が刻まれている。","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","next":"trap_03_02","choices":[{"label":"続ける","next":"trap_03_02"}]},"trap_03_02":{"text":"「永久に消え去る王に、汝が捧げるべき真の言葉は何か」とあり、壁には二つの石造りのボタンが用意されていた。","type":"text","bg_key":"bg_spot_markand_mirror","next":"choice_trap_03","choices":[{"label":"続ける","next":"choice_trap_03"}]},"choice_trap_03":{"text":"壁の選択肢を見つめる。無名王は自身の存在が風化し、世界から「忘れ去られること」を恐れて呪いをかけたと言われている。","type":"choice","bg_key":"bg_spot_markand_mirror","bgm":"bgm_quest_mystery","choices":[{"label":"「忘却」を選ぶ（真実）","next":"boss_king_intro"},{"label":"「称賛」を選ぶ（偽り）","next":"battle_trap_03_intro"}]},"battle_trap_03_intro":{"text":"「称賛」のボタンを押した瞬間、棺の蓋が跳ね飛び、朽ち果てた大剣と盾を手にした二体の凶悪な骸骨衛兵が這い出してきた。","type":"text","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","next":"battle_trap_03","choices":[{"label":"続ける","next":"battle_trap_03"}]},"battle_trap_03":{"type":"battle","bg_key":"bg_spot_markand_mirror","bgm":"bgm_battle_strong","enemy_group_id":"332","choices":[{"label":"win","next":"boss_king_intro"},{"label":"lose","next":"end_failure"}],"battle_success_next":"boss_king_intro"},"boss_king_intro":{"text":"すべての罠を潜り抜けた最深部。眩いばかりの黄金に彩られた広間の玉座で、三千年間沈黙していたミイラ化した王がゆっくりと動き出した。","type":"text","bg_key":"bg_spot_markand_king","bgm":"bgm_spot_final_boss","next":"boss_king_intro_02","choices":[{"label":"続ける","next":"boss_king_intro_02"}]},"boss_king_intro_02":{"text":"「……三千年だ。この暗闇の玉座で、俺の名を呼び、俺を記憶する者が現れるのを、ずっと待っていた」","type":"text","bg_key":"bg_spot_markand_king","speaker_name":"砂王","speaker":"砂王","next":"boss_king_intro_03","choices":[{"label":"続ける","next":"boss_king_intro_03"}]},"boss_king_intro_03":{"text":"「俺の帝国も名も歴史から完全に忘れ去られた。だから俺は、俺を忘れた世界を、民を、この砂の病で呪ったのだ！」","type":"text","bg_key":"bg_spot_markand_king","speaker_name":"砂王","speaker":"砂王","next":"boss_king_intro_04","choices":[{"label":"続ける","next":"boss_king_intro_04"}]},"boss_king_intro_04":{"text":"ミイラの全身に黄金の砂の鎧が激しい音を立てて形成され、巨大な黄金の広間全体がその怒りによって震え出す。","type":"text","bg_key":"bg_spot_markand_king","next":"battle_king","choices":[{"label":"続ける","next":"battle_king"}]},"battle_king":{"type":"battle","bg_key":"bg_spot_markand_king","bgm":"bgm_spot_final_boss","enemy_group_id":"333","choices":[{"label":"win","next":"final_choice"},{"label":"lose","next":"end_failure"}],"battle_success_next":"final_choice"},"final_choice":{"text":"激闘の末、砂王の巨躯は崩れ去り、静かに砂へと還った。しかし、玉座の跡地には、呪いの核である眩く輝く「王の心臓」たる宝石が不気味に明滅している。","type":"text","bg_key":"bg_spot_markand_king","bgm":"bgm_spot_final_choice","next":"final_choice_02","choices":[{"label":"続ける","next":"final_choice_02"}]},"final_choice_02":{"text":"「その宝石を破壊すれば呪いは消える。だが、それを飲み干せば、我が三千年の知恵と砂の魔力が、お前の肉体に宿るだろう……」","type":"text","bg_key":"bg_spot_markand_king","speaker_name":"砂王の残響","speaker":"砂王の残響","next":"choice_node","choices":[{"label":"続ける","next":"choice_node"}]},"choice_node":{"text":"不気味に脈打つ王の心臓を前に、あなたはこの呪いをどう処理するべきか、選択を迫られる。","type":"choice","bg_key":"bg_spot_markand_king","bgm":"bgm_spot_final_choice","choices":[{"label":"心臓を破壊し呪いを断つ","next":"end_break"},{"label":"心臓を宿し呪いを制御する","next":"end_curse"}]},"end_break":{"text":"あなたは躊躇なく黒い宝石を踏み砕いた。甲高い破砕音と共に心臓は粉々になり、王墓を満たしていた不可視の呪いと淀んだ魔力は完全に消え去った。","type":"text","bg_key":"bg_spot_markand_king","bgm":"bgm_quest_calm","next":"end_break_02","choices":[{"label":"続ける","next":"end_break_02"}]},"end_break_02":{"text":"地上へと帰還すると、市場の病人たちは砂の病から完全に回復しており、語り部の老人が安堵の笑みを浮かべてあなたを出迎えた。","type":"text","bg_key":"bg_spot_markand_ruins","next":"end_break_03","choices":[{"label":"続ける","next":"end_break_03"}]},"end_break_03":{"text":"無名王の名は完全に歴史から消え去ったが、あなたの偉業を称え、ギルドから『砂王の断罪刃』を授けられた。","type":"end","result":"success","bg_key":"bg_spot_markand_ruins","params":{"rewards":{"exp":500,"gold":10000,"reputation":200}},"choices":[]},"end_curse":{"text":"あなたは宝石を口に含み、一気に飲み干した。その瞬間、三千年の年月がもたらした膨大な知恵と、狂気のような渇きの呪いが、体中を駆け巡って定着していく。","type":"text","bg_key":"bg_spot_markand_king","bgm":"bgm_quest_calm","next":"end_curse_02","choices":[{"label":"続ける","next":"end_curse_02"}]},"end_curse_02":{"text":"王墓を後にしたあなたの腕には、砂王の紋章が怪しく浮かび上がっていた。人々はその異様な雰囲気を察し、あなたを恐れ避けるようになった。","type":"text","bg_key":"bg_spot_markand_king","next":"end_curse_03","choices":[{"label":"続ける","next":"end_curse_03"}]},"end_curse_03":{"text":"砂の病の力を自身の意志で完全に制御下に置き、あなたは固有スキル『砂塵の支配』を手に入れた。","type":"end","result":"success","bg_key":"bg_spot_markand_ruins","params":{"rewards":{"exp":500,"reputation":-100}},"choices":[]},"end_failure":{"text":"激しい砂の嵐に呑み込まれ、息が詰まる。薄れゆく意識の奥で、無名王の寂しげな呟きが冷たく木霊した。\n「やはり、お前も他の有象無象と同様に……俺を忘れ去るのだな……」","type":"end","result":"failure","bg_key":"bg_spot_markand_king","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"マルカンドスポット: 禁忌の王墓が出現。罠と守護者を越え無名王の呪いを断て。"}'::jsonb,
    7,
    3
) ON CONFLICT (id) DO UPDATE SET
