    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 5101: 墓荒らしの退治 (qst_rep_graverobber)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5101,
    'qst_rep_graverobber',
    '墓荒らしの退治',
    '[指名依頼] 聖墓地を荒らす盗掘団を追い払え。遺品の返還も任務に含む。',
    '聖堂騎士団',
    2,
    5,
    3,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep01","min_reputation":10,"nation_id":"loc_roland"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep01","min_reputation":10,"nation_id":"loc_roland"}'::jsonb,
    '{"nodes":{"start":{"text":"「冒険者よ、聖堂騎士団からの指名依頼だ。聖墓地が盗掘団に荒らされている」","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","speaker_name":"聖堂騎士","speaker":"聖堂騎士","next":"start_01_02","choices":[{"label":"続ける","next":"start_01_02"}]},"start_01_02":{"text":"聖堂の厳かな空気の中に、騎士の重苦しいため息が静かに響いた。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「眠れる騎士たちの遺品が次々と盗まれ、闇市に流れている」","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","speaker_name":"聖堂騎士","speaker":"聖堂騎士","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（聖なる墓を暴き、死者の眠りを妨げるか。許しがたい暴挙だな）","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「盗掘団を排除し、盗まれた遺品を回収してほしい」","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","speaker_name":"聖堂騎士","speaker":"聖堂騎士","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"「死者の尊厳を守るためだ。どうか手を貸してくれ」","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","speaker_name":"聖堂騎士","speaker":"聖堂騎士","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"死者の安らぎを乱す不届き者か。墓地へ向かおう。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"聖都郊外の丘を越えると、広大な聖墓地が見えてきた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"重く立ち込める雲の下、無数の白い墓標が静まり返っている。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"墓地に近づくと、掘り返された墓穴がいくつも目に入る。ひどい有様だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"travel_02_02","choices":[{"label":"続ける","next":"travel_02_02"}]},"travel_02_02":{"text":"（土がまだ新しい。奴らは今もこの墓地のどこかに潜んでいるはずだ）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"graveyard_01","choices":[{"label":"続ける","next":"graveyard_01"}]},"graveyard_01":{"text":"盗掘団は地下納骨堂に拠点を構えているらしい。入り口は二つある。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"graveyard_02","choices":[{"label":"続ける","next":"graveyard_02"}]},"graveyard_02":{"text":"正面の大扉か、裏手の崩れた壁の隙間か。どちらから入る？","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"choice_approach","choices":[{"label":"続ける","next":"choice_approach"}]},"choice_approach":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_tense","choices":[{"label":"「正面から堂々と乗り込む」","next":"front_01"},{"label":"「裏手の崩れた壁から忍び込む」","next":"back_01"}]},"front_01":{"text":"大扉を蹴り開けて突入する！ 中にいた見張りの盗掘者が武器を取った！","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"front_01_02","choices":[{"label":"続ける","next":"front_01_02"}]},"front_01_02":{"text":"薄暗い石造りの大廊下に、金属音がけたたましく響き渡る。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle","enemy_group_id":"101","choices":[{"label":"win","next":"merge_inner"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"merge_inner"},"back_01":{"text":"崩れた壁の隙間に身を滑り込ませる。暗く狭い通路が続いている……。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"back_01_02","choices":[{"label":"続ける","next":"back_01_02"}]},"back_01_02":{"text":"（音を立てるな。闇に紛れて、奴らの背後を執るんだ）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"back_random","choices":[{"label":"続ける","next":"back_random"}]},"back_random":{"type":"random_branch","bg_key":"bg_crypt","prob":60,"choices":[{"label":"success","next":"back_success"},{"label":"failure","next":"back_fail"}]},"back_success":{"text":"誰にも見つからず、納骨堂の内部に潜入できた。奥から声が聞こえる。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"back_success_02","choices":[{"label":"続ける","next":"back_success_02"}]},"back_success_02":{"text":"（どうやら気づかれずに済んだな。声のする方へ進もう）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"merge_inner","choices":[{"label":"続ける","next":"merge_inner"}]},"back_fail":{"text":"足元の瓦礫を踏んでしまった！ 崩れた天井から石が降ってくる！","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"back_trap","choices":[{"label":"続ける","next":"back_trap"}]},"back_trap":{"text":"落石で傷を負ったが、なんとか通路を抜けた。","type":"hp_damage","bg_key":"bg_crypt","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"back_trap_02","choices":[{"label":"続ける","next":"back_trap_02"}]},"back_trap_02":{"text":"（くそ、不覚を取った。だが騒ぎにはなっていないようだ）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"merge_inner","choices":[{"label":"続ける","next":"merge_inner"}]},"merge_inner":{"text":"納骨堂の奥に進むと、松明の明かりに照らされた広間に出た。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"merge_inner_02","choices":[{"label":"続ける","next":"merge_inner_02"}]},"merge_inner_02":{"text":"カビと埃の臭いに混じり、腐肉の不快な臭いが鼻をつく。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"inner_01","choices":[{"label":"続ける","next":"inner_01"}]},"inner_01":{"text":"石棺がこじ開けられ、中の副葬品が乱雑に袋に詰め込まれている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"inner_01_02","choices":[{"label":"続ける","next":"inner_01_02"}]},"inner_01_02":{"text":"無残に暴かれた歴史の遺産が、薄汚れた布袋に詰め込まれている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"inner_02","choices":[{"label":"続ける","next":"inner_02"}]},"inner_02":{"text":"広間の奥に、仲間に指示を出している大柄な男がいる。頭目だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"inner_02_02","choices":[{"label":"続ける","next":"inner_02_02"}]},"inner_02_02":{"text":"（あいつが頭目か。死者を冒涜した罪、その身で償ってもらう）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"boss_intro_01","choices":[{"label":"続ける","next":"boss_intro_01"}]},"boss_intro_01":{"text":"「なんだ、テメェは！ 騎士団の犬か！？」","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"盗掘団の頭目","speaker":"盗掘団の頭目","next":"boss_intro_02","choices":[{"label":"続ける","next":"boss_intro_02"}]},"boss_intro_02":{"text":"「死人の持ち物に用はねえだろ！ ここは俺たちの縄張りだ！」","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"盗掘団の頭目","speaker":"盗掘団の頭目","next":"boss_intro_02_02","choices":[{"label":"続ける","next":"boss_intro_02_02"}]},"boss_intro_02_02":{"text":"頭目は抜身の大剣を担ぎ、獰猛な笑みを浮かべてこちらを睨みつけた。","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle_boss","enemy_group_id":"9101","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"頭目が呻き声を上げて倒れ伏すと、手下たちは一斉に逃げ出した。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"静まり返った納骨堂に、自分の荒い呼吸の音だけが響いている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"盗まれた遺品の山を発見した。金銀の装飾品や古い勲章が大量にある。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_02_02","choices":[{"label":"続ける","next":"victory_02_02"}]},"victory_02_02":{"text":"（どれも歴史ある貴重な品だ。さて、これをどう処理するか……）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_calm","choices":[{"label":"「すべて騎士団に返還する。それが正しい」","next":"fate_order_01"},{"label":"「一部を懐に入れてから報告する」","next":"fate_evil_01"}]},"fate_order_01":{"text":"遺品をすべて聖堂騎士団に引き渡した。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"fate_order_01_02","choices":[{"label":"続ける","next":"fate_order_01_02"}]},"fate_order_01_02":{"text":"騎士団の聖堂へと運び込まれた遺品は、厳かに並べ直された。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"fate_order_02","choices":[{"label":"続ける","next":"fate_order_02"}]},"fate_order_02":{"text":"「見事だ。死者たちも安らかに眠れるだろう。感謝する」","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","speaker_name":"聖堂騎士","speaker":"聖堂騎士","next":"fate_order_02_02","choices":[{"label":"続ける","next":"fate_order_02_02"}]},"fate_order_02_02":{"text":"騎士は深く頭を下げた。その顔には、安堵の表情が浮かんでいた。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"end_success_order","choices":[{"label":"続ける","next":"end_success_order"}]},"end_success_order":{"text":"依頼達成。正しき行いは、確かな信頼となって返ってきた。","type":"end","result":"success","bg_key":"bg_church","params":{"rewards":{"gold":500,"exp":80,"reputation":3,"alignment_shift":{"order":3}}},"choices":[]},"fate_evil_01":{"text":"金目のものをいくつか懐に忍ばせ、残りだけを騎士団に返却した。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_mystery","next":"fate_evil_01_02","choices":[{"label":"続ける","next":"fate_evil_01_02"}]},"fate_evil_01_02":{"text":"（これくらいなら誰も気づくまい。死者にはもう不要なものだ）","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_mystery","next":"fate_evil_02","choices":[{"label":"続ける","next":"fate_evil_02"}]},"fate_evil_02":{"text":"裏路地の質屋で遺品を換金した。騎士団は気づいていないようだ。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_mystery","next":"fate_evil_02_02","choices":[{"label":"続ける","next":"fate_evil_02_02"}]},"fate_evil_02_02":{"text":"手に入った金貨の重みが、懐で重く、しかし心地よく揺れる。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_mystery","next":"end_success_evil","choices":[{"label":"続ける","next":"end_success_evil"}]},"end_success_evil":{"text":"依頼達成。死者の遺品で私腹を肥やした。罪悪感はいつか薄れるだろう。","type":"end","result":"success","bg_key":"bg_slums","params":{"rewards":{"gold":800,"exp":80,"reputation":-20,"alignment_shift":{"evil":3}}},"choices":[]},"end_failure_01":{"text":"深手を負い、冷たい石床の上に力なく崩れ落ちた。意識が薄れていく。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"目が覚めた時には、盗掘団の姿も、遺品もすべて消え去っていた。","type":"end","result":"failure","bg_key":"bg_crypt","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[指名依頼] 聖墓地を荒らす盗掘団を追い払え。遺品の返還も任務に含む。"}'::jsonb,
    3,
    1
) ON CONFLICT (id) DO UPDATE SET
