-- Scenario 5102: 巨大蠍の討伐 (qst_rep_scorpion_hunt)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5102,
    'qst_rep_scorpion_hunt',
    '巨大蠍の討伐',
    '[討伐依頼] オアシス近郊に巣を作った巨大毒蠍を駆除せよ。',
    'オアシス村長',
    2,
    6,
    3,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep01","min_reputation":10,"nation_id":"loc_marcund"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep01","min_reputation":10,"nation_id":"loc_marcund"}'::jsonb,
    '{"nodes":{"start":{"text":"「冒険者殿、村の近くに巨大な毒蠍が巣を作っておってな」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"オアシス村長","speaker":"オアシス村長","next":"start_01_02","choices":[{"label":"続ける","next":"start_01_02"}]},"start_01_02":{"text":"砂漠の強い風が、開け放たれた窓から熱い砂を室内に運んでくる。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「家畜を何頭も喰われた。旅人が毒で倒れたという報告もある」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"オアシス村長","speaker":"オアシス村長","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（砂漠の毒蠍か。その毒は一滴でラクダを即死させると聞くが……）","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「このままでは交易路も使えん。どうか蠍を退治してくだされ」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"オアシス村長","speaker":"オアシス村長","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"「退治してくれれば、村の貯蓄から十分な報酬を支払おう」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"オアシス村長","speaker":"オアシス村長","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"巨大蠍の討伐か。砂漠の危険な相手だが、受けよう。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"灼熱の砂漠を進む。足跡と思しき溝が砂に刻まれている。蠍の痕跡だ。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"照りつける太陽が、砂の一粒一粒を黄金色に焼き尽くしていく。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"砂丘の向こうに、巨大な穴が見えてきた。蠍の巣穴に違いない。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"travel_02_02","choices":[{"label":"続ける","next":"travel_02_02"}]},"travel_02_02":{"text":"（周囲の熱気が、あの穴の近くだけさらに濃くなっているようだ）","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"desert_01","choices":[{"label":"続ける","next":"desert_01"}]},"desert_01":{"text":"巣穴の周囲には砕かれた骨や干からびた家畜の死骸が散乱している。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"desert_02","choices":[{"label":"続ける","next":"desert_02"}]},"desert_02":{"text":"あの穴に入るか、火を使って追い出すか。どちらにするか。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"choice_hunt","choices":[{"label":"続ける","next":"choice_hunt"}]},"choice_hunt":{"type":"choice","bg_key":"bg_desert","bgm":"bgm_quest_tense","choices":[{"label":"「枯れ草を集めて煙で巣穴から追い出す」","next":"fire_01"},{"label":"「巣穴に直接侵入して仕留める」","next":"cave_01"}]},"fire_01":{"text":"巣穴の入口に枯れ草を山と積み、火を放つ。煙が穴の中に充満していく。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"fire_01_02","choices":[{"label":"続ける","next":"fire_01_02"}]},"fire_01_02":{"text":"黒い煙が、熱風に乗って巣穴の奥深くへと吸い込まれていく。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"fire_02","choices":[{"label":"続ける","next":"fire_02"}]},"fire_02":{"text":"地面が震え始めた。何かが中から出てこようとしている……！","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"fire_random","choices":[{"label":"続ける","next":"fire_random"}]},"fire_random":{"type":"random_branch","bg_key":"bg_desert","prob":50,"choices":[{"label":"success","next":"fire_success"},{"label":"failure","next":"fire_fail"}]},"fire_success":{"text":"煙に耐えきれず、子蠍たちが四方八方に逃げ出した。親蠍だけが残っている。好機だ。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_mystery","next":"fire_success_02","choices":[{"label":"続ける","next":"fire_success_02"}]},"fire_success_02":{"text":"（雑魚は逃げたか。あとはあの巨大な親を仕留めるだけだな）","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_mystery","next":"fire_fail","choices":[{"label":"続ける","next":"fire_fail"}]},"fire_fail":{"text":"煙が足りない！ 怒った蠍が地中から飛び出し、毒尾が空を切った！","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"fire_trap","choices":[{"label":"続ける","next":"fire_trap"}]},"fire_trap":{"text":"毒尾の一撃をかわしきれず、腕をかすめた。毒が微かに体を蝕む。","type":"hp_damage","bg_key":"bg_desert","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"fire_trap_02","choices":[{"label":"続ける","next":"fire_trap_02"}]},"fire_trap_02":{"text":"（くっ、素早いな。だがまだ致命傷ではない。立て直そう）","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"merge_boss_02","choices":[{"label":"続ける","next":"merge_boss_02"}]},"cave_01":{"text":"砂にまみれながら巣穴の中に潜り込む。暗く、じっとりと湿った空気が漂う。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_mystery","next":"cave_01_02","choices":[{"label":"続ける","next":"cave_01_02"}]},"cave_01_02":{"text":"（暗くて視界が効かないな。音と空気の揺れを頼りに進むか）","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_mystery","next":"cave_02","choices":[{"label":"続ける","next":"cave_02"}]},"cave_02":{"text":"奥から無数の小さな目がこちらを見ている。子蠍の群れだ！","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"type":"battle","bg_key":"bg_desert","bgm":"bgm_battle","enemy_group_id":"422","choices":[{"label":"win","next":"merge_boss"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"merge_boss"},"merge_boss":{"text":"子蠍を蹴散らした先に、ひときわ巨大な影が蠢いている。親蠍だ。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"merge_boss_02","choices":[{"label":"続ける","next":"merge_boss_02"}]},"merge_boss_02":{"text":"巣穴の奥の暗闇から、カチカチと不気味な音が響き渡る。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"boss_intro_01","choices":[{"label":"続ける","next":"boss_intro_01"}]},"boss_intro_01":{"text":"全長3メートルはある巨体。硬質な甲殻が陽光を弾いている。","type":"text","bg_key":"bg_desert","bgm":"bgm_battle_boss","next":"boss_intro_02","choices":[{"label":"続ける","next":"boss_intro_02"}]},"boss_intro_02":{"text":"巨大な鋏がガチガチと鳴り、毒を滴らせた尾が高く振り上げられた。","type":"text","bg_key":"bg_desert","bgm":"bgm_battle_boss","next":"boss_intro_03","choices":[{"label":"続ける","next":"boss_intro_03"}]},"boss_intro_03":{"text":"巨大毒蠍が襲いかかってきた！","type":"text","bg_key":"bg_desert","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_desert","bgm":"bgm_battle_boss","enemy_group_id":"9102","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"巨大蠍の甲殻を貫き、ついに仕留めた。砂漠に静けさが戻る。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"巨大な蠍の巨体が崩れ落ち、砂塵がゆっくりと舞い降りた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"蠍の毒腺から希少な毒素を採取できた。薬にも毒にもなる代物だ。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"victory_02_02","choices":[{"label":"続ける","next":"victory_02_02"}]},"victory_02_02":{"text":"（これを村に届けるか、あるいは闇市で売るか……悩ましいな）","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_desert","bgm":"bgm_quest_calm","choices":[{"label":"「村の薬師に渡す。解毒薬の材料になるはずだ」","next":"fate_just_01"},{"label":"「闇市に売る。希少な毒素は高値がつくだろう」","next":"fate_chaos_01"}]},"fate_just_01":{"text":"蠍の毒素を村の薬師に手渡した。これで被害者の解毒薬が作れる。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"fate_just_01_02","choices":[{"label":"続ける","next":"fate_just_01_02"}]},"fate_just_01_02":{"text":"薬師は震える手で瓶を受け取り、深く感謝の頭を下げた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"fate_just_02","choices":[{"label":"続ける","next":"fate_just_02"}]},"fate_just_02":{"text":"「蠍を退治し、毒素まで薬師に！ 恩人だ、本当にありがとう」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"オアシス村長","speaker":"オアシス村長","next":"fate_just_02_02","choices":[{"label":"続ける","next":"fate_just_02_02"}]},"fate_just_02_02":{"text":"村長は自分の手を両手で握りしめ、涙ながらに感謝した。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"end_success_justice","choices":[{"label":"続ける","next":"end_success_justice"}]},"end_success_justice":{"text":"依頼達成。毒蠍を討ち、村に安全を取り戻した。正しき行いが人々を救った。","type":"end","result":"success","bg_key":"bg_marcund","params":{"rewards":{"gold":600,"exp":90,"reputation":3,"alignment_shift":{"justice":3}}},"choices":[]},"fate_chaos_01":{"text":"闇市の毒薬商に蠍の毒素を持ち込み、取引を持ちかけた。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_mystery","next":"fate_chaos_01_02","choices":[{"label":"続ける","next":"fate_chaos_01_02"}]},"fate_chaos_01_02":{"text":"「これは極上の毒素だな……。よし、言い値で買い取ろう」","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_mystery","speaker_name":"毒薬商","speaker":"毒薬商","next":"fate_chaos_02","choices":[{"label":"続ける","next":"fate_chaos_02"}]},"fate_chaos_02":{"text":"村長には「蠍は退治したが毒腺は破壊された」と報告した。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_mystery","next":"fate_chaos_02_02","choices":[{"label":"続ける","next":"fate_chaos_02_02"}]},"fate_chaos_02_02":{"text":"村長は少し残念そうにしたが、蠍が消えたことに満足した。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_mystery","next":"end_success_chaos","choices":[{"label":"続ける","next":"end_success_chaos"}]},"end_success_chaos":{"text":"依頼達成。毒素を密売して私腹を肥やした。罪悪感など砂漠の風に消える。","type":"end","result":"success","bg_key":"bg_slums","params":{"rewards":{"gold":900,"exp":90,"reputation":-20,"alignment_shift":{"chaos":3}}},"choices":[]},"end_failure_01":{"text":"鋭い毒尾が胸を貫く。灼熱の毒が全身を巡り、力なく崩れ落ちた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"砂漠の熱い砂の上で、意識は暗闇の底へと溶けて消えていった。","type":"end","result":"failure","bg_key":"bg_desert","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[討伐依頼] オアシス近郊に巣を作った巨大毒蠍を駆除せよ。"}'::jsonb,
    3,
    1
