-- Scenario 5103: 山賊の関所破り (qst_rep_toll_bandit)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5103,
    'qst_rep_toll_bandit',
    '山賊の関所破り',
    '[討伐依頼] 山間の街道に不法な関所を設けた山賊を排除せよ。',
    '自警団',
    2,
    5,
    3,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep01","min_reputation":10,"nation_id":"loc_yatoshin"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep01","min_reputation":10,"nation_id":"loc_yatoshin"}'::jsonb,
    '{"nodes":{"start":{"text":"「山道に山賊が勝手に関所を作りやがった。旅人から金を奪っている」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"自警団の長","speaker":"自警団の長","next":"start_01_02","choices":[{"label":"続ける","next":"start_01_02"}]},"start_01_02":{"text":"集会所の古びた机を、自警団の長が悔しげに拳で叩いた。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「払えない者は身ぐるみ剥がされる。抵抗した商人は半殺しにされた」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"自警団の長","speaker":"自警団の長","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（通行料と称した恐喝か。放置すれば街道が完全に死んでしまうな）","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「俺たちでは手に負えん。腕利きの冒険者に頼むしかないんだ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"自警団の長","speaker":"自警団の長","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"「どうか奴らを叩き出してくれ。街道の平和を戻してほしい」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"自警団の長","speaker":"自警団の長","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"山賊の関所か。街道の安全は冒険者にとっても死活問題だ。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"夜刀神国の山間部へ向かう。木々が鬱蒼と茂り、視界は悪い。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"湿った風が笹の葉を揺らし、不気味なざわめきが山に満ちている。","type":"text","bg_key":"bg_yato_road","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"山道を登っていくと、前方に粗末な柵と見張り台が見えてきた。あれが関所か。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"travel_02_02","choices":[{"label":"続ける","next":"travel_02_02"}]},"travel_02_02":{"text":"（警戒はそれほど厳重ではないな。これなら奇襲も難しくはない）","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"road_01","choices":[{"label":"続ける","next":"road_01"}]},"road_01":{"text":"関所の前には通行人が数人、金を払わされて渋い顔をしている。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"road_02","choices":[{"label":"続ける","next":"road_02"}]},"road_02":{"text":"見張りは3人。奥の小屋に頭目がいるはずだ。どうする？","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"choice_approach","choices":[{"label":"続ける","next":"choice_approach"}]},"choice_approach":{"type":"choice","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","choices":[{"label":"「旅人を装って関所を通り、隙を突く」","next":"disguise_01"},{"label":"「正面から武器を構えて蹴散らす」","next":"assault_01"}]},"disguise_01":{"text":"武器を隠し、ただの旅人のふりをしてのんびりと関所に近づく。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_mystery","next":"disguise_01_02","choices":[{"label":"続ける","next":"disguise_01_02"}]},"disguise_01_02":{"text":"（通してもらおうか。用があるのは頭目だが、まずはこいつらだ）","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_mystery","next":"disguise_random","choices":[{"label":"続ける","next":"disguise_random"}]},"disguise_random":{"type":"random_branch","bg_key":"bg_yato_mountain","prob":50,"choices":[{"label":"success","next":"disguise_success"},{"label":"failure","next":"disguise_fail"}]},"disguise_success":{"text":"通行料を払うふりをして、見張りの懐に飛び込んで一撃で気絶させた！","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_mystery","next":"disguise_success_02","choices":[{"label":"続ける","next":"disguise_success_02"}]},"disguise_success_02":{"text":"（よし、静かに片付いたな。このまま奥の小屋へ向かおう）","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_mystery","next":"disguise_fail","choices":[{"label":"続ける","next":"disguise_fail"}]},"disguise_fail":{"text":"「おい、こいつ武器を隠し持ってやがる！ 冒険者の回し者だ！」","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","speaker_name":"山賊の見張り","speaker":"山賊の見張り","next":"disguise_trap","choices":[{"label":"続ける","next":"disguise_trap"}]},"disguise_trap":{"text":"不意打ちの棍棒を食らったが、反撃して見張りを制圧した。","type":"hp_damage","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"disguise_trap_02","choices":[{"label":"続ける","next":"disguise_trap_02"}]},"disguise_trap_02":{"text":"（チッ、見破られたか。だが囲まれる前に片付けられて幸いだ）","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"merge_hideout_02","choices":[{"label":"続ける","next":"merge_hideout_02"}]},"assault_01":{"text":"正面から抜刀し、大声を上げて山賊どもに斬りかかる！","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"assault_01_02","choices":[{"label":"続ける","next":"assault_01_02"}]},"assault_01_02":{"text":"（関所遊びは終わりだ！ お前たちのような悪党に払う金はない！）","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"type":"battle","bg_key":"bg_yato_mountain","bgm":"bgm_battle","enemy_group_id":"433","choices":[{"label":"win","next":"merge_hideout"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"merge_hideout"},"merge_hideout":{"text":"関所を突破し、山道の奥にある山賊の小屋に到達した。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","next":"merge_hideout_02","choices":[{"label":"続ける","next":"merge_hideout_02"}]},"merge_hideout_02":{"text":"小屋の周囲には、旅人から奪ったと思われる荷物が積まれている。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","next":"hideout_01","choices":[{"label":"続ける","next":"hideout_01"}]},"hideout_01":{"text":"小屋の中から大声が聞こえる。頭目は部下と酒を飲んでいるようだ。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","next":"hideout_02","choices":[{"label":"続ける","next":"hideout_02"}]},"hideout_02":{"text":"扉を蹴り開けて踏み込むと、酒瓶を持った大男と目が合った。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","next":"hideout_02_02","choices":[{"label":"続ける","next":"hideout_02_02"}]},"hideout_02_02":{"text":"（こいつが親玉か。酒の酔いなど一瞬で吹き飛ばしてやる）","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_tense","next":"boss_intro_01","choices":[{"label":"続ける","next":"boss_intro_01"}]},"boss_intro_01":{"text":"「なんだテメェ、俺の関所を壊しやがったのか！」","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_battle_boss","speaker_name":"山賊の頭","speaker":"山賊の頭","next":"boss_intro_02","choices":[{"label":"続ける","next":"boss_intro_02"}]},"boss_intro_02":{"text":"大男が酒瓶を叩き割り、巨大な斧を手に取って立ち上がった。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_battle_boss","next":"boss_intro_03","choices":[{"label":"続ける","next":"boss_intro_03"}]},"boss_intro_03":{"text":"「俺の稼ぎを邪魔する奴は、山の肥やしにしてやるぜ！」","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_battle_boss","speaker_name":"山賊の頭","speaker":"山賊の頭","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_yato_forest","bgm":"bgm_battle_boss","enemy_group_id":"9103","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"山賊の頭が倒れた。巻き上げた金貨の袋がいくつも転がっている。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"頭目は地面に這いつくばり、青ざめた顔でこちらを見上げている。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「ま、待ってくれ！ この金は全部やる！ だから見逃してくれよ！」","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","speaker_name":"山賊の頭","speaker":"山賊の頭","next":"victory_02_02","choices":[{"label":"続ける","next":"victory_02_02"}]},"victory_02_02":{"text":"（命乞いをするか。悪党の言い訳など、耳を傾ける価値もないが）","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_yato_forest","bgm":"bgm_quest_calm","choices":[{"label":"「黙れ。縄で縛って代官所へ突き出す」","next":"fate_order_01"},{"label":"「……金を置いて消えろ。二度とこの道に来るな」","next":"fate_evil_01"}]},"fate_order_01":{"text":"山賊を縛り上げ、代官所に引き渡した。巻き上げた金も返却された。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"fate_order_01_02","choices":[{"label":"続ける","next":"fate_order_01_02"}]},"fate_order_01_02":{"text":"連行される山賊の頭は、代官の兵たちに引きずられていった。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"fate_order_02","choices":[{"label":"続ける","next":"fate_order_02"}]},"fate_order_02":{"text":"「ありがてえ！ これで商人たちも安心して街道を通れる」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"自警団の長","speaker":"自警団の長","next":"fate_order_02_02","choices":[{"label":"続ける","next":"fate_order_02_02"}]},"fate_order_02_02":{"text":"自警団の長は笑顔を浮かべ、強く握手を求めてきた。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"end_success_order","choices":[{"label":"続ける","next":"end_success_order"}]},"end_success_order":{"text":"依頼達成。街道の秩序を取り戻し、旅人たちの安全を守った。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":500,"exp":80,"reputation":5,"alignment_shift":{"order":3}}},"choices":[]},"fate_evil_01":{"text":"山賊の頭は這いつくばるようにして、慌てて山奥へ逃げていった。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_mystery","next":"fate_evil_01_02","choices":[{"label":"続ける","next":"fate_evil_01_02"}]},"fate_evil_01_02":{"text":"誰もいなくなった小屋で、床に転がっていた金袋を懐に収める。","type":"text","bg_key":"bg_yato_forest","bgm":"bgm_quest_mystery","next":"fate_evil_02","choices":[{"label":"続ける","next":"fate_evil_02"}]},"fate_evil_02":{"text":"自警団には「討伐した」とだけ報告した。懐の金袋はずっしりと重い。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_mystery","next":"fate_evil_02_02","choices":[{"label":"続ける","next":"fate_evil_02_02"}]},"fate_evil_02_02":{"text":"血を流すこともなく、ただ懐に大金が舞い込んだ。悪くない取引だ。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_mystery","next":"end_success_evil","choices":[{"label":"続ける","next":"end_success_evil"}]},"end_success_evil":{"text":"依頼達成。山賊は逃がしたが、金は得た。正義より実利が大切だ。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":800,"exp":80,"reputation":-20,"alignment_shift":{"evil":3}}},"choices":[]},"end_failure_01":{"text":"山賊の振るう巨大な斧が肩口に食い込む。激痛の中で視界が揺らぐ。","type":"text","bg_key":"bg_yato_mountain","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"「身ぐるみ剥いでやるぜ」という嘲笑を最後に、意識は途絶えた。","type":"end","result":"failure","bg_key":"bg_yato_mountain","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[討伐依頼] 山間の街道に不法な関所を設けた山賊を排除せよ。"}'::jsonb,
    3,
    1
) ON CONFLICT (id) DO UPDATE SET
