-- Scenario 5104: 河伯の怒り (qst_rep_river_god)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5104,
    'qst_rep_river_god',
    '河伯の怒り',
    '[鎮撫依頼] 河の氾濫を引き起こす妖怪を鎮めよ。',
    '村の長老',
    2,
    6,
    3,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep01","min_reputation":10,"nation_id":"loc_haryu"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep01","min_reputation":10,"nation_id":"loc_haryu"}'::jsonb,
    '{"nodes":{"start":{"text":"「冒険者殿、どうかお力をお貸しくだされ。河が荒れ、田畑が水に沈んでおるのです」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"村の長老","speaker":"村の長老","next":"start_01_02","choices":[{"label":"続ける","next":"start_01_02"}]},"start_01_02":{"text":"都の喧騒を離れた薄暗い宿場で、長老は震える手で茶碗を握りしめていた。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「村の者は、河に棲む妖怪\"河伯\"の怒りだと恐れておりまして……」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"村の長老","speaker":"村の長老","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（河伯か。水神とも称される強力な妖怪だな。簡単にはいかないぞ）","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「河伯を鎮めてくだされ。このままでは村が滅んでしまいます」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"村の長老","speaker":"村の長老","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"老人の切実な訴えに、周囲の冒険者たちも無言で耳を傾けている。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"「分かった、長老。まずは現地へ向かい、河の様子を確かめてみよう」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"start_04_02","choices":[{"label":"続ける","next":"start_04_02"}]},"start_04_02":{"text":"荷物をまとめ、華陽の都の重厚な門をくぐり、辺境の村へと旅立った。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"辺境の農村に到着した。田畑は泥水に浸かり、村人たちの顔は暗い。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"水浸しになった畦道で、農民たちが途方に暮れて泥水を眺めていた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"河の水は異様に濁り、悪臭が漂っている。これは……ただの氾濫ではない。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"travel_02_02","choices":[{"label":"続ける","next":"travel_02_02"}]},"travel_02_02":{"text":"（この鼻をつく悪臭……まるで腐った染料のようなにおいがするな）","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"river_01","choices":[{"label":"続ける","next":"river_01"}]},"river_01":{"text":"河伯の祠は下流にあるらしいが、水の汚れは上流から来ているようだ。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"river_01_02","choices":[{"label":"続ける","next":"river_01_02"}]},"river_01_02":{"text":"川縁にしゃがみ込み、濁った水を指ですくう。ぬるりとした油膜が浮く。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"river_02","choices":[{"label":"続ける","next":"river_02"}]},"river_02":{"text":"まず上流を調べるか、それとも直接河伯の祠へ向かうか。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"river_02_02","choices":[{"label":"続ける","next":"river_02_02"}]},"river_02_02":{"text":"（原因を突き止めるか、それとも河伯の言い分を直接聞きに行くか……）","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","next":"choice_approach","choices":[{"label":"続ける","next":"choice_approach"}]},"choice_approach":{"type":"choice","bg_key":"bg_karyu_village","bgm":"bgm_quest_tense","choices":[{"label":"「まず上流を調査して原因を探る」","next":"upstream_01"},{"label":"「河伯の祠へ直行して直接交渉する」","next":"shrine_01"}]},"upstream_01":{"text":"上流を辿ると、河岸に染料工房があった。廃液が河にそのまま流されている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"upstream_01_02","choices":[{"label":"続ける","next":"upstream_01_02"}]},"upstream_01_02":{"text":"工房からは絶え間なく廃液が噴き出し、河水をどす黒く染めている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"upstream_02","choices":[{"label":"続ける","next":"upstream_02"}]},"upstream_02":{"text":"これが河伯の怒りの原因か。汚染の証拠を手に入れた。祠へ向かおう。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"upstream_02_02","choices":[{"label":"続ける","next":"upstream_02_02"}]},"upstream_02_02":{"text":"（証拠は揃った。これを突きつければ、河伯とも対話ができるはずだ）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"shrine_01":{"text":"河沿いの険しい道を祠へ向かう。濁流の中から不穏な気配がする……。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"shrine_01_02","choices":[{"label":"続ける","next":"shrine_01_02"}]},"shrine_01_02":{"text":"荒れ狂う泥水が波しぶきを上げ、牙を剥くように足元をかすめていく。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"shrine_random","choices":[{"label":"続ける","next":"shrine_random"}]},"shrine_random":{"type":"random_branch","bg_key":"bg_karyu_mountain","prob":50,"choices":[{"label":"success","next":"shrine_success"},{"label":"failure","next":"shrine_fail"}]},"shrine_success":{"text":"河の流れを読み、飛び石を渡って無事に祠の前に辿り着いた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"shrine_success_02","choices":[{"label":"続ける","next":"shrine_success_02"}]},"shrine_success_02":{"text":"水しぶきを避けながら、急峻な岩場を登りきって祠の境内へと入る。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"shrine_fail","choices":[{"label":"続ける","next":"shrine_fail"}]},"shrine_fail":{"text":"突然、濁流が渦を巻いて水柱が襲いかかってきた！","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"shrine_fail_02","choices":[{"label":"続ける","next":"shrine_fail_02"}]},"shrine_fail_02":{"text":"（しまっ、足場が——！ 回避が間に合わない！）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"shrine_trap","choices":[{"label":"続ける","next":"shrine_trap"}]},"shrine_trap":{"text":"水の塊に叩きつけられた。ずぶ濡れになりながらも祠に辿り着いた。","type":"hp_damage","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"shrine_trap_02","choices":[{"label":"続ける","next":"shrine_trap_02"}]},"shrine_trap_02":{"text":"全身に鈍痛が走るが、何とか立ち上がり、息を整えて祠へと進んだ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"merge_shrine","choices":[{"label":"続ける","next":"merge_shrine"}]},"merge_shrine":{"text":"苔むした古い祠の前に立つと、河の水面が不自然に盛り上がった。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"merge_shrine_02","choices":[{"label":"続ける","next":"merge_shrine_02"}]},"merge_shrine_02":{"text":"水面が割れ、渦巻く激流が巨大な影を形作っていく。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"encounter_01","choices":[{"label":"続ける","next":"encounter_01"}]},"encounter_01":{"text":"水の中から、蛙に似た巨大な妖怪の姿が浮かび上がった。河伯だ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"encounter_01_02","choices":[{"label":"続ける","next":"encounter_01_02"}]},"encounter_01_02":{"text":"その体躯はぬらぬらと光り、怒りに燃える双眸が鋭くこちらを射抜く。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"encounter_02","choices":[{"label":"続ける","next":"encounter_02"}]},"encounter_02":{"text":"「人間が来おったか……。この穢れた河を見よ。全てお前たちのせいだ！」","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","speaker_name":"河伯","speaker":"河伯","next":"encounter_02_02","choices":[{"label":"続ける","next":"encounter_02_02"}]},"encounter_02_02":{"text":"（すさまじい敵意だ。こちらの言葉を聞く余裕はなさそうだな）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","next":"boss_intro_01","choices":[{"label":"続ける","next":"boss_intro_01"}]},"boss_intro_01":{"text":"「河を汚し、我が眷属を殺し、それでも知らぬ顔をする。許さぬ！」","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","speaker_name":"河伯","speaker":"河伯","next":"boss_intro_01_02","choices":[{"label":"続ける","next":"boss_intro_01_02"}]},"boss_intro_01_02":{"text":"河伯が咆哮すると、周囲の水流が巻き上がり、無数の水の刃となった。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","next":"boss_intro_02","choices":[{"label":"続ける","next":"boss_intro_02"}]},"boss_intro_02":{"text":"河伯は問答無用で襲いかかってきた！ まずは力で抑え込むしかない！","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","enemy_group_id":"9104","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"河伯が力を失い、水面に膝をついた。怒りの目が少しだけ和らいだ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"周囲の逆巻く水流が引いていき、川面に静けさが戻っていく。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……お前、我を殺すのか。ならば好きにするがいい」","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","speaker_name":"河伯","speaker":"河伯","next":"victory_02_02","choices":[{"label":"続ける","next":"victory_02_02"}]},"victory_02_02":{"text":"（殺すのは容易い。だが、根本的な原因である汚染を止めねば解決せぬ）","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","choices":[{"label":"「殺さない。上流の汚染を止めてみせる」","next":"fate_justice_01"},{"label":"「村の安全のため、ここで始末する」","next":"fate_evil_01"}]},"fate_justice_01":{"text":"村へ戻り、染料工房の廃液を止めさせた。河伯は静かに祠へ帰っていった。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"fate_justice_01_02","choices":[{"label":"続ける","next":"fate_justice_01_02"}]},"fate_justice_01_02":{"text":"かつての清流が戻り始め、泥に沈んだ畑にも新たな芽が息吹きだした。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"fate_justice_02","choices":[{"label":"続ける","next":"fate_justice_02"}]},"fate_justice_02":{"text":"「河が澄み始めた！ 妖怪と人が共に生きる道を見つけてくださったのですね」","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","speaker_name":"村の長老","speaker":"村の長老","next":"fate_justice_02_02","choices":[{"label":"続ける","next":"fate_justice_02_02"}]},"fate_justice_02_02":{"text":"長老は涙を流して深く感謝し、村のなけなしの宝を差し出してきた。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_calm","next":"end_success_justice","choices":[{"label":"続ける","next":"end_success_justice"}]},"end_success_justice":{"text":"依頼達成。河伯の怒りを鎮め、人と妖の共存の道を示した。","type":"end","result":"success","bg_key":"bg_karyu_village","params":{"rewards":{"gold":550,"exp":90,"reputation":5,"alignment_shift":{"justice":3}}},"choices":[]},"fate_evil_01":{"text":"河伯に止めを刺した。水面が静まり返り、祠の灯が消えた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"fate_evil_01_02","choices":[{"label":"続ける","next":"fate_evil_01_02"}]},"fate_evil_01_02":{"text":"息絶えた河伯の骸は泥水に溶け、ただ濁った川だけが静かに流れる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"fate_evil_02","choices":[{"label":"続ける","next":"fate_evil_02"}]},"fate_evil_02":{"text":"「河伯を退治しました」と報告した。村人は安堵したが、河の汚れは変わらない。","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_mystery","next":"fate_evil_02_02","choices":[{"label":"続ける","next":"fate_evil_02_02"}]},"fate_evil_02_02":{"text":"（これで本当に良かったのか。汚染の元を断たねば同じことだ……）","type":"text","bg_key":"bg_karyu_village","bgm":"bgm_quest_mystery","next":"end_success_evil","choices":[{"label":"続ける","next":"end_success_evil"}]},"end_success_evil":{"text":"依頼達成。妖怪は消えたが、河の汚染はそのままだ。いずれまた問題が起きるだろう。","type":"end","result":"success","bg_key":"bg_karyu_village","params":{"rewards":{"gold":800,"exp":90,"reputation":-20,"alignment_shift":{"evil":3}}},"choices":[]},"end_failure_01":{"text":"河伯の放った凄まじい濁流が体を打ち抜く。視界が急速に狭まっていく。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"河伯の水流に呑まれ、意識が薄れていく。冷たい水が全身を包み込んだ。","type":"end","result":"failure","bg_key":"bg_karyu_mountain","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[鎮撫依頼] 河の氾濫を引き起こす妖怪を鎮めよ。"}'::jsonb,
    3,
    1
