-- Scenario 5111: 狂気の錬金術師 (qst_rep_mutant)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5111,
    'qst_rep_mutant',
    '狂気の錬金術師',
    '[指名手配] 地下水道で違法な生体実験を繰り返す狂気の錬金術師を捕縛せよ。',
    '聖騎士団',
    3,
    10,
    4,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep02","min_reputation":30,"nation_id":"loc_roland"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep02","min_reputation":30,"nation_id":"loc_roland"}'::jsonb,
    '{"nodes":{"start":{"text":"「今回は聖騎士団からの直接指名依頼です。地下水道に潜む狂人の捕縛ですね」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルド受付嬢","speaker":"ギルド受付嬢","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「相手は破門された錬金術師。人間と魔物を掛け合わせる禁忌の実験を行っているとか……」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルド受付嬢","speaker":"ギルド受付嬢","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「危険な生体兵器がいるかもしれません。十分な準備をして挑んでください」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルド受付嬢","speaker":"ギルド受付嬢","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"中堅冒険者としての実力が試される任務だ。気を引き締めて地下水道へ向かう。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"聖都の地下へと続く隠し通路は、貧民街の奥にあった。ひどい悪臭が漂っている。","type":"text","bg_key":"bg_slums","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"地下水道に降り立った。空気は淀み、壁には不気味な粘液が付着している。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"sewer_01","choices":[{"label":"続ける","next":"sewer_01"}]},"sewer_01":{"text":"騎士団の情報によれば、この奥に錬金術師の実験区画があるはずだ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"sewer_02","choices":[{"label":"続ける","next":"sewer_02"}]},"sewer_02":{"text":"奥へ進むと、頑丈な鉄格子で道が塞がれていた。錠前には見慣れない魔法陣が刻まれている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"choice_gate","choices":[{"label":"続ける","next":"choice_gate"}]},"choice_gate":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_tense","choices":[{"label":"「武器で錠前を力任せに破壊する」","next":"gate_break_01"},{"label":"「周囲を探索して解除キーを探す」","next":"gate_search_01"}]},"gate_break_01":{"text":"魔法陣ごと力任せに破壊する！ けたたましい音と共に鉄格子が開いたが——","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"gate_break_trap","choices":[{"label":"続ける","next":"gate_break_trap"}]},"gate_break_trap":{"text":"破壊に反応して、仕掛けられていた爆薬が作動！ 爆発に巻き込まれた。","type":"hp_damage","bg_key":"bg_crypt","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"gate_break_02","choices":[{"label":"続ける","next":"gate_break_02"}]},"gate_break_02":{"text":"煙を払いながら立ち上がる。傷を負ったが、先へ進むことはできそうだ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"merge_lab","choices":[{"label":"続ける","next":"merge_lab"}]},"gate_search_01":{"text":"周囲の汚水の中を探る。錬金術師の弟子が落とした鍵がないだろうか……。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"gate_search_random","choices":[{"label":"続ける","next":"gate_search_random"}]},"gate_search_random":{"type":"random_branch","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","prob":60,"next":"search_success","choices":[{"label":"成功","next":"search_success"},{"label":"失敗","next":"search_fail"}]},"search_success":{"text":"汚泥の中から魔法陣の解除キーを発見した。無傷で鉄格子を開けることに成功した。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"merge_lab","choices":[{"label":"続ける","next":"merge_lab"}]},"search_fail":{"text":"汚泥の中を探った瞬間、潜んでいた毒スライムに腕を噛みつかれた！","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"search_fail_trap","choices":[{"label":"続ける","next":"search_fail_trap"}]},"search_fail_trap":{"text":"スライムを振り払うが、軽度の毒を受けた。結局、力任せに鉄格子を壊して進む。","type":"hp_damage","bg_key":"bg_crypt","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"merge_lab","choices":[{"label":"続ける","next":"merge_lab"}]},"merge_lab":{"text":"鉄格子を抜け、実験区画の入り口に到達した。鼻を突く薬品の臭いが強くなる。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"lab_01","choices":[{"label":"続ける","next":"lab_01"}]},"lab_01":{"text":"廊下の奥には、不気味な培養槽が並ぶ部屋が見える。あそこが最深部だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"lab_02","choices":[{"label":"続ける","next":"lab_02"}]},"lab_02":{"text":"しかし、扉の前には巨大な肉塊のような化け物が鎮座している。失敗作のキメラだ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"lab_03","choices":[{"label":"続ける","next":"lab_03"}]},"lab_03":{"text":"見張りのようだが、知性は低そうだ。どうやって突破するか？","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"choice_guard","choices":[{"label":"続ける","next":"choice_guard"}]},"choice_guard":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_tense","choices":[{"label":"「先制攻撃で仕留める」","next":"guard_fight_01"},{"label":"「肉片を投げて気を逸らし、背後を通る」","next":"guard_sneak_01"}]},"guard_fight_01":{"text":"正面から武器を構え、見張りのキメラに突撃する！","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"text":"失敗作キメラが襲いかかってきた！","type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle","enemy_group_id":"460","choices":[{"label":"win","next":"merge_boss"},{"label":"lose","next":"end_failure"}],"battle_success_next":"merge_boss"},"guard_sneak_01":{"text":"道中で拾った魔物の肉片を、部屋の隅へ向けて思い切り投げた。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"guard_sneak_02","choices":[{"label":"続ける","next":"guard_sneak_02"}]},"guard_sneak_02":{"text":"キメラは肉片の音に釣られ、のそりと移動した。その隙に背後をすり抜ける。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"merge_boss","choices":[{"label":"続ける","next":"merge_boss"}]},"merge_boss":{"text":"ついに最深部の実験室に踏み込んだ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"boss_intro_01","choices":[{"label":"続ける","next":"boss_intro_01"}]},"boss_intro_01":{"text":"「なんだね君は！ 私の美しい実験を邪魔するつもりか！」","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"狂気の錬金術師","speaker":"狂気の錬金術師","next":"boss_intro_02","choices":[{"label":"続ける","next":"boss_intro_02"}]},"boss_intro_02":{"text":"白衣を血と薬品で汚した男が、狂気に満ちた笑みを浮かべて振り返る。その後ろにある巨大な培養槽から、恐ろしい姿のキメラが姿を現した。","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"狂気の錬金術師","speaker":"狂気の錬金術師","next":"boss_intro_03","choices":[{"label":"続ける","next":"boss_intro_03"}]},"boss_intro_03":{"text":"「さあ、私の最高傑作の餌食になりたまえ！」","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"狂気の錬金術師","speaker":"狂気の錬金術師","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"錬金術師と完成体キメラとの戦い！","type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle_boss","enemy_group_id":"9111","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"キメラが崩れ落ち、錬金術師は怯えて尻餅をついた。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"錬金術師を縄で縛り上げた。机の上には、禁忌の生体実験の詳細が記された分厚い研究資料が置かれている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_calm","choices":[{"label":"「すべて聖騎士団に提出する」","next":"report_order_01"},{"label":"「資料は闇市に高く売る」","next":"report_evil_01"}]},"report_order_01":{"text":"錬金術師とすべての資料を聖騎士団に引き渡した。「見事な働きだ。この資料は異端審問会で厳重に処分しよう」","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"report_order_02","choices":[{"label":"続ける","next":"report_order_02"}]},"report_order_02":{"text":"騎士団長から労いの言葉と共に、規定通りの報酬を受け取った。ローランドの秩序は、今日も一つ保たれた。","type":"text","bg_key":"bg_church","bgm":"bgm_quest_calm","next":"end_success_order","choices":[{"label":"続ける","next":"end_success_order"}]},"end_success_order":{"text":"依頼達成。法と秩序を守り抜いた名誉は、中堅冒険者としての評価を確かなものにした。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":"Gold:1000|Exp:150|Rep:5|Order:5"},"choices":[]},"report_evil_01":{"text":"錬金術師だけを騎士団に引き渡し、資料はこっそり持ち出して闇市のブローカーに売り払った。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_mystery","next":"report_evil_02","choices":[{"label":"続ける","next":"report_evil_02"}]},"report_evil_02":{"text":"「こいつは上物だ。いくらでも買い手がつくぜ」ブローカーから渡された金袋は、騎士団の報酬よりもずっと重かった。","type":"text","bg_key":"bg_slums","bgm":"bgm_quest_mystery","next":"end_success_evil","choices":[{"label":"続ける","next":"end_success_evil"}]},"end_success_evil":{"text":"依頼達成。裏の手段で莫大な利益を得た。正義だけでは食っていけない——それもまた真理だ。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":"Gold:1800|Exp:120|Rep:0|Evil:5"},"choices":[]},"end_failure":{"text":"キメラの凶爪が深々と肉を裂いた。薄れゆく意識の中で、狂気の笑い声が聞こえる。「新しい実験体だ！」","type":"end","result":"failure","bg_key":"bg_crypt","choices":[]}},"short_description":"[指名手配] 地下水道で違法な生体実験を繰り返す狂気の錬金術師を捕縛せよ。"}'::jsonb,
    4,
    2
