-- Scenario 5112: 砂漠の盗賊王 (qst_rep_bandit_king)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5112,
    'qst_rep_bandit_king',
    '砂漠の盗賊王',
    '[討伐依頼] マルカンド近郊のキャラバンを襲う「砂漠の盗賊王」のアジトを強襲せよ。',
    '商人ギルド',
    3,
    11,
    4,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep02","min_reputation":30,"nation_id":"loc_marcund"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep02","min_reputation":30,"nation_id":"loc_marcund"}'::jsonb,
    '{"nodes":{"start":{"text":"「商人ギルドからの依頼だ。キャラバンを襲う盗賊団のアジトを特定したらしい」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルド受付","speaker":"ギルド受付","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「相手は『砂漠の盗賊王バシム』。砂嵐を利用して神出鬼没に略奪を繰り返す男だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルド受付","speaker":"ギルド受付","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「兵士の目につかない岩陰に要塞を築いているという。腕利きの冒険者の出番だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルド受付","speaker":"ギルド受付","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"盗賊の親玉か。報酬は悪くない。準備を整え、砂漠へと足を踏み入れた。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"強烈な日差しが降り注ぐマルカンド大砂漠。水筒の水を大事に飲みながら進む。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"アジトがあるとされる岩山地帯まではまだ距離がある。砂に足を取られ、体力が削られる。","type":"text","bg_key":"bg_desert","bgm":"bgm_field","next":"desert_01","choices":[{"label":"続ける","next":"desert_01"}]},"desert_01":{"text":"空が急に暗くなった。前方から巨大な砂嵐が迫ってきている！","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"desert_02","choices":[{"label":"続ける","next":"desert_02"}]},"desert_02":{"text":"盗賊たちはこの砂嵐を利用して移動するらしいが、まともに巻き込まれれば危険だ。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"choice_sandstorm","choices":[{"label":"続ける","next":"choice_sandstorm"}]},"choice_sandstorm":{"type":"choice","bg_key":"bg_desert","bgm":"bgm_quest_tense","choices":[{"label":"「マントで顔を覆い、強行突破する」","next":"storm_push_01"},{"label":"「近くのオアシスに避難し、嵐が過ぎるのを待つ」","next":"oasis_wait_01"}]},"storm_push_01":{"text":"砂嵐の中に飛び込む！ 視界が完全に奪われ、強風で飛んできた岩が体に当たる。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"storm_push_trap","choices":[{"label":"続ける","next":"storm_push_trap"}]},"storm_push_trap":{"text":"鋭い岩片が直撃した！ 息も絶え絶えになりながら砂嵐を抜ける。","type":"hp_damage","bg_key":"bg_desert","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"storm_push_02","choices":[{"label":"続ける","next":"storm_push_02"}]},"storm_push_02":{"text":"砂まみれになったが、アジトのある岩山へは予想より早く到着できた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"merge_hideout","choices":[{"label":"続ける","next":"merge_hideout"}]},"oasis_wait_01":{"text":"オアシスに身を隠す。風が止むのを待つ間、周囲の気配を探る……。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_mystery","next":"oasis_random","choices":[{"label":"続ける","next":"oasis_random"}]},"oasis_random":{"type":"random_branch","bg_key":"bg_desert","bgm":"bgm_quest_mystery","prob":50,"next":"oasis_safe_01","choices":[{"label":"成功","next":"oasis_safe_01"},{"label":"失敗","next":"oasis_ambush_01"}]},"oasis_safe_01":{"text":"砂嵐が過ぎ去った。体力を温存したまま、アジトへと向かうことができた。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_calm","next":"merge_hideout","choices":[{"label":"続ける","next":"merge_hideout"}]},"oasis_ambush_01":{"text":"「誰かいるぞ！」オアシスをねぐらにしていた砂漠の魔物に目をつけられた！","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"battle_ambush","choices":[{"label":"続ける","next":"battle_ambush"}]},"battle_ambush":{"text":"砂漠の魔物との戦闘！","type":"battle","bg_key":"bg_desert","bgm":"bgm_battle","enemy_group_id":"422","choices":[{"label":"win","next":"merge_hideout"},{"label":"lose","next":"end_failure"}],"battle_success_next":"merge_hideout"},"merge_hideout":{"text":"岩山に到着した。見張りの盗賊が立っている。奥がアジトへの入り口だ。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"hideout_01","choices":[{"label":"続ける","next":"hideout_01"}]},"hideout_01":{"text":"入り口には重武装の盗賊が複数いる。真正面から行くか、一工夫するか。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"hideout_02","choices":[{"label":"続ける","next":"hideout_02"}]},"hideout_02":{"text":"ちょうど、略奪を終えて帰還してきたらしい商人の服を着た盗賊の一団がいる。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"hideout_03","choices":[{"label":"続ける","next":"hideout_03"}]},"hideout_03":{"text":"あの服を奪えば変装できるかもしれない。どうする？","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"choice_infiltrate","choices":[{"label":"続ける","next":"choice_infiltrate"}]},"choice_infiltrate":{"type":"choice","bg_key":"bg_desert","bgm":"bgm_quest_tense","choices":[{"label":"「小細工は無用。正面から蹴散らす」","next":"assault_01"},{"label":"「商人の服を奪い、変装して潜入する」","next":"disguise_01"}]},"assault_01":{"text":"武器を抜き、見張りに斬りかかる！「敵襲だぁ！！」","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"text":"盗賊の見張り部隊との戦闘！","type":"battle","bg_key":"bg_desert","bgm":"bgm_battle","enemy_group_id":"414","choices":[{"label":"win","next":"merge_boss"},{"label":"lose","next":"end_failure"}],"battle_success_next":"merge_boss"},"disguise_01":{"text":"商人の服を被り、うつむき加減で見張りの前を通過する……。「おい、お前。見ない顔だな？」","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_mystery","next":"disguise_random","choices":[{"label":"続ける","next":"disguise_random"}]},"disguise_random":{"type":"random_branch","bg_key":"bg_desert","bgm":"bgm_quest_mystery","prob":60,"next":"disguise_success_01","choices":[{"label":"成功","next":"disguise_success_01"},{"label":"失敗","next":"disguise_fail_01"}]},"disguise_success_01":{"text":"「ああ、新入りの……」適当に誤魔化すと、見張りは興味を失った。無傷で潜入に成功した。","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_mystery","next":"merge_boss","choices":[{"label":"続ける","next":"merge_boss"}]},"disguise_fail_01":{"text":"「嘘をつけ！ 侵入者だ！」見張りに背後から蹴りを入れられ、囲まれた！","type":"text","bg_key":"bg_desert","bgm":"bgm_quest_tense","next":"disguise_trap","choices":[{"label":"続ける","next":"disguise_trap"}]},"disguise_trap":{"text":"包囲を力ずくで突破し、アジトの奥へ逃げ込む。無駄な傷を負ってしまった。","type":"hp_damage","bg_key":"bg_desert","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"merge_boss","choices":[{"label":"続ける","next":"merge_boss"}]},"merge_boss":{"text":"騒ぎの中、アジトの最深部である広間に到達した。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"boss_intro_01","choices":[{"label":"続ける","next":"boss_intro_01"}]},"boss_intro_01":{"text":"「俺の要塞にネズミが入り込んだと聞いてな。随分と威勢がいいじゃねえか」","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"盗賊王バシム","speaker":"盗賊王バシム","next":"boss_intro_02","choices":[{"label":"続ける","next":"boss_intro_02"}]},"boss_intro_02":{"text":"豪華な絨毯の上に座る、巨体の男。彼こそが砂漠の盗賊王バシムだ。巨大な曲刀を手に、ゆっくりと立ち上がる。","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"盗賊王バシム","speaker":"盗賊王バシム","next":"boss_intro_03","choices":[{"label":"続ける","next":"boss_intro_03"}]},"boss_intro_03":{"text":"「砂漠の掟を教えてやる。弱い奴は、死ぬんだよ！」","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"盗賊王バシム","speaker":"盗賊王バシム","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"盗賊王バシムとの決戦！","type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle_boss","enemy_group_id":"9112","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"「ま、待て！ 降参だ、俺の負けだ！」巨体を揺らし、盗賊王は武器を捨てて土下座した。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「命だけは助けてくれ！ あんたには俺が隠し持ってる財宝を全部くれてやる！ 金なら一生遊んで暮らせるだけあるんだ！」","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","speaker_name":"盗賊王バシム","speaker":"盗賊王バシム","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_calm","choices":[{"label":"「悪党の命乞いなど聞く耳を持たん。斬る」","next":"fate_justice_01"},{"label":"「……その話、乗ろう。財宝の場所を吐け」","next":"fate_chaos_01"}]},"fate_justice_01":{"text":"「ひっ、やめっ——！」命乞いをする悪党に容赦なく刃を振り下ろし、その息の根を止めた。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"fate_justice_02","choices":[{"label":"続ける","next":"fate_justice_02"}]},"fate_justice_02":{"text":"盗賊王の首を持ち帰り、ギルドに報告した。「見事だ。これでキャラバンの安全も保たれる」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"end_success_justice","choices":[{"label":"続ける","next":"end_success_justice"}]},"end_success_justice":{"text":"依頼達成。悪を許さぬ正義の刃は、街の商人たちから大いに称賛された。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":"Gold:1200|Exp:180|Rep:8|Justice:5"},"choices":[]},"fate_chaos_01":{"text":"隠し財宝の場所を案内させ、金銀財宝をすべて自分の袋に詰め込んだ。「これでいいだろ？ 見逃してくれよな」","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"fate_chaos_02","choices":[{"label":"続ける","next":"fate_chaos_02"}]},"fate_chaos_02":{"text":"ギルドには「取り逃がした。だがアジトは壊滅させた」と報告した。報酬は少なかったが、そんなものはどうでもいいほどの金を既に手に入れている。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_mystery","next":"end_success_chaos","choices":[{"label":"続ける","next":"end_success_chaos"}]},"end_success_chaos":{"text":"依頼達成……？ ギルドの信用は落ちたが、懐は桁違いに温かくなった。悪党を利用するのも冒険者の生存戦略だ。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":"Gold:2500|Exp:150|Rep:-5|Chaos:5"},"choices":[]},"end_failure":{"text":"盗賊王の曲刀が胴体を薙ぎ払った。「砂漠の砂の養分になりな！」下品な笑い声が遠ざかっていく……。","type":"end","result":"failure","bg_key":"bg_crypt","choices":[]}},"short_description":"[討伐依頼] マルカンド近郊のキャラバンを襲う「砂漠の盗賊王」のアジトを強襲せよ。"}'::jsonb,
