-- Scenario 5113: 妖刀の辻斬り (qst_rep_cursed_blade)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5113,
    'qst_rep_cursed_blade',
    '妖刀の辻斬り',
    '[討伐依頼] 夜な夜な町を徘徊する辻斬り事件の解決。妖刀に憑かれた剣士を討て。',
    '町奉行',
    3,
    12,
    4,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep03","min_reputation":40,"nation_id":"loc_yatoshin"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep03","min_reputation":40,"nation_id":"loc_yatoshin"}'::jsonb,
    '{"nodes":{"start":{"text":"「夜刀神国を騒がせている辻斬りの件、ギルドを通じて貴殿に依頼したい」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"町奉行の使い","speaker":"町奉行の使い","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「犯人は紫の妖気を放つ刀を持っているそうだ。恐らく、古の妖刀に精神を乗っ取られている」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"町奉行の使い","speaker":"町奉行の使い","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「被害者はすでに十数人。これ以上犠牲が出る前に、妖刀ごと奴を斬ってくれ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"町奉行の使い","speaker":"町奉行の使い","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"妖刀の辻斬りか。生半可な剣客では逆に斬られるだけだ。夜の町へ向かう。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"town_01","choices":[{"label":"続ける","next":"town_01"}]},"town_01":{"text":"夜の城下町。人々は辻斬りを恐れて固く戸を閉ざし、通りには誰もいない。","type":"text","bg_key":"bg_yato_street_night","bgm":"bgm_quest_mystery","next":"town_02","choices":[{"label":"続ける","next":"town_02"}]},"town_02":{"text":"足音だけが響く。奴を見つけるにはどうすればいいか。","type":"text","bg_key":"bg_yato_street_night","bgm":"bgm_quest_mystery","next":"choice_search","choices":[{"label":"続ける","next":"choice_search"}]},"choice_search":{"type":"choice","bg_key":"bg_yato_street_night","bgm":"bgm_quest_mystery","choices":[{"label":"「情報屋に金を払い、目撃情報を買う」","next":"info_buy_01"},{"label":"「大通りに立ち、自ら囮になって待つ」","next":"bait_01"}]},"info_buy_01":{"text":"裏路地の情報屋に銀貨を握らせた。「……奴なら、町外れの廃神社に向かったぜ」","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_mystery","next":"info_buy_02","choices":[{"label":"続ける","next":"info_buy_02"}]},"info_buy_02":{"text":"確実な情報を得た。背後を気にすることなく、目的地へ直行する。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_mystery","next":"merge_shrine","choices":[{"label":"続ける","next":"merge_shrine"}]},"bait_01":{"text":"月明かりの下、大通りのど真ん中で目を閉じて気配を探る。……来た！","type":"text","bg_key":"bg_yato_street_night","bgm":"bgm_quest_tense","next":"bait_random","choices":[{"label":"続ける","next":"bait_random"}]},"bait_random":{"type":"random_branch","bg_key":"bg_yato_street_night","bgm":"bgm_quest_tense","prob":50,"next":"bait_success_01","choices":[{"label":"成功","next":"bait_success_01"},{"label":"失敗","next":"bait_fail_01"}]},"bait_success_01":{"text":"背後からの殺気を完璧に読み取り、初撃を弾き返した！ 辻斬りは驚いたように後退し、町外れの廃神社へ逃げていった。","type":"text","bg_key":"bg_yato_street_night","bgm":"bgm_quest_tense","next":"merge_shrine","choices":[{"label":"続ける","next":"merge_shrine"}]},"bait_fail_01":{"text":"殺気に気付くのが遅れた！ 凄まじい踏み込みからの斬撃が迫る！","type":"text","bg_key":"bg_yato_street_night","bgm":"bgm_quest_tense","next":"bait_trap","choices":[{"label":"続ける","next":"bait_trap"}]},"bait_trap":{"text":"間一髪で致命傷は避けたが、肩を斬られた。辻斬りは血の匂いに満足したのか、廃神社の方角へ去っていった。追うぞ。","type":"hp_damage","bg_key":"bg_yato_street_night","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"merge_shrine","choices":[{"label":"続ける","next":"merge_shrine"}]},"merge_shrine":{"text":"町外れの廃神社に到着した。鳥居の向こうから、むせ返るような妖気が漂ってくる。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"shrine_path_01","choices":[{"label":"続ける","next":"shrine_path_01"}]},"shrine_path_01":{"text":"参道を進むと、目に見えない障壁にぶつかった。妖力で編まれた結界だ。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"shrine_path_02","choices":[{"label":"続ける","next":"shrine_path_02"}]},"shrine_path_02":{"text":"周囲には古いお札が散らばっている。これを使えば安全に解けそうだが……。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"choice_barrier","choices":[{"label":"続ける","next":"choice_barrier"}]},"choice_barrier":{"type":"choice","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","choices":[{"label":"「面倒だ。気合で強引に結界を突破する」","next":"barrier_break_01"},{"label":"「周囲を探索し、使えるお札を探す」","next":"barrier_search_01"}]},"barrier_break_01":{"text":"武器に闘気を込め、結界を力任せに打ち破る！","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","next":"barrier_trap","choices":[{"label":"続ける","next":"barrier_trap"}]},"barrier_trap":{"text":"結界が弾ける際の呪詛をまともに浴びた。体力を少し削られたが、道は開いた。","type":"hp_damage","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"merge_boss","choices":[{"label":"続ける","next":"merge_boss"}]},"barrier_search_01":{"text":"草むらを掻き分け、まだ魔力の残っているお札を探す。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"barrier_random","choices":[{"label":"続ける","next":"barrier_random"}]},"barrier_random":{"type":"random_branch","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","prob":60,"next":"search_success_01","choices":[{"label":"成功","next":"search_success_01"},{"label":"失敗","next":"search_fail_01"}]},"search_success_01":{"text":"使えるお札を見つけた。結界に貼り付けると、音もなく障壁が霧散した。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"merge_boss","choices":[{"label":"続ける","next":"merge_boss"}]},"search_fail_01":{"text":"お札を探している最中、結界に引き寄せられた妖怪たちに見つかってしまった！","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","next":"battle_yokai","choices":[{"label":"続ける","next":"battle_yokai"}]},"battle_yokai":{"text":"夜刀妖怪の群れとの戦闘！","type":"battle","bg_key":"bg_yato_shrine","bgm":"bgm_battle","enemy_group_id":"430","choices":[{"label":"win","next":"merge_boss"},{"label":"lose","next":"end_failure"}],"battle_success_next":"merge_boss"},"merge_boss":{"text":"神社の本殿前に辿り着いた。月明かりの中、一人の剣士が立っている。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_tense","next":"boss_intro_01","choices":[{"label":"続ける","next":"boss_intro_01"}]},"boss_intro_01":{"text":"「キル……斬ル……血ガ、タリナイ……」","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_battle_boss","speaker_name":"妖刀の剣士","speaker":"妖刀の剣士","next":"boss_intro_02","choices":[{"label":"続ける","next":"boss_intro_02"}]},"boss_intro_02":{"text":"剣士の目は虚ろで、手にした紫色の妖刀から伸びる魔力の糸に操られているようだ。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_battle_boss","speaker_name":"妖刀の剣士","speaker":"妖刀の剣士","next":"boss_intro_03","choices":[{"label":"続ける","next":"boss_intro_03"}]},"boss_intro_03":{"text":"「オマエノ血デ……刀ヲ潤ス！！」","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_battle_boss","speaker_name":"妖刀の剣士","speaker":"妖刀の剣士","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"妖刀の剣客との決戦！","type":"battle","bg_key":"bg_yato_shrine","bgm":"bgm_battle_boss","enemy_group_id":"9113","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"剣士が膝から崩れ落ちる。同時に、手から離れた妖刀の禍々しい光が消え失せた。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"剣士はすでに息絶えていた。残された妖刀からは、未だに微かな魔力を感じる。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","choices":[{"label":"「神社の祭壇に奉納し、お札で封印・浄化する」","next":"fate_order_01"},{"label":"「町奉行には処分したと嘘をつき、持ち帰る」","next":"fate_chaos_01"}]},"fate_order_01":{"text":"このままにしては新たな被害者が出る。神社の祭壇に妖刀を安置し、周囲のお札で封印した。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_calm","next":"fate_order_02","choices":[{"label":"続ける","next":"fate_order_02"}]},"fate_order_02":{"text":"町奉行に事件の顛末を報告した。「見事な差配だ。これで町に平穏が戻るだろう」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"end_success_order","choices":[{"label":"続ける","next":"end_success_order"}]},"end_success_order":{"text":"依頼達成。誘惑に負けず正しき行いをしたことで、名声と秩序が高まった。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":"Gold:1500|Exp:200|Rep:15|Order:5"},"choices":[]},"fate_chaos_01":{"text":"布で刀身を厳重に包み、背中に背負った。使い方次第で、これは強力な武器になる。","type":"text","bg_key":"bg_yato_shrine","bgm":"bgm_quest_mystery","next":"fate_chaos_02","choices":[{"label":"続ける","next":"fate_chaos_02"}]},"fate_chaos_02":{"text":"町奉行には「妖刀は完全に破壊した」と報告した。偽りの報告で報酬を受け取る。背中の刀が、微かに喜ぶように震えた気がした。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_mystery","next":"end_success_chaos","choices":[{"label":"続ける","next":"end_success_chaos"}]},"end_success_chaos":{"text":"依頼達成。嘘をつき妖刀を手に入れた。禁忌の力は、いつか我が身を助ける（滅ぼす）かもしれない。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":"Gold:1500|Exp:200|Rep:10|Chaos:5"},"choices":[]},"end_failure":{"text":"妖刀が首筋を捉えた。冷たい刃が肉を断つ感触。最後に見たのは、刀が自分の血を啜る恐ろしい光景だった。","type":"end","result":"failure","bg_key":"bg_yato_shrine","choices":[]}},"short_description":"[討伐依頼] 夜な夜な町を徘徊する辻斬り事件の解決。妖刀に憑かれた剣士を討て。"}'::jsonb,
    4,
    2
