-- Scenario 5114: 偽りの邪仙 (qst_rep_false_sage)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5114,
    'qst_rep_false_sage',
    '偽りの邪仙',
    '[討伐依頼] 不死の薬と偽って毒を売り捌き、村人を洗脳する「邪仙」を討伐せよ。',
    '地方役人',
    3,
    13,
    4,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep03","min_reputation":40,"nation_id":"loc_haryu"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep03","min_reputation":40,"nation_id":"loc_haryu"}'::jsonb,
    '{"nodes":{"start":{"text":"「辺境の山にある道観で、邪悪な術師が『不死の薬』と称して村人たちを洗脳しておる」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"地方役人","speaker":"地方役人","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「薬を飲んだ者は廃人となり、ただ彼奴の命令に従うだけの人形と化すのだ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"地方役人","speaker":"地方役人","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「どうか、あの偽りの仙人を討伐し、村人たちを解放してやってくれ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"地方役人","speaker":"地方役人","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"不死の薬などあるはずがない。人々の弱みにつけ込む外道を討つため、山へ向かう。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"華龍国の辺境。険しい山道を登っていくと、周囲に濃い霧が立ち込めてきた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"ただの霧ではない。霊力を帯びた幻術の霧だ。方向感覚が狂わされる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"mountain_01","choices":[{"label":"続ける","next":"mountain_01"}]},"mountain_01":{"text":"この霧を抜けた先に、目当ての道観があるはずだ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"mountain_02","choices":[{"label":"続ける","next":"mountain_02"}]},"mountain_02":{"text":"どうやって進む？ ギルドで買った霊符を使えば霧を払えるが、術者に気付かれる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"choice_mist","choices":[{"label":"続ける","next":"choice_mist"}]},"choice_mist":{"type":"choice","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","choices":[{"label":"「気付かれないよう、霧の中を勘で進む」","next":"mist_walk_01"},{"label":"「霊符を使って強引に霧を払い、道を開く」","next":"mist_clear_01"}]},"mist_walk_01":{"text":"幻術に惑わされないよう、精神を集中させて霧の中を歩く……。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"mist_random","choices":[{"label":"続ける","next":"mist_random"}]},"mist_random":{"type":"random_branch","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","prob":50,"next":"mist_success_01","choices":[{"label":"成功","next":"mist_success_01"},{"label":"失敗","next":"mist_fail_01"}]},"mist_success_01":{"text":"見事、幻術を打ち破り、道観への正しいルートを見つけ出した。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"merge_temple","choices":[{"label":"続ける","next":"merge_temple"}]},"mist_fail_01":{"text":"しまった、同じ場所をぐるぐると回っている！ 幻術が精神を蝕む……！","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"mist_trap","choices":[{"label":"続ける","next":"mist_trap"}]},"mist_trap":{"text":"精神的な疲労により、体力を大きく消耗した。","type":"hp_damage","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"mist_fail_02","choices":[{"label":"続ける","next":"mist_fail_02"}]},"mist_fail_02":{"text":"数時間の彷徨の末、なんとか霧を抜け、道観の入り口に辿り着いた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"merge_temple","choices":[{"label":"続ける","next":"merge_temple"}]},"mist_clear_01":{"text":"霊符を掲げると、霧が晴れ道が開けた！ だが同時に、侵入者に気付いたキョンシーたちが襲いかかってきた！","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"text":"道観の門番（キョンシー）との戦闘！","type":"battle","bg_key":"bg_karyu_mountain","bgm":"bgm_battle","enemy_group_id":"440","choices":[{"label":"win","next":"merge_temple"},{"label":"lose","next":"end_failure"}],"battle_success_next":"merge_temple"},"merge_temple":{"text":"道観の内部に潜入した。強いお香の匂いが漂っている。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"temple_01","choices":[{"label":"続ける","next":"temple_01"}]},"temple_01":{"text":"中庭には、虚ろな目をした村人たちがうろついていた。皆、洗脳されている。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"temple_02","choices":[{"label":"続ける","next":"temple_02"}]},"temple_02":{"text":"彼らは侵入者であるこちらに気づき、武器（農具）を構えて立ちはだかった！","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"choice_villagers","choices":[{"label":"続ける","next":"choice_villagers"}]},"choice_villagers":{"type":"choice","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","choices":[{"label":"「峰打ちで気絶させ、強行突破する」","next":"villager_force_01"},{"label":"「大声で呼びかけ、正気に戻そうとする」","next":"villager_talk_01"}]},"villager_force_01":{"text":"彼らを殺すわけにはいかない。武器の峰で一人ずつ気絶させていく。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"villager_trap","choices":[{"label":"続ける","next":"villager_trap"}]},"villager_trap":{"text":"手加減をした隙を突かれ、鍬で殴られた！ 痛手を負ったが全員無力化した。","type":"hp_damage","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"villager_force_02","choices":[{"label":"続ける","next":"villager_force_02"}]},"villager_force_02":{"text":"息を整え、邪仙のいる本堂へと急ぐ。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"merge_boss","choices":[{"label":"続ける","next":"merge_boss"}]},"villager_talk_01":{"text":"「目を覚ませ！ お前たちは騙されているんだ！」大声で呼びかけ、隙を突こうとする。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"villager_random","choices":[{"label":"続ける","next":"villager_random"}]},"villager_random":{"type":"random_branch","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","prob":60,"next":"talk_success_01","choices":[{"label":"成功","next":"talk_success_01"},{"label":"失敗","next":"talk_fail_01"}]},"talk_success_01":{"text":"村人の一人がハッと我に返った。連鎖的に他の者も動きを止め、その隙に奥へ進む。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"merge_boss","choices":[{"label":"続ける","next":"merge_boss"}]},"talk_fail_01":{"text":"言葉は届かない！ 洗脳は思いのほか深く、彼らは狂乱状態で襲いかかってきた！","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"battle_villager","choices":[{"label":"続ける","next":"battle_villager"}]},"battle_villager":{"text":"洗脳された村人たちとの戦闘！","type":"battle","bg_key":"bg_karyu_palace","bgm":"bgm_battle","enemy_group_id":"443","choices":[{"label":"win","next":"merge_boss"},{"label":"lose","next":"end_failure"}],"battle_success_next":"merge_boss"},"merge_boss":{"text":"本堂に突入した。祭壇の前に、胡散臭い道着を着た男が立っている。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_tense","next":"boss_intro_01","choices":[{"label":"続ける","next":"boss_intro_01"}]},"boss_intro_01":{"text":"「愚かな冒険者よ。我が不死の霊薬を邪魔しに来たか」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_battle_boss","speaker_name":"邪仙・道士","speaker":"邪仙・道士","next":"boss_intro_02","choices":[{"label":"続ける","next":"boss_intro_02"}]},"boss_intro_02":{"text":"男が懐から札を取り出すと、周囲の空気が禍々しい妖気で満たされた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_battle_boss","speaker_name":"邪仙・道士","speaker":"邪仙・道士","next":"boss_intro_03","choices":[{"label":"続ける","next":"boss_intro_03"}]},"boss_intro_03":{"text":"「貴様も我が薬の材料にしてくれるわ！」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_battle_boss","speaker_name":"邪仙・道士","speaker":"邪仙・道士","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"邪仙・道士との決戦！","type":"battle","bg_key":"bg_karyu_palace","bgm":"bgm_battle_boss","enemy_group_id":"9114","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"邪仙が倒れ伏す。彼の使っていた怪しい薬壺をすべて叩き割った。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"外に出ると、正気に戻りつつある村人たちが集まってきた。「我々を導いてくださった仙人様は……？」","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","choices":[{"label":"「あれは偽者だ。お前たちは毒で操られていたんだ」","next":"fate_justice_01"},{"label":"「彼は天に帰った。これからは自分たちの足で生きろ」","next":"fate_chaos_01"}]},"fate_justice_01":{"text":"厳しい真実を告げる。村人たちは絶望し泣き崩れたが、やがて現実を受け入れた。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_calm","next":"fate_justice_02","choices":[{"label":"続ける","next":"fate_justice_02"}]},"fate_justice_02":{"text":"役人に報告を終えた。「真実を知らねば、人はまた同じ過ちを繰り返す。正しい選択だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"end_success_justice","choices":[{"label":"続ける","next":"end_success_justice"}]},"end_success_justice":{"text":"依頼達成。苦い真実を与え、正しき道を示した。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":"Gold:1800|Exp:220|Rep:10|Justice:5"},"choices":[]},"fate_chaos_01":{"text":"真実を隠し、美しい嘘をついた。村人たちは祈りを捧げ、穏やかな顔で山を下りていった。","type":"text","bg_key":"bg_karyu_palace","bgm":"bgm_quest_mystery","next":"fate_chaos_02","choices":[{"label":"続ける","next":"fate_chaos_02"}]},"fate_chaos_02":{"text":"役人には討伐の事実だけを報告した。「平和になったのなら、真実などどうでもよいことだ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_mystery","next":"end_success_chaos","choices":[{"label":"続ける","next":"end_success_chaos"}]},"end_success_chaos":{"text":"依頼達成。嘘で安寧を与えた。時には混沌とした対応が人々を救うこともある。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":"Gold:1800|Exp:220|Rep:10|Chaos:5"},"choices":[]},"end_failure":{"text":"邪仙の放つ毒薬を吸い込み、意識が混濁する。「さあ、お前も我が人形となるのだ……」","type":"end","result":"failure","bg_key":"bg_karyu_palace","choices":[]}},"short_description":"[討伐依頼] 不死の薬と偽って毒を売り捌き、村人を洗脳する「邪仙」を討伐せよ。"}'::jsonb,
    4,
    2
