-- Scenario 5201: 聖騎士団の叛逆者 (qst_rep_crusader)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5201,
    'qst_rep_crusader',
    '聖騎士団の叛逆者',
    '[討伐令] 聖騎士団を脱走した元団長が辺境で反乱。鎮圧せよ。',
    '王国軍',
    4,
    15,
    6,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep05","min_reputation":50,"nation_id":"loc_holy_empire"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep05","min_reputation":50,"nation_id":"loc_holy_empire"}'::jsonb,
    '{"nodes":{"start":{"text":"「名声ある冒険者殿、急ぎの案件だ。聖騎士団から脱走者が出た」","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","speaker_name":"王国軍将校","speaker":"王国軍将校","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「元団長ガレス。聖騎士団最強と謳われた男だ」","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","speaker_name":"王国軍将校","speaker":"王国軍将校","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（ガレス元団長か。その名は王都だけでなく、隣国にまで轟いている）","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「奴は教会の腐敗を糾弾し、精鋭を率いて辺境へ逃亡したのだ」","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","speaker_name":"王国軍将校","speaker":"王国軍将校","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"将校の怒りに満ちた声が、重厚な執務室の木壁に反射する。","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"将校の表情は険しい。元団長の脱走は王国の威信に関わる問題だ。","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","next":"prepare_01","choices":[{"label":"続ける","next":"prepare_01"}]},"prepare_01":{"text":"ガレスの情報を集める。彼は辺境のルヴァン廃城を拠点に、教会の輸送隊を襲撃しているらしい。","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","next":"prepare_01_02","choices":[{"label":"続ける","next":"prepare_01_02"}]},"prepare_01_02":{"text":"（輸送隊を襲撃しているが、商人の護衛を殺害したという報告はないな）","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","next":"prepare_02","choices":[{"label":"続ける","next":"prepare_02"}]},"prepare_02":{"text":"聖騎士の装備は一級品。正面から挑めば苦戦は必至だ。慎重に作戦を練る必要がある。","type":"text","bg_key":"bg_office","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"ルヴァン廃城へ向かう。街道の途中、襲撃された輸送隊の残骸を見つけた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"（散乱した木箱や荷車……襲撃の跡は生々しいが、やはり血痕が見当たらん）","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"荷が散乱しているが、人の遺体はない。ガレスは略奪はしても殺しはしていないようだ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"approach_01","choices":[{"label":"続ける","next":"approach_01"}]},"approach_01":{"text":"廃城が見えてきた。崩れかけた城壁の上に、見張りの聖騎士が立っている。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"approach_01_02","choices":[{"label":"続ける","next":"approach_01_02"}]},"approach_01_02":{"text":"（流石は元精鋭たちだ。無駄のない立ち振る舞いで周囲を警戒している）","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"approach_02","choices":[{"label":"続ける","next":"approach_02"}]},"approach_02":{"text":"正門は堅固に守られている。だが、城壁の東側に崩れた箇所がある。どちらから入るか——","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"choice_route","choices":[{"label":"続ける","next":"choice_route"}]},"choice_route":{"type":"choice","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","choices":[{"label":"「正面から堂々と突入する」","next":"front_01"},{"label":"「崩れた城壁から裏口潜入する」","next":"sneak_01"}]},"front_01":{"text":"正門に向かって歩を進める。見張りが気づき、角笛を吹いた。敵が集まってくる。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"front_02","choices":[{"label":"続ける","next":"front_02"}]},"front_02":{"text":"「侵入者だ！ 団長に報告しろ！」聖騎士たちが武器を構えて立ちはだかる。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"front_02_02","choices":[{"label":"続ける","next":"front_02_02"}]},"front_02_02":{"text":"（数は三人……手強いが、ここを引き下がるわけにはいかない！）","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"front_03","choices":[{"label":"続ける","next":"front_03"}]},"front_03":{"text":"正面突破しかない。覚悟を決めて剣を抜く。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"battle_gate","choices":[{"label":"続ける","next":"battle_gate"}]},"battle_gate":{"type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle","enemy_group_id":"416","choices":[{"label":"win","next":"merge_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"merge_01"},"sneak_01":{"text":"崩れた城壁の隙間を慎重に進む。瓦礫が不安定で、一歩間違えれば崩れ落ちる。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_mystery","next":"sneak_02","choices":[{"label":"続ける","next":"sneak_02"}]},"sneak_02":{"text":"城壁の内側に出た。だが足元の石が崩れ、瓦礫の下敷きになりかける——！","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_mystery","next":"sneak_02_02","choices":[{"label":"続ける","next":"sneak_02_02"}]},"sneak_02_02":{"text":"（くっ、崩落するか！ 重心を受け流し、素早く横へ跳び退く！）","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_mystery","next":"sneak_trap","choices":[{"label":"続ける","next":"sneak_trap"}]},"sneak_trap":{"text":"瓦礫が崩落し、足を挟まれた。なんとか引き抜いたが、傷を負った。","type":"hp_damage","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"sneak_03","choices":[{"label":"続ける","next":"sneak_03"}]},"sneak_03":{"text":"傷は浅い。城の内部へ忍び込むことに成功した。見張りには気づかれていない。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_mystery","next":"merge_01","choices":[{"label":"続ける","next":"merge_01"}]},"merge_01":{"text":"廃城の内部は意外と整えられていた。脱走兵たちが生活している痕跡がある。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"merge_01_02","choices":[{"label":"続ける","next":"merge_01_02"}]},"merge_01_02":{"text":"（略奪物だけでなく、聖堂の古い書物などが綺麗に並べられているな）","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"merge_02","choices":[{"label":"続ける","next":"merge_02"}]},"merge_02":{"text":"壁には「真の信仰を取り戻せ」と書かれた檄文が貼られている。ガレスの信念が窺える。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"inner_01","choices":[{"label":"続ける","next":"inner_01"}]},"inner_01":{"text":"城の奥へ進むと、武装した聖騎士が通路を塞いでいる。ガレスの親衛隊だ。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"inner_01_02","choices":[{"label":"続ける","next":"inner_01_02"}]},"inner_01_02":{"text":"（大剣を構える姿勢に隙がない。これが白銀の剣の直属か）","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"inner_02","choices":[{"label":"続ける","next":"inner_02"}]},"inner_02":{"text":"「ここから先は通さん。団長の邪魔をする者は——たとえ何者であろうとな！」","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle","enemy_group_id":"413","choices":[{"label":"win","next":"confront_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"confront_01"},"confront_01":{"text":"親衛隊を倒し、最奥の大広間に辿り着いた。玉座に腰掛ける男がいる。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_mystery","next":"confront_01_02","choices":[{"label":"続ける","next":"confront_01_02"}]},"confront_01_02":{"text":"その男は重厚な甲冑をまとい、静かにこちらを待っていた。彼がガレスだ。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_mystery","next":"confront_02","choices":[{"label":"続ける","next":"confront_02"}]},"confront_02":{"text":"「……来たか。噂は聞いている。名声高き冒険者よ」","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_battle_boss","speaker_name":"ガレス","speaker":"ガレス","next":"confront_03","choices":[{"label":"続ける","next":"confront_03"}]},"confront_03":{"text":"「自分は教会の腐敗を正したいだけだ。だが、お前が王国の犬として来たのなら——剣で語ろう」","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_battle_boss","speaker_name":"ガレス","speaker":"ガレス","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_ruins_field","bgm":"bgm_battle_boss","enemy_group_id":"9061","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"ガレスの剣が折れ、片膝をついた。だがその目に敗者の色はない。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"（あれほどの使い手を圧倒したか……。だが、彼に未だ戦意は感じられない）","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……見事だ。お前の強さは本物だ。……さて、自分をどうする？ 縛って王国に差し出すか？ それとも——」","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","speaker_name":"ガレス","speaker":"ガレス","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","choices":[{"label":"「王国の命令だ。抵抗するなら力ずくで連行する」","next":"suppress_01"},{"label":"「お前の言い分もわかる。自首するなら口添えしてやる」","next":"persuade_01"}]},"suppress_01":{"text":"ガレスを拘束した。部下たちは抵抗したが、団長の命令で武器を置いた。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"suppress_01_02","choices":[{"label":"続ける","next":"suppress_01_02"}]},"suppress_01_02":{"text":"（ガレスは無言のまま、自分の両腕を縄に差し出してきた）","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"suppress_02","choices":[{"label":"続ける","next":"suppress_02"}]},"suppress_02":{"text":"王国軍にガレスを引き渡した。叛逆者として裁かれるだろう。秩序は保たれた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「叛逆者ガレスの拘束を確認。王国の秩序を守った功績、高く評価する」\n報奨金と名声を受け取った。だがガレスの言葉が、胸に残った。","type":"end","result":"success","bg_key":"bg_church","params":{"rewards":{"gold":3000,"exp":350,"reputation":15,"alignment_shift":{"order":5}}},"choices":[]},"persuade_01":{"text":"「……自首、か。教会の腐敗を公に訴えられるなら、それも悪くない」","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","speaker_name":"ガレス","speaker":"ガレス","next":"persuade_01_02","choices":[{"label":"続ける","next":"persuade_01_02"}]},"persuade_01_02":{"text":"（彼の瞳にわずかな希望の光が灯る。無益な血は流れなかった）","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","next":"persuade_02","choices":[{"label":"続ける","next":"persuade_02"}]},"persuade_02":{"text":"ガレスは部下たちに武器を置くよう命じた。「剣ではなく、言葉で戦おう」","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_calm","next":"persuade_03","choices":[{"label":"続ける","next":"persuade_03"}]},"persuade_03":{"text":"ガレスと共に王都へ向かった。道中、彼は教会の内部事情を語った。その告発は重い。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success_peace","choices":[{"label":"続ける","next":"end_success_peace"}]},"end_success_peace":{"text":"ガレスは自首し、教会の腐敗を公に告発した。報酬は減額されたが、正義の種は蒔かれた。\n王国軍は面目を失ったが、民衆からの評価は高まった。","type":"end","result":"success","bg_key":"bg_church","params":{"rewards":{"gold":2000,"exp":300,"reputation":20,"alignment_shift":{"justice":5}}},"choices":[]},"end_failure_01":{"text":"ガレスの放った白銀の剣閃が視界を埋める。激痛とともに崩れ落ちた。","type":"text","bg_key":"bg_ruins_field","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"ガレスの聖剣が閃き、意識が遠のいた。「お前では自分は止められぬ。出直してこい」","type":"end","result":"failure","bg_key":"bg_ruins_field","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[討伐令] 聖騎士団を脱走した元団長が辺境で反乱。鎮圧せよ。"}'::jsonb,
    6,
    3
) ON CONFLICT (id) DO UPDATE SET
