    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 5202: 砂漠の僭王 (qst_rep_sand_king)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5202,
    'qst_rep_sand_king',
    '砂漠の僭王',
    '[緊急依頼] 砂漠の交易路を支配する「砂の王」を排除せよ。',
    '交易商会',
    4,
    16,
    6,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep05","min_reputation":60,"nation_id":"loc_marcund"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep05","min_reputation":60,"nation_id":"loc_marcund"}'::jsonb,
    '{"nodes":{"start":{"text":"「交易路が完全に止まっている。砂塵の王国に仇なす『砂の王』のせいだ」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"商会長","speaker":"商会長","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「奴は元傭兵団長だ。砂漠の地理を知り尽くし、精鋭を百人以上抱えている」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"商会長","speaker":"商会長","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（砂漠の傭兵団か。砂嵐を利用した奇襲を得意とする厄介な集団だな）","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「正面からは厳しい。まずオアシスの町で情報を集めてくれ」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"商会長","speaker":"商会長","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"商会長は焦燥しきった様子で、書類の山を荒々しく叩いた。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"報酬は破格だ。それだけ商会も追い詰められているということだろう。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"砂漠の街道を東へ進む。途中、襲撃された隊商の残骸を幾つも見た。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"（焼け焦げた馬車から細い煙が昇っている。まだ襲撃から間もないようだ）","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"砂の王の配下は組織的だ。見張り、伝令、襲撃部隊——軍隊のように統制されている。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"oasis_01","choices":[{"label":"続ける","next":"oasis_01"}]},"oasis_01":{"text":"オアシスの町に着いた。砂の王の影響で町は閑散としている。情報を集める方法は二つ。","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_calm","next":"oasis_01_02","choices":[{"label":"続ける","next":"oasis_01_02"}]},"oasis_01_02":{"text":"（砂の舞うオアシスで怪しまれずに動くには、変装が必要だな）","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_calm","next":"choice_intel","choices":[{"label":"続ける","next":"choice_intel"}]},"choice_intel":{"type":"choice","bg_key":"bg_memory_oasis","bgm":"bgm_quest_calm","choices":[{"label":"「酒場で傭兵たちから情報を聞き出す」","next":"tavern_01"},{"label":"「闇市で砂の王の内通者を探す」","next":"black_01"}]},"tavern_01":{"text":"酒場に入ると、元傭兵らしき男たちが酒を飲んでいる。金を渡して話を聞く。","type":"text","bg_key":"bg_tavern_day","bgm":"bgm_quest_calm","next":"tavern_01_02","choices":[{"label":"続ける","next":"tavern_01_02"}]},"tavern_01_02":{"text":"（男は渡された金貨を素早く懐に収め、周囲を警戒しながら口を開いた）","type":"text","bg_key":"bg_tavern_day","bgm":"bgm_quest_calm","next":"tavern_02","choices":[{"label":"続ける","next":"tavern_02"}]},"tavern_02":{"text":"「砂の王の砦は砂丘の裏にある。護衛は交代制で、夜明け前が最も手薄だ」","type":"text","bg_key":"bg_tavern_day","bgm":"bgm_quest_calm","speaker_name":"元傭兵","speaker":"元傭兵","next":"tavern_03","choices":[{"label":"続ける","next":"tavern_03"}]},"tavern_03":{"text":"有益な情報を得た。護衛の弱点を突けば、前哨戦の突破が楽になるだろう。","type":"text","bg_key":"bg_tavern_day","bgm":"bgm_quest_calm","next":"inner_01_02","choices":[{"label":"続ける","next":"inner_01_02"}]},"black_01":{"text":"闇市の路地裏を歩く。怪しげな商人に声をかけ、内通者の情報を探る。","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_mystery","next":"black_01_02","choices":[{"label":"続ける","next":"black_01_02"}]},"black_01_02":{"text":"（薄暗い露店の影から、布で顔を覆った商人が手招きしている）","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_mystery","next":"black_02","choices":[{"label":"続ける","next":"black_02"}]},"black_02":{"text":"「内通者？ いるにはいるが——代償が必要だ」商人が笑う。罠かもしれない。","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_mystery","next":"black_02_02","choices":[{"label":"続ける","next":"black_02_02"}]},"black_02_02":{"text":"（商人の目が怪しく光った瞬間、背後の暗闇から殺気が膨れ上がった！）","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_mystery","next":"black_trap","choices":[{"label":"続ける","next":"black_trap"}]},"black_trap":{"text":"案の定、罠だった！ 路地裏で刺客に襲われた。なんとか撃退するが傷を負う。","type":"hp_damage","bg_key":"bg_memory_oasis","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"black_03","choices":[{"label":"続ける","next":"black_03"}]},"black_03":{"text":"刺客を尋問し、砂の王の内部事情を聞き出した。部下の不満が溜まっているらしい。","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_mystery","next":"merge_approach","choices":[{"label":"続ける","next":"merge_approach"}]},"merge_approach":{"text":"情報を元に、砂の王の砦を目指す。砂丘を越えた先に、岩壁に囲まれた要塞が見えた。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"desert_01","choices":[{"label":"続ける","next":"desert_01"}]},"desert_01":{"text":"砂嵐が近づいている。嵐に紛れて接近するか——","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"desert_01_02","choices":[{"label":"続ける","next":"desert_01_02"}]},"desert_01_02":{"text":"（叩きつけるような砂と風が、視界を遮る盾となってくれている）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"desert_02","choices":[{"label":"続ける","next":"desert_02"}]},"desert_02":{"text":"砂嵐の中を突き進み、要塞の壁際まで辿り着いた。見張りの姿は見えない。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"fortress_01","choices":[{"label":"続ける","next":"fortress_01"}]},"fortress_01":{"text":"要塞の入口に、砂の王の精鋭が待ち構えている。突破するしかない。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"fortress_01_02","choices":[{"label":"続ける","next":"fortress_01_02"}]},"fortress_01_02":{"text":"（精鋭部隊の構える盾が隙間なく並び、強固な陣形を敷いている）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"fortress_02","choices":[{"label":"続ける","next":"fortress_02"}]},"fortress_02":{"text":"「何者だ！ ここは砂の王の領土だ！ 帰るなら今のうちだぞ！」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"type":"battle","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle","enemy_group_id":"421","choices":[{"label":"win","next":"inner_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"inner_01"},"inner_01":{"text":"要塞の内部は予想以上に豪華だった。略奪品で飾られた廊下を進む。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"inner_01_02","choices":[{"label":"続ける","next":"inner_01_02"}]},"inner_01_02":{"text":"（砂漠の過酷な環境とは対照的な、贅を尽くした絨毯が敷かれている）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"inner_02","choices":[{"label":"続ける","next":"inner_02"}]},"inner_02":{"text":"壁に掛かった武器は一級品ばかり。砂の王は相当な財を蓄えているようだ。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"inner_03","choices":[{"label":"続ける","next":"inner_03"}]},"inner_03":{"text":"奥の大広間に、一段高い玉座が見える。そこに座る男が——砂の王だ。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"throne_01","choices":[{"label":"続ける","next":"throne_01"}]},"throne_01":{"text":"「ほう……商会の犬が来たか。自分の砦に単身で乗り込むとは、大したものだ」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","speaker_name":"砂の王","speaker":"砂の王","next":"throne_01_02","choices":[{"label":"続ける","next":"throne_01_02"}]},"throne_01_02":{"text":"（男は獰猛な笑みを浮かべ、玉座の脇に立てかけてあった巨刀を引き抜いた）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","next":"throne_02","choices":[{"label":"続ける","next":"throne_02"}]},"throne_02":{"text":"「だが砂漠の王は自分だ。この地で生き延びたければ、自分に跪け」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","speaker_name":"砂の王","speaker":"砂の王","next":"throne_03","choices":[{"label":"続ける","next":"throne_03"}]},"throne_03":{"text":"砂の王が立ち上がった。巨大な湾刀を抜き、殺気が部屋を満たす。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","enemy_group_id":"9062","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"砂の王が膝をついた。湾刀が床に転がる。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"（激しい息を吐きながら、彼は不敵な笑みを浮かべてこちらを見上げている）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……見事だ。好きにしろ。だが自分を殺しても、次の王が現れるだけだ」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","speaker_name":"砂の王","speaker":"砂の王","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","choices":[{"label":"「商会の依頼通り、討伐する」","next":"slay_01"},{"label":"「お前の組織を内側から瓦解させる。協力しろ」","next":"betray_01"}]},"slay_01":{"text":"砂の王を討った。部下たちは散り散りに逃走した。交易路は再び開かれる。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"slay_01_02","choices":[{"label":"続ける","next":"slay_01_02"}]},"slay_01_02":{"text":"（主を失った要塞から、略奪者どもが慌てて逃げ去っていく足音が響く）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"slay_02","choices":[{"label":"続ける","next":"slay_02"}]},"slay_02":{"text":"商会に討伐の証拠を持ち帰った。正当な報酬が支払われた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「砂の王の討伐を確認。交易路は復活した。感謝する」\n冒険者としての実力を、砂漠の民にも示した。","type":"end","result":"success","bg_key":"bg_marcund","params":{"rewards":{"gold":3500,"exp":350,"reputation":15,"alignment_shift":{"chaos":5}}},"choices":[]},"betray_01":{"text":"「……瓦解だと？ 自分を生かしておいて、何を企む」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","speaker_name":"砂の王","speaker":"砂の王","next":"betray_01_02","choices":[{"label":"続ける","next":"betray_01_02"}]},"betray_01_02":{"text":"（冷酷な交渉を持ちかけると、砂の王は値踏みするように目を細めた）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"betray_02","choices":[{"label":"続ける","next":"betray_02"}]},"betray_02":{"text":"砂の王の部下たちに「王は倒された」と偽情報を流す。組織は内部から崩壊を始めた。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"betray_03","choices":[{"label":"続ける","next":"betray_03"}]},"betray_03":{"text":"砂の王を「生かさず殺さず」の状態で放置し、混乱の中で要塞の財宝を回収した。汚い仕事だ。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"end_success_evil","choices":[{"label":"続ける","next":"end_success_evil"}]},"end_success_evil":{"text":"商会には「組織は壊滅した」と報告。裏で回収した財宝の分け前は——帳簿には載らない。\n名声は地に落ちたが、懐は潤った。","type":"end","result":"success","bg_key":"bg_slums","params":{"rewards":{"gold":4500,"exp":250,"reputation":-20,"alignment_shift":{"evil":8}}},"choices":[]},"end_failure_01":{"text":"砂の王が振るう巨刀が防具ごと肉を裂く。熱い砂の上に倒れ込んだ。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"砂の王の湾刀が閃き、砂漠の熱風と共に意識が途切れた。","type":"end","result":"failure","bg_key":"bg_pyramid_chamber","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[緊急依頼] 砂漠の交易路を支配する「砂の王」を排除せよ。"}'::jsonb,
    6,
    3
