-- Scenario 5203: 鬼将軍の再臨 (qst_rep_oni_general)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5203,
    'qst_rep_oni_general',
    '鬼将軍の再臨',
    '[退魔依頼] 古戦場に百年前の鬼将の亡霊が復活。周辺の村が脅かされている。',
    '代官所',
    4,
    16,
    6,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep05","min_reputation":60,"nation_id":"loc_yatoshin"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep05","min_reputation":60,"nation_id":"loc_yatoshin"}'::jsonb,
    '{"nodes":{"start":{"text":"「北の古戦場から、異様な報告が届いている。百年前の亡霊が蘇ったと」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"代官","speaker":"代官","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「鬼将・蛮骨。百年前の大合戦で討たれたはずの鬼の大将だ」","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","speaker_name":"代官","speaker":"代官","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（蛮骨……。夜刀神国の歴史書に必ず名が出る、伝説的な大悪鬼だな）","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"代官の顔は蒼い。蛮骨の名は今なお夜刀の民を震え上がらせる。名声ある者でなければ引き受ける者はいまい。","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"（代官は小刻みに手を震わせながら、厳重に封をされた依頼書を手渡した）","type":"text","bg_key":"bg_yato_city","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"古戦場へ向かう。道中、逃げてきた村人たちとすれ違った。目に恐怖が浮かんでいる。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"（彼らは着の身着のままで、背後の荒野を恐れるように何度も振り返っていた）","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"古戦場が近づくと、空気が変わった。冷たく、重い——瘴気だ。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"field_01","choices":[{"label":"続ける","next":"field_01"}]},"field_01":{"text":"古戦場に入った。地面には錆びた武具が散乱し、霧が立ち込めている。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"field_01_02","choices":[{"label":"続ける","next":"field_01_02"}]},"field_01_02":{"text":"（百年前の血を吸った土壌から、青白い怨念の霧が絶え間なく湧き出ている）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"field_02","choices":[{"label":"続ける","next":"field_02"}]},"field_02":{"text":"濃い霧の中では方向感覚が狂う。正しい道を見極められるか——","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"random_fog","choices":[{"label":"続ける","next":"random_fog"}]},"random_fog":{"type":"random_branch","bg_key":"bg_forest_night","prob":60,"choices":[{"label":"success","next":"safe_path"},{"label":"failure","next":"lost_01"}]},"safe_path":{"text":"風向きを読み、霧の薄い方向へ進んだ。古戦場の中心部が見えてきた。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"safe_path_02","choices":[{"label":"続ける","next":"safe_path_02"}]},"safe_path_02":{"text":"体力を温存したまま、古戦場の核心部に到達できた。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"lost_01","choices":[{"label":"続ける","next":"lost_01"}]},"lost_01":{"text":"霧に惑わされ、足元の朽ちた武具に足を取られた——","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"lost_01_02","choices":[{"label":"続ける","next":"lost_01_02"}]},"lost_01_02":{"text":"（底なしの泥濘と、刃のように鋭い瓦礫が足元を襲う！）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"lost_trap","choices":[{"label":"続ける","next":"lost_trap"}]},"lost_trap":{"text":"地面に埋まっていた古い槍が足を貫いた！ 百年前の罠がまだ生きているのか。","type":"hp_damage","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"lost_02","choices":[{"label":"続ける","next":"lost_02"}]},"lost_02":{"text":"傷を手当てし、なんとか古戦場の中心部に辿り着いた。体力は削られたが、進むしかない。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"lost_02_02","choices":[{"label":"続ける","next":"lost_02_02"}]},"lost_02_02":{"text":"（痛む足を引きずりながら、怨念の渦巻く中心地へと足を進める）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"merge_battle","choices":[{"label":"続ける","next":"merge_battle"}]},"merge_battle":{"text":"霧の中から、青白い炎をまとった兵士たちが現れた。百年前の亡霊兵だ。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"battle_ghost","choices":[{"label":"続ける","next":"battle_ghost"}]},"battle_ghost":{"type":"battle","bg_key":"bg_forest_night","bgm":"bgm_battle","enemy_group_id":"416","choices":[{"label":"win","next":"deeper_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"deeper_01"},"deeper_01":{"text":"亡霊兵を退けると、霧が少し晴れた。古戦場の最奥に、朽ちた陣屋が見える。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"deeper_01_02","choices":[{"label":"続ける","next":"deeper_01_02"}]},"deeper_01_02":{"text":"（かつての大将軍が腰掛けたであろう、戦塵に塗れた幕舎が厳かに佇んでいる）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"deeper_02","choices":[{"label":"続ける","next":"deeper_02"}]},"deeper_02":{"text":"陣屋の周囲には、百年前の武将旗が風に揺れている。蛮骨の本陣だ。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"deeper_02_02","choices":[{"label":"続ける","next":"deeper_02_02"}]},"deeper_02_02":{"text":"（破れた旗には、蛮骨の家紋が黒々とした怨念のオーラを帯びて浮かんでいる）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"deeper_03","choices":[{"label":"続ける","next":"deeper_03"}]},"deeper_03":{"text":"陣屋の扉を開ける。中は異様な冷気に満ちている。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"altar_01","choices":[{"label":"続ける","next":"altar_01"}]},"altar_01":{"text":"陣屋の奥に、巨大な骨が組み上げられた祭壇がある。その上に——鬼の影が立っていた。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"altar_01_02","choices":[{"label":"続ける","next":"altar_01_02"}]},"altar_01_02":{"text":"（その影はゆっくりと振り向き、深紅の光を帯びた眼光でこちらを睨み据えた）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"altar_02","choices":[{"label":"続ける","next":"altar_02"}]},"altar_02":{"text":"「……百年ぶりに、自分と戦える者が来たか」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","speaker_name":"蛮骨","speaker":"蛮骨","next":"altar_03","choices":[{"label":"続ける","next":"altar_03"}]},"altar_03":{"text":"「自分の怨念は深い。この戦場で死んだ兵たちの無念と共に——お前を葬る！」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","speaker_name":"蛮骨","speaker":"蛮骨","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","enemy_group_id":"9063","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"蛮骨の巨体が揺らいだ。怨念の炎が弱まっている。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"（大気を震わせていた強大な瘴気が霧散し、彼の巨躯から力が抜けていく）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……強い。百年前のどの武者よりも。自分の怨念を断つか、鎮めるか——お前が決めろ」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","speaker_name":"蛮骨","speaker":"蛮骨","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"蛮骨が片膝をつき、静かに目を閉じた。その表情には怒りではなく、疲れがある。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","choices":[{"label":"「怨念ごと討ち滅ぼす。二度と蘇るな」","next":"destroy_01"},{"label":"「鎮魂の儀を行う。安らかに眠れ」","next":"requiem_01"}]},"destroy_01":{"text":"蛮骨の核を砕いた。怨念が爆発し、古戦場の霧が一気に晴れた。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"destroy_01_02","choices":[{"label":"続ける","next":"destroy_01_02"}]},"destroy_01_02":{"text":"（天を覆っていた黒雲が裂け、差し込む月光が荒涼とした古戦場を照らし出す）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"destroy_02","choices":[{"label":"続ける","next":"destroy_02"}]},"destroy_02":{"text":"古戦場は静寂に包まれた。百年の呪いは完全に消えた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「鬼将の怨念を完全に消滅させたか。力ずくだが、確実な方法だ」\n村人たちは安堵した。恐怖は去り、日常が戻る。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":3000,"exp":400,"reputation":15,"alignment_shift":{"justice":5}}},"choices":[]},"requiem_01":{"text":"古の鎮魂の祈りを捧げる。蛮骨の体が光に包まれていく。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"requiem_01_02","choices":[{"label":"続ける","next":"requiem_01_02"}]},"requiem_01_02":{"text":"（懐から取り出した香を焚き、静かに鎮魂の祝詞を唱え始める）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"requiem_02","choices":[{"label":"続ける","next":"requiem_02"}]},"requiem_02":{"text":"「……感謝する。百年、ずっと戦い続けていた。……もう、疲れた」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","speaker_name":"蛮骨","speaker":"蛮骨","next":"requiem_02_02","choices":[{"label":"続ける","next":"requiem_02_02"}]},"requiem_02_02":{"text":"（蛮骨の巨躯は穏やかな光の粒子となり、夜空へとゆっくり昇っていった）","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"requiem_03","choices":[{"label":"続ける","next":"requiem_03"}]},"requiem_03":{"text":"蛮骨と共に、亡霊兵たちも光の中に消えていった。古戦場に、百年ぶりの静寂が訪れた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success_peace","choices":[{"label":"続ける","next":"end_success_peace"}]},"end_success_peace":{"text":"「鎮魂の儀で成仏させたか。報酬は控えめだが、村の長老たちが深く感謝している」\n秩序を乱さず、怨霊を鎮めた。古の武士道に通じる選択だった。","type":"end","result":"success","bg_key":"bg_yato_city","params":{"rewards":{"gold":2000,"exp":350,"reputation":25,"alignment_shift":{"order":8}}},"choices":[]},"end_failure_01":{"text":"蛮骨の放った大太刀の一撃が防具を粉砕する。激痛と衝撃に視界が暗転した。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"蛮骨の拳が全てを薙ぎ払った。百年の怨念の前に、自分の力はまだ足りなかった。","type":"end","result":"failure","bg_key":"bg_forest_night","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[退魔依頼] 古戦場に百年前の鬼将の亡霊が復活。周辺の村が脅かされている。"}'::jsonb,
    6,
    3
