-- Scenario 5204: 翡翠蛇の毒牙 (qst_rep_jade_serpent)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5204,
    'qst_rep_jade_serpent',
    '翡翠蛇の毒牙',
    '[討伐令] 翡翠鉱脈に巣を作った巨大毒蛇を排除せよ。',
    '地方太守',
    4,
    17,
    6,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep05","min_reputation":70,"nation_id":"loc_haryu"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep05","min_reputation":70,"nation_id":"loc_haryu"}'::jsonb,
    '{"nodes":{"start":{"text":"「太守閣下から直々の依頼だ。翡翠鉱脈に大蛇が巣を作った」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"太守の使者","speaker":"太守の使者","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「鉱脈は国の財源だ。採掘が止まれば民の暮らしに響く」","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","speaker_name":"太守の使者","speaker":"太守の使者","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（翡翠は華龍国の特産品だ。経済が停滞すれば太守の立場も危ういな）","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"翡翠鉱脈は霊山の中腹にある。大蛇の巣に辿り着くには山道を越えねばならない。","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"（使者は焦るように指示書を押しつけ、都の宮殿の方へと立ち去った）","type":"text","bg_key":"bg_har_city","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"霊山の麓に着いた。山の空気が澄んでいるが、どこか不穏な気配がある。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"（見上げれば霊峰の峰々に厚い雲が立ち込め、鳥の鳴き声すら聞こえない）","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"山道に入ると、蛇の脱け殻が散乱していた。鱗の大きさから、相当な巨体だ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_field","next":"mountain_01","choices":[{"label":"続ける","next":"mountain_01"}]},"mountain_01":{"text":"山道が二手に分かれている。渓流沿いの道と、尾根を行く道だ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"choice_path","choices":[{"label":"続ける","next":"choice_path"}]},"choice_path":{"type":"choice","bg_key":"bg_mountain","bgm":"bgm_quest_tense","choices":[{"label":"「渓流沿いの道を行く——水場なら蛇の痕跡を追える」","next":"creek_01"},{"label":"「尾根道を行く——高所から巣の位置を見下ろせるはず」","next":"ridge_01"}]},"creek_01":{"text":"渓流沿いを進む。清水が岩を洗い、心地よい音を立てている。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"creek_01_02","choices":[{"label":"続ける","next":"creek_01_02"}]},"creek_01_02":{"text":"（水辺の湿った砂の上に、這った跡がはっきりと残されている）","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"creek_02","choices":[{"label":"続ける","next":"creek_02"}]},"creek_02":{"text":"水辺に巨大な蛇 of 足跡を発見。この方向で間違いない。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"creek_03","choices":[{"label":"続ける","next":"creek_03"}]},"creek_03":{"text":"渓流を遡ると、岩壁に大きな洞窟の入口が見えた。蛇の巣はあの中だ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"avoid_01_02","choices":[{"label":"続ける","next":"avoid_01_02"}]},"ridge_01":{"text":"尾根道を登る。見晴らしは良いが、足場が悪い。突風が吹き——！","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"ridge_01_02","choices":[{"label":"続ける","next":"ridge_01_02"}]},"ridge_01_02":{"text":"（突風に足元をすくわれ、小石が音を立てて谷底へと落ちていく）","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"ridge_trap","choices":[{"label":"続ける","next":"ridge_trap"}]},"ridge_trap":{"text":"足場が崩れ、転落しかけた！ 岩に掴まったが腕を負傷した。","type":"hp_damage","bg_key":"bg_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"ridge_02","choices":[{"label":"続ける","next":"ridge_02"}]},"ridge_02":{"text":"傷を押さえながら尾根を越えた。上から巣の位置は把握できた。洞窟に向かう。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"merge_cave","choices":[{"label":"続ける","next":"merge_cave"}]},"merge_cave":{"text":"洞窟に入った。翡翠の鉱脈が壁面に光っているが、地面には毒液の跡がある。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"cave_01","choices":[{"label":"続ける","next":"cave_01"}]},"cave_01":{"text":"奥に進むと、生温い空気が漂う。蛇の巣は近い。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"cave_01_02","choices":[{"label":"続ける","next":"cave_01_02"}]},"cave_01_02":{"text":"（壁面を覆う翡翠の緑光が、暗闇を冷たく照らし出している）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"cave_02","choices":[{"label":"続ける","next":"cave_02"}]},"cave_02":{"text":"通路の先で、小型の蛇が数匹蠢いている。親蛇の子供だろうか。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"encounter_01","choices":[{"label":"続ける","next":"encounter_01"}]},"encounter_01":{"text":"子蛇たちがこちらに気づいた。攻撃してくるか——それとも回り道するか。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"choice_snake","choices":[{"label":"続ける","next":"choice_snake"}]},"choice_snake":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_tense","choices":[{"label":"「邪魔だ。排除する」","next":"attack_01"},{"label":"「刺激せず迂回する」","next":"avoid_01"}]},"attack_01":{"text":"子蛇たちを攻撃する。小さいが毒牙は鋭い——油断はできない！","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"attack_01_02","choices":[{"label":"続ける","next":"attack_01_02"}]},"attack_01_02":{"text":"（大剣を抜き払い、襲いかかってくる子蛇たちを牽制する！）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle","enemy_group_id":"120","choices":[{"label":"win","next":"nest_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"nest_01"},"avoid_01":{"text":"子蛇を刺激しないよう、壁際を慎重に進む。息を殺し、足音を消す。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"avoid_01_02","choices":[{"label":"続ける","next":"avoid_01_02"}]},"avoid_01_02":{"text":"（静かに重心を移しながら、岩の影を縫うように歩を進めていく）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"avoid_02","choices":[{"label":"続ける","next":"avoid_02"}]},"avoid_02":{"text":"無事に通過できた。子蛇たちは気づかなかったようだ。体力を温存できた。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"nest_01","choices":[{"label":"続ける","next":"nest_01"}]},"nest_01":{"text":"洞窟の最奥、翡翠が密集する広大な空間に出た。ここが巣の本体だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"nest_01_02","choices":[{"label":"続ける","next":"nest_01_02"}]},"nest_01_02":{"text":"（中央には大量の卵が産み落とされ、翡翠の輝きを受けて淡く光っている）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"nest_02","choices":[{"label":"続ける","next":"nest_02"}]},"nest_02":{"text":"天井から巨大な鱗が覗いている。翡翠色の光を帯びた大蛇——翡翠大蛇だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","next":"nest_03","choices":[{"label":"続ける","next":"nest_03"}]},"nest_03":{"text":"大蛇がゆっくりと頭をもたげた。翡翠色の瞳がこちらを見つめている。臨戦態勢だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle_boss","enemy_group_id":"9064","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"翡翠大蛇が力なく横たわった。まだ息はあるが、抵抗する力は残っていない。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"（巨躯がズシンと地面を揺らして倒れ込み、洞窟内の毒気が霧散していく）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"巣ごと壊滅させれば鉱脈は安全になる。だが、この蛇は翡翠の精霊とも言われている。別の山に誘導する手もある。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_calm","choices":[{"label":"「巣ごと壊滅させる。鉱脈の安全が最優先だ」","next":"destroy_01"},{"label":"「蛇を別の山に誘導する。霊山の精霊を殺すべきではない」","next":"lure_01"}]},"destroy_01":{"text":"大蛇と卵を全て処分した。鉱脈は完全に安全になった。だが、翡翠の輝きが少し鈍くなった気がする。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"destroy_01_02","choices":[{"label":"続ける","next":"destroy_01_02"}]},"destroy_01_02":{"text":"（精霊の死によって、鉱脈を照らしていた光が弱まっていくのを感じた）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"destroy_02","choices":[{"label":"続ける","next":"destroy_02"}]},"destroy_02":{"text":"太守に報告した。鉱脈の再開が命じられ、手厚い報酬を受け取った。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「翡翠鉱脈の脅威を排除した功績、高く評価する」\n採掘が再開し、華龍国の経済は息を吹き返した。","type":"end","result":"success","bg_key":"bg_har_city","params":{"rewards":{"gold":3500,"exp":400,"reputation":10,"alignment_shift":{"evil":5}}},"choices":[]},"lure_01":{"text":"薬草を焚き、大蛇を別の山へ誘導する。蛇は静かに従った。精霊の知恵があるのかもしれない。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"lure_01_02","choices":[{"label":"続ける","next":"lure_01_02"}]},"lure_01_02":{"text":"（大蛇は感謝するかのように一度首を傾げ、闇の奥へ消え去っていった）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"lure_02","choices":[{"label":"続ける","next":"lure_02"}]},"lure_02":{"text":"大蛇は隣の霊山に新しい巣を作った。翡翠鉱脈は無事だが、完全な解決とは言いづらい。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"lure_02_02","choices":[{"label":"続ける","next":"lure_02_02"}]},"lure_02_02":{"text":"（それでも、霊山の豊かな自然は壊されずに保たれた。これでいいはずだ）","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"lure_03","choices":[{"label":"続ける","next":"lure_03"}]},"lure_03":{"text":"太守には「蛇は排除した」と報告した。嘘はついていない——場所を移しただけだ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success_peace","choices":[{"label":"続ける","next":"end_success_peace"}]},"end_success_peace":{"text":"「鉱脈は無事か。ご苦労」太守は満足げだ。だが報酬は控えめだった。\n山の老人が静かに頭を下げた。「精霊を守ってくれて感謝する」","type":"end","result":"success","bg_key":"bg_karyu_village","params":{"rewards":{"gold":2500,"exp":350,"reputation":20,"alignment_shift":{"justice":8}}},"choices":[]},"end_failure_01":{"text":"大蛇の強烈な尾の一撃が体に叩きつけられる。岩壁に叩きつけられ意識を失った。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"翡翠大蛇の毒牙が閃いた。全身に毒が回り、意識が遠のいていく。","type":"end","result":"failure","bg_key":"bg_crypt","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[討伐令] 翡翠鉱脈に巣を作った巨大毒蛇を排除せよ。"}'::jsonb,
    6,
    4
