-- Scenario 5205: 異端の大賢者 (qst_rep_heretic_sage)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5205,
    'qst_rep_heretic_sage',
    '異端の大賢者',
    '[最重要] 禁忌の魔法を研究する大賢者が地下墓地で実験を続けている。',
    '冒険者ギルド',
    5,
    18,
    6,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep10","min_reputation":80,"nation_id":"loc_holy_empire"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep10","min_reputation":80,"nation_id":"loc_holy_empire"}'::jsonb,
    '{"nodes":{"start":{"text":"「地下墓地で異常なアンデッドの発生が報告されている。原因は一人の大賢者だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「死霊術の禁忌に手を出した男——元宮廷魔術師のメルヴィンだ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（メルヴィン……。十年前、禁忌の研究が露見して追放されたはずだが）","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「教会は面子があって動けない。元宮廷の人間だからな。だからギルドに話が来た」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"ギルドマスターは声を潜め、周囲に会話が漏れないよう注意深く周囲を見渡した。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"禁忌の魔法使い相手だ。地下墓地は罠だらけだろう。慎重に進む必要がある。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"聖王国の南、古い墓地の入口に着いた。地面が微かに震えている——死霊術の余波だ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"（枯れ果てた樹木が立ち並ぶ墓地には、人影はなく、ただ重苦しい静寂が支配している）","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"crypt_01","choices":[{"label":"続ける","next":"crypt_01"}]},"crypt_01":{"text":"地下への階段を降りる。壁面に刻まれた魔法陣が青白く光っている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"crypt_01_02","choices":[{"label":"続ける","next":"crypt_01_02"}]},"crypt_01_02":{"text":"（魔力の波が空気を通じて伝わり、皮膚を刺すような微かな痛みを覚える）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"crypt_02","choices":[{"label":"続ける","next":"crypt_02"}]},"crypt_02":{"text":"通路の先に魔法の罠が仕掛けられている。解除する技術があれば安全に通れるが——","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"choice_approach","choices":[{"label":"続ける","next":"choice_approach"}]},"choice_approach":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_tense","choices":[{"label":"「魔法陣を分析して罠を解除する」","next":"trap_route_01"},{"label":"「時間をかけず強行突破する」","next":"force_01"}]},"trap_route_01":{"text":"魔法陣の構造を分析する。メルヴィンの仕掛けは精巧だが、理論的な弱点がある。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"trap_route_01_02","choices":[{"label":"続ける","next":"trap_route_01_02"}]},"trap_route_01_02":{"text":"（複雑に絡み合う魔力回路を一つずつ丁寧に解きほぐしていく）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"trap_route_02","choices":[{"label":"続ける","next":"trap_route_02"}]},"trap_route_02":{"text":"弱点を突いて魔法陣を無力化した。静かに通路を進む。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"trap_route_03","choices":[{"label":"続ける","next":"trap_route_03"}]},"trap_route_03":{"text":"罠を全て解除し、安全に通過できた。体力を温存したまま奥へ進める。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"lab_01_02","choices":[{"label":"続ける","next":"lab_01_02"}]},"force_01":{"text":"罠を無視して突っ走る。魔法陣が反応し、電撃が走る——！","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"force_01_02","choices":[{"label":"続ける","next":"force_01_02"}]},"force_01_02":{"text":"（激しい魔力の放電が通路を照らし、青白い火花が飛び散る！）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"force_02","choices":[{"label":"続ける","next":"force_02"}]},"force_02":{"text":"壁からゴーレムの腕が飛び出し、通路が崩れる。足元の床が陥没した——！","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"force_trap","choices":[{"label":"続ける","next":"force_trap"}]},"force_trap":{"text":"連続する罠を食らった！ 全身に電撃と打撃のダメージを受ける。","type":"hp_damage","bg_key":"bg_crypt","bgm":"bgm_quest_tense","params":{"hp_percent":20,"percent":20},"next":"force_03","choices":[{"label":"続ける","next":"force_03"}]},"force_03":{"text":"ボロボロだが通り抜けた。罠を解除する知恵があればと悔やむが、先に進むしかない。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"merge_deep","choices":[{"label":"続ける","next":"merge_deep"}]},"merge_deep":{"text":"地下墓地の深部に入った。壁の棺から、アンデッドが這い出してくる。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"deep_01","choices":[{"label":"続ける","next":"deep_01"}]},"deep_01":{"text":"死霊術で蘇らせられた死者たち。意思はなく、ただ動くだだけの人形だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"deep_01_02","choices":[{"label":"続ける","next":"deep_01_02"}]},"deep_01_02":{"text":"（カタカタと骨を鳴らし、虚ろな眼窩に怪しい光を宿した骸骨たちが迫る）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"deep_02","choices":[{"label":"続ける","next":"deep_02"}]},"deep_02":{"text":"アンデッドの群れが道を塞がいんでいる。突破するしかない！","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"battle_undead","choices":[{"label":"続ける","next":"battle_undead"}]},"battle_undead":{"type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle","enemy_group_id":"416","choices":[{"label":"win","next":"lab_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"lab_01"},"lab_01":{"text":"アンデッドを退けると、研究室らしき部屋に辿り着いた。実験器具が整然と並んでいる。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"lab_01_02","choices":[{"label":"続ける","next":"lab_01_02"}]},"lab_01_02":{"text":"（薬品のすっぱい臭いが部屋に充満し、謎の液体がフラスコで沸騰している）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"lab_02","choices":[{"label":"続ける","next":"lab_02"}]},"lab_02":{"text":"机の上に研究ノートがある。死霊術の理論が事細かに記されている。恐ろしい内容だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"lab_03","choices":[{"label":"続ける","next":"lab_03"}]},"lab_03":{"text":"研究室の奥に鉄の扉がある。その前に、石のゴーレムが番人のように立っている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"lab_03_02","choices":[{"label":"続ける","next":"lab_03_02"}]},"lab_03_02":{"text":"（ゴーレムの全身には、メルヴィンの魔力供給ラインと思われる青い光の筋が走る）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"lab_04","choices":[{"label":"続ける","next":"lab_04"}]},"lab_04":{"text":"ゴーレムの目が赤く光った。メルヴィンが作った護衛だ。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"battle_golem","choices":[{"label":"続ける","next":"battle_golem"}]},"battle_golem":{"type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle","enemy_group_id":"413","choices":[{"label":"win","next":"sage_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"sage_01"},"sage_01":{"text":"ゴーレムを破壊し、鉄の扉を開けた。奥にはさらに広大な空間が広がっている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"sage_01_02","choices":[{"label":"続ける","next":"sage_01_02"}]},"sage_01_02":{"text":"（大空間の床には巨大な魔法陣が描かれ、死者の魂と思しき光が吸い込まれている）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"sage_02","choices":[{"label":"続ける","next":"sage_02"}]},"sage_02":{"text":"部屋の中央に、白髪の老人が佇んでいる。周囲を死霊の光が渦巻いている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","next":"sage_02_02","choices":[{"label":"続ける","next":"sage_02_02"}]},"sage_02_02":{"text":"（メルヴィンはゆっくりと振り向き、深い皺の刻まれた顔に狂気の笑みを浮かべた）","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","next":"sage_03","choices":[{"label":"続ける","next":"sage_03"}]},"sage_03":{"text":"「……客か。自分の研究を邪魔しに来たのだな」","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"メルヴィン","speaker":"メルヴィン","next":"sage_04","choices":[{"label":"続ける","next":"sage_04"}]},"sage_04":{"text":"「死は克服できる。自分はそれを証明する。邪魔をするなら——自分の実験台になってもらう」","type":"text","bg_key":"bg_crypt","bgm":"bgm_battle_boss","speaker_name":"メルヴィン","speaker":"メルヴィン","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"type":"battle","bg_key":"bg_crypt","bgm":"bgm_battle_boss","enemy_group_id":"9065","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"メルヴィンの杖が折れ、死霊の光が消えた。老賢者は座り込んで肩を震わせている。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"（膝をついた老人の周囲から、渦巻いていた冷たい魔力が静かに霧散していく）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……負けたか。好きにしろ。だが自分の研究成果は本物だ。死を克服する鍵がここにある」","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","speaker_name":"メルヴィン","speaker":"メルヴィン","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"メルヴィンの研究ノートが目の前にある。破壊すべきか——それとも。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_calm","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_crypt","bgm":"bgm_quest_calm","choices":[{"label":"「研究所ごと破壊する。禁忌の知識は封じるべきだ」","next":"destroy_01"},{"label":"「研究成果だけ没収する。メルヴィンは……見逃してやる」","next":"deal_01"}]},"destroy_01":{"text":"研究ノートを燃やし、実験器具を破壊した。メルヴィンを教会に引き渡す。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"destroy_01_02","choices":[{"label":"続ける","next":"destroy_01_02"}]},"destroy_01_02":{"text":"（炎に包まれる魔術書を見つめ、メルヴィンは絶望の叫びを上げた）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"destroy_02","choices":[{"label":"続ける","next":"destroy_02"}]},"destroy_02":{"text":"教会は即座にメルヴィンを裁いた。禁忌の知識は完全に封じられた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「大賢者の拘束と研究所の破壊を確認。秩序を守った功績、高く評価する」\n禁忌の知識が世に出ることはなくなった。正しい選択だと信じる。","type":"end","result":"success","bg_key":"bg_church","params":{"rewards":{"gold":4000,"exp":450,"reputation":20,"alignment_shift":{"order":8}}},"choices":[]},"deal_01":{"text":"「……見逃す、だと？ 何を企んでいる」","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","speaker_name":"メルヴィン","speaker":"メルヴィン","next":"deal_01_02","choices":[{"label":"続ける","next":"deal_01_02"}]},"deal_01_02":{"text":"（こちらの条件を聞くと、老賢者は驚きと疑心の入り混じった目でこちらを見つめた）","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"deal_02","choices":[{"label":"続ける","next":"deal_02"}]},"deal_02":{"text":"研究ノートだけ回収し、メルヴィンを解放した。このノートは闇市場で高値がつくだろう。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_mystery","next":"deal_03","choices":[{"label":"続ける","next":"deal_03"}]},"deal_03":{"text":"ギルドには「研究所を破壊し、賢者は逃走した」と報告。真実を知る者はいない。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success_deal","choices":[{"label":"続ける","next":"end_success_deal"}]},"end_success_deal":{"text":"研究ノートを闇市で売りさばき、莫大な金を手にした。\nだがギルドからの信頼は失墜した。「異端者を逃がした」という噂が広まっている。","type":"end","result":"success","bg_key":"bg_slums","params":{"rewards":{"gold":5500,"exp":350,"reputation":-20,"alignment_shift":{"chaos":10}}},"choices":[]},"end_failure_01":{"text":"メルヴィンの放った漆黒の魔力弾が胸元に直撃する。激痛に耐えかね、崩れ落ちた。","type":"text","bg_key":"bg_crypt","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"メルヴィンの死霊魔法が全身を蝕んだ。意識が遠のく中、老賢者の呟きが聞こえた。\n「やはり、死は克服できない——まだ」","type":"end","result":"failure","bg_key":"bg_crypt","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[最重要] 禁忌の魔法を研究する大賢者が地下墓地で実験を続けている。"}'::jsonb,
    6,
    4
