-- Scenario 5206: 戦の魔神 (qst_rep_war_djinn)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5206,
    'qst_rep_war_djinn',
    '戦の魔神',
    '[封印解除] 砂漠の遺跡から封印が解けた戦の魔神が目覚めた。',
    '冒険者ギルド',
    5,
    18,
    6,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep10","min_reputation":90,"nation_id":"loc_marcund"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep10","min_reputation":90,"nation_id":"loc_marcund"}'::jsonb,
    '{"nodes":{"start":{"text":"「砂塵の王国マルカンドの南方遺跡から魔神が目覚めた。集落が三つ消えた」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「戦の魔神ジン。古代に封じられた闘争の化身だ。封印の劣化で復活した」","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02_02","choices":[{"label":"続ける","next":"start_02_02"}]},"start_02_02":{"text":"（かつて砂漠全体を恐怖に陥れたという伝説の魔神。ここで食い止めねば）","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"魔神相手だ。事前準備が生死を分ける。遺跡に入る前に、何を用意するか考える。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"start_03_02","choices":[{"label":"続ける","next":"start_03_02"}]},"start_03_02":{"text":"ギルドマスターは警告の書かれた羊皮紙を差し出し、厳粛な面持ちで見つめた。","type":"text","bg_key":"bg_marcund","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"砂漠を南下する。途中、破壊されたキャラバンの残骸を見た。凄まじい暴力の痕跡だ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_01_02","choices":[{"label":"続ける","next":"travel_01_02"}]},"travel_01_02":{"text":"（熱風が砂を巻き上げる中、赤黒い熱気が南の地平線から立ち上るのが見える）","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"古代遺跡が見えてきた。上空に赤い光が渦巻いている。魔神の力だ。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"travel_02_02","choices":[{"label":"続ける","next":"travel_02_02"}]},"travel_02_02":{"text":"（遺跡の周囲は異様な高熱に包まれ、陽炎がゆらゆらと周囲の景色を歪めている）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"ruin_01","choices":[{"label":"続ける","next":"ruin_01"}]},"ruin_01":{"text":"遺跡の入口手前で足を止める。このまま入るのは無謀だ。何か対策を——","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"ruin_01_02","choices":[{"label":"続ける","next":"ruin_01_02"}]},"ruin_01_02":{"text":"（幸いにも、近くの集落にはかつて魔神を封じた者たちの末裔がいるという）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"ruin_02","choices":[{"label":"続ける","next":"ruin_02"}]},"ruin_02":{"text":"近くの集落の長老が助言をくれた。「聖水で魔神の炎を鎮めるか、武器を打ち直して刃を通すか——どちらかだ」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"choice_prep","choices":[{"label":"続ける","next":"choice_prep"}]},"choice_prep":{"type":"choice","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","choices":[{"label":"「集落の祠で聖水を入手する」","next":"holywater_01"},{"label":"「鍛冶師に武器を強化してもらう」","next":"forge_01"}]},"holywater_01":{"text":"集落の祠を訪ねる。老巫女が古い聖水を分けてくれた。","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_calm","next":"holywater_01_02","choices":[{"label":"続ける","next":"holywater_01_02"}]},"holywater_01_02":{"text":"（冷たく澄んだ聖水から、清浄な魔力の波長が伝わる。これなら猛火に勝てる）","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_calm","next":"holywater_02","choices":[{"label":"続ける","next":"holywater_02"}]},"holywater_02":{"text":"「この聖水を魔神に振りかければ、炎の力を弱められるだろう」","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_calm","speaker_name":"老巫女","speaker":"老巫女","next":"holywater_03","choices":[{"label":"続ける","next":"holywater_03"}]},"holywater_03":{"text":"聖水を受け取った。魔神の炎を鎮め、戦いやすくなるはずだ。","type":"text","bg_key":"bg_memory_oasis","bgm":"bgm_quest_calm","next":"set_holywater","choices":[{"label":"続ける","next":"set_holywater"}]},"set_holywater":{"type":"modify_flag","bg_key":"bg_memory_oasis","next":"deep_01_02","choices":[{"label":"続ける","next":"deep_01_02"}]},"forge_01":{"text":"集落の鍛冶師を訪ねる。砂漠の民は古来、魔物の鱗で武器を打つ技術を持っている。","type":"text","bg_key":"bg_shop","bgm":"bgm_quest_calm","next":"forge_01_02","choices":[{"label":"続ける","next":"forge_01_02"}]},"forge_01_02":{"text":"（赤く焼けた鉄が叩かれるたび、火花が散り、力強い金属音が響き渡る）","type":"text","bg_key":"bg_shop","bgm":"bgm_quest_calm","next":"forge_02","choices":[{"label":"続ける","next":"forge_02"}]},"forge_02":{"text":"「魔神殺しの刃か。材料はある。一晩で仕上げてやろう」","type":"text","bg_key":"bg_shop","bgm":"bgm_quest_calm","speaker_name":"鍛冶師","speaker":"鍛冶師","next":"forge_03","choices":[{"label":"続ける","next":"forge_03"}]},"forge_03":{"text":"武器を強化してもらった。刃に砂漠の古い文様が刻まれている。これなら魔神の皮も斬れるだろう。","type":"text","bg_key":"bg_shop","bgm":"bgm_quest_calm","next":"set_forge","choices":[{"label":"続ける","next":"set_forge"}]},"set_forge":{"type":"modify_flag","bg_key":"bg_shop","next":"merge_enter","choices":[{"label":"続ける","next":"merge_enter"}]},"merge_enter":{"text":"準備を終え、遺跡に突入する。入口から灼熱の空気が噴き出している。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"enter_01","choices":[{"label":"続ける","next":"enter_01"}]},"enter_01":{"text":"遺跡の内部は赤い光に満ちていた。壁の彫刻が熱で歪んでいる。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"enter_01_02","choices":[{"label":"続ける","next":"enter_01_02"}]},"enter_01_02":{"text":"（崩れかけた石壁の間から、マグマのように赤い熱風が吹き抜け、全身を焦がす！）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"enter_02","choices":[{"label":"続ける","next":"enter_02"}]},"enter_02":{"text":"通路の先に、炎をまとった魔物が徘徊している。魔神の眷属だ。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"battle_guard","choices":[{"label":"続ける","next":"battle_guard"}]},"battle_guard":{"type":"battle","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle","enemy_group_id":"421","choices":[{"label":"win","next":"deep_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"deep_01"},"deep_01":{"text":"眷属を倒し、遺跡の深部へ進む。壁画には古代の戦争が描かれている。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"deep_01_02","choices":[{"label":"続ける","next":"deep_01_02"}]},"deep_01_02":{"text":"（かつてこの地を支配した魔神と、それを封じた古代戦士たちの記録だ）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"deep_02","choices":[{"label":"続ける","next":"deep_02"}]},"deep_02":{"text":"壁画の中心に、巨大な人影が描かれている。四本の腕を持つ戦士——ジンだ。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"deep_03","choices":[{"label":"続ける","next":"deep_03"}]},"deep_03":{"text":"壁画の下に碑文がある。「闘争を愛し、闘争に飽きた者は永遠に眠る」——封印の言葉か。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_mystery","next":"chamber_01","choices":[{"label":"続ける","next":"chamber_01"}]},"chamber_01":{"text":"最奥の大広間に出た。砕けた封印石の破片が散乱している。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"chamber_01_02","choices":[{"label":"続ける","next":"chamber_01_02"}]},"chamber_01_02":{"text":"（大部屋の中央に立つ巨影が、こちらに向けてゆっくりと振り返った！）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"chamber_02","choices":[{"label":"続ける","next":"chamber_02"}]},"chamber_02":{"text":"「……久しぶりの獲物だ。貴様、なかなかの闘気を持っているな」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","speaker_name":"戦魔ジン","speaker":"戦魔ジン","next":"chamber_03","choices":[{"label":"続ける","next":"chamber_03"}]},"chamber_03":{"text":"「自分は戦いを求める。強き者との死闘を渇望する。——さあ、来い！」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","speaker_name":"戦魔ジン","speaker":"戦魔ジン","next":"check_prep","choices":[{"label":"続ける","next":"check_prep"}]},"check_prep":{"type":"check_flags","bg_key":"bg_pyramid_chamber","choices":[{"label":"success","next":"battle_boss_holy"},{"label":"failure","next":"battle_boss_forge"}]},"battle_boss_holy":{"text":"聖水を振りかけ、炎が弱まった戦魔ジンとの激突——！","type":"battle","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","enemy_group_id":"9068","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"battle_boss_forge":{"text":"強化された武器を構え、装甲を貫く戦魔ジンとの激突——！","type":"battle","bg_key":"bg_pyramid_chamber","bgm":"bgm_battle_boss","enemy_group_id":"9069","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure_01"}],"battle_success_next":"victory_01"},"victory_01":{"text":"ジンが膝をついた。四本の腕が力なく垂れ下がる。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","next":"victory_01_02","choices":[{"label":"続ける","next":"victory_01_02"}]},"victory_01_02":{"text":"（巨躯から吹き出していた炎が徐々に収まり、周囲の熱気が引いていく）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……満足だ。久しぶりに本気で戦えた。殺すか、封じるか——好きにしろ」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","speaker_name":"戦魔ジン","speaker":"戦魔ジン","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","choices":[{"label":"「二度と暴れさせない。ここで終わらせる」","next":"slay_01"},{"label":"「碑文の通りに再封印する。いつか闘争に飽きて眠ることを願う」","next":"seal_01"}]},"slay_01":{"text":"ジンの核を砕いた。魔神の体が灰となり、遺跡の赤い光が消えた。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"slay_01_02","choices":[{"label":"続ける","next":"slay_01_02"}]},"slay_01_02":{"text":"（魔神の呪縛から解き放たれた遺跡は、ゆっくりと崩壊を始めた。急ぎ脱出せねば）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"slay_02","choices":[{"label":"続ける","next":"slay_02"}]},"slay_02":{"text":"遺跡から出ると、砂漠に静寂が戻っていた。魔神の脅威は永遠に去った。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「戦の魔神を完全に討伐したか。凄まじい力だ」\n砂漠の民は安堵した。キャラバンも再び動き出すだろう。","type":"end","result":"success","bg_key":"bg_marcund","speaker_name":"ギルドマスター","speaker":"ギルドマスター","params":{"rewards":{"gold":4000,"exp":450,"reputation":20,"alignment_shift":{"chaos":8}}},"choices":[]},"seal_01":{"text":"碑文の封印術を唱える。ジンの体が光に包まれ、封印石が再構成されていく。","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","next":"seal_01_02","choices":[{"label":"続ける","next":"seal_01_02"}]},"seal_01_02":{"text":"（光が収まると、そこには再び堅牢な封印が施された石版が静かに佇んでいた）","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","next":"seal_02","choices":[{"label":"続ける","next":"seal_02"}]},"seal_02":{"text":"「封印か……退屈な眠りだ。だが、お前との戦いは夢に見よう。……次に目覚める時は——」","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_calm","speaker_name":"戦魔ジン","speaker":"戦魔ジン","next":"seal_03","choices":[{"label":"続ける","next":"seal_03"}]},"seal_03":{"text":"封印を完了し、遺跡を後にした。長老が新しい結界を張り直してくれた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success_seal","choices":[{"label":"続ける","next":"end_success_seal"}]},"end_success_seal":{"text":"「再封印を完了したな。報酬は控えめだが、禍根を残さない選択だ」\n殺さずに済んだ——それが正しかったかは、わからない。","type":"end","result":"success","bg_key":"bg_marcund","speaker_name":"ギルドマスター","speaker":"ギルドマスター","params":{"rewards":{"gold":3000,"exp":400,"reputation":25,"alignment_shift":{"order":10}}},"choices":[]},"end_failure_01":{"text":"魔神の圧倒的な力に押し潰され、体が動かない。意識が遠のいていく……","type":"text","bg_key":"bg_pyramid_chamber","bgm":"bgm_quest_tense","next":"end_failure","choices":[{"label":"続ける","next":"end_failure"}]},"end_failure":{"text":"ジンの拳が全てを砕いた。「弱い。次の獲物を探すとしよう」\n砂漠に魔神の哄笑が響いた。","type":"end","result":"failure","bg_key":"bg_pyramid_chamber","params":{"rewards":{"gold":0}},"choices":[]}},"short_description":"[封印解除] 砂漠の遺跡から封印が解けた戦の魔神が目覚めた。"}'::jsonb,
    6,
    4
