-- Scenario 5207: 九尾の大狐 (qst_rep_nine_tails)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    5207,
    'qst_rep_nine_tails',
    '九尾の大狐',
    '[最高討伐令] 東方二国にまたがる霊山に千年の大妖狐が出現。地脈が乱れ災厄が広がる。',
    '冒険者ギルド',
    5,
    20,
    6,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep10","min_reputation":100}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep10","min_reputation":100}'::jsonb,
    '{"nodes":{"start":{"text":"「両国のギルドから共同依頼だ。霊山に九尾の大妖狐が現れた」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「千年を生きた大妖。妖力で地脈を乱し、両国に災厄をばらまいている」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「名声100以上の冒険者にしか頼めない案件だ。頼んだぞ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"千年の大妖か。これまでの相手とは格が違う。万全の準備で臨む。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"travel_01","choices":[{"label":"続ける","next":"travel_01"}]},"travel_01":{"text":"夜刀と華龍の国境にある霊山へ向かう。国境では両国の兵士が共同で警戒にあたっていた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"travel_02","choices":[{"label":"続ける","next":"travel_02"}]},"travel_02":{"text":"山の麓に着くと、空気が異様に歪んでいるのがわかった。妖力の影響だ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"border_01","choices":[{"label":"続ける","next":"border_01"}]},"border_01":{"text":"霊山への入口は二つある。夜刀側の北ルートと、華龍側の南ルートだ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"border_02","choices":[{"label":"続ける","next":"border_02"}]},"border_02":{"text":"北ルートは妖怪が多いが道は明瞭。南ルートは険しいが妖怪は少ない——と聞いた。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"choice_path","choices":[{"label":"続ける","next":"choice_path"}]},"choice_path":{"type":"choice","bg_key":"bg_mountain","bgm":"bgm_quest_tense","choices":[{"label":"「夜刀側（北ルート）から登る——妖怪を倒しながら進む」","next":"north_01"},{"label":"「華龍側（南ルート）から登る——険しい山道を行く」","next":"south_01"}]},"north_01":{"text":"北ルートを進む。竹林の中を歩くと、早速妖怪の気配が漂ってきた。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"north_02","choices":[{"label":"続ける","next":"north_02"}]},"north_02":{"text":"九尾の妖力に引き寄せられた下級妖怪たちが群れをなしている。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"north_03","choices":[{"label":"続ける","next":"north_03"}]},"north_03":{"text":"道を塞ぐ妖怪の群れ。突破するしかない——！","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"north_battle","choices":[{"label":"続ける","next":"north_battle"}]},"north_battle":{"text":"霊山の妖怪たちが襲いかかる！","type":"battle","bg_key":"bg_forest_night","bgm":"bgm_battle","enemy_group_id":"130","choices":[{"label":"win","next":"south_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"south_01"},"south_01":{"text":"南ルートを登る。岩場が続き、足場が悪い。人の手が入っていない獣道だ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"south_02","choices":[{"label":"続ける","next":"south_02"}]},"south_02":{"text":"崖際の細い道を慎重に進む。一歩踏み外せば谷底だ。そのとき——足場が崩れた！","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"south_trap","choices":[{"label":"続ける","next":"south_trap"}]},"south_trap":{"text":"落石に巻き込まれ、全身を打った！ 致命傷は避けたが、体が痛む。","type":"hp_damage","bg_key":"bg_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"south_03","choices":[{"label":"続ける","next":"south_03"}]},"south_03":{"text":"傷を押さえながら登り続ける。やがて山の中腹に出た。ここからは共通の道だ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"merge_peak","choices":[{"label":"続ける","next":"merge_peak"}]},"merge_peak":{"text":"霊山の中腹。空気が澄んでいるのに、視界が歪む。妖力が空間そのものを歪めている。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_mystery","next":"peak_01","choices":[{"label":"続ける","next":"peak_01"}]},"peak_01":{"text":"目の前に美しい花畑が広がった——だがこんな山頂に花畑があるはずがない。幻術だ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_mystery","next":"peak_02","choices":[{"label":"続ける","next":"peak_02"}]},"peak_02":{"text":"九尾の幻術に惑わされまいと精神を集中する。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_mystery","next":"illusion_01","choices":[{"label":"続ける","next":"illusion_01"}]},"illusion_01":{"text":"花畑の中に、美しい女性が立っている。「お疲れでしょう。休んでいきませんか」","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_mystery","next":"illusion_02","choices":[{"label":"続ける","next":"illusion_02"}]},"illusion_02":{"text":"甘い声だ。意識がぼやける——。これは幻術。見破れるか——","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_mystery","next":"random_illusion","choices":[{"label":"続ける","next":"random_illusion"}]},"random_illusion":{"type":"random_branch","bg_key":"bg_mountain","prob":50,"choices":[{"label":"success","next":"see_through"},{"label":"failure","next":"tricked_01"}]},"see_through":{"text":"「——幻術か。見事だが、自分は騙されない」花畑が霧散し、荒涼とした岩山が現れた。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"merge_shrine","choices":[{"label":"続ける","next":"merge_shrine"}]},"tricked_01":{"text":"気づいた時には、崖の縁に立っていた。幻術に誘導されたのだ——！","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"tricked_trap","choices":[{"label":"続ける","next":"tricked_trap"}]},"tricked_trap":{"text":"幻術が解け、足を踏み外した。岩場に叩きつけられる。","type":"hp_damage","bg_key":"bg_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"tricked_02","choices":[{"label":"続ける","next":"tricked_02"}]},"tricked_02":{"text":"体を起こす。幻術に翻弄された——油断していた。九尾の力は底知れない。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_tense","next":"merge_shrine","choices":[{"label":"続ける","next":"merge_shrine"}]},"merge_shrine":{"text":"山頂が見えてきた。そこに、古びた祠が佇んでいる。九尾の大妖狐の住処だ。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_mystery","next":"shrine_01","choices":[{"label":"続ける","next":"shrine_01"}]},"shrine_01":{"text":"祠の前に、九本の巨大な尾が揺らめいている。金色の毛並みが月光に輝く。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"shrine_02","choices":[{"label":"続ける","next":"shrine_02"}]},"shrine_02":{"text":"「……千年ぶりの客だ。自分の幻術を抜けてここまで来るとは——見込みがある」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","speaker_name":"九尾の大妖狐","speaker":"九尾の大妖狐","next":"shrine_03","choices":[{"label":"続ける","next":"shrine_03"}]},"shrine_03":{"text":"「だが来た以上は試させてもらう。お前が自分を殺すに足る者か——あるいは、手を組むに足る者か」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","speaker_name":"九尾の大妖狐","speaker":"九尾の大妖狐","next":"confront_01","choices":[{"label":"続ける","next":"confront_01"}]},"confront_01":{"text":"九尾の大妖狐が立ち上がった。体長は馬車ほどもある。九本の尾が天を覆い、妖力が大気を震わせる。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","next":"confront_02","choices":[{"label":"続ける","next":"confront_02"}]},"confront_02":{"text":"周囲の木々が妖力で白くなっていく。地面に霜が降り、呼吸が白く染まった。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","next":"confront_03","choices":[{"label":"続ける","next":"confront_03"}]},"confront_03":{"text":"九尾が跳躍した。月を背に、九つの炎が弧を描く——！","type":"text","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"千年の大妖——九尾の大妖狐との死闘——！","type":"battle","bg_key":"bg_forest_night","bgm":"bgm_battle_boss","enemy_group_id":"9067","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"九尾が倒れた。だがその体は消えず、穏やかな目でこちらを見つめている。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……千年生きて、初めて負けた。お前は自分が認めた最後の人間だ」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","speaker_name":"九尾の大妖狐","speaker":"九尾の大妖狐","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"「さて——殺すか。それとも契約を結ぶか。自分の妖力の一部を分けてやってもいい」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","speaker_name":"九尾の大妖狐","speaker":"九尾の大妖狐","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_forest_night","bgm":"bgm_quest_calm","choices":[{"label":"「依頼通り討伐する。お前が生きている限り地脈は乱れ続ける」","next":"slay_01"},{"label":"「契約を結ぶ。お前の力を分けてもらう代わりに、地脈の乱れを止めろ」","next":"pact_01"}]},"slay_01":{"text":"九尾に止めを刺した。千年の命が消える瞬間、九つの炎が天に昇っていった。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_tense","next":"slay_02","choices":[{"label":"続ける","next":"slay_02"}]},"slay_02":{"text":"山の空気が澄んでいく。地脈の乱れが収まり、大地が穏やかな表情を取り戻した。","type":"text","bg_key":"bg_mountain","bgm":"bgm_quest_calm","next":"slay_03","choices":[{"label":"続ける","next":"slay_03"}]},"slay_03":{"text":"両国のギルドに報告した。千年の脅威が去った安堵が、国境を越えて広がった。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「千年の大妖を討伐——これは歴史に残る偉業だ」\n両国から手厚い報酬を受け取った。冒険者として最高峰の名声を得た。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":6000,"exp":550,"reputation":25,"alignment_shift":{"justice":8}}},"choices":[]},"pact_01":{"text":"「契約か。面白い人間だ。いいだろう——自分の妖力の一部をお前に預ける」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","speaker_name":"九尾の大妖狐","speaker":"九尾の大妖狐","next":"pact_02","choices":[{"label":"続ける","next":"pact_02"}]},"pact_02":{"text":"九尾の体から金色の炎が一つ、自分の体に宿った。全身に力が漲る——。","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","next":"pact_03","choices":[{"label":"続ける","next":"pact_03"}]},"pact_03":{"text":"「地脈の乱れは抑えてやる。だが覚えておけ——妖の力には代償がある。いずれわかる」","type":"text","bg_key":"bg_forest_night","bgm":"bgm_quest_mystery","speaker_name":"九尾の大妖狐","speaker":"九尾の大妖狐","next":"pact_04","choices":[{"label":"続ける","next":"pact_04"}]},"pact_04":{"text":"両国のギルドには「大妖は倒したが遺体は消えた」と報告した。嘘ではない——半分は。\n大量の報酬を手にしたが、冒険者としての信頼は失われた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success_pact","choices":[{"label":"続ける","next":"end_success_pact"}]},"end_success_pact":{"text":"莫大な報酬を手にした。だがギルドからは不信の目で見られている。\n「本当に倒したのか？ 地脈の乱れは収まったが……」噂は尾を引くだろう。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":8000,"exp":400,"reputation":-20,"alignment_shift":{"chaos":12}}},"choices":[]},"end_failure":{"text":"九尾の幻術と妖力に呑まれ、意識が深い闇に沈んだ。\n最後に聞こえたのは、どこか寂しげな狐の鳴き声だった。","type":"end","result":"failure","bg_key":"bg_forest_night","choices":[]}},"short_description":"[最高討伐令] 東方二国にまたがる霊山に千年の大妖狐が出現。地脈が乱れ災厄が広がる。"}'::jsonb,
    6,
    4
) ON CONFLICT (id) DO UPDATE SET
