-- Scenario 6105: 悪魔バフォメット (qst_legend_baphomet)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6105,
    'qst_legend_baphomet',
    '悪魔バフォメット',
    '[封印指定] 古代の封印が解け、大悪魔バフォメットが地上に現れた。討伐せよ。',
    '冒険者ギルド',
    6,
    25,
    8,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep15"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep15"}'::jsonb,
    '{"nodes":{"start":{"text":"「最高危険度の封印指定だ。古代遺跡から大悪魔の魔力波が検知された」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「千年前の大戦で封じた悪魔——バフォメット。封印が劣化している」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「完全復活すれば国一つが灰になる。それだけの力を持つ存在だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"ギルドマスターの目は冗談を言う色ではなかった。これは国家規模の脅威だ。覚悟を決めて準備を始める。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"prepare_01","choices":[{"label":"続ける","next":"prepare_01"}]},"prepare_01":{"text":"ギルドから支給された古文書を読む。バフォメットは闇と炎の二属性を操り、精神を蝕む咆哮を放つ。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"prepare_02","choices":[{"label":"続ける","next":"prepare_02"}]},"prepare_02":{"text":"弱点は聖属性と光。だが古文書には「光すら喰らう闇の中では、勇気のみが武器となる」とある。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"prepare_03","choices":[{"label":"続ける","next":"prepare_03"}]},"prepare_03":{"text":"装備を整え、ローランド聖王国の南端にある古代遺跡へと向かった。入口には既に聖騎士団が結界を張っている。","type":"text","bg_key":"bg_road_day","bgm":"bgm_field","next":"descend_01","choices":[{"label":"続ける","next":"descend_01"}]},"descend_01":{"text":"結界を抜け、地下へ降りる。石段は苔に覆われ、空気は澱んで重い。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"descend_02","choices":[{"label":"続ける","next":"descend_02"}]},"descend_02":{"text":"松明の炎が不自然に揺れる。魔力の残滓が空気中に漂っているのだ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"descend_03","choices":[{"label":"続ける","next":"descend_03"}]},"descend_03":{"text":"第一層の通路に入ると、床に刻まれた古代文字が赤く脈動していた。罠か——","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"trap_spike","choices":[{"label":"続ける","next":"trap_spike"}]},"trap_spike":{"text":"床の文字を踏んだ瞬間、壁から毒針が射出された！ 咄嗟に身を捻るが、腕を掠める。","type":"hp_damage","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"trap_spike_02","choices":[{"label":"続ける","next":"trap_spike_02"}]},"trap_spike_02":{"text":"傷は浅いが、針には弱い呪毒が塗られていた。体の芯が少し重くなる。先を急ごう。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"corridor_01","choices":[{"label":"続ける","next":"corridor_01"}]},"corridor_01":{"text":"通路の壁に、千年前の戦いを描いた壁画がある。聖騎士たちがバフォメットと対峙している。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"corridor_02","choices":[{"label":"続ける","next":"corridor_02"}]},"corridor_02":{"text":"壁画の最後——聖騎士たちは勝利したのではなく、命と引き換えに封印したのだ。その数、百余名。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"corridor_03","choices":[{"label":"続ける","next":"corridor_03"}]},"corridor_03":{"text":"通路の先から、不気味な呻き声が聞こえる。封印の魔力に引き寄せられた亡者たちだ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"封印の残滓に引き寄せられた怨霊たちが襲いかかる！","type":"battle","bg_key":"bg_ruin_crypt","bgm":"bgm_battle","enemy_group_id":"416","choices":[{"label":"win","next":"after_battle_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"after_battle_01"},"after_battle_01":{"text":"怨霊を退け、第二層への扉に辿り着いた。扉には古代のルーン文字が刻まれている。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"after_battle_02","choices":[{"label":"続ける","next":"after_battle_02"}]},"after_battle_02":{"text":"ルーン文字を読み解かなければ扉は開かない。古文書の知識を頼りに解読を試みる。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"puzzle_01","choices":[{"label":"続ける","next":"puzzle_01"}]},"puzzle_01":{"text":"文字の配列は複雑だが、パターンが見える。「光」「闇」「均衡」——三つの概念の組み合わせか。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"puzzle_02","choices":[{"label":"続ける","next":"puzzle_02"}]},"puzzle_02":{"text":"正しい順番でルーンに触れる。指先に魔力が走り、扉が反応した——","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"random_rune","choices":[{"label":"続ける","next":"random_rune"}]},"random_rune":{"type":"random_branch","bg_key":"bg_ruin_crypt","prob":60,"choices":[{"label":"success","next":"rune_success"},{"label":"failure","next":"rune_fail"}]},"rune_success":{"text":"ルーンが青白く輝き、扉が静かに開いた。正解だ。安全に第二層へ進める。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","next":"rune_success_02","choices":[{"label":"続ける","next":"rune_success_02"}]},"rune_success_02":{"text":"扉の向こうから、より濃厚な魔力の気配が漂ってくる。覚悟を決めて足を踏み入れた。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","next":"sanctum_01","choices":[{"label":"続ける","next":"sanctum_01"}]},"rune_fail":{"text":"ルーンが赤く輝いた——間違えた！ 扉から魔力の衝撃波が放たれる！","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"rune_fail_trap","choices":[{"label":"続ける","next":"rune_fail_trap"}]},"rune_fail_trap":{"text":"衝撃波を全身に受けた。骨が軋む。だが扉は開いた——強引に突破する。","type":"hp_damage","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"rune_fail_02","choices":[{"label":"続ける","next":"rune_fail_02"}]},"rune_fail_02":{"text":"体を引きずりながら第二層に入る。ダメージは痛いが、立ち止まるわけにはいかない。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"sanctum_01","choices":[{"label":"続ける","next":"sanctum_01"}]},"sanctum_01":{"text":"第二層は広大な聖堂のような空間だった。だが祭壇は逆十字に変えられ、壁には魔法陣が刻まれている。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"sanctum_02","choices":[{"label":"続ける","next":"sanctum_02"}]},"sanctum_02":{"text":"天井から黒い霧が垂れ下がり、床の亀裂からは赤い光が漏れている。封印の最終層だ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"sanctum_03","choices":[{"label":"続ける","next":"sanctum_03"}]},"sanctum_03":{"text":"聖堂の中央に巨大な石棺がある。石棺の蓋に刻まれた封印紋が、脈動するように明滅している。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"sanctum_04","choices":[{"label":"続ける","next":"sanctum_04"}]},"sanctum_04":{"text":"石棺の周囲に、バフォメットの眷属と思しき魔物が蠢いている。まずはこいつらを片付けなければ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"sanctum_05","choices":[{"label":"続ける","next":"sanctum_05"}]},"sanctum_05":{"text":"魔物たちがこちらに気づいた。一斉に牙を剥く——！","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"バフォメットの眷属たちが牙を剥く！","type":"battle","bg_key":"bg_ruin_crypt","bgm":"bgm_battle","enemy_group_id":"413","choices":[{"label":"win","next":"altar_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"altar_01"},"altar_01":{"text":"眷属を倒すと、石棺の封印紋が一際強く輝いた。そして——亀裂が入った。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"altar_02","choices":[{"label":"続ける","next":"altar_02"}]},"altar_02":{"text":"石棺の蓋が弾け飛んだ。中から噴き出す漆黒の魔力が聖堂を満たしていく。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"altar_03","choices":[{"label":"続ける","next":"altar_03"}]},"altar_03":{"text":"闇の中に、二本の巨大な角が浮かび上がった。山羊の頭。燃える双眸。人の体に獣の四肢。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"awaken_01","choices":[{"label":"続ける","next":"awaken_01"}]},"awaken_01":{"text":"「……千年か。随分と眠ったものだ」","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_battle_boss","speaker_name":"バフォメット","speaker":"バフォメット","next":"awaken_02","choices":[{"label":"続ける","next":"awaken_02"}]},"awaken_02":{"text":"「封じた聖騎士どもの骨はとうに朽ちたか。だがまだ生贄を送ってくるとは、人の子も愚かだ」","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_battle_boss","speaker_name":"バフォメット","speaker":"バフォメット","next":"awaken_03","choices":[{"label":"続ける","next":"awaken_03"}]},"awaken_03":{"text":"「さあ、見せてみろ。千年の間に人間がどれほど進歩したか——あるいは退化したか」","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_battle_boss","speaker_name":"バフォメット","speaker":"バフォメット","next":"awaken_04","choices":[{"label":"続ける","next":"awaken_04"}]},"awaken_04":{"text":"バフォメットが立ち上がった。その体躯は石棺の二倍以上。聖堂の天井に角が届く。全身から地獄の業火が噴き出す——！","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"大悪魔バフォメットとの最終決戦——！","type":"battle","bg_key":"bg_ruin_crypt","bgm":"bgm_battle_boss","enemy_group_id":"9021","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"渾身の一撃がバフォメットの胸を貫いた。大悪魔が初めて膝をつく。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……ほう。まさか倒されるとはな。千年前の聖騎士どもより、貴様の方が強いとでも言うのか」","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","speaker_name":"バフォメット","speaker":"バフォメット","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"「だが知っておけ。自分を殺せば、この遺跡に封じられた魔力が暴走する。殺すか——再び封じるか。選べ」\nバフォメットは不敵に笑った。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","speaker_name":"バフォメット","speaker":"バフォメット","next":"choice_seal","choices":[{"label":"続ける","next":"choice_seal"}]},"choice_seal":{"type":"choice","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","choices":[{"label":"「止めを刺す。お前の脅しには屈しない」","next":"slay_01"},{"label":"「封印を強化する。二度と目覚めぬように」","next":"seal_01"}]},"slay_01":{"text":"剣を振り下ろした。バフォメットの体が黒い灰となって崩れ、聖堂が激しく振動する。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"slay_02","choices":[{"label":"続ける","next":"slay_02"}]},"slay_02":{"text":"遺跡から脱出した。背後で遺跡が崩落する轟音が響いた。大悪魔は滅び、遺跡と共に地に還った。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"ギルドに凱旋した。「大悪魔バフォメットの討伐を確認。これは歴史に刻まれる偉業だ」\nギルドマスターが深く頭を下げた。千年の脅威に、終止符が打たれた。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":5000,"exp":500,"reputation":20,"alignment_shift":{"order":10}}},"choices":[]},"seal_01":{"text":"古文書の封印術を唱える。バフォメットの体に新たな封印紋が刻まれていく。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","next":"seal_02","choices":[{"label":"続ける","next":"seal_02"}]},"seal_02":{"text":"「……賢い選択だ。だが覚えておけ。封印は永遠ではない。また千年後に——」\n声は封印の光に呑まれ、消えた。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","speaker_name":"バフォメット","speaker":"バフォメット","next":"seal_03","choices":[{"label":"続ける","next":"seal_03"}]},"seal_03":{"text":"遺跡から戻ると、聖騎士団が新たな結界を張り直していた。今度の封印は、より強固だ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success_seal","choices":[{"label":"続ける","next":"end_success_seal"}]},"end_success_seal":{"text":"「封印強化の報告を受けた。討伐こそならなかったが、これで当面の脅威は去った」\n報酬は控えめだったが、大地を守る選択に悔いはない。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":3000,"exp":500,"reputation":10,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure":{"text":"バフォメットの漆黒の炎に焼かれ、意識が遠のいていく。\n最後に見えたのは、大悪魔が嗤う姿だった。「次の千年も、人は変わらぬか」","type":"end","result":"failure","bg_key":"bg_ruin_crypt","choices":[]}},"short_description":"[封印指定] 古代の封印が解け、大悪魔バフォメットが地上に現れた。討伐せよ。"}'::jsonb,
    8,
    4
) ON CONFLICT (id) DO UPDATE SET
    slug = EXCLUDED.slug,
    title = EXCLUDED.title,
    description = EXCLUDED.description,
    client_name = EXCLUDED.client_name,
    difficulty = EXCLUDED.difficulty,
    rec_level = EXCLUDED.rec_level,
    time_cost = EXCLUDED.time_cost,
    rewards = EXCLUDED.rewards,
    is_urgent = EXCLUDED.is_urgent,
    quest_type = EXCLUDED.quest_type,
    requirements = EXCLUDED.requirements,
    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6106: 降臨せし天使 (qst_legend_angel)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6106,
    'qst_legend_angel',
    '降臨せし天使',
    '[神罰] 天空から降臨した天使が聖都を焼き払おうとしている。止めるのは貴方だ。',
    '冒険者ギルド',
    6,
    25,
    8,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep15"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep15"}'::jsonb,
    '{"nodes":{"start":{"text":"「信じられるか。天使が聖都を攻撃しているんだ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「教会は大混乱だ。信仰の対象に剣を向けろと言うのだからな」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「だが放置すれば聖都が灰になる。信仰も糞もない。止めなければ人が死ぬ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"天使を討つ——それがどれほど途方もないことか。だが、目の前で人が死ぬのを黙って見ていることはできない。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"start_05","choices":[{"label":"続ける","next":"start_05"}]},"start_05":{"text":"聖都に近づくと、空が白く輝いていた。太陽ではない。天使の放つ光だ。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"city_01","choices":[{"label":"続ける","next":"city_01"}]},"city_01":{"text":"市街地は阿鼻叫喚だった。建物は半壊し、逃げ惑う市民の悲鳴が響く。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"city_02","choices":[{"label":"続ける","next":"city_02"}]},"city_02":{"text":"聖堂の尖塔が光の剣で真っ二つに切り裂かれている。天使の力は想像以上だ。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"city_03","choices":[{"label":"続ける","next":"city_03"}]},"city_03":{"text":"瓦礫の下から助けを求める声。だが今は立ち止まれない。天使を止めなければ被害は広がる一方だ。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"city_04","choices":[{"label":"続ける","next":"city_04"}]},"city_04":{"text":"市街地を進むと、天使に仕える下位の光の戦士たちが降下してきた。人間を「浄化」しようとしている。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"city_05","choices":[{"label":"続ける","next":"city_05"}]},"city_05":{"text":"市民を守るため、立ちはだかる。光の戦士たちがこちらに槍を向けた——！","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"天使の先兵——光の戦士たちが襲いかかる！","type":"battle","bg_key":"bg_holy_empire","bgm":"bgm_battle","enemy_group_id":"218","choices":[{"label":"win","next":"ascend_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"ascend_01"},"ascend_01":{"text":"光の戦士を退けた。市民たちが感謝の声を上げるが、振り返る余裕はない。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"ascend_02","choices":[{"label":"続ける","next":"ascend_02"}]},"ascend_02":{"text":"天使は聖都の大聖堂の尖塔の上に浮かんでいる。あそこまで辿り着かなければ。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"ascend_03","choices":[{"label":"続ける","next":"ascend_03"}]},"ascend_03":{"text":"大聖堂の中に入ると、床に光の魔法陣が浮かび上がっていた。これは——天に昇るための道か。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"ascend_04","choices":[{"label":"続ける","next":"ascend_04"}]},"ascend_04":{"text":"魔法陣を踏むと、体が浮き上がった。光の渦に包まれ、大聖堂の天蓋を突き抜けていく——","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"trial_01","choices":[{"label":"続ける","next":"trial_01"}]},"trial_01":{"text":"雲の上に出た。そこには黄金の回廊が続いている。天使の領域だ。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"trial_02","choices":[{"label":"続ける","next":"trial_02"}]},"trial_02":{"text":"回廊の先に門がある。門は光の文字で封じられている。「罪なき者のみ通れ」——試練か。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"trial_03","choices":[{"label":"続ける","next":"trial_03"}]},"trial_03":{"text":"光の文字に手を触れる。心の奥底を探られるような感覚が走った——","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"random_trial","choices":[{"label":"続ける","next":"random_trial"}]},"random_trial":{"type":"random_branch","bg_key":"bg_holy_empire","prob":50,"choices":[{"label":"success","next":"trial_pass"},{"label":"failure","next":"trial_fail"}]},"trial_pass":{"text":"光の文字が消え、門が開いた。自分の中にある覚悟が、試練を超えたのだ。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","next":"trial_pass_02","choices":[{"label":"続ける","next":"trial_pass_02"}]},"trial_pass_02":{"text":"門の向こうに、より強い光が見える。天使の玉座は近い。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","next":"throne_01","choices":[{"label":"続ける","next":"throne_01"}]},"trial_fail":{"text":"光が体を灼いた。「罪あり」——門が裁きの光を放つ！","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"trial_fail_trap","choices":[{"label":"続ける","next":"trial_fail_trap"}]},"trial_fail_trap":{"text":"裁きの光が全身を貫いた。倒れかけるが、歯を食いしばって前に進む。門は——強引に砕いた。","type":"hp_damage","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","params":{"hp_percent":20,"percent":20},"next":"trial_fail_02","choices":[{"label":"続ける","next":"trial_fail_02"}]},"trial_fail_02":{"text":"試練は失敗したが、意志の力で門を突破した。体は痛むが、立ち止まるわけにはいかない。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"throne_01","choices":[{"label":"続ける","next":"throne_01"}]},"throne_01":{"text":"門の先は、雲で作られた玉座の間だった。黄金の光に満ちている。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"throne_02","choices":[{"label":"続ける","next":"throne_02"}]},"throne_02":{"text":"玉座の間の中央に、天使の護衛が控えている。大天使の名を持つ強大な存在だ。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"throne_03","choices":[{"label":"続ける","next":"throne_03"}]},"throne_03":{"text":"護衛の天使が光の槍を構える。「ここから先は通さぬ。引き返せ、人の子よ」","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"throne_04","choices":[{"label":"続ける","next":"throne_04"}]},"throne_04":{"text":"引き返すつもりはない。武器を構え、真正面から対峙する。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"throne_05","choices":[{"label":"続ける","next":"throne_05"}]},"throne_05":{"text":"護衛の天使が翼を広げた。光の粒子が舞い散り、目を開けていられないほどの輝き。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"throne_06","choices":[{"label":"続ける","next":"throne_06"}]},"throne_06":{"text":"「人の子の覚悟、試してやろう。神の御名において——」","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"大天使とその従者が立ちはだかる！","type":"battle","bg_key":"bg_holy_empire","bgm":"bgm_battle_boss","enemy_group_id":"219","choices":[{"label":"win","next":"dialogue_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"dialogue_01"},"dialogue_01":{"text":"護衛の天使を退けた。その先に——光の玉座に座る存在が見えた。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"dialogue_02","choices":[{"label":"続ける","next":"dialogue_02"}]},"dialogue_02":{"text":"六枚の翼。人の姿をしているが、纏う光はこの世のものではない。降臨せし天使——その本体だ。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","next":"dialogue_03","choices":[{"label":"続ける","next":"dialogue_03"}]},"dialogue_03":{"text":"「よくぞここまで来た。だが理解しているか？ 自分は世界を正しているだけだ」","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","speaker_name":"降臨せし天使","speaker":"降臨せし天使","next":"dialogue_04","choices":[{"label":"続ける","next":"dialogue_04"}]},"dialogue_04":{"text":"「人は殺し合い、奪い合い、嘘をつく。千年見守ったが、改善の兆しはない。故に——浄化する」","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_mystery","speaker_name":"降臨せし天使","speaker":"降臨せし天使","next":"confront_01","choices":[{"label":"続ける","next":"confront_01"}]},"confront_01":{"text":"天使の言葉に一理ある。人間は確かに愚かだ。だが——だからと言って、全てを焼き払っていいはずがない。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"confront_02","choices":[{"label":"続ける","next":"confront_02"}]},"confront_02":{"text":"「不完全だからこそ、人は足掻く。変わろうとする。お前にはそれが分からないだけだ」","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"confront_03","choices":[{"label":"続ける","next":"confront_03"}]},"confront_03":{"text":"「……言葉では納得できぬ。ならば力で示してみせよ。人の意志の強さを——」\n天使が玉座から立ち上がり、六枚の翼を広げた。光の剣が顕現する。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_battle_boss","speaker_name":"降臨せし天使","speaker":"降臨せし天使","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"降臨せし天使との決戦——！","type":"battle","bg_key":"bg_holy_empire","bgm":"bgm_battle_boss","enemy_group_id":"9022","choices":[{"label":"win","next":"aftermath_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"aftermath_01"},"aftermath_01":{"text":"天使の光の剣が砕けた。六枚の翼が力を失い、天使が膝をつく。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","next":"aftermath_02","choices":[{"label":"続ける","next":"aftermath_02"}]},"aftermath_02":{"text":"「……認めよう。貴方には意志がある。自分が裁こうとした人間にも、確かに光はあった」","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","speaker_name":"降臨せし天使","speaker":"降臨せし天使","next":"aftermath_03","choices":[{"label":"続ける","next":"aftermath_03"}]},"aftermath_03":{"text":"「だが自分はもう天に帰れぬ。降臨の代償だ。ここで朽ちるか——あるいは」\n天使は静かにこちらを見つめた。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","speaker_name":"降臨せし天使","speaker":"降臨せし天使","next":"choice_fate","choices":[{"label":"続ける","next":"choice_fate"}]},"choice_fate":{"type":"choice","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","choices":[{"label":"「止めを刺す。これ以上の脅威を残すわけにはいかない」","next":"execute_01"},{"label":"「帰りたいなら、帰す方法を探そう」","next":"persuade_01"}]},"execute_01":{"text":"剣を振り下ろした。天使の体が光の粒子となって散り、空に還っていく。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_tense","next":"execute_02","choices":[{"label":"続ける","next":"execute_02"}]},"execute_02":{"text":"光が消えると、雲の玉座も崩れ始めた。大聖堂の床に降り立つ。聖都の空は、元の青さを取り戻していた。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「降臨せし天使の討伐を確認。聖都の被害は甚大だが、これ以上の犠牲は免れた」\nギルドマスターは複雑な表情だった。天使を殺した——その重みは、報酬では量れない。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":5000,"exp":500,"reputation":20,"alignment_shift":{"chaos":10}}},"choices":[]},"persuade_01":{"text":"「帰す——だと？ 人間が天使を救おうと言うのか」\n天使は信じられないという顔をした。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","speaker_name":"降臨せし天使","speaker":"降臨せし天使","next":"persuade_02","choices":[{"label":"続ける","next":"persuade_02"}]},"persuade_02":{"text":"「お前が言っただろう。人は不完全だと。不完全だから、敵にも手を差し伸べる」","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","next":"persuade_03","choices":[{"label":"続ける","next":"persuade_03"}]},"persuade_03":{"text":"「……奇妙な生き物だ。だが、嫌いではない」\n天使は微かに笑い、残った光を集め始めた。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","speaker_name":"降臨せし天使","speaker":"降臨せし天使","next":"persuade_04","choices":[{"label":"続ける","next":"persuade_04"}]},"persuade_04":{"text":"光の柱が天を穿ち、天使の体がゆっくりと浮かび上がる。最後に一度だけ振り返り——光と共に消えた。","type":"text","bg_key":"bg_holy_empire","bgm":"bgm_quest_calm","next":"end_success_peace","choices":[{"label":"続ける","next":"end_success_peace"}]},"end_success_peace":{"text":"「天使が去った……のか。信じられんが、聖都上空の異変は収まった」\n討伐ではなく帰還。教会はこの事実をどう解釈するだろうか。だが、少なくとも今は——空は穏やかだ。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":3500,"exp":500,"reputation":15,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure":{"text":"天使の光の剣が体を貫いた。視界が白く焼かれていく。\n最後に聞こえたのは、天使の静かな声だった。「やはり人は——脆い」","type":"end","result":"failure","bg_key":"bg_holy_empire","choices":[]}},"short_description":"[神罰] 天空から降臨した天使が聖都を焼き払おうとしている。止めるのは貴方だ。"}'::jsonb,
    8,
    4
