    days_failure = EXCLUDED.days_failure;

-- Scenario 6107: デザートドラゴン (qst_legend_dragon)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6107,
    'qst_legend_dragon',
    'デザートドラゴン',
    '[竜殺し] マルカンドの大砂漠に古代の砂竜が覚醒した。命知らずの猛者を求む。',
    '冒険者ギルド',
    6,
    27,
    10,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep15"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep15"}'::jsonb,
    '{"nodes":{"start":{"text":"「マルカンドの交易路が完全に止まった。砂の下から竜が出たそうだ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「デザートドラゴン。千年以上前の古文書にしか記録がない伝説の存在だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「交易商会が報酬を積み上げている。だが、正直に言おう——生きて帰れる保証はない」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"竜殺し。物語の中でしか聞かない言葉だ。だが今、それが自分に求められている。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"caravan_01","choices":[{"label":"続ける","next":"caravan_01"}]},"caravan_01":{"text":"マルカンドの港町から砂漠へ出発した。護衛を申し出た交易商が同行してくれる。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_field","next":"caravan_02","choices":[{"label":"続ける","next":"caravan_02"}]},"caravan_02":{"text":"「竜が出たのはこの先の大砂丘地帯だ。最後に目撃したキャラバンは全滅した」","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_field","next":"caravan_03","choices":[{"label":"続ける","next":"caravan_03"}]},"caravan_03":{"text":"商人を安全な場所で待たせ、単身で砂丘の奥へ向かった。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_field","next":"desert_01","choices":[{"label":"続ける","next":"desert_01"}]},"desert_01":{"text":"大砂丘地帯。見渡す限りの砂の海。太陽が容赦なく照りつける。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"desert_02","choices":[{"label":"続ける","next":"desert_02"}]},"desert_02":{"text":"砂の上に、巨大な爪跡が刻まれていた。幅は自分の両腕を広げた以上。これが竜の痕跡か。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"desert_03","choices":[{"label":"続ける","next":"desert_03"}]},"desert_03":{"text":"突然、風が止んだ。空気が灼けるように熱い。次の瞬間——砂嵐が襲ってきた！","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"sandstorm_trap","choices":[{"label":"続ける","next":"sandstorm_trap"}]},"sandstorm_trap":{"text":"竜のブレスの残熱が砂嵐を引き起こしたのか。灼けた砂粒が肌を削る。","type":"hp_damage","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"sandstorm_02","choices":[{"label":"続ける","next":"sandstorm_02"}]},"sandstorm_02":{"text":"砂嵐が収まると、地形が変わっていた。砂がガラス状の平原に溶けている。竜の吐息の跡だ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"oasis_01","choices":[{"label":"続ける","next":"oasis_01"}]},"oasis_01":{"text":"ガラスの平原の先に、不自然な緑が見えた。砂漠のオアシスか——蜃気楼か？","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"oasis_02","choices":[{"label":"続ける","next":"oasis_02"}]},"oasis_02":{"text":"近づくと水音がする。本物のオアシスだ。だが水面が異様に輝いている。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"oasis_03","choices":[{"label":"続ける","next":"oasis_03"}]},"oasis_03":{"text":"オアシスを迂回するか、突っ切るか。方角を見失わないよう慎重に進む——","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"random_mirage","choices":[{"label":"続ける","next":"random_mirage"}]},"random_mirage":{"type":"random_branch","bg_key":"bg_marcund_desert","prob":50,"choices":[{"label":"success","next":"mirage_clear"},{"label":"failure","next":"mirage_lost"}]},"mirage_clear":{"text":"蜃気楼のパターンを読み、正しい道を選んだ。竜の巣の方角が見えてきた。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"approach_01","choices":[{"label":"続ける","next":"approach_01"}]},"mirage_lost":{"text":"蜃気楼に惑わされた！ 同じ場所を何度も回り、体力が削られていく。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"mirage_trap","choices":[{"label":"続ける","next":"mirage_trap"}]},"mirage_trap":{"text":"灼熱と脱水で意識が朦朧とする。必死に星の位置を読み、ようやく方角を取り戻した。","type":"hp_damage","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"mirage_lost_02","choices":[{"label":"続ける","next":"mirage_lost_02"}]},"mirage_lost_02":{"text":"大きく消耗したが、竜の巣の方角は掴めた。水を一口だけ含み、前に進む。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"approach_01","choices":[{"label":"続ける","next":"approach_01"}]},"approach_01":{"text":"砂丘を越えると、巨大なクレーターが現れた。直径は城壁の一辺ほど。竜の巣だ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"approach_02","choices":[{"label":"続ける","next":"approach_02"}]},"approach_02":{"text":"クレーターの底に、溶けた砂がガラスの洞窟を形成している。熱気が陽炎のように揺らめく。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"approach_03","choices":[{"label":"続ける","next":"approach_03"}]},"approach_03":{"text":"洞窟の入口付近に砂漠の魔獣たちが巣を張っている。竜の余熱に寄り付いた下等な魔物だ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"approach_04","choices":[{"label":"続ける","next":"approach_04"}]},"approach_04":{"text":"背後を突かれないよう、まずは排除する。武器を抜いた——","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"nest_01","choices":[{"label":"続ける","next":"nest_01"}]},"nest_01":{"text":"魔獣たちがこちらに気づき、一斉に唸り声を上げた。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"nest_02","choices":[{"label":"続ける","next":"nest_02"}]},"nest_02":{"text":"砂蟲とサソリの群れが迫る——！","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"砂漠の魔獣たちが襲いかかる！","type":"battle","bg_key":"bg_marcund_desert","bgm":"bgm_battle","enemy_group_id":"421","choices":[{"label":"win","next":"nest_03"},{"label":"lose","next":"end_failure"}],"battle_success_next":"nest_03"},"nest_03":{"text":"ガラスの洞窟に足を踏み入れた。壁面が虹色に輝いている。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"nest_04","choices":[{"label":"続ける","next":"nest_04"}]},"nest_04":{"text":"洞窟の奥は天然のドーム状空洞。天井に竜の鱗が突き刺さっている。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"nest_05","choices":[{"label":"続ける","next":"nest_05"}]},"nest_05":{"text":"大空洞の中央に、砂金と宝石が山のように積まれていた。竜の財宝か。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"nest_06","choices":[{"label":"続ける","next":"nest_06"}]},"nest_06":{"text":"財宝の山の向こうに、巨大な影が横たわっている。規則的な呼吸が洞窟全体を揺らす。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"nest_07","choices":[{"label":"続ける","next":"nest_07"}]},"nest_07":{"text":"デザートドラゴン。全長は城の塔ほど。黄金色の鱗、燃え上がるような紅い瞳。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"nest_08","choices":[{"label":"続ける","next":"nest_08"}]},"nest_08":{"text":"竜がこちらに気づいた。巨大な首がゆっくりと持ち上がる。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"roar_01","choices":[{"label":"続ける","next":"roar_01"}]},"roar_01":{"text":"「——人間か。千年ぶりに目覚めてみれば、蟻の如き者がやってきたか」","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_battle_boss","speaker_name":"デザートドラゴン","speaker":"デザートドラゴン","next":"roar_02","choices":[{"label":"続ける","next":"roar_02"}]},"roar_02":{"text":"「自分の宝を守っているだけだ。なぜ人間は討ちに来る。身の程を知れ」","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_battle_boss","speaker_name":"デザートドラゴン","speaker":"デザートドラゴン","next":"roar_03","choices":[{"label":"続ける","next":"roar_03"}]},"roar_03":{"text":"「交易路を塞いでいるのはお前の巣だ。人が暮らせなくなっている」——言葉を返す。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_battle_boss","next":"roar_04","choices":[{"label":"続ける","next":"roar_04"}]},"roar_04":{"text":"「知ったことか。ならば力で示せ。竜に挑む愚かさの代償を——その身で味わえ」\n竜が翼を広げた。洞窟が地鳴りのように震える。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_battle_boss","speaker_name":"デザートドラゴン","speaker":"デザートドラゴン","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"デザートドラゴンとの死闘——！","type":"battle","bg_key":"bg_marcund_desert","bgm":"bgm_battle_boss","enemy_group_id":"9023","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"竜の巨体が揺らぎ、崩れ落ちた。黄金の鱗が剥がれていく。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……千年眠り、目覚めた途端に敗れるか。人間とは——面白い種族だ」","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","speaker_name":"デザートドラゴン","speaker":"デザートドラゴン","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"「殺すか、それとも封じるか。竜は、負けた者に従う」\n竜は静かに首を下げた。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","speaker_name":"デザートドラゴン","speaker":"デザートドラゴン","next":"choice_dragon","choices":[{"label":"続ける","next":"choice_dragon"}]},"choice_dragon":{"type":"choice","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","choices":[{"label":"「止めを刺す。竜の脅威を永久に除く」","next":"slay_01"},{"label":"「巣を砂漠の奥に移せ。人の道から離れろ」","next":"coexist_01"}]},"slay_01":{"text":"渾身の一撃を竜の額に叩き込んだ。洞窟が崩落し始める。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"slay_02","choices":[{"label":"続ける","next":"slay_02"}]},"slay_02":{"text":"崩れゆく洞窟から脱出した。背後で竜の巣が砂に沈む。竜殺しの英雄——称号が現実になった。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「デザートドラゴン討伐を確認！ 交易路は復旧する。お前は英雄だ」\n交易商会から莫大な報酬を受け取った。竜の鱗は勲章として飾られるだろう。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":8000,"exp":600,"reputation":25,"alignment_shift":{"chaos":10}}},"choices":[]},"coexist_01":{"text":"「……殺さぬか。珍しい人間だ」\n竜の紅い瞳にわずかな感情が灯った。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","speaker_name":"デザートドラゴン","speaker":"デザートドラゴン","next":"coexist_02","choices":[{"label":"続ける","next":"coexist_02"}]},"coexist_02":{"text":"「ここから東に三日の場所に、人の通わぬ岩山がある。そこへ巣を移せ」","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"coexist_03","choices":[{"label":"続ける","next":"coexist_03"}]},"coexist_03":{"text":"「承知した。自分は恩を忘れぬ種族だ。次に会う時は、味方として来よう」\n竜は翼を広げ、砂嵐と共に東の空へ消えた。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","speaker_name":"デザートドラゴン","speaker":"デザートドラゴン","next":"end_success_peace","choices":[{"label":"続ける","next":"end_success_peace"}]},"end_success_peace":{"text":"「竜が去ったのか……交易路の安全は確認された」\n報酬は控えめだが、砂漠の空に黄金の影が消えていく姿は——悪くなかった。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":5000,"exp":600,"reputation":15,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure":{"text":"竜のブレスが全身を包んだ。砂が硝子に変わる灼熱の中、意識が溶けていく。\n「蟻は所詮——蟻か」","type":"end","result":"failure","bg_key":"bg_marcund_desert","choices":[]}},"short_description":"[竜殺し] マルカンドの大砂漠に古代の砂竜が覚醒した。命知らずの猛者を求む。"}'::jsonb,
    10,
    5
