-- Scenario 6108: 神域の幻獣 (qst_legend_kirin)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6108,
    'qst_legend_kirin',
    '神域の幻獣',
    '[封印指定] 華龍国の霊峰に神獣・麒麟が降臨し、結界を張って人の立ち入りを拒んでいる。',
    '冒険者ギルド',
    6,
    27,
    10,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep15"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep15"}'::jsonb,
    '{"nodes":{"start":{"text":"「華龍国から緊急の依頼だ。霊峰に神獣が現れ、山を封鎖している」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「麒麟——古来、仁徳の象徴とされる幻の聖獣だ。だが今は人間を拒絶している」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「山麓の民は薬草園と鉱脈を失い、飢え始めている。一刻の猶予もない」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"神獣を討つのか、それとも対話するのか。まずは霊峰に向かい、真意を確かめなければ。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"climb_01","choices":[{"label":"続ける","next":"climb_01"}]},"climb_01":{"text":"崑崙山の麓に到着した。山道の入口に結界の光が薄く漂っている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_field","next":"climb_02","choices":[{"label":"続ける","next":"climb_02"}]},"climb_02":{"text":"結界に触れると、穏やかだが確かな拒絶の力を感じる。通り抜けるには覚悟がいる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"climb_03","choices":[{"label":"続ける","next":"climb_03"}]},"climb_03":{"text":"意を決して結界に踏み込んだ。体が軋むような圧力——だが、前に進む。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"climb_04","choices":[{"label":"続ける","next":"climb_04"}]},"climb_04":{"text":"結界を突破した。だがその代償は体に刻まれている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"barrier_trap","choices":[{"label":"続ける","next":"barrier_trap"}]},"barrier_trap":{"text":"結界の浄化の力が体を蝕む。人間の穢れを灼いているのか——全身に鈍い痛みが走った。","type":"hp_damage","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"barrier_02","choices":[{"label":"続ける","next":"barrier_02"}]},"barrier_02":{"text":"結界の内側は、外界とは空気が異なっていた。澄み切った霊気が肌を撫でる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"forest_01","choices":[{"label":"続ける","next":"forest_01"}]},"forest_01":{"text":"山道を登ると、かつての薬草園が見えた。人の手入れが途絶え、野生に還りつつある。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"forest_02","choices":[{"label":"続ける","next":"forest_02"}]},"forest_02":{"text":"だが植生は異常に豊かだ。麒麟の霊気が山全体を活性化させているのか。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"forest_03","choices":[{"label":"続ける","next":"forest_03"}]},"forest_03":{"text":"鳥の声、獣の気配。結界の中は楽園のようだ。麒麟は山を守っている——ように見える。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"forest_04","choices":[{"label":"続ける","next":"forest_04"}]},"forest_04":{"text":"だが楽園の番人は来訪者を歓迎しない。森の奥から、精霊たちが警戒の眼差しを向けている。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"結界の守護精霊たちが侵入者を排除しようと襲いかかる！","type":"battle","bg_key":"bg_karyu_mountain","bgm":"bgm_battle","enemy_group_id":"108","choices":[{"label":"win","next":"summit_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"summit_01"},"summit_01":{"text":"精霊を退け、山頂への最後の登りに差しかかった。空気が薄いが、霊気は濃密だ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"summit_02","choices":[{"label":"続ける","next":"summit_02"}]},"summit_02":{"text":"山頂の台地に出た。一面の雲海。その中央に、白銀の光を纏う存在が佇んでいる。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"summit_03","choices":[{"label":"続ける","next":"summit_03"}]},"summit_03":{"text":"鹿の体に龍の頭、全身を覆う光の鱗。一本角が虹色に輝く。麒麟だ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_mystery","next":"random_judge","choices":[{"label":"続ける","next":"random_judge"}]},"random_judge":{"type":"random_branch","bg_key":"bg_karyu_mountain","prob":50,"choices":[{"label":"success","next":"judge_pass"},{"label":"failure","next":"judge_fail"}]},"judge_pass":{"text":"麒麟の光がこちらを包んだ。体が温かい。害意はないと判断されたようだ。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"confront_01","choices":[{"label":"続ける","next":"confront_01"}]},"judge_fail":{"text":"麒麟の光が裁きに変わった。「穢れあり」——浄化の光が体を貫く！","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"judge_trap","choices":[{"label":"続ける","next":"judge_trap"}]},"judge_trap":{"text":"浄化の光が全身を灼いた。膝をつくが、歯を食いしばって立ち上がる。","type":"hp_damage","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","params":{"hp_percent":20,"percent":20},"next":"judge_fail_02","choices":[{"label":"続ける","next":"judge_fail_02"}]},"judge_fail_02":{"text":"裁きは受けた。だが退くつもりはない。顔を上げ、麒麟を真っ直ぐ見据えた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"confront_01","choices":[{"label":"続ける","next":"confront_01"}]},"confront_01":{"text":"「……人の子よ。なぜここに来た」\n麒麟の声は風のように穏やかだが、底知れぬ威厳を帯びていた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","speaker_name":"麒麟","speaker":"麒麟","next":"confront_02","choices":[{"label":"続ける","next":"confront_02"}]},"confront_02":{"text":"「山麓の民が困っている。結界を解いてほしい」——率直に伝えた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"confront_03","choices":[{"label":"続ける","next":"confront_03"}]},"confront_03":{"text":"「人間は山を削り、水を汚し、獣を追い立てた。自分はこの山を人間から守っているのだ」","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","speaker_name":"麒麟","speaker":"麒麟","next":"confront_04","choices":[{"label":"続ける","next":"confront_04"}]},"confront_04":{"text":"「千年見守ったが、人間の業は深まる一方。故に結界を張った。これは罰ではない——保護だ」","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","speaker_name":"麒麟","speaker":"麒麟","next":"confront_05","choices":[{"label":"続ける","next":"confront_05"}]},"confront_05":{"text":"麒麟の言葉に嘘はない。だが山麓の民は飢えている。どちらの正義を選ぶべきか。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"confront_06","choices":[{"label":"続ける","next":"confront_06"}]},"confront_06":{"text":"「言葉で通じぬなら、力で示すがよい。自分を超えるなら——人の言葉に耳を傾けよう」\n麒麟の一本角が白熱した。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","speaker_name":"麒麟","speaker":"麒麟","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"霊獣・麒麟との決戦——！","type":"battle","bg_key":"bg_karyu_mountain","bgm":"bgm_battle_boss","enemy_group_id":"9024","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"麒麟の角が砕けた。霊獣が膝をつき、光が弱まっていく。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……認めよう。貴方には力がある。だが力だけでは山は守れぬ」","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","speaker_name":"麒麟","speaker":"麒麟","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"「殺すか。それとも、人と山が共に生きる道を示すか。どちらを選ぶ」","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","speaker_name":"麒麟","speaker":"麒麟","next":"choice_kirin","choices":[{"label":"続ける","next":"choice_kirin"}]},"choice_kirin":{"type":"choice","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","choices":[{"label":"「脅威は排除する。結界を確実に解くために」","next":"slay_01"},{"label":"「人と山の共存を約束する。結界を部分的に解いてくれ」","next":"peace_01"}]},"slay_01":{"text":"剣を振り下ろした。麒麟の体が光の粒子に還り、山頂に風が吹き抜けた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_tense","next":"slay_02","choices":[{"label":"続ける","next":"slay_02"}]},"slay_02":{"text":"結界が消え、山が元の姿を取り戻した。だが空気は少し、澱んだ気がする。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「麒麟の討伐を確認。結界は解除され、山麓の民は元の暮らしに戻れる」\n報酬を受け取ったが、山頂の清浄な空気を思い出すと——少しだけ、胸が痛んだ。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":6000,"exp":600,"reputation":20,"alignment_shift":{"chaos":10}}},"choices":[]},"peace_01":{"text":"「……共存か。千年待ったが、ようやくそう言う人間が現れたか」\n麒麟の瞳に穏やかな光が戻った。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","speaker_name":"麒麟","speaker":"麒麟","next":"peace_02","choices":[{"label":"続ける","next":"peace_02"}]},"peace_02":{"text":"「薬草園と鉱脈の一部を開放する。だが奥の森と水源には人を入れるな。約束できるか」","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","next":"peace_03","choices":[{"label":"続ける","next":"peace_03"}]},"peace_03":{"text":"「よかろう。約束は守れ——自分はこの山から離れぬ。見守っている」\n結界が薄くなり、山道が開かれた。","type":"text","bg_key":"bg_karyu_mountain","bgm":"bgm_quest_calm","speaker_name":"麒麟","speaker":"麒麟","next":"end_success_peace","choices":[{"label":"続ける","next":"end_success_peace"}]},"end_success_peace":{"text":"「結界が部分的に解除された。山麓の民は安堵している」\n麒麟との約束——人と山の共存。それを守れるかどうかは、人間の覚悟次第だ。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":4000,"exp":600,"reputation":25,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure":{"text":"麒麟の浄化の光が体を焼き尽くした。山は静けさを取り戻し——人の痕跡は消えた。","type":"end","result":"failure","bg_key":"bg_karyu_mountain","choices":[]}},"short_description":"[封印指定] 華龍国の霊峰に神獣・麒麟が降臨し、結界を張って人の立ち入りを拒んでいる。"}'::jsonb,
    10,
    5
) ON CONFLICT (id) DO UPDATE SET
