    location_tags = EXCLUDED.location_tags,
    conditions = EXCLUDED.conditions,
    script_data = EXCLUDED.script_data,
    days_success = EXCLUDED.days_success,
    days_failure = EXCLUDED.days_failure;

-- Scenario 6109: オメガ・ゴーレム (qst_legend_golem)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6109,
    'qst_legend_golem',
    'オメガ・ゴーレム',
    '[封印指定] 古代魔導帝国の遺跡から起動した巨大ゴーレムが都市に向かっている。迎撃せよ。',
    '冒険者ギルド',
    6,
    25,
    8,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep15"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep15"}'::jsonb,
    '{"nodes":{"start":{"text":"「緊急事態だ。辺境の遺跡から古代兵器が起動した」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「オメガ・ゴーレム。高さ十メートル超の鋼鉄の巨人だ。都市に向かって進行している」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「到達予測は三日後。聖騎士団は結界を張って遅延させているが、抜かれるのは時間の問題だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"古代文明の最終兵器。対処法すら分からない。だが止めなければ、都市が消える。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"march_01","choices":[{"label":"続ける","next":"march_01"}]},"march_01":{"text":"辺境へ急行した。街道にゴーレムの進路の痕跡が残っている——巨大な足跡が大地を抉っていた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"march_02","choices":[{"label":"続ける","next":"march_02"}]},"march_02":{"text":"足跡の周囲の樹木は根こそぎ倒れ、岩は粉砕されている。圧倒的な質量の暴力。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"march_03","choices":[{"label":"続ける","next":"march_03"}]},"march_03":{"text":"進路を逆に辿ると、ゴーレムが起動した遺跡に到達した。崩壊した入口の先に研究室がある。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"march_04","choices":[{"label":"続ける","next":"march_04"}]},"march_04":{"text":"研究室の古文書を漁る。ゴーレムの動力源は「コア」と呼ばれる魔力結晶。それを破壊すれば停止する。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"learn_weakness","choices":[{"label":"続ける","next":"learn_weakness"}]},"learn_weakness":{"type":"modify_flag","bg_key":"bg_ruin_crypt","next":"ruin_battle_01","choices":[{"label":"続ける","next":"ruin_battle_01"}]},"ruin_battle_01":{"text":"古文書を持って遺跡を出ようとした時、崩壊した遺跡から目覚めた亡者たちが襲いかかってきた！","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"遺跡のアンデッドたちが襲いかかる！","type":"battle","bg_key":"bg_ruin_crypt","bgm":"bgm_battle","enemy_group_id":"101","choices":[{"label":"win","next":"intercept_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"intercept_01"},"intercept_01":{"text":"亡者を退け、ゴーレムの進路に先回りした。都市まであと半日の場所で迎撃する。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"intercept_02","choices":[{"label":"続ける","next":"intercept_02"}]},"intercept_02":{"text":"地平線の先に砂塵が見えた。ゴーレムが来る。地面が規則的に揺れ始めた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"intercept_03","choices":[{"label":"続ける","next":"intercept_03"}]},"intercept_03":{"text":"鋼鉄の巨体が姿を現した。錆びた装甲。赤く光るコアの眼。千年経っても止まらぬ殺戮装置。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"intercept_04","choices":[{"label":"続ける","next":"intercept_04"}]},"intercept_04":{"text":"ゴーレムがこちらを認識した。腕を振り上げ——地面を叩きつけた！","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"shockwave_trap","choices":[{"label":"続ける","next":"shockwave_trap"}]},"shockwave_trap":{"text":"衝撃波が大地を走り、全身に叩きつけられる。骨が軋む。だがまだ立てる。","type":"hp_damage","bg_key":"bg_road_day","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"shockwave_02","choices":[{"label":"続ける","next":"shockwave_02"}]},"shockwave_02":{"text":"態勢を立て直す。コアは胸部の装甲の奥にある。あそこを狙うしかない。","type":"text","bg_key":"bg_road_day","bgm":"bgm_battle_boss","next":"shockwave_03","choices":[{"label":"続ける","next":"shockwave_03"}]},"shockwave_03":{"text":"ゴーレムが再び腕を振り上げた。今度は——正面から受けて立つ！","type":"text","bg_key":"bg_road_day","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"古代最終兵器オメガ・ゴーレムとの激突——！","type":"battle","bg_key":"bg_road_day","bgm":"bgm_battle_boss","enemy_group_id":"9025","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"胸部装甲を打ち砕いた。コアが剥き出しになり、ゴーレムの動きが鈍る。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"コアは脈打つように光っている。これは単なる動力源ではない——古代文明の叡智の結晶だ。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"完全に破壊すれば脅威は消える。だがこのコアを保存すれば、古代の技術を解明できるかもしれない。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"choice_golem","choices":[{"label":"続ける","next":"choice_golem"}]},"choice_golem":{"type":"choice","bg_key":"bg_road_day","bgm":"bgm_quest_calm","choices":[{"label":"「コアを破壊する。二度と起動させてはならない」","next":"destroy_01"},{"label":"「コアだけ回収する。この技術は人の役に立つ」","next":"preserve_01"}]},"destroy_01":{"text":"渾身の一撃をコアに叩き込んだ。結晶が砕け、ゴーレムが崩壊する。大地を揺らす轟音。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_tense","next":"destroy_02","choices":[{"label":"続ける","next":"destroy_02"}]},"destroy_02":{"text":"鋼鉄の残骸が散らばる中、空は晴れていた。千年の殺戮装置は、ようやく眠りについた。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「オメガ・ゴーレム、完全破壊を確認。都市は救われた。見事だ」\n古代兵器の脅威は消えた。だがあの技術が永遠に失われたことを惜しむ声もある。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":5000,"exp":500,"reputation":20,"alignment_shift":{"order":10}}},"choices":[]},"preserve_01":{"text":"慎重にコアを取り外した。ゴーレムの巨体が力を失い、ゆっくりと膝をつく。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"preserve_02","choices":[{"label":"続ける","next":"preserve_02"}]},"preserve_02":{"text":"コアは手の中で穏やかに脈動している。千年前の技術者たちの知恵が、ここに詰まっている。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"preserve_03","choices":[{"label":"続ける","next":"preserve_03"}]},"preserve_03":{"text":"ゴーレムの残骸は動かない。コアを外せば、ただの鉄くずだ。もう脅威ではない。","type":"text","bg_key":"bg_road_day","bgm":"bgm_quest_calm","next":"end_success_preserve","choices":[{"label":"続ける","next":"end_success_preserve"}]},"end_success_preserve":{"text":"「コアの回収を確認。学術院に引き渡す。古代技術の解析が始まるだろう」\n兵器としてではなく、知識として——古代の遺産は新たな価値を得た。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":3500,"exp":500,"reputation":15,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure":{"text":"ゴーレムの鉄拳に弾き飛ばされた。意識が遠のく中、鋼鉄の巨人は都市に向かって歩き続けている。\n止められなかった——。","type":"end","result":"failure","bg_key":"bg_road_day","choices":[]}},"short_description":"[封印指定] 古代魔導帝国の遺跡から起動した巨大ゴーレムが都市に向かっている。迎撃せよ。"}'::jsonb,
    8,
    4
) ON CONFLICT (id) DO UPDATE SET
