-- Scenario 6110: 大海の悪夢 クラーケン (qst_legend_kraken)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6110,
    'qst_legend_kraken',
    '大海の悪夢 クラーケン',
    '[封印指定] 交易海域に巨大な海魔クラーケンが出現し、船舶を沈めている。海上決戦に挑め。',
    '冒険者ギルド',
    6,
    28,
    12,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep15"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep15"}'::jsonb,
    '{"nodes":{"start":{"text":"「海が死んだ。交易船がまた三隻沈められた。クラーケンの仕業だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「海軍が軍船を一隻貸してくれた。だが船員は志願者だけだ。皆、死を覚悟している」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「報酬は破格だ。だが正直に言う——海の化け物を陸の戦士が倒せるかは分からん」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"海の上での戦い。不慣れな領域だが、交易路を守るためには誰かが行かなければならない。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"sail_01","choices":[{"label":"続ける","next":"sail_01"}]},"sail_01":{"text":"港で軍船に乗り込んだ。甲板は緊張した船員たちでいっぱいだ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_field","next":"sail_02","choices":[{"label":"続ける","next":"sail_02"}]},"sail_02":{"text":"出航。港の灯りが遠ざかり、海だけが広がる。風は穏やかだが、誰も笑わない。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_field","next":"sail_03","choices":[{"label":"続ける","next":"sail_03"}]},"sail_03":{"text":"二日目の夜。海面が不気味に凪いだ。水面下に巨大な影が揺らめいている。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"sail_04","choices":[{"label":"続ける","next":"sail_04"}]},"sail_04":{"text":"突如、空が暗転した。雲が渦を巻き、海が荒れ始める。クラーケンが嵐を呼んでいる——！","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"storm_trap","choices":[{"label":"続ける","next":"storm_trap"}]},"storm_trap":{"text":"暴風雨が船を襲う。巨大な波に叩きつけられ、甲板に激突した。","type":"hp_damage","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"storm_02","choices":[{"label":"続ける","next":"storm_02"}]},"storm_02":{"text":"嵐の中、海面から触腕が伸びてきた！ 船体を掴もうとしている。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"storm_03","choices":[{"label":"続ける","next":"storm_03"}]},"storm_03":{"text":"触腕に引き寄せられた海棲の魔物たちが、甲板に飛び上がってきた——！","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"海棲魔物たちが甲板に襲来！","type":"battle","bg_key":"bg_marcund_desert","bgm":"bgm_battle","enemy_group_id":"104","choices":[{"label":"win","next":"navigate_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"navigate_01"},"navigate_01":{"text":"魔物を退けたが、嵐で方角を見失った。クラーケンの棲む海溝はどこだ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"navigate_02","choices":[{"label":"続ける","next":"navigate_02"}]},"navigate_02":{"text":"濃い霧が立ち込める。船員たちが「海魔の霧だ」と震えている。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"fog_nav","choices":[{"label":"続ける","next":"fog_nav"}]},"fog_nav":{"type":"random_branch","bg_key":"bg_marcund_desert","prob":50,"choices":[{"label":"success","next":"nav_success"},{"label":"failure","next":"nav_fail"}]},"nav_success":{"text":"星の位置を頼りに航路を修正した。霧の向こうに、海溝の入口が見えてきた。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"deep_01","choices":[{"label":"続ける","next":"deep_01"}]},"nav_fail":{"text":"霧に惑わされ、座礁しかけた！ 船底が岩に擦れ、浸水が始まる。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"nav_fail_trap","choices":[{"label":"続ける","next":"nav_fail_trap"}]},"nav_fail_trap":{"text":"浸水を止めるために海中に飛び込んだ。冷たい海水が体温を奪い、四肢が痺れる。","type":"hp_damage","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"nav_fail_02","choices":[{"label":"続ける","next":"nav_fail_02"}]},"nav_fail_02":{"text":"なんとか浸水を塞いだ。体は冷え切ったが、海溝は目の前にある。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"deep_01","choices":[{"label":"続ける","next":"deep_01"}]},"deep_01":{"text":"海溝の上に停泊した。海面が泡立ち、深海から禍々しい気配が昇ってくる。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"deep_02","choices":[{"label":"続ける","next":"deep_02"}]},"deep_02":{"text":"船の錨を下ろし、潜水の準備をする。船員が魔力の護符で水中呼吸の術を施してくれた。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_mystery","next":"deep_03","choices":[{"label":"続ける","next":"deep_03"}]},"deep_03":{"text":"海中に飛び込んだ。暗い深海が広がる。光は届かず、唯一の灯りは護符の微かな光だけだ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"deep_04","choices":[{"label":"続ける","next":"deep_04"}]},"deep_04":{"text":"海溝の壁面に沿って降りる。深くなるほど水圧が増し、体が軋む。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"deep_05","choices":[{"label":"続ける","next":"deep_05"}]},"deep_05":{"text":"海溝の底に辿り着いた。岩と珊瑚の間に、巨大な洞窟がぽっかりと口を開けている。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"deep_06","choices":[{"label":"続ける","next":"deep_06"}]},"deep_06":{"text":"洞窟の奥から、無数の触腕が蠢いている。中央に巨大な瞳が一つ——クラーケンの本体だ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_battle_boss","next":"kraken_01","choices":[{"label":"続ける","next":"kraken_01"}]},"kraken_01":{"text":"触腕が一斉に伸びてきた。海底が震え、水流が渦を巻く——！","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_battle_boss","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"大海の悪夢——クラーケンとの海底決戦！","type":"battle","bg_key":"bg_marcund_desert","bgm":"bgm_battle_boss","enemy_group_id":"9026","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"クラーケンの巨大な瞳が閉じた。触腕が力を失い、海底に沈んでいく。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"だがクラーケンはまだ息がある。止めを刺すか、それとも——","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"この海溝はクラーケンの棲家だ。ここから出さなければ、人間に害はない。追い返すことも可能だ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"choice_kraken","choices":[{"label":"続ける","next":"choice_kraken"}]},"choice_kraken":{"type":"choice","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","choices":[{"label":"「止めを刺す。再び暴れ出す前に」","next":"slay_01"},{"label":"「海溝の奥に追い込む。ここから出るな」","next":"banish_01"}]},"slay_01":{"text":"弱った心臓部に最後の一撃を叩き込んだ。クラーケンの体が痙攣し、動きを止めた。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_tense","next":"slay_02","choices":[{"label":"続ける","next":"slay_02"}]},"slay_02":{"text":"海面に浮上した。空は晴れ、海は凪いでいる。千年の海魔は、海底の墓場に還った。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「クラーケン討伐を確認！ 交易海域は再開される。お前の勇気が海を救った」\n破格の報酬。だが海底で見たあの巨大な瞳は——忘れられそうにない。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":10000,"exp":700,"reputation":30,"alignment_shift":{"chaos":10}}},"choices":[]},"banish_01":{"text":"護符の光で壁を作り、クラーケンを海溝の最深部に追い込んだ。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"banish_02","choices":[{"label":"続ける","next":"banish_02"}]},"banish_02":{"text":"海溝の入口を古代の封印術で塞ぐ。クラーケンが暴れるが、封印は持ちこたえた。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"banish_03","choices":[{"label":"続ける","next":"banish_03"}]},"banish_03":{"text":"海面に浮上すると、嵐は収まっていた。クラーケンは深海に封じた——少なくとも、当面は。","type":"text","bg_key":"bg_marcund_desert","bgm":"bgm_quest_calm","next":"end_success_banish","choices":[{"label":"続ける","next":"end_success_banish"}]},"end_success_banish":{"text":"「海魔を封じたか。封印がいつまで持つかは分からんが——交易路は再開できる」\n殺さずに済んだ。海の生態系を守った——と信じたい。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":6000,"exp":700,"reputation":20,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure":{"text":"触腕に絡めとられ、深海へ引きずり込まれていく。光が遠ざかり、冷たい闇だけが残った。","type":"end","result":"failure","bg_key":"bg_marcund_desert","choices":[]}},"short_description":"[封印指定] 交易海域に巨大な海魔クラーケンが出現し、船舶を沈めている。海上決戦に挑め。"}'::jsonb,
    12,
    6
