-- Scenario 6111: 迷宮の覇者 牛頭王 (qst_legend_minotaur)
INSERT INTO scenarios (
    id, slug, title, description, client_name, difficulty, rec_level, time_cost,
    rewards, is_urgent, quest_type, requirements, location_tags, conditions,
    script_data, days_success, days_failure
) VALUES (
    6111,
    'qst_legend_minotaur',
    '迷宮の覇者 牛頭王',
    '[封印指定] 夜刀神国の地下に古代の迷宮が出現し、牛頭の化け物が支配している。',
    '冒険者ギルド',
    6,
    26,
    9,
    '{"gold":0,"items":[]}'::jsonb,
    false,
    'special',
    '{"completed_quest":"main_ep15"}'::jsonb,
    ARRAY[]::text[],
    '{"completed_quest":"main_ep15"}'::jsonb,
    '{"nodes":{"start":{"text":"「夜刀神国の山中に地割れが起きた。中から古代の迷宮が現れたそうだ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_02","choices":[{"label":"続ける","next":"start_02"}]},"start_02":{"text":"「迷宮の主は『牛頭王』と呼ばれる化け物だ。入った者は誰一人戻っていない」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_03","choices":[{"label":"続ける","next":"start_03"}]},"start_03":{"text":"「周辺の村落から避難民が押し寄せている。迷宮から魔物が溢れ出るのも時間の問題だ」","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","speaker_name":"ギルドマスター","speaker":"ギルドマスター","next":"start_04","choices":[{"label":"続ける","next":"start_04"}]},"start_04":{"text":"迷宮攻略。最も危険で、最も栄誉ある冒険だ。装備を整え、夜刀神国へ向かう。","type":"text","bg_key":"bg_guild","bgm":"bgm_quest_calm","next":"entrance_01","choices":[{"label":"続ける","next":"entrance_01"}]},"entrance_01":{"text":"山中の地割れに到着した。裂け目の底に、人工的な石造りの入口が見える。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"entrance_02","choices":[{"label":"続ける","next":"entrance_02"}]},"entrance_02":{"text":"入口の両脇に、牛の頭蓋骨が飾られている。警告か、それとも自慢か。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"entrance_03","choices":[{"label":"続ける","next":"entrance_03"}]},"entrance_03":{"text":"松明を灯し、迷宮の暗闇に足を踏み入れた。背後で入口の扉が重い音を立てて閉まった。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_tense","next":"maze_01","choices":[{"label":"続ける","next":"maze_01"}]},"maze_01":{"text":"第一層。石壁の通路が無数に分岐している。古代の設計者の悪意が透けて見える。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"maze_02","choices":[{"label":"続ける","next":"maze_02"}]},"maze_02":{"text":"壁には骨が埋め込まれている。過去に迷い込んだ者たちの成れの果てだ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"maze_03","choices":[{"label":"続ける","next":"maze_03"}]},"maze_03":{"text":"通路の床に罠の気配。慎重に足を運ぶが——","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"pit_trap","choices":[{"label":"続ける","next":"pit_trap"}]},"pit_trap":{"text":"床板が抜け落ちた！ 咄嗟に壁を掴んだが、指が滑り数メートル落下した。","type":"hp_damage","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","params":{"hp_percent":10,"percent":10},"next":"maze_04","choices":[{"label":"続ける","next":"maze_04"}]},"maze_04":{"text":"痛む足を引きずりながら、這い上がった。迷宮は容赦がない。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"maze_fork","choices":[{"label":"続ける","next":"maze_fork"}]},"maze_fork":{"text":"T字路。左右どちらにも同じような通路が続いている。壁の模様から方角を推測する——","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"random_fork","choices":[{"label":"続ける","next":"random_fork"}]},"random_fork":{"type":"random_branch","bg_key":"bg_ruin_crypt","prob":50,"choices":[{"label":"success","next":"fork_right"},{"label":"failure","next":"fork_wrong"}]},"fork_right":{"text":"壁の模様に従い右を選んだ。奥から微かな風が吹いてくる。正解だ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","next":"yokai_area","choices":[{"label":"続ける","next":"yokai_area"}]},"fork_wrong":{"text":"左を選んだが、行き止まりだ。しかも壁から毒の霧が噴き出してきた！","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"fork_trap","choices":[{"label":"続ける","next":"fork_trap"}]},"fork_trap":{"text":"毒霧を吸い込み、頭がクラクラする。口を覆いながら引き返し、右の道へ急いだ。","type":"hp_damage","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","params":{"hp_percent":15,"percent":15},"next":"fork_wrong_02","choices":[{"label":"続ける","next":"fork_wrong_02"}]},"fork_wrong_02":{"text":"毒が体に回りつつある。早く先に進まなければ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"yokai_area","choices":[{"label":"続ける","next":"yokai_area"}]},"yokai_area":{"text":"広い部屋に出た。迷宮に棲みついた妖怪たちが、薄闇の中でこちらを睨んでいる。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"battle_01","choices":[{"label":"続ける","next":"battle_01"}]},"battle_01":{"text":"迷宮に棲む妖怪の群れが襲いかかる！","type":"battle","bg_key":"bg_ruin_crypt","bgm":"bgm_battle","enemy_group_id":"106","choices":[{"label":"win","next":"deep_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"deep_01"},"deep_01":{"text":"妖怪を退け、第二層への階段を見つけた。空気がさらに淀んでいる。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"deep_02","choices":[{"label":"続ける","next":"deep_02"}]},"deep_02":{"text":"第二層は天井が高い。巨大な何かが通れるように設計されている——牛頭王の通路だ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"deep_03","choices":[{"label":"続ける","next":"deep_03"}]},"deep_03":{"text":"床に巨大な蹄の跡が刻まれている。新しい。近い——主は。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"deep_04","choices":[{"label":"続ける","next":"deep_04"}]},"deep_04":{"text":"通路の先から重い足音が聞こえてきた。一歩ごとに壁が震える。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"deep_05","choices":[{"label":"続ける","next":"deep_05"}]},"deep_05":{"text":"角を曲がると、天狗の一団が陣を張っていた。迷宮に棲みついた強力な妖怪だ。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"deep_06","choices":[{"label":"続ける","next":"deep_06"}]},"deep_06":{"text":"牛頭王の手前の最後の障壁。突破しなければならない——！","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"battle_02","choices":[{"label":"続ける","next":"battle_02"}]},"battle_02":{"text":"天狗の精鋭が立ちはだかる！","type":"battle","bg_key":"bg_ruin_crypt","bgm":"bgm_battle","enemy_group_id":"107","choices":[{"label":"win","next":"throne_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"throne_01"},"throne_01":{"text":"天狗を退け、迷宮の最深部に到達した。巨大な玉座の間。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"throne_02","choices":[{"label":"続ける","next":"throne_02"}]},"throne_02":{"text":"玉座の間には骨と武具が散乱している。挑戦者たちの末路がここに積み重なっている。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_mystery","next":"throne_03","choices":[{"label":"続ける","next":"throne_03"}]},"throne_03":{"text":"「——また来たか。人間どもは懲りぬ」\n闇の奥から、巨大な影が立ち上がった。牛の頭に人の体。手には大斧。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_battle_boss","speaker_name":"牛頭王","speaker":"牛頭王","next":"throne_04","choices":[{"label":"続ける","next":"throne_04"}]},"throne_04":{"text":"「この迷宮は自分の世界だ。侵入者は例外なく——骨にしてやる」\n大斧が振り上げられ、地面が割れた。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_battle_boss","speaker_name":"牛頭王","speaker":"牛頭王","next":"battle_boss","choices":[{"label":"続ける","next":"battle_boss"}]},"battle_boss":{"text":"迷宮の覇者——牛頭王との最終決戦！","type":"battle","bg_key":"bg_ruin_crypt","bgm":"bgm_battle_boss","enemy_group_id":"9027","choices":[{"label":"win","next":"victory_01"},{"label":"lose","next":"end_failure"}],"battle_success_next":"victory_01"},"victory_01":{"text":"大斧を弾き飛ばし、牛頭王を組み伏せた。地面に叩きつけられた巨体が痙攣する。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","next":"victory_02","choices":[{"label":"続ける","next":"victory_02"}]},"victory_02":{"text":"「……千年、この迷宮を守ってきた。だが自分を超える者がようやく現れたか」","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","speaker_name":"牛頭王","speaker":"牛頭王","next":"victory_03","choices":[{"label":"続ける","next":"victory_03"}]},"victory_03":{"text":"牛頭王を殺せば迷宮は無力化する。だが迷宮ごと封印すれば、内部の財宝と共に安全に埋められる。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","next":"choice_mino","choices":[{"label":"続ける","next":"choice_mino"}]},"choice_mino":{"type":"choice","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","choices":[{"label":"「止めを刺す。お前のような化け物は二度と蘇らせない」","next":"slay_01"},{"label":"「迷宮ごと封印する。二度と地上に出るな」","next":"seal_01"}]},"slay_01":{"text":"剣を突き立てた。牛頭王の咆哮が迷宮全体を震わせ——やがて、静寂が訪れた。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_tense","next":"slay_02","choices":[{"label":"続ける","next":"slay_02"}]},"slay_02":{"text":"迷宮から脱出した。地割れが少しずつ閉じ始めている。主を失った迷宮は崩壊する。","type":"text","bg_key":"bg_yato_den","bgm":"bgm_quest_calm","next":"end_success","choices":[{"label":"続ける","next":"end_success"}]},"end_success":{"text":"「牛頭王の討伐を確認。迷宮は崩壊し、村落の安全は確保された」\n骨と武具の山——あの中には、自分と同じ夢を持った冒険者たちもいたのだろう。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":6000,"exp":550,"reputation":20,"alignment_shift":{"order":10}}},"choices":[]},"seal_01":{"text":"入口に戻り、封印の術を施した。地割れが閉じ、迷宮は再び地の底に沈む。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","next":"seal_02","choices":[{"label":"続ける","next":"seal_02"}]},"seal_02":{"text":"「……封じるのか。殺さぬとは、奇妙な奴だ」\n牛頭王の声が地中から微かに聞こえた。だがもう、地上に出ることはない。","type":"text","bg_key":"bg_ruin_crypt","bgm":"bgm_quest_calm","speaker_name":"牛頭王","speaker":"牛頭王","next":"end_success_seal","choices":[{"label":"続ける","next":"end_success_seal"}]},"end_success_seal":{"text":"「迷宮の封印を確認。地割れは塞がり、村は平和を取り戻した」\n殺すだけが答えではない。閉じ込めるのもまた——一つの決着だ。","type":"end","result":"success","bg_key":"bg_guild","params":{"rewards":{"gold":4000,"exp":550,"reputation":15,"alignment_shift":{"justice":10}}},"choices":[]},"end_failure":{"text":"牛頭王の大斧が体を叩き割った。骨の山に新たな一つが加わった。\n迷宮は、次の挑戦者を待っている。","type":"end","result":"failure","bg_key":"bg_ruin_crypt","choices":[]}},"short_description":"[封印指定] 夜刀神国の地下に古代の迷宮が出現し、牛頭の化け物が支配している。"}'::jsonb,
